-- Poems batch 71
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5f58bb3c-db82-4f06-8ec1-07d6aba4512a','別魯頌','李白','唐','唐诗','tang','','["\u6cf0\u5c71"]','誰道泰山高，下却魯連節。',72,'全唐诗/poet.tang.8000.json','["誰道泰山高，下却魯連節。", "誰云秦軍衆，摧却魯連舌。", "獨立天地間，清風灑蘭雪。", "夫子還倜儻，攻文繼前烈。", "錯落石上松，無爲秋霜折。", "贈言鏤寶刀，千歲庶不滅。"]'),
('e50c7847-073b-4256-8126-719dc53ecc72','別中都明府兄','李白','唐','唐诗','tang','','[]','吾兄詩酒繼陶君，試宰中都天下聞。',64,'全唐诗/poet.tang.8000.json','["吾兄詩酒繼陶君，試宰中都天下聞。", "東樓喜奉連枝會，南陌愁爲落葉分。", "城隅淥水明秋日，海上青山隔暮雲。", "取醉不辭留夜月，鴈行中斷惜離羣。"]'),
('606d0bd8-31d2-4a7a-97ee-341956e7be60','夢遊天姥吟留別','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e00\u5e74\u7ea7\u4e0b\u518c", "\u4e03\u8a00\u53e4\u8bd7", "\u9ad8\u4e2d\u53e4\u8bd7", "\u8bb0\u68a6", "\u53e4\u4f53"]','海客談瀛洲，煙濤微茫信難求。',330,'全唐诗/poet.tang.8000.json','["海客談瀛洲，煙濤微茫信難求。", "越人語天姥，雲霓明滅或可覩。", "天姥連天向天橫，勢拔五嶽掩赤城。", "天台四萬八千丈，對此欲倒東南傾。", "我欲因之夢吳越，一夜飛度鏡湖月。", "湖月照我影，送我至剡溪。", "謝公宿處今尚在，淥水蕩漾清猨啼。", "脚著謝公屐，身登青雲梯。", "半壁見海日，空中聞天雞。", "千巖萬轉路不定，迷花倚石忽已暝。", "熊咆龍吟殷巖泉，慄深林兮驚層巔。", "雲青青兮欲雨，水澹澹兮生煙。", "列缺霹靂，丘巒崩摧。", "洞天石扇，訇然中開。", "青冥浩蕩不見底，日月照耀金銀臺。", "霓爲衣兮風爲馬，雲之君兮紛紛而來下。", "虎鼓瑟兮鸞迴車，仙之人兮列如麻。", "忽魂悸以魄動，怳驚起而長嗟。", "惟覺時之枕席，失向來之煙霞。", "世間行樂亦如此，古來萬事東流水。", "別君去時何時還，且放白鹿青崖間，須行即騎訪名山。", "安能摧眉折腰事權貴？", "使我不得開心顏。"]'),
('3b2213a7-0259-4177-9efd-9649879e36f8','留別曹南羣官之江南','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','我昔釣白龍，放龍溪水傍。',264,'全唐诗/poet.tang.8000.json','["我昔釣白龍，放龍溪水傍。", "道成本欲去，揮手凌蒼蒼。", "時來不關人，談笑遊軒皇。", "獻納少成事，歸休辭建章。", "十年罷西笑，覽鏡如秋霜。", "閉劒琉璃匣，鍊丹紫翠房。", "身佩豁落圖，腰垂虎鞶囊。", "仙人駕彩鳳，志在窮遐荒。", "戀子四五人，裴回未翱翔。", "東流送白日，驟歌蘭蕙芳。", "仙宮兩無從，人間久摧藏。", "范蠡說句踐，屈平去懷王。", "飄飄紫霞心，流浪憶江鄉。", "愁爲萬里別，復此一銜觴。", "淮水帝王州，金陵繞丹陽。", "樓臺照海色，衣馬搖川光。", "及此北望君，相思淚成行。", "朝雲落夢渚，瑤草空高堂。", "帝子隔洞庭，青楓滿瀟湘。", "懷君路綿邈，覽古情淒涼。", "登岳眺百川，杳然萬恨長。", "知戀峨眉去，弄景偶騎羊。"]'),
('0ce20900-4e76-49be-9a95-da3529e1b5a9','留別于十一兄逖裴十三遊塞垣','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u79bb\u522b"]','太公渭川水，李斯上蔡門。',172,'全唐诗/poet.tang.8000.json','["太公渭川水，李斯上蔡門。", "釣周獵秦安黎元，小魚㕙兔何足言。", "天張雲卷有時節，吾徒莫嘆羝觸藩。", "于公白首大梁野，使人悵望何可論。", "既知朱亥爲壯士，且願束心秋毫裏。", "秦趙虎爭血中原，當去抱關救公子。", "裴生覽千古，龍鸞炳文章。", "悲吟雨雪動林木，放書輟劒思高堂。", "勸爾一杯酒，拂爾裘上霜。", "爾爲我楚舞，吾爲爾楚歌。", "且探虎穴向沙漠，鳴鞭走馬凌黃河。", "耻作易水別，臨岐淚滂沱。"]'),
('e3b14f9d-89e4-4363-85b1-612171025de6','留別王司馬嵩','李白','唐','唐诗','tang','','[]','魯連賣談笑，豈是顧千金。',108,'全唐诗/poet.tang.8000.json','["魯連賣談笑，豈是顧千金。", "陶朱雖相越，本有五湖心。", "余亦南陽子，時爲梁甫吟。", "蒼山容偃蹇，白日惜頹侵。", "願一佐明主，功成還舊林。", "西來何所爲，孤劒託知音。", "鳥愛碧山遠，魚遊滄海深。", "呼鷹過上蔡，賣畚向嵩岑。", "他日閑相訪，丘中有素琴。"]'),
('51967264-2d27-486f-b782-23d9407527a0','夜別張五','李白','唐','唐诗','tang','','[]','吾多張公子，別酌酣高堂。',48,'全唐诗/poet.tang.8000.json','["吾多張公子，別酌酣高堂。", "聽歌舞銀燭，把酒輕羅裳。", "橫笛弄秋月，琵琶彈陌桑。", "龍泉解錦帶，爲爾傾千觴。"]'),
('b538c239-a55b-40b2-8845-43e7eb0e45ae','魏郡別蘇明府因北遊','李白','唐','唐诗','tang','','["\u79bb\u522b", "\u5199\u666f", "\u53cb\u60c5"]','魏都接燕趙，美女誇芙蓉。',132,'全唐诗/poet.tang.8000.json','["魏都接燕趙，美女誇芙蓉。", "淇水流碧玉，舟車日奔衝。", "青樓夾兩岸，萬室喧歌鍾。", "天下稱豪貴，遊此每相逢。", "洛陽蘇季子，劒戟森詞鋒。", "六印雖未佩，軒車若飛龍。", "黃金數百鎰，白璧有幾雙。", "散盡空掉臂，高歌賦還邛。", "落魄乃如此，何人不相從。", "遠別隔兩河，雲山杳千重。", "何時更杯酒，再得論心胸。"]'),
('86520d8e-c92d-4500-a5b3-faedeb0faa87','留別西河劉少府','李白','唐','唐诗','tang','','[]','秋髮已種種，所爲竟無成。',120,'全唐诗/poet.tang.8000.json','["秋髮已種種，所爲竟無成。", "閑傾魯壺酒，笑對劉公榮。", "謂我是方朔，人間落歲星。", "白衣千萬乘，何事去天庭。", "君亦不得意，高歌羨鴻冥。", "世人若醯雞，安可識梅生。", "雖爲刀筆吏，緬懷在赤城。", "余亦如流萍，隨波樂休明。", "自有兩少妾，雙騎駿馬行。", "東山春酒綠，歸隱謝浮名。"]'),
('8e3e922b-bebf-49df-8c01-ba3334bbdc03','潁陽別元丹丘之淮陽','李白','唐','唐诗','tang','','["\u53cb\u4eba", "\u9001\u522b"]','吾將元夫子，異姓爲天倫。',156,'全唐诗/poet.tang.8000.json','["吾將元夫子，異姓爲天倫。", "本無軒裳契，素以煙霞親。", "嘗恨迫世網，銘意俱未伸。", "松柏雖寒苦，羞逐桃李春。", "悠悠市朝間，玉顏日緇磷。", "所失重山岳，所得輕埃塵。", "精魄漸蕪穢，衰老相憑因。", "我有錦囊訣，可以持君身。", "當餐黃金藥，去爲紫陽賓。", "萬事難並立，百年猶崇晨。", "別爾東南去，悠悠多悲辛。", "前志庶不易，遠途期所遵。", "已矣歸去來，白雲飛天津。"]'),
('76b0cbd3-a3af-4571-b177-8b448f32a91a','留別廣陵諸公','李白','唐','唐诗','tang','','[]','憶昔作少年，結交趙與燕。',156,'全唐诗/poet.tang.8000.json','["憶昔作少年，結交趙與燕。", "金羈絡駿馬，錦帶橫龍泉。", "寸心無疑事，所向非徒然。", "晚節覺此疎，獵精草太玄。", "空名束壯士，薄俗棄高賢。", "中回聖明顧，揮翰凌雲煙。", "騎虎不敢下，攀龍忽墮天。", "還家守清真，孤潔勵秋蟬。", "鍊丹費火石，採藥窮山川。", "臥海不關人，租稅遼東田。", "乘興忽復起，櫂歌溪中船。", "臨醉謝葛强，山公欲倒鞭。", "狂歌自此別，垂釣滄浪前。"]'),
('26a0c773-86ba-48c4-8e39-9465c603606b','廣陵贈別','李白','唐','唐诗','tang','','["\u79bb\u522b", "\u8d60\u522b", "\u53cb\u8c0a"]','玉瓶沽美酒，數里送君還。',48,'全唐诗/poet.tang.8000.json','["玉瓶沽美酒，數里送君還。", "繫馬垂楊下，銜盃大道間。", "天邊看淥水，海上見青山。", "興罷各分袂，何須醉別顏。"]'),
('a68e6197-cce4-4674-920e-ac5dd54ab6f5','感時留別從兄徐王延年從弟延陵','李白','唐','唐诗','tang','','[]','天籟何參差，噫然大塊吹。',288,'全唐诗/poet.tang.8000.json','["天籟何參差，噫然大塊吹。", "玄元包橐籥，紫氣何逶迤。", "七葉運皇化，千齡光本支。", "仙風生指樹，大雅歌螽斯。", "諸王若鸞虬，肅穆列藩維。", "哲兄錫茅土，聖代羅榮滋。", "九卿領徐方，七步繼陳思。", "伊昔全盛日，雄豪動京師。", "冠劒朝鳳闕，樓船侍龍池。", "鼓鐘出朱邸，金翠照丹墀。", "君王一顧盼，選色獻蛾眉。", "列戟十八年，未曾輙遷移。", "大臣小喑鳴，謫竄天南垂。", "長沙不足舞，貝錦且成詩。", "佐郡浙江西，病閑絕驅馳。", "階軒日苔蘚，鳥雀噪簷帷。", "時乘平肩輿，出入畏人知。", "北宅聊偃憩，歡愉恤惸嫠。", "羞言梁苑地，烜赫耀旌旗。", "兄弟八九人，吳秦各分離。", "太賢達機兆，豈獨慮安危。", "小子謝麟閣，雁行忝肩隨。", "令弟字延陵，鳳毛出天姿。", "清英神仙骨，芬馥茝蘭蕤。"]'),
('5c61ac26-7837-467a-8c85-c3178010a31f','別儲邕之剡中','李白','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u5199\u82b1", "\u82b1", "\u79bb\u522b", "\u5199\u6c34"]','借問剡中道，東南指越鄉。',48,'全唐诗/poet.tang.8000.json','["借問剡中道，東南指越鄉。", "舟從廣陵去，水入會稽長。", "竹色溪下綠，荷花鏡裏香。", "辭君向天姥，拂石臥秋霜。"]'),
('43e2b06f-39de-4867-9086-77efbdff12fb','留別金陵諸公','李白','唐','唐诗','tang','','[]','海水昔飛動，三龍紛戰爭。',120,'全唐诗/poet.tang.8000.json','["海水昔飛動，三龍紛戰爭。", "鍾山危波瀾，傾側駭奔鯨。", "黃旗一掃蕩，割壤開吳京。", "六代更霸王，遺跡見都城。", "至今秦淮間，禮樂秀羣英。", "地扇鄒魯學，詩騰顏謝名。", "五月金陵西，祖余白下亭。", "欲尋廬峰頂，先遶漢水行。", "香爐紫煙滅，瀑布落太清。", "若攀星辰去，揮手緬含情。"]'),
('45ce3da3-9327-4909-997b-c7804ecb4796','口號','李白','唐','唐诗','tang','','[]','食出野田美，酒臨遠水傾。',24,'全唐诗/poet.tang.8000.json','["食出野田美，酒臨遠水傾。", "東流若未盡，應見別離情。"]'),
('809ad73b-9a8e-436e-9874-f9295b624af0','金陵酒肆留別','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u53e4\u8bd7", "\u79bb\u522b", "\u996e\u9152"]','風吹柳花滿店香，吳姬壓酒喚客嘗。',48,'全唐诗/poet.tang.8000.json','["風吹柳花滿店香，吳姬壓酒喚客嘗。", "金陵子弟來相送，欲行不行各盡觴。", "請君試問東流水，別意與之誰短長。"]'),
('2d470a73-2f50-4fe4-b3f3-cb8951b47fc0','金陵白下亭留別','李白','唐','唐诗','tang','','[]','驛亭三楊樹，正當白下門。',48,'全唐诗/poet.tang.8000.json','["驛亭三楊樹，正當白下門。", "吳煙暝長條，漢水齧古根。", "向來送行處，迴首阻笑言。", "別後若見之，爲余一攀翻。"]'),
('088d7e4e-8670-4caa-8790-60b58a2480a3','別東林寺僧','李白','唐','唐诗','tang','','["\u5e90\u5c71", "\u9001\u522b"]','東林送客處，月出白猨啼。',24,'全唐诗/poet.tang.8000.json','["東林送客處，月出白猨啼。", "笑別廬山遠，何煩過虎溪。"]'),
('087750d7-a87c-4a98-a086-ca8076f48253','竄夜郎於烏江留別宗十六璟','李白','唐','唐诗','tang','','["\u79bb\u522b", "\u4f24\u611f", "\u6292\u6000", "\u611f\u6168"]','君家全盛日，台鼎何陸離。',156,'全唐诗/poet.tang.8000.json','["君家全盛日，台鼎何陸離。", "斬鼇翼媧皇，鍊石補天維。", "一迴日月顧，三入鳳皇池。", "失勢青門傍，種瓜復幾時。", "猶會衆賓客，三千光路岐。", "皇恩雪憤懣，松柏含榮滋。", "我非東牀人，令姊忝齊眉。", "浪跡未出世，空名動京師。", "適遭雲羅解，翻謫夜郎悲。", "拙妻莫邪劒，及此二龍隨。", "慙君湍波苦，千里遠從之。", "白帝曉猨斷，黃牛過客遲。", "遙瞻明月峽，西去益相思。"]'),
('bcd63f19-0a2b-447c-87f1-f19c120d8d8f','留別龔處士','李白','唐','唐诗','tang','','[]','龔子棲閑地，都無人世喧。',48,'全唐诗/poet.tang.8000.json','["龔子棲閑地，都無人世喧。", "柳深陶令宅，竹暗辟疆園。", "我去黃牛峽，遙愁白帝猨。", "贈君卷葹草，心斷竟何言。"]'),
('660e8871-459a-4d4c-861a-997c1e174eb4','贈別鄭判官','李白','唐','唐诗','tang','','[]','竄逐勿復哀，慚君問寒灰。',48,'全唐诗/poet.tang.8000.json','["竄逐勿復哀，慚君問寒灰。", "浮雲本無意，吹落章華臺。", "遠別淚空盡，長愁心已摧。", "二年吟澤畔，顦顇幾時迴。"]'),
('d43a4767-2240-44b7-8d5b-c2acdc689839','黃鶴樓送孟浩然之廣陵','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u957f\u6c5f", "\u9ec4\u9e64\u697c", "\u79bb\u522b", "\u5e26\u6709\u5730\u540d", "\u5c0f\u5b66\u53e4\u8bd7"]','故人西辭黃鶴樓，煙花三月下揚州。',32,'全唐诗/poet.tang.8000.json','["故人西辭黃鶴樓，煙花三月下揚州。", "孤帆遠影碧山盡，唯見長江天際流。"]'),
('7a02a999-6ea6-4a50-bc53-90b665f10897','將遊衡嶽過漢陽雙松亭留別族弟浮屠談皓','李白','唐','唐诗','tang','','[]','秦欺趙氏璧，却入邯鄲宮。',132,'全唐诗/poet.tang.8000.json','["秦欺趙氏璧，却入邯鄲宮。", "本是楚家玉，還來荆山中。", "丹彩瀉滄溟，精輝凌白虹。", "青蠅一相點，流落此時同。", "卓絕道門秀，談玄乃支公。", "延蘿結幽居，剪竹繞芳叢。", "涼花拂戶牖，天籟鳴虛空。", "憶我初來時，蒲萄開景風。", "今茲大火落，秋葉黃梧桐。", "水色夢沅湘，長沙去何窮。", "寄書訪衡嶠，但與南飛鴻。"]'),
('c0e8867b-a945-4f03-8e0e-eacbf3c6c0ee','留別賈舍人至二首 一','李白','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','大梁白雲起，飄颻來南洲。',120,'全唐诗/poet.tang.8000.json','["大梁白雲起，飄颻來南洲。", "裴回蒼梧野，十見羅浮秋。", "鼇抃山海傾，四溟揚洪流。", "意欲託孤鳳，從之摩天遊。", "鳳苦道路難，翱翔還崑丘。", "不肯銜我去，哀鳴慙不周。", "遠客謝主人，明珠難暗投。", "拂拭倚天劒，西登岳陽樓。", "長嘯萬里風，掃清胷中憂。", "誰念劉越石，化爲繞指柔。"]'),
('02e2ee6f-0796-49c6-b9bd-96e786042baf','留別賈舍人至二首 二','李白','唐','唐诗','tang','','[]','秋風吹胡霜，凋此簷下芳。',84,'全唐诗/poet.tang.8000.json','["秋風吹胡霜，凋此簷下芳。", "折芳怨歲晚，離別悽以傷。", "謬攀青瑣賢，延我於北堂。", "君爲長沙客，我獨之夜郎。", "勸此一杯酒，豈惟道路長。", "割珠兩分贈，寸心貴不忘。", "何必兒女仁，相看淚成行。"]'),
('bf8918b8-a05a-4ccf-bb2e-3f9b81f6bbfc','渡荆門送別','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u957f\u6c5f", "\u9001\u522b", "\u4e94\u8a00\u5f8b\u8bd7", "\u521d\u4e2d\u53e4\u8bd7", "\u516b\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5185)"]','渡遠荆門外，來從楚國遊。',48,'全唐诗/poet.tang.8000.json','["渡遠荆門外，來從楚國遊。", "山隨平野盡，江入大荒流。", "月下飛天鏡，雲生結海樓。", "仍連故鄉水，萬里送行舟。"]'),
('fa70d3d0-dc0d-417b-aa49-3bcebfcbe727','聞李太尉大舉秦兵百萬出征東南懦夫請纓冀申一割之用半道病還留別金陵崔侍御十九韻','李白','唐','唐诗','tang','','["\u957f\u6c5f", "\u9ec4\u6cb3"]','秦出天下兵，蹴踏燕趙傾。',228,'全唐诗/poet.tang.8000.json','["秦出天下兵，蹴踏燕趙傾。", "黃河飲馬竭，赤羽連天明。", "太尉杖旄鉞，雲旗繞彭城。", "三軍受號令，千里肅雷霆。", "函谷絕飛鳥，武關擁連營。", "意在斬巨鼇，何論鱠長鯨。", "恨無左軍略，多愧魯連生。", "拂劒照嚴霜，彫戈鬘胡纓。", "願雪會稽恥，將期報恩榮。", "半道謝病還，無因東南征。", "亞夫未見顧，劇孟阻先行。", "天奪壯士心，長吁別吳京。", "金陵遇太守，倒屣相逢迎。", "羣公咸祖餞，四座羅朝英。", "初發臨滄觀，醉棲征虜亭。", "舊國見秋月，長江流寒聲。", "帝車信迴轉，河漢復縱橫。", "孤鳳向西海，飛鴻辭北溟。", "因之出寥廓，揮手謝公卿。"]'),
('d5d3b296-7f8d-4e30-b6a7-7942a5cf4902','別韋少府','李白','唐','唐诗','tang','','["\u79bb\u522b", "\u4e0d\u820d", "\u53cb\u4eba"]','西出蒼龍門，南登白鹿原。',96,'全唐诗/poet.tang.8000.json','["西出蒼龍門，南登白鹿原。", "欲尋商山皓，猶戀漢皇恩。", "水國遠行邁，仙經深討論。", "洗心向溪月，清耳敬亭猨。", "築室在人境，閉門無世喧。", "多君枉高駕，贈我以微言。", "交乃意氣合，道因風雅存。", "別離有相思，瑤瑟與金樽。"]'),
('0b826256-9c22-40b7-b797-669974fac0bc','南陵別兒童入京','李白','唐','唐诗','tang','','[]','白酒新熟山中歸，黃雞啄黍秋正肥。',96,'全唐诗/poet.tang.8000.json','["白酒新熟山中歸，黃雞啄黍秋正肥。", "呼童烹雞酌白酒，兒女嬉笑牽人衣。", "高歌取醉欲自慰，起舞落日爭光輝。", "游說萬乘苦不早，著鞭跨馬涉遠道。", "會稽愚婦輕買臣，余亦辭家西入秦。", "仰天大笑出門去，我輩豈是蓬蒿人。"]'),
('a6d524a9-aab5-4440-8b4b-380c3d9223e3','別山僧','李白','唐','唐诗','tang','','[]','何處名僧到水西，乘舟弄月宿涇溪。',80,'全唐诗/poet.tang.8000.json','["何處名僧到水西，乘舟弄月宿涇溪。", "平明別我上山去，手攜金策踏雲梯。", "騰身轉覺三天近，舉足迴看萬嶺低。", "謔浪肯居支遁下，風流還與遠公齊。", "此度別離何日見，相思一夜暝猨啼。"]'),
('ba723a17-18b0-4899-846e-b3143b80fd7b','贈別王山人歸布山','李白','唐','唐诗','tang','','[]','王子析道論，微言破秋毫。',84,'全唐诗/poet.tang.8000.json','["王子析道論，微言破秋毫。", "還歸布山隱，興入天雲高。", "爾去安可遲，瑤草恐衰歇。", "我心亦懷歸，屢夢松上月。", "傲然遂獨往，長嘯開巖扉。", "林壑久已蕪，石道生薔薇。", "願言弄笙鶴，歲晚來相依。"]'),
('2af4241c-3cb4-4351-a5f9-8207e2a73905','江夏別宋之悌','李白','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u53cb\u60c5", "\u6c34", "\u79bb\u522b", "\u5199\u6c34"]','楚水清若空，遙將碧海通。',48,'全唐诗/poet.tang.8000.json','["楚水清若空，遙將碧海通。", "人分千里外，興在一杯中。", "谷鳥吟晴日，江猨嘯晚風。", "平生不下淚，於此泣無窮。"]'),
('7dbf7997-7bc5-4919-8ed5-de4504f5e044','南陽送客','李白','唐','唐诗','tang','','["\u79bb\u522b", "\u53cb\u4eba", "\u9001\u522b"]','斗酒勿爲薄，寸心貴不忘。',48,'全唐诗/poet.tang.8000.json','["斗酒勿爲薄，寸心貴不忘。", "坐惜故人去，偏令遊子傷。", "離顏怨芳草，春思結垂楊。", "揮手再三別，臨岐空斷腸。"]'),
('a03956af-1c8f-4f59-bbc9-c018f2920d13','送張舍人之江東','李白','唐','唐诗','tang','','["\u79bb\u522b", "\u79cb\u5929"]','張翰江東去，正值秋風時。',48,'全唐诗/poet.tang.8000.json','["張翰江東去，正值秋風時。", "天清一鴈遠，海闊孤帆遲。", "白日行欲暮，滄波杳難期。", "吳洲如見月，千里幸相思。"]'),
('82a18575-a154-499c-92a1-cc906f3ce6a0','送王屋山人魏萬還王屋','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u53cb\u4eba", "\u9001\u522b", "\u5f52\u9690", "\u60cb\u60dc"]','仙人東方生，浩蕩弄雲海。',288,'全唐诗/poet.tang.8000.json','["仙人東方生，浩蕩弄雲海。", "沛然乘天遊，獨往失所在。", "魏侯繼大名，本家聊攝城。", "卷舒入元化，跡與古賢幷。", "十三弄文史，揮筆如振綺。", "辯折田巴生，心齊魯連子。", "西涉清洛源，頗驚人世喧。", "采秀臥王屋，因窺洞天門。", "朅來遊嵩峰，羽客何雙雙。", "朝攜月光子，暮宿玉女牕。", "鬼谷上窈窕，龍潭下奔潨。", "東浮汴河水，訪我三千里。", "逸興滿吳雲，飄颻淛江汜。", "揮手杭越間，樟亭望潮還。", "濤卷海門石，雲橫天際山。", "白馬走素車，雷奔駭心顏。", "遙聞會稽美，且度耶溪水。", "萬壑與千巖，崢嶸鏡湖裏。", "秀色不可名，清輝滿江城。", "人遊月邊去，舟在空中行。", "此中久延佇，入剡尋王許。", "笑讀曹娥碑，沈吟黃絹語。", "天台連四明，日入向國清。", "五峰轉月色，百里行松聲。"]'),
('366d68c6-fc8b-4dad-b805-13ce2eb26fbb','送當塗趙少府赴長蘆','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u53cb\u4eba", "\u9001\u522b"]','我來揚都市，送客回輕舠。',72,'全唐诗/poet.tang.8000.json','["我來揚都市，送客回輕舠。", "因誇楚太子，便覩廣陵濤。", "仙尉趙家玉，英風凌四豪。", "維舟至長蘆，目送煙雲高。", "搖扇對酒樓，持袂把蟹螯。", "前途儻相思，登嶽一長謠。"]'),
('f46c4b42-c765-44f4-bd22-bf30b4a7a5c7','送友人尋越中山水','李白','唐','唐诗','tang','','["\u9001\u522b", "\u5c71\u6c34"]','聞道稽山去，偏宜謝客才。',72,'全唐诗/poet.tang.8000.json','["聞道稽山去，偏宜謝客才。", "千巖泉灑落，萬壑樹縈迴。", "東海橫秦望，西陵遶越臺。", "湖清霜鏡曉，濤白雪山來。", "八月枚乘筆，三吳張翰杯。", "此中多逸興，早晚向天台。"]'),
('50f662a3-b036-4f18-acd8-255e8581bb1f','送族弟凝之滁求婚崔氏','李白','唐','唐诗','tang','','[]','與爾情不淺，忘筌已得魚。',48,'全唐诗/poet.tang.8000.json','["與爾情不淺，忘筌已得魚。", "玉臺挂寶鏡，持此意何如。", "坦腹東牀下，由來志氣疎。", "遙知向前路，擲果定盈車。"]'),
('a6b982a2-5e34-487d-a54a-fbb388df57ec','送友人遊梅湖','李白','唐','唐诗','tang','','[]','送君游梅湖，應見梅花發。',48,'全唐诗/poet.tang.8000.json','["送君游梅湖，應見梅花發。", "有使寄我來，無令紅芳歇。", "暫行新林浦，定醉金陵月。", "莫惜一鴈書，音塵坐胡越。"]'),
('d01a5e0f-196c-43be-83ff-6c4ccad25e17','送崔十二遊天竺寺','李白','唐','唐诗','tang','','[]','還聞天竺寺，夢想懷東越。',48,'全唐诗/poet.tang.8000.json','["還聞天竺寺，夢想懷東越。", "每年海樹霜，桂子落秋月。", "送君遊此地，已屬流芳歇。", "待我來歲行，相隨浮溟渤。"]'),
('bbacef3d-8cc5-44cb-bf68-4f36ccc13b35','送楊山人歸天台','李白','唐','唐诗','tang','','[]','客有思天台，東行路超忽。',96,'全唐诗/poet.tang.8000.json','["客有思天台，東行路超忽。", "濤落浙江秋，沙明浦陽月。", "今遊方厭楚，昨夢先歸越。", "且盡秉燭歡，無辭凌晨發。", "我家小阮賢，剖竹赤城邊。", "詩人多見重，官燭未曾然。", "興引登山屐，情催泛海船。", "石橋如可度，攜手弄雲煙。"]'),
('123288b6-f986-4c06-99d4-433f9e22274b','送溫處士歸黃山白鵝峰舊居','李白','唐','唐诗','tang','','["\u9ec4\u5c71", "\u5199\u5c71", "\u9001\u522b", "\u5199\u666f", "\u63cf\u5199\u5c71"]','黃山四千仞，三十二蓮峰。',132,'全唐诗/poet.tang.8000.json','["黃山四千仞，三十二蓮峰。", "丹崖夾石柱，菡萏金芙蓉。", "伊昔昇絕頂，下窺天目松。", "仙人鍊玉處，羽化留餘蹤。", "亦聞溫伯雪，獨往今相逢。", "採秀辭五岳，攀巖歷萬重。", "歸休白鵝嶺，渴飲丹砂井。", "鳳吹我時來，雲車爾當整。", "去去陵陽東，行行芳桂叢。", "迴溪十六度，碧嶂盡晴空。", "他日還相訪，乘橋躡綵虹。"]'),
('c62f4f89-1398-4b22-9e2f-17480decca73','送方士趙叟之東平','李白','唐','唐诗','tang','','[]','長桑曉洞視，五藏無全牛。',48,'全唐诗/poet.tang.8000.json','["長桑曉洞視，五藏無全牛。", "趙叟得祕訣，還從方士遊。", "西過獲麟臺，爲我弔孔丘。", "念別復懷古，潸然空淚流。"]'),
('77f7b9e4-ad7c-4af2-a41a-ee2afcb2428b','送韓準裴政孔巢父還山','李白','唐','唐诗','tang','','[]','獵客張兔罝，不能挂龍虎。',144,'全唐诗/poet.tang.8000.json','["獵客張兔罝，不能挂龍虎。", "所以青雲人，高歌在巖戶。", "韓生信英彥，裴子含清真。", "孔侯復秀出，俱與雲霞親。", "峻節凌遠松，同衾臥盤石。", "斧冰嗽寒泉，三子同二屐。", "時時或乘興，往往雲無心。", "出山揖牧伯，長嘯輕衣簪。", "昨宵夢裏還，云弄竹溪月。", "今晨魯東門，帳飲與君別。", "雪崖滑去馬，蘿徑迷歸人。", "相思若煙草，歷亂無冬春。"]'),
('92c9a3c7-04ef-449b-9b8a-a9f5c7b1f76e','送楊少府赴選','李白','唐','唐诗','tang','','["\u9001\u522b"]','大國置衡鏡，準平天地心。',156,'全唐诗/poet.tang.8000.json','["大國置衡鏡，準平天地心。", "羣賢無邪人，朗鑒窮情深。", "吾君詠南風，衮冕彈鳴琴。", "時泰多美士，京國會纓簪。", "山苗落澗底，幽松出高岑。", "夫子有盛才，主司得球琳。", "流水非鄭曲，前行遇知音。", "衣工剪綺繡，一悞傷千金。", "何惜刀尺餘，不裁寒女衾。", "我非彈冠者，感別但開襟。", "空谷無白駒，賢人豈悲吟。", "大道安棄物，時來或招尋。", "爾見山吏部，當應無陸沈。"]'),
('598b7bf9-47f1-4af6-a69e-6ca4f21565d4','對雪奉餞任城六父秩滿歸京','李白','唐','唐诗','tang','','["\u9001\u522b", "\u996e\u9152", "\u53cb\u60c5"]','龍虎謝鞭策，鵷鸞不司晨。',144,'全唐诗/poet.tang.8000.json','["龍虎謝鞭策，鵷鸞不司晨。", "君看海上鶴，何似籠中鶉。", "獨用天地心，浮雲乃吾身。", "雖將簪組狎，若與煙霞親。", "季父有英風，白眉超常倫。", "一官即夢寐，脫屐歸西秦。", "竇公敞華筵，墨客盡來臻。", "燕歌落胡鴈，郢曲迴陽春。", "征馬百度嘶，遊車動行塵。", "躊躇未忍去，戀此四座人。", "餞離駐高駕，惜別空殷勤。", "何時竹林下，更與步兵鄰。"]'),
('9a55c5ec-f335-4e3d-89c3-2d54c1c6f0d6','魯郡堯祠送吳五之瑯琊','李白','唐','唐诗','tang','','[]','堯沒三千歲，青松古廟存。',48,'全唐诗/poet.tang.8000.json','["堯沒三千歲，青松古廟存。", "送行奠桂酒，拜舞清心魂。", "日色促歸人，連歌倒芳樽。", "馬嘶俱醉起，分手更何言。"]'),
('a5ab3e24-6d68-4cdf-ae96-33aa58599bbf','魯郡堯祠送竇明府薄華還西京','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u6292\u60c5", "\u53cb\u4eba", "\u9001\u522b", "\u6124\u61d1"]','朝策犂眉騧，舉鞭力不堪。',386,'全唐诗/poet.tang.8000.json','["朝策犂眉騧，舉鞭力不堪。", "强扶愁疾向何處，角巾微服堯祠南。", "長楊掃地不見日，石門噴作金沙潭。", "笑誇故人指絕境，山光水色青於藍。", "廟中往往來擊鼓，堯本無心爾何苦。", "門前長跪雙石人，有女如花日歌舞。", "銀鞍繡轂往復迴，簸林蹶石鳴風雷。", "遠煙空翠時明滅，白鷗歷亂長飛雪。", "紅泥亭子赤闌干，碧流環轉青錦湍。", "深沈百丈洞海底，那知不有蛟龍蟠。", "君不見綠珠潭水流東海，綠珠紅粉沈光彩。", "綠珠樓下花滿園，今日曾無一枝在。", "昨夜秋聲閶闔來，洞庭木落騷人哀。", "遂將三五少年輩，登高遠望形神開。", "生前一笑輕九鼎，魏武何悲銅雀臺。", "我歌白雲倚牕牖，爾聞其聲但揮手。", "長風吹月度海來，遙勸仙人一杯酒。", "酒中樂酣宵向分，舉觴酹堯堯可聞。", "何不令臯繇擁篲橫八極，直上青天揮浮雲。", "高陽小飲真瑣瑣，山公酩酊何如我。", "竹林七子去道賒，蘭亭雄筆安足誇。", "堯祠笑殺五湖水，至今顦悴空荷花。", "爾向西秦我東越，暫向瀛洲訪金闕。", "藍田太白若可期，爲余掃灑石上月。"]'),
('d25baae5-ed69-4115-b06b-58b50d1cab42','金鄉送韋八之西京','李白','唐','唐诗','tang','','["\u9001\u522b", "\u60dc\u522b"]','客自長安來，還歸長安去。',48,'全唐诗/poet.tang.8000.json','["客自長安來，還歸長安去。", "狂風吹我心，西挂咸陽樹。", "此情不可道，此別何時遇。", "望望不見君，連山起煙霧。"]'),
('5297d9ed-84f3-4369-9f08-57993a2a185f','送薛九被讒去魯','李白','唐','唐诗','tang','','[]','宋人不辨玉，魯賤東家丘。',192,'全唐诗/poet.tang.8000.json','["宋人不辨玉，魯賤東家丘。", "我笑薛夫子，胡爲兩地遊。", "黃金消衆口，白璧竟難投。", "梧桐生蒺藜，綠竹乏佳實。", "鳳凰宿誰家，遂與羣雞匹。", "田家養老馬，窮士歸其門。", "蛾眉笑躄者，賓客去平原。", "却斬美人首，三千還駿奔。", "毛公一挺劒，楚趙兩相存。", "孟嘗習狡兔，三窟賴馮諼。", "信陵奪兵符，爲用侯生言。", "春申一何愚，刎首爲李園。", "賢哉四公子，撫掌黃泉裏。", "借問笑何人，笑人不好士。", "爾去且勿諠，桃李竟何言。", "沙丘無漂母，誰肯飯王孫。"]'),
('e3a9ed68-08f2-47e1-a06d-15004d23bdf3','單父東樓秋夜送族弟沈之秦','李白','唐','唐诗','tang','','[]','爾從咸陽來，問我何勞苦。',192,'全唐诗/poet.tang.8000.json','["爾從咸陽來，問我何勞苦。", "沐猴而冠不足言，身騎土牛滯東魯。", "沈弟欲行凝弟留，孤飛一雁秦雲秋。", "坐來黃葉落四五，北斗已挂西城樓。", "絲桐感人弦亦絕，滿堂送君皆惜別。", "卷簾見月清興來，疑是山陰夜中雪。", "明日斗酒別，惆悵清路塵。", "遙望長安日，不見長安人。", "長安宮闕九天上，此地曾經爲近臣。", "一朝復一朝，髮白心不改。", "屈原憔悴滯江潭，亭伯流離放遼海。", "折翮翻飛隨轉蓬，聞弦墜虛下霜空。", "聖朝久棄青雲士，他日誰憐張長公。"]'),
('a3773616-f026-453c-ae3f-356fea47a3a0','送族弟凝至晏堌','李白','唐','唐诗','tang','','[]','雪滿原野白，戎裝出盤遊。',84,'全唐诗/poet.tang.8000.json','["雪滿原野白，戎裝出盤遊。", "揮鞭布獵騎，四顧登高丘。", "兔起馬足間，蒼鷹下平疇。", "喧呼相馳逐，取樂銷人憂。", "舍此戒禽荒，微聲列齊謳。", "鳴雞發晏堌，別雁驚淶溝。", "西行有東音，寄與長河流。"]'),
('f821e44c-1c77-4aea-9a9c-edb7c391b832','魯城北郭曲腰桑下送張子還嵩陽','李白','唐','唐诗','tang','','[]','送別枯桑下，凋葉落半空。',48,'全唐诗/poet.tang.8000.json','["送別枯桑下，凋葉落半空。", "我行懵道遠，爾獨知天風。", "誰念張仲蔚，還依蒿與蓬。", "何時一杯酒，更與李膺同。"]'),
('c0579b6e-b0bf-481f-a654-33f38f275b4b','送魯郡劉長史遷弘農長史','李白','唐','唐诗','tang','','[]','魯國一杯水，難容橫海鱗。',156,'全唐诗/poet.tang.8000.json','["魯國一杯水，難容橫海鱗。", "仲尼且不敬，況乃尋常人。", "白玉換斗粟，黃金買尺薪。", "閉門木葉下，始覺秋非春。", "聞君向西遷，地即鼎湖鄰。", "寶鏡匣蒼蘚，丹經埋素塵。", "軒后上天時，攀龍遺小臣。", "及此留惠愛，庶幾風化淳。", "魯縞如白煙，五縑不成束。", "臨行贈貧交，一尺重山岳。", "相國齊晏子，贈行不及言。", "託陰當樹李，忘憂當樹萱。", "他日見張祿，綈袍懷舊恩。"]'),
('abc5f4d7-c9b8-464a-a3c8-a5f618d374cc','送族弟單父主簿凝攝宋城主簿至郭南月橋却迴棲霞山留飲贈之','李白','唐','唐诗','tang','','[]','吾家青萍劍，操割有餘閑。',72,'全唐诗/poet.tang.8000.json','["吾家青萍劍，操割有餘閑。", "往來糾二邑，此去何時還。", "鞍馬月橋南，光輝岐路間。", "賢豪相追餞，却到棲霞山。", "羣花散芳園，斗酒開離顏。", "樂酣相顧起，征馬無由攀。"]'),
('432f0351-d99d-41eb-9712-143f2850cb42','魯郡東石門送杜二甫','李白','唐','唐诗','tang','','["\u9001\u522b", "\u53cb\u60c5"]','醉別復幾日，登臨徧池臺。',48,'全唐诗/poet.tang.8000.json','["醉別復幾日，登臨徧池臺。", "何時石門路，重有金樽開。", "秋波落泗水，海色明徂徠。", "飛蓬各自遠，且盡手中杯。"]'),
('5ca3ce18-f054-4812-9399-fd831efdf337','魯郡堯祠送張十四遊河北','李白','唐','唐诗','tang','','["\u6cf0\u5c71"]','猛虎伏尺草，雖藏難蔽身。',60,'全唐诗/poet.tang.8000.json','["猛虎伏尺草，雖藏難蔽身。", "有如張公子，骯髒在風塵。", "豈無橫腰劒，屈彼淮陰人。", "擊筑向北燕，燕歌易水濱。", "歸來泰山上，當與爾爲鄰。"]'),
('44151303-461e-45bb-9f23-ea06a04d66bb','杭州送裴大澤赴廬州長史','李白','唐','唐诗','tang','','[]','西江天柱遠，東越海門深。',48,'全唐诗/poet.tang.8000.json','["西江天柱遠，東越海門深。", "去割慈親戀，行憂報國心。", "好風吹落日，流水引長吟。", "五月披裘者，應知不取金。"]'),
('604817ba-67b1-4e3c-8390-c93753deb12f','灞陵行送別','李白','唐','唐诗','tang','','["\u9001\u522b", "\u6101\u7eea", "\u53cb\u60c5", "\u5199\u666f"]','送君灞陵亭，灞水流浩浩。',78,'全唐诗/poet.tang.8000.json','["送君灞陵亭，灞水流浩浩。", "上有無花之古樹，下有傷心之春草。", "我向秦人問路岐，云是王粲南登之古道。", "古道連綿走西京，紫闕落日浮雲生。", "正當今夕斷腸處，黃鸝愁絕不忍聽。"]'),
('e6605a4d-7343-4a17-9663-0cded2180293','送賀監歸四明應制','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','久辭榮祿遂初衣，曾向長生說息機。',64,'全唐诗/poet.tang.8000.json','["久辭榮祿遂初衣，曾向長生說息機。", "真訣自從茅氏得，恩波寧阻洞庭歸。", "瑤臺含霧星辰滿，仙嶠浮空島嶼微。", "借問欲棲珠樹鶴，何年却向帝城飛。"]'),
('fafa4d1f-a604-4719-b5fe-00d79fc1cfd6','送竇司馬貶宜春','李白','唐','唐诗','tang','','[]','天馬白銀鞍，親承明主歡。',72,'全唐诗/poet.tang.8000.json','["天馬白銀鞍，親承明主歡。", "鬬雞金宮裏，射鴈碧雲端。", "堂上羅中貴，歌鍾清夜闌。", "何言謫南國，拂劍坐長歎。", "趙璧爲誰點，隋珠枉被彈。", "聖朝多雨露，莫厭此行難。"]'),
('824f6cd7-1d32-4f85-8bb0-0c67072094a8','送羽林陶將軍','李白','唐','唐诗','tang','','[]','將軍出使擁樓船，江上旌旗拂紫煙。',48,'全唐诗/poet.tang.8000.json','["將軍出使擁樓船，江上旌旗拂紫煙。", "萬里橫戈探虎穴，三杯拔劍舞龍泉。", "莫道詞人無膽氣，臨行將贈繞朝鞭。"]'),
('55e92c8e-80af-4dcc-a34d-706c95138e91','送程劉二侍郎兼獨孤判官赴安西幕府','李白','唐','唐诗','tang','','[]','安西幕府多材雄，喧喧惟道三數公。',80,'全唐诗/poet.tang.8000.json','["安西幕府多材雄，喧喧惟道三數公。", "繡衣貂裘明積雪，飛書走檄如飄風。", "朝辭明主出紫宮，銀鞍送別金城空。", "天外飛霜下蔥海，火旗雲馬生光彩。", "胡塞清塵幾日歸，漢家草綠遙相待。"]'),
('2b49f2a8-865d-4327-80e3-96df2ed6db27','送姪良攜二妓赴會稽戲有此贈','李白','唐','唐诗','tang','','[]','攜妓東山去，春光半道催。',24,'全唐诗/poet.tang.8000.json','["攜妓東山去，春光半道催。", "遙看若桃李，雙入鏡中開。"]'),
('e410354e-db61-419e-96f8-b2f28f9e7aca','送賀賓客歸越','李白','唐','唐诗','tang','','["\u8d60\u522b", "\u53cb\u60c5"]','鏡湖流水漾清波，狂客歸舟逸興多。',32,'全唐诗/poet.tang.8000.json','["鏡湖流水漾清波，狂客歸舟逸興多。", "山陰道士如相見，應寫黃庭換白鵝。"]'),
('4d306d38-234e-48e7-a35f-d1f155264786','送張遙之壽陽幕府','李白','唐','唐诗','tang','','[]','壽陽信天險，天險橫荆關。',84,'全唐诗/poet.tang.8000.json','["壽陽信天險，天險橫荆關。", "苻堅百萬衆，遙阻八公山。", "不假築長城，大賢在其間。", "戰夫若熊虎，破敵有餘閑。", "張子勇且英，少輕衛霍孱。", "投軀紫髯將，千里望風顏。", "勗爾効才略，功成衣錦還。"]'),
('e8c0f376-de6c-49b9-ace2-bdcefbaad76f','送裴十八圖南歸嵩山二首 一','李白','唐','唐诗','tang','','["\u9001\u522b", "\u5f52\u9690"]','何處可爲別，長安青綺門。',72,'全唐诗/poet.tang.8000.json','["何處可爲別，長安青綺門。", "胡姬招素手，延客醉金樽。", "臨當上馬時，我獨與君言。", "風吹芳蘭折，日沒鳥雀喧。", "舉手指飛鴻，此情難具論。", "同歸無早晚，潁水有清源。"]'),
('aeb0797b-6b0c-4e04-8be3-06cbb3c535fe','送裴十八圖南歸嵩山二首 二','李白','唐','唐诗','tang','','[]','君思潁水綠，忽復歸嵩岑。',48,'全唐诗/poet.tang.8000.json','["君思潁水綠，忽復歸嵩岑。", "歸時莫洗耳，爲我洗其心。", "洗心得真情，洗耳徒買名。", "謝公終一起，相與濟蒼生。"]'),
('ecaff990-891b-4270-be58-232b9ce0a501','同王昌齡送族弟襄歸桂陽二首 一','李白','唐','唐诗','tang','','[]','秦地見碧草，楚謠對清樽。',72,'全唐诗/poet.tang.8000.json','["秦地見碧草，楚謠對清樽。", "把酒爾何思，鷓鴣啼南園。", "余欲羅浮隱，猶懷明主恩。", "躊躇紫宮戀，孤負滄洲言。", "終然無心雲，海上同飛翻。", "相期乃不淺，幽桂有芳根。"]'),
('84f4fe6b-129d-4ab3-b888-b014cc21eef9','同王昌齡送族弟襄歸桂陽二首 二','李白','唐','唐诗','tang','','[]','爾家何在瀟湘川，青莎白石長沙邊。',96,'全唐诗/poet.tang.8000.json','["爾家何在瀟湘川，青莎白石長沙邊。", "昨夢江花照江日，幾枝正發東牕前。", "覺來欲往心悠然，魂隨越鳥飛南天。", "秦雲連山海相接，桂水橫煙不可涉。", "送君此去令人愁，風帆茫茫隔河洲。", "春潭瓊草綠可折，西寄長安明月樓。"]'),
('f38cc5ab-e7ac-48ce-93fc-e89315ca64b7','送外甥鄭灌從軍三首 一','李白','唐','唐诗','tang','','[]','六博爭雄好彩來，金盤一擲萬人開。',32,'全唐诗/poet.tang.8000.json','["六博爭雄好彩來，金盤一擲萬人開。", "丈夫賭命報天子，當斬胡頭衣錦回。"]'),
('fb306ab2-2ab6-4420-a78d-14d23e4c4365','送外甥鄭灌從軍三首 二','李白','唐','唐诗','tang','','[]','丈八蛇矛出隴西，彎弧拂箭白猨啼。',32,'全唐诗/poet.tang.8000.json','["丈八蛇矛出隴西，彎弧拂箭白猨啼。", "破胡必用龍韜策，積甲應將熊耳齊。"]'),
('3a86a1fa-6d4e-4878-bfb5-20797ad298ad','送外甥鄭灌從軍三首 三','李白','唐','唐诗','tang','','["\u9ec4\u6cb3"]','月蝕西方破敵時，及瓜歸日未應遲。',32,'全唐诗/poet.tang.8000.json','["月蝕西方破敵時，及瓜歸日未應遲。", "斬胡血變黃河水，梟首當懸白鵲旗。"]'),
('4c589b3c-f792-4b59-b3d4-b81efc736077','送于十八應四子舉落第還嵩山','李白','唐','唐诗','tang','','[]','吾祖吹橐籥，天人信森羅。',108,'全唐诗/poet.tang.8000.json','["吾祖吹橐籥，天人信森羅。", "歸根復太素，羣動熙元和。", "炎炎四真人，摛辯若濤波。", "交流無時寂，楊墨日成科。", "夫子聞洛誦，誇才才固多。", "爲金好踊躍，久客方蹉跎。", "道可束賣之，五寶溢山河。", "勸君還嵩丘，開酌盼庭柯。", "三花如未落，乘興一來過。"]'),
('4fa83850-46d1-4f9e-b970-d8c24bbb353a','送別','李白','唐','唐诗','tang','','["\u957f\u6c5f"]','尋陽五溪水，沿洄直入巫山裏。',62,'全唐诗/poet.tang.8000.json','["尋陽五溪水，沿洄直入巫山裏。", "勝境由來人共傳，君到南中自稱美。", "送君別有八月秋，颯颯蘆花復益愁。", "雲帆望遠不相見，日暮長江空自流。"]'),
('bb506670-0684-403a-95a3-5404d868c97b','送族弟綰從軍安西','李白','唐','唐诗','tang','','[]','漢家兵馬乘北風，鼓行而西破犬戎。',64,'全唐诗/poet.tang.8000.json','["漢家兵馬乘北風，鼓行而西破犬戎。", "爾隨漢將出門去，剪虜若草收奇功。", "君王按劍望邊色，旄頭已落胡天空。", "匈奴繫頭數應盡，明年應入蒲萄宮。"]'),
('26d3de06-7a8a-4b52-b740-fd9ceb59bddd','送梁公昌從信安北征','李白','唐','唐诗','tang','','[]','入幕推英選，捐書事遠戎。',72,'全唐诗/poet.tang.8000.json','["入幕推英選，捐書事遠戎。", "高談百戰術，鬱作萬夫雄。", "起舞蓮花劍，行歌明月弓。", "將飛天地陣，兵出塞垣通。", "祖席留丹景，征麾拂彩虹。", "旋應獻凱入，麟閣佇深功。"]'),
('9e8a5439-6648-4b6b-aca8-a5420585c67d','送白利從金吾董將軍西征','李白','唐','唐诗','tang','','["\u53cb\u4eba", "\u5199\u4eba", "\u62b1\u8d1f", "\u6218\u4e89", "\u5199\u4eba\u8bd7"]','西羌延國討，白起佐軍威。',48,'全唐诗/poet.tang.8000.json','["西羌延國討，白起佐軍威。", "劍決浮雲氣，弓彎明月輝。", "馬行邊草綠，旌卷曙霜飛。", "抗手凜相顧，寒風生鐵衣。"]'),
('e962ed06-2f60-49ae-9114-3650b2e72283','送張秀才從軍','李白','唐','唐诗','tang','','[]','六駁食猛虎，恥從駑馬羣。',84,'全唐诗/poet.tang.8000.json','["六駁食猛虎，恥從駑馬羣。", "一朝長鳴去，矯若龍行雲。", "壯士懷遠略，志存解世紛。", "周粟猶不顧，齊珪安肯分。", "抱劍辭高堂，將投崔冠軍。", "長策掃河洛，寧親歸汝墳。", "當令千古後，麟閣著奇勳。"]'),
('d60e7aa0-bc6e-4bf5-8e2b-c28fd0295d69','送崔度還吳','李白','唐','唐诗','tang','','[]','幽燕沙雪地，萬里盡黃雲。',96,'全唐诗/poet.tang.8000.json','["幽燕沙雪地，萬里盡黃雲。", "朝吹歸秋雁，南飛日幾羣。", "中有孤鳳雛，哀鳴九天聞。", "我乃重此鳥，綵章五色分。", "胡爲雜凡禽，雛鶩輕賤君。", "舉手捧爾足，疾心若火焚。", "拂羽淚滿面，送之吳江濆。", "去影忽不見，躊躇日將曛。"]'),
('59ef98eb-2b16-40d4-9092-e497299b0aed','送祝八之江東賦得浣紗石','李白','唐','唐诗','tang','','[]','西施越溪女，明豔光雲海。',92,'全唐诗/poet.tang.8000.json','["西施越溪女，明豔光雲海。", "未入吳王宮殿時，浣紗古石今猶在。", "桃李新開映古查，菖蒲猶短出平沙。", "昔時紅粉照流水，今日青苔覆落花。", "君去西秦適東越，碧山青江幾超忽。", "若到天涯思故人，浣紗石上窺明月。"]'),
('0460180e-63da-42ae-870b-7d943e7913c5','送侯十一','李白','唐','唐诗','tang','','[]','朱亥已擊晉，侯嬴尚隱身。',48,'全唐诗/poet.tang.8000.json','["朱亥已擊晉，侯嬴尚隱身。", "時無魏公子，豈貴抱關人。", "余亦不火食，遊梁同在陳。", "空餘湛盧劍，贈爾託交親。"]'),
('ecedf7b9-697a-41be-a017-e66ea1d9a4f4','魯中送二從弟赴舉之西京','李白','唐','唐诗','tang','','["\u9001\u522b", "\u7231\u56fd", "\u8ff0\u5fd7", "\u8d5e\u7f8e"]','魯客向西笑，君門若夢中。',72,'全唐诗/poet.tang.8000.json','["魯客向西笑，君門若夢中。", "霜凋逐臣髮，日憶明光宮。", "復羨二龍去，才華冠世雄。", "平衢騁高足，逸翰凌長風。", "舞袖拂秋月，歌筵聞蚤鴻。", "送君日千里，良會何由同。"]'),
('ee2b6255-9e07-43af-b7b6-28f39f33f8da','奉餞高尊師如貴道士傳道籙畢歸北海','李白','唐','唐诗','tang','','[]','道隱不可見，靈書藏洞天。',48,'全唐诗/poet.tang.8000.json','["道隱不可見，靈書藏洞天。", "吾師四萬劫，歷世遰相傳。", "別杖留青竹，行歌躡紫煙。", "離心無遠近，長在玉京懸。"]'),
('e5654e19-ae83-4262-918c-8916798f6da6','金陵送張十一再遊東吳','李白','唐','唐诗','tang','','[]','張翰黃花句，風流五百年。',72,'全唐诗/poet.tang.8000.json','["張翰黃花句，風流五百年。", "誰人今繼作，夫子世稱賢。", "再動游吳櫂，還浮入海船。", "春光白門柳，霞色赤城天。", "去國難爲別，思歸各未旋。", "空餘賈生淚，相顧共悽然。"]'),
('fdc2f505-9c71-4539-a5c9-ab2bcbdd756a','送紀秀才遊越','李白','唐','唐诗','tang','','[]','海水不滿眼，觀濤難稱心。',72,'全唐诗/poet.tang.8000.json','["海水不滿眼，觀濤難稱心。", "即知蓬萊石，却是巨鼇簪。", "送爾遊華頂，令余發舃吟。", "仙人居射的，道士住山陰。", "禹穴尋溪入，雲門隔嶺深。", "綠蘿秋月夜，相憶在鳴琴。"]'),
('f9c79a97-d07a-425f-8dbd-11de4e9aa98d','送長沙陳太守二首 一','李白','唐','唐诗','tang','','["\u8861\u5c71"]','長沙陳太守，逸氣凌青松。',48,'全唐诗/poet.tang.8000.json','["長沙陳太守，逸氣凌青松。", "英主賜五馬，本是天池龍。", "湘水迴九曲，衡山望五峰。", "榮君按節去，不及遠相從。"]'),
('314f7709-ef88-4638-b8e3-6d9b4cd147ca','送長沙陳太守二首 二','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','七郡長沙國，南連湘水濱。',48,'全唐诗/poet.tang.8000.json','["七郡長沙國，南連湘水濱。", "定王垂舞袖，地窄不迴身。", "莫小二千石，當安遠俗人。", "洞庭鄉路遠，遙羨錦衣春。"]'),
('0c018949-4bbb-43bb-8af9-02690f2ca715','送楊燕之東魯','李白','唐','唐诗','tang','','["\u957f\u6c5f"]','關西楊伯起，漢日舊稱賢。',108,'全唐诗/poet.tang.8000.json','["關西楊伯起，漢日舊稱賢。", "四代三公族，清風播人天。", "夫子華陰居，開門對玉蓮。", "何事歷衡霍，雲帆今始還。", "君坐稍解顏，爲君歌此篇。", "我固侯門士，謬登聖主筵。", "一辭金華殿，蹭蹬長江邊。", "二子魯門東，別來已經年。", "因君此中去，不覺淚如泉。"]'),
('cb6f5ac0-a2bb-406f-9049-28ac81cfee12','送蔡山人','李白','唐','唐诗','tang','','["\u5bb4\u4f1a", "\u9001\u522b", "\u6292\u6000", "\u6000\u624d\u4e0d\u9047"]','我本不棄世，世人自棄我。',60,'全唐诗/poet.tang.8000.json','["我本不棄世，世人自棄我。", "一乘無倪舟，八極縱遠柂。", "燕客期躍馬，唐生安敢譏。", "採珠勿驚龍，大道可暗歸。", "故山有松月，遲爾翫清暉。"]'),
('f394334a-c211-47e1-9a8f-04fb2a368b6e','送蕭三十一之魯中兼問稚子伯禽','李白','唐','唐诗','tang','','[]','六月南風吹白沙，吳牛喘月氣成霞。',96,'全唐诗/poet.tang.8000.json','["六月南風吹白沙，吳牛喘月氣成霞。", "水國鬱蒸不可處，時炎道遠無行車。", "夫子如何涉江路，雲帆嫋嫋金陵去。", "高堂倚門望伯魚，魯中正是趨庭處。", "我家寄在沙丘傍，三年不歸空斷腸。", "君行既識伯禽子，應駕小車騎白羊。"]'),
('581767e0-8a5f-4db3-8855-61b3163c7ad1','送楊山人歸嵩山','李白','唐','唐诗','tang','','["\u53cb\u4eba", "\u9001\u522b", "\u611f\u6168"]','我有萬古宅，嵩陽玉女峰。',48,'全唐诗/poet.tang.8000.json','["我有萬古宅，嵩陽玉女峰。", "長留一片月，挂在東溪松。", "爾去掇仙草，菖蒲花紫茸。", "歲晚或相訪，青天騎白龍。"]'),
('0e42cf58-6dcd-43a4-9aa2-256c33dedaa4','送殷淑三首 一','李白','唐','唐诗','tang','','[]','海水不可解，連江夜爲潮。',48,'全唐诗/poet.tang.8000.json','["海水不可解，連江夜爲潮。", "俄然蒲嶼闊，岸去酒船遙。", "惜別耐取醉，鳴榔且長謠。", "天明爾當去，應便有風飄。"]'),
('3fd8eece-59e8-4a12-a883-23f87975623f','送殷淑三首 二','李白','唐','唐诗','tang','','[]','白鷺洲前月，天明送客回。',48,'全唐诗/poet.tang.8000.json','["白鷺洲前月，天明送客回。", "青龍山後日，早出海雲來。", "流水無情去，征帆逐吹開。", "相看不忍別，更進手中杯。"]'),
('4a33769b-fc5f-499b-9c51-f6148e39b6bd','送殷淑三首 三','李白','唐','唐诗','tang','','[]','痛飲龍筇下，燈青月復寒。',24,'全唐诗/poet.tang.8000.json','["痛飲龍筇下，燈青月復寒。", "醉歌驚白鷺，半夜起沙灘。"]'),
('a0054440-69e5-4449-8264-132d442e293a','送岑徵君歸鳴臯山','李白','唐','唐诗','tang','','[]','岑公相門子，雅望歸安石。',144,'全唐诗/poet.tang.8000.json','["岑公相門子，雅望歸安石。", "奕世皆夔龍，中台竟三拆。", "至人達機兆，高揖九州伯。", "奈何天地間，而作隱淪客。", "貴道能全真，潛輝臥幽鄰。", "探元入窅默，觀化游無垠。", "光武有天下，嚴陵爲故人。", "雖登洛陽殿，不屈巢由身。", "余亦謝明主，今稱偃蹇臣。", "登高覽萬古，思與廣成鄰。", "蹈海寧受賞，還山非問津。", "西來一搖扇，共拂元規塵。"]'),
('d1be5a0f-d53a-4e62-859e-113d59c04fe6','送范山人歸泰山','李白','唐','唐诗','tang','','["\u6cf0\u5c71", "\u6292\u60c5", "\u5411\u5f80", "\u5199\u666f"]','魯客抱白鶴，別余往泰山。',48,'全唐诗/poet.tang.8000.json','["魯客抱白鶴，別余往泰山。", "初行若片雲，杳在青崖間。", "高高至天門，日觀近可攀。", "雲山望不及，此去何時還。"]'),
('a21edaa7-dbf6-4eaf-b3b2-4e75862f7796','送韓侍御之廣德','李白','唐','唐诗','tang','','["\u53cb\u4eba", "\u9001\u522b", "\u53cb\u8c0a"]','昔日繡衣何足榮，今宵貰酒與君傾。',32,'全唐诗/poet.tang.8000.json','["昔日繡衣何足榮，今宵貰酒與君傾。", "暫就東山賒月色，酣歌一夜送泉明。"]'),
('e91e6239-120e-4368-8ff1-d6aa69f0b2fe','送通禪師還南陵隱靜寺','李白','唐','唐诗','tang','','[]','我聞隱靜寺，山水多奇蹤。',48,'全唐诗/poet.tang.8000.json','["我聞隱靜寺，山水多奇蹤。", "巖種朗公橘，門深杯渡松。", "道人制猛虎，振錫還孤峰。", "他日南陵下，相期谷口逢。"]'),
('1f83fccf-7476-464b-8cd4-8a2b4569c7a0','送友人','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u516b\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5916)", "\u53cb\u60c5", "\u5199\u666f", "\u9001\u522b", "\u4e94\u8a00\u5f8b\u8bd7"]','青山橫北郭，白水遶東城。',48,'全唐诗/poet.tang.8000.json','["青山橫北郭，白水遶東城。", "此地一爲別，孤蓬萬里征。", "浮雲遊子意，落日故人情。", "揮手自茲去，蕭蕭班馬鳴。"]'),
('ff9a4eff-8500-475e-ba0c-7799f8e76346','送別','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u996e\u9152", "\u9001\u522b"]','斗酒渭城邊，壚頭醉不眠。',48,'全唐诗/poet.tang.8000.json','["斗酒渭城邊，壚頭醉不眠。", "梨花千樹雪，楊葉萬條煙。", "惜別傾壺醑，臨分贈馬鞭。", "看君潁上去，新月到應圓。"]'),
('b178a1e5-c1cf-42a0-bd17-8c11b5d524fa','江上送女道士褚三清遊南嶽','李白','唐','唐诗','tang','','["\u8861\u5c71", "\u9001\u522b", "\u5199\u4eba"]','吳江女道士，頭戴蓮花巾。',48,'全唐诗/poet.tang.8000.json','["吳江女道士，頭戴蓮花巾。", "霓衣不濕雨，特異陽臺雲。", "足下遠遊履，凌波生素塵。", "尋仙向南嶽，應見魏夫人。"]'),
('972ed983-f073-4cfb-b780-184a9553f458','送友人入蜀','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u9001\u522b", "\u529d\u52c9", "\u5c71\u6c34"]','見說蠶叢路，崎嶇不易行。',48,'全唐诗/poet.tang.8000.json','["見說蠶叢路，崎嶇不易行。", "山從人面起，雲傍馬頭生。", "芳樹籠秦棧，春流遶蜀城。", "升沉應已定，不必問君平。"]'),
('4e2966af-bfef-446e-8b14-e65dd19958cc','送李青歸南葉陽川','李白','唐','唐诗','tang','','[]','伯陽仙家子，容色如青春。',48,'全唐诗/poet.tang.8000.json','["伯陽仙家子，容色如青春。", "日月祕靈洞，雲霞辭世人。", "化心養精魄，隱几窅天真。", "莫作千年別，歸來城郭新。"]'),
('b84f9fdd-5ef7-44a5-935a-840772cb7c38','送舍弟','李白','唐','唐诗','tang','','[]','吾家白額駒，遠別臨東道。',28,'全唐诗/poet.tang.8000.json','["吾家白額駒，遠別臨東道。", "他日相思一夢君，應得池塘生春草。"]'),
('88cbcc21-f372-4656-988c-088b4b1beabd','送別得書字','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u9001\u522b"]','水色南天遠，舟行若在虛。',48,'全唐诗/poet.tang.8000.json','["水色南天遠，舟行若在虛。", "遷人發佳興，吾子訪閑居。", "日落看歸鳥，潭澄羨躍魚。", "聖朝思賈誼，應降紫泥書。"]'),
('d3ef7870-ff4a-46eb-8518-64e0d9a63742','送麴十少府','李白','唐','唐诗','tang','','[]','試發清秋興，因爲吳會吟。',48,'全唐诗/poet.tang.8000.json','["試發清秋興，因爲吳會吟。", "碧雲歛海色，流水折江心。", "我有延陵劍，君無陸賈金。", "艱難此爲別，惆悵一何深。"]'),
('4cf451ee-3c75-458c-b898-d9b11b5cc887','送張秀才謁高中丞','李白','唐','唐诗','tang','','[]','秦帝淪玉鏡，留侯降氛氳。',156,'全唐诗/poet.tang.8000.json','["秦帝淪玉鏡，留侯降氛氳。", "感激黃石老，經過滄海君。", "壯士揮金槌，報讐六國聞。", "智勇冠終古，蕭陳難與羣。", "兩龍爭鬬時，天地動風雲。", "酒酣舞長劍，倉卒解漢紛。", "宇宙初倒懸，鴻溝勢將分。", "英謀信奇絕，夫子揚清芬。", "胡月入紫微，三光亂天文。", "高公鎮淮海，談笑却妖氛。", "採爾幕中畫，戡難光殊勳。", "我無燕霜感，玉石俱燒焚。", "但灑一行淚，臨岐竟何云。"]'),
('14eb557e-c913-4fcc-a0d7-9e95b091920f','尋陽送弟昌峒鄱陽司馬作','李白','唐','唐诗','tang','','[]','桑落洲渚連，滄江無雲煙。',156,'全唐诗/poet.tang.8000.json','["桑落洲渚連，滄江無雲煙。", "潯陽非剡水，忽見子猷船。", "飄然欲相近，來遲杳若仙。", "人乘海上月，帆落湖中天。", "一覩無二諾，朝懽更勝昨。", "爾則吾惠連，吾非爾康樂。", "朱紱白銀章，上官佐鄱陽。", "松門拂中道，石鏡迴清光。", "搖扇及于越，水亭風氣涼。", "與爾期此亭，期在秋月滿。", "時過或未來，兩鄉心已斷。", "吳山對楚岸，彭蠡當中州。", "相思定如此，有窮盡年愁。"]'),
('f1190a8c-2227-4651-8793-c9090c1b406f','餞校書叔雲','李白','唐','唐诗','tang','','[]','少年費白日，歌笑矜朱顏。',60,'全唐诗/poet.tang.8000.json','["少年費白日，歌笑矜朱顏。", "不知忽已老，喜見春風還。", "惜別且爲歡，裴回桃李間。", "看花飲美酒，聽鳥臨晴山。", "向晚竹林寂，無人空閉關。"]'),
('07e842a2-5d7c-4c5b-93f1-d485c2661410','送王孝廉覲省','李白','唐','唐诗','tang','','[]','彭蠡將天合，姑蘇在日邊。',48,'全唐诗/poet.tang.8000.json','["彭蠡將天合，姑蘇在日邊。", "寧親候海色，欲動孝廉船。", "窈窕晴江轉，參差遠岫連。", "相思無晝夜，東泣似長川。"]'),
('1ddfb05d-8274-4fba-b4be-c5432bb06bff','同吳王送杜秀芝赴舉入京','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u666f", "\u5199\u4eba\u8bd7"]','秀才何翩翩，王許回也賢。',48,'全唐诗/poet.tang.8000.json','["秀才何翩翩，王許回也賢。", "暫別廬江守，將遊京兆天。", "秋山宜落日，秀水出寒烟。", "欲折一枝桂，還來雁沼前。"]'),
('51c91cee-edab-4aeb-8082-743a00ebe9aa','洞庭醉後送絳州呂使君果流澧州','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','昔別若夢中，天涯忽相逢。',48,'全唐诗/poet.tang.8000.json','["昔別若夢中，天涯忽相逢。", "洞庭破秋月，縱酒開愁容。", "贈劍刻玉字，延平兩蛟龍。", "送君不盡意，書及雁迴峯。"]'),
('bac8896f-6fbd-4d45-be8f-3510fb2e548d','與諸公送陳郎將歸衡陽','李白','唐','唐诗','tang','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56", "\u4e0d\u820d", "\u9001\u522b", "\u5199\u666f"]','衡山蒼蒼入紫冥，下看南極老人星。',80,'全唐诗/poet.tang.8000.json','["衡山蒼蒼入紫冥，下看南極老人星。", "迴飆吹散五峰雪，往往飛花落洞庭。", "氣清嶽秀有如此，郎將一家拖金紫。", "門前食客亂浮雲，世人皆比孟嘗君。", "江上送行無白璧，臨歧惆悵若爲分。"]'),
('65eadbc6-65ad-43d6-8b4a-1ba2a0bd0439','送趙判官赴黔府中丞叔幕','李白','唐','唐诗','tang','','["\u9001\u522b", "\u5199\u4eba", "\u8d5e\u7f8e"]','廓落青雲心，交結黃金盡。',144,'全唐诗/poet.tang.8000.json','["廓落青雲心，交結黃金盡。", "富貴翻相忘，令人忽自哂。", "蹭蹬鬢毛斑，盛時難再還。", "巨源咄石生，何事馬蹄間。", "綠蘿長不厭，却欲還東山。", "君爲魯曾子，拜揖高堂裏。", "叔繼趙平原，偏承明主恩。", "風霜推獨坐，旌節鎮雄藩。", "虎士秉金鉞，蛾眉開玉樽。", "才高幕下去，義重林中言。", "水宿五溪月，霜啼三峽猨。", "東風春草綠，江上候歸軒。"]'),
('dc3c1811-4e94-4507-88f5-8423aed5454d','送陸判官往琵琶峽','李白','唐','唐诗','tang','','["\u9001\u522b", "\u6292\u6000", "\u58ee\u5fd7\u672a\u916c"]','水國秋風夜，殊非遠別時。',24,'全唐诗/poet.tang.8000.json','["水國秋風夜，殊非遠別時。", "長安如夢裏，何日是歸期。"]'),
('4b42fe36-c0b8-4a38-ad72-606c96e063df','送梁四歸東平','李白','唐','唐诗','tang','','[]','玉壺挈美酒，送別強爲歡。',48,'全唐诗/poet.tang.8000.json','["玉壺挈美酒，送別強爲歡。", "大火南星月，長郊北路難。", "殷王期負鼎，汶水起垂竿。", "莫學東山臥，參差老謝安。"]'),
('e953a156-417e-4dc8-8277-8d0e447ddae9','江夏送友人','李白','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','雪點翠雲裘，送君黃鶴樓。',48,'全唐诗/poet.tang.8000.json','["雪點翠雲裘，送君黃鶴樓。", "黃鶴振玉羽，西飛帝王州。", "鳳無瑯玕實，何以贈遠遊。", "裴回相顧影，淚下漢江流。"]'),
('63caa6e1-7b61-44b5-a165-d25866147d31','送郄昂謫巴中','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u8d60\u522b", "\u6625\u5929"]','瑤草寒不死，移植滄江濱。',48,'全唐诗/poet.tang.8000.json','["瑤草寒不死，移植滄江濱。", "東風灑雨露，會入天地春。", "予若洞庭葉，隨波送逐臣。", "思歸未可得，書此謝情人。"]'),
('51e83caa-ceda-4586-9109-4ce8d3fe8295','江夏送張丞','李白','唐','唐诗','tang','','[]','欲別心不忍，臨行情更親。',48,'全唐诗/poet.tang.8000.json','["欲別心不忍，臨行情更親。", "酒傾無限月，客醉幾重春。", "藉草依流水，攀花贈遠人。", "送君從此去，迴首泣迷津。"]'),
('f4c05057-064c-463f-b810-97caadf2da0a','賦得白鷺鷥送宋少府入三峽','李白','唐','唐诗','tang','','["\u601d\u4e61", "\u5199\u666f"]','白鷺拳一足，月明秋水寒。',24,'全唐诗/poet.tang.8000.json','["白鷺拳一足，月明秋水寒。", "人驚遠飛去，直向使君灘。"]'),
('eb55610a-61f5-4e16-9f21-aff30f8fc47d','送二季之江東','李白','唐','唐诗','tang','','["\u5e90\u5c71"]','初發强中作，題詩與惠連。',72,'全唐诗/poet.tang.8000.json','["初發强中作，題詩與惠連。", "多慚一日長，不及二龍賢。", "西塞當中路，南風欲進船。", "雲峰出遠海，帆影挂清川。", "禹穴藏書地，匡山種杏田。", "此行俱有適，遲爾早歸旋。"]'),
('960e1e5c-e218-4104-8f45-9fc62cfd7d6f','江西送友人之羅浮','李白','唐','唐诗','tang','','["\u8861\u5c71"]','桂水分五嶺，衡山朝九疑。',96,'全唐诗/poet.tang.8000.json','["桂水分五嶺，衡山朝九疑。", "鄉關渺安西，流浪將何之。", "素色愁明湖，秋渚晦寒姿。", "疇昔紫芳意，已過黃髮期。", "君王縱疎散，雲壑借巢夷。", "爾去之羅浮，我還憩峨眉。", "中闊道萬里，霞月遙相思。", "如尋楚狂子，瓊樹有芳枝。"]'),
('5593d522-b820-4c06-bab6-0ab5a0fc1d46','宣州謝朓樓餞別校書叔雲','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5916)", "\u4e03\u8a00\u53e4\u8bd7", "\u521d\u4e2d\u53e4\u8bd7", "\u54f2\u7406", "\u79bb\u522b"]','棄我去者昨日之日不可留，亂我心者今日之日多煩憂。',104,'全唐诗/poet.tang.8000.json','["棄我去者昨日之日不可留，亂我心者今日之日多煩憂。", "長風萬里送秋雁，對此可以酣高樓。", "蓬萊文章建安骨，中間小謝又清發。", "俱懷逸興壯思飛，欲上青天覽日月。", "抽刀斷水水更流，舉杯銷愁愁更愁。", "人生在世不稱意，明朝散髮弄扁舟。"]'),
('142c446d-7944-4336-836d-cca5c1544299','宣城送劉副使入秦','李白','唐','唐诗','tang','','["\u79bb\u522b", "\u5199\u4eba", "\u8d5e\u7f8e"]','君即劉越石，雄豪冠當時。',252,'全唐诗/poet.tang.8000.json','["君即劉越石，雄豪冠當時。", "淒清橫吹曲，慷慨扶風詞。", "虎嘯俟騰躍，雞鳴遭亂離。", "千金市駿馬，萬里逐王師。", "結交樓煩將，侍從羽林兒。", "統兵捍吳越，豺虎不敢窺。", "大勳竟莫敘，已過秋風吹。", "秉鉞有季公，凜然負英姿。", "寄深且戎幕，望重必台司。", "感激一然諾，縱橫兩無疑。", "伏奏歸北闕，鳴騶忽西馳。", "列將咸出祖，英僚惜分離。", "斗酒滿四筵，歌嘯宛溪湄。", "君攜東山妓，我詠北門詩。", "貴賤交不易，恐傷中園葵。", "昔贈紫騮駒，今傾白玉巵。", "同歡萬斛酒，未足解相思。", "此別又千里，秦吳渺天涯。", "月明關山苦，水劇隴頭悲。", "借問幾時還，春風入黃池。", "無令長相憶，折斷綠楊枝。"]'),
('106d9d4c-02d5-41b2-b10e-6aeba5134628','涇川送族弟錞','李白','唐','唐诗','tang','','[]','涇川三百里，若耶羞見之。',192,'全唐诗/poet.tang.8000.json','["涇川三百里，若耶羞見之。", "錦石照碧山，兩邊白鷺鷥。", "佳境千萬曲，客行無歇時。", "上有琴高水，下有陵陽祠。", "仙人不見我，明月空相知。", "問我何事來，盧敖結幽期。", "蓬山振雄筆，繡服揮清詞。", "江湖發秀色，草木含榮滋。", "置酒送惠連，吾家稱白眉。", "愧無海嶠作，敢闕河梁詩。", "見爾復幾朝，俄然告將離。", "中流漾彩鷁，列岸叢金羈。", "歎息蒼梧鳳，分棲瓊樹枝。", "清晨各飛去，飄落天南垂。", "望極落日盡，秋深暝猨悲。", "寄情與流水，但有長相思。"]'),
('dea526f7-0c75-442d-9451-0cd306fd9ad0','五松山送殷淑','李白','唐','唐诗','tang','','[]','秀色發江左，風流奈若何。',72,'全唐诗/poet.tang.8000.json','["秀色發江左，風流奈若何。", "仲文了不還，獨立揚清波。", "載酒五松山，頹然白雲歌。", "中天度落月，萬里遙相過。", "撫酒惜此月，流光畏蹉跎。", "明日別離去，連峰鬱嵯峨。"]'),
('8f85ff26-043f-4052-8cce-3162cb5013ae','送崔氏昆季之金陵','李白','唐','唐诗','tang','','[]','放歌倚東樓，行子期曉發。',96,'全唐诗/poet.tang.8000.json','["放歌倚東樓，行子期曉發。", "秋風渡江來，吹落山上月。", "主人出美酒，滅燭延清光。", "二崔向金陵，安得不盡觴。", "水客弄歸櫂，雲帆卷輕霜。", "扁舟敬亭下，五兩先飄揚。", "峽石入水花，碧流日更長。", "思君無歲月，西笑阻河梁。"]'),
('030741a9-3313-4f3a-ade8-fff5f5fb5370','登黃山凌歊臺送族弟溧陽尉濟充泛舟赴華陰','李白','唐','唐诗','tang','','["\u9ec4\u5c71"]','鸞乃鳳之族，翱翔紫雲霓。',192,'全唐诗/poet.tang.8000.json','["鸞乃鳳之族，翱翔紫雲霓。", "文章輝五色，雙在瓊樹棲。", "一朝各飛去，鳳與鸞俱啼。", "炎赫五月中，朱曦爍河堤。", "爾從泛舟役，使我心魂悽。", "秦地無碧草，南雲喧鼓鼙。", "君王減玉膳，早起思鳴雞。", "漕引救關輔，疲人免塗泥。", "宰相作霖雨，農夫得耕犂。", "靜者伏草間，羣才滿金閨。", "空手無壯士，窮居使人低。", "送君登黃山，長嘯倚天梯。", "小舟若鳧鴈，大舟若鯨鯢。", "開帆散長風，舒卷與雲齊。", "日入牛渚晦，蒼然夕煙迷。", "相思定何許，杳在洛陽西。"]'),
('76e44eb0-9d93-4d3e-a6b2-bb87ba7f200d','送儲邕之武昌','李白','唐','唐诗','tang','','["\u957f\u6c5f", "\u79bb\u522b", "\u53cb\u4eba", "\u9001\u522b"]','黃鶴西樓月，長江萬里情。',72,'全唐诗/poet.tang.8000.json','["黃鶴西樓月，長江萬里情。", "春風三十度，空憶武昌城。", "送爾難爲別，銜杯惜未傾。", "湖連張樂地，山逐泛舟行。", "諾爲楚人重，詩傳謝朓清。", "滄浪吾有曲，寄入櫂歌聲。"]'),
('57a217db-5002-456f-8cea-a3b34391733d','詶談少府','李白','唐','唐诗','tang','','[]','一尉居倏忽，梅生有僊骨。',60,'全唐诗/poet.tang.8000.json','["一尉居倏忽，梅生有僊骨。", "三事或可羞，匈奴哂千秋。", "壯士屈黃綬，浪跡寄滄洲。", "昨觀荆峴作，如從雲漢遊。", "老夫當暮矣，蹀足懼驊騮。"]'),
('521ad669-99db-4a3f-95b1-21257e042e3a','詶宇文少府見贈桃竹書筒','李白','唐','唐诗','tang','','[]','桃竹書筒綺繡文，良工巧妙稱絕羣。',48,'全唐诗/poet.tang.8000.json','["桃竹書筒綺繡文，良工巧妙稱絕羣。", "靈心圓映三江月，彩質疊成五色雲。", "中藏寶訣峨眉去，千里提攜長憶君。"]'),
('d883127b-410b-4c45-9007-d1bcaa1c0823','五月東魯行荅汶上君','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u8ff0\u5fd7", "\u62b1\u8d1f"]','五月梅始黃，蠶凋桑柘空。',108,'全唐诗/poet.tang.8000.json','["五月梅始黃，蠶凋桑柘空。", "魯人重織作，機杼鳴簾櫳。", "顧余不及仕，學劍來山東。", "舉鞭訪前途，獲笑汶上翁。", "下愚忽壯士，未足論窮通。", "我以一箭書，能取聊城功。", "終然不受賞，羞與時人同。", "西歸去直道，落日昏陰虹。", "此去爾勿言，甘心爲轉蓬。"]'),
('b7cff6ef-5554-47d7-95d8-5266f2feb1e3','早秋單父南樓詶竇公衡','李白','唐','唐诗','tang','','["\u6cf0\u5c71", "\u6000\u4eba", "\u5c71", "\u5199\u666f"]','白露見日滅，紅顏隨霜凋。',104,'全唐诗/poet.tang.8000.json','["白露見日滅，紅顏隨霜凋。", "別君若俯仰，春芳辭秋條。", "泰山嵯峨夏雲在，疑是白波漲東海。", "散爲飛雨川上來，遙帷却卷清浮埃。", "知君獨坐青軒下，此時結念同所懷。", "我閉南樓看道書，幽簾清寂在仙居。", "曾無好事來相訪，賴爾高文一起予。"]'),
('c917044e-fd87-42fe-aa91-9f09d7a8a704','山中問荅','李白','唐','唐诗','tang','','[]','問余何意栖碧山，笑而不荅心自閑。',32,'全唐诗/poet.tang.8000.json','["問余何意栖碧山，笑而不荅心自閑。", "桃花流水窅然去，別有天地非人間。"]'),
('b4e822c6-4f27-4e22-8869-ab99a688c8e6','荅友人贈烏紗帽','李白','唐','唐诗','tang','','[]','領得烏紗帽，全勝白接䍦。',24,'全唐诗/poet.tang.8000.json','["領得烏紗帽，全勝白接䍦。", "山人不照鏡，稚子道相宜。"]'),
('f6fd78b7-835f-4e77-8dec-76850d74bdd8','詶張司馬贈墨','李白','唐','唐诗','tang','','[]','上黨碧松煙，夷陵丹砂末。',56,'全唐诗/poet.tang.8000.json','["上黨碧松煙，夷陵丹砂末。", "蘭麝凝珍墨，精光乃堪掇。", "黃頭奴子雙鴉鬟，錦囊養之懷袖間。", "今日贈予蘭亭去，興來灑筆會稽山。"]'),
('bbe494e2-d45f-47db-aad6-ceeacdfc52a8','荅湖州迦葉司馬問白是何人','李白','唐','唐诗','tang','','[]','青蓮居士謫仙人，酒肆藏名三十春。',32,'全唐诗/poet.tang.8000.json','["青蓮居士謫仙人，酒肆藏名三十春。", "湖州司馬何須問，金粟如來是後身。"]'),
('be99fd0b-ad10-42b2-9f51-1e001e700ae5','荅長安崔少府叔封遊終南翠微寺太宗皇帝金沙泉見寄','李白','唐','唐诗','tang','','[]','河伯見海若，傲然誇秋水。',192,'全唐诗/poet.tang.8000.json','["河伯見海若，傲然誇秋水。", "小物昧遠圖，寧知通方士。", "多君紫霄意，獨往蒼山裏。", "地古寒雲深，巖高長風起。", "初登翠微嶺，復憩金沙泉。", "踐苔朝霜滑，弄波夕月圓。", "飲彼石下流，結蘿宿溪煙。", "鼎湖夢淥水，龍駕空茫然。", "早行子午關，却登山路遠。", "拂琴聽霜猨，滅燭乃星飯。", "人煙無明異，鳥道絕往返。", "攀厓倒青天，下視白日晚。", "既過石門隱，還唱石潭歌。", "涉雪搴紫芳，濯纓想清波。", "此人不可見，此地君自過。", "爲余謝風泉，其如幽意何。"]'),
('07433585-ef7a-40ab-bd05-90f4f144f768','詶崔五郎中','李白','唐','唐诗','tang','','[]','朔雲橫高天，萬里起秋色。',204,'全唐诗/poet.tang.8000.json','["朔雲橫高天，萬里起秋色。", "壯士心飛揚，落日空歎息。", "長嘯出原野，凜然寒風生。", "幸遭聖明時，功業猶未成。", "奈何懷良圖，鬱悒獨愁坐。", "杖策尋英豪，立談乃知我。", "崔公生民秀，緬邈青雲姿。", "制作參造化，託諷含神祇。", "海嶽尚可傾，吐諾終不移。", "是時霜飆寒，逸興臨華池。", "起舞拂長劍，四座皆揚眉。", "因得窮懽情，贈我以新詩。", "又結汗漫期，九垓遠相待。", "舉身憩蓬壺，濯足弄滄海。", "從此凌倒景，一去無時還。", "朝遊明光宮，暮入閶闔關。", "但得長把袂，何必嵩丘山。"]'),
('63c9547a-a949-4d41-b38b-ee3c39464cd7','以詩代書荅元丹丘','李白','唐','唐诗','tang','','["\u6000\u4eba", "\u6292\u60c5", "\u53cb\u4eba"]','青鳥海上來，今朝發何處。',96,'全唐诗/poet.tang.8000.json','["青鳥海上來，今朝發何處。", "口銜雲錦字，與我忽飛去。", "鳥去凌紫煙，書留綺窗前。", "開緘方一笑，乃是故人傳。", "故人深相勗，憶我勞心曲。", "離居在咸陽，三見秦草綠。", "置書雙袂間，引領不暫閑。", "長望杳難見，浮雲橫遠山。"]'),
('04549ca6-3a4c-4a3e-b044-4cce3883bd59','金門荅蘇秀才','李白','唐','唐诗','tang','','[]','君還石門日，朱火始改木。',252,'全唐诗/poet.tang.8000.json','["君還石門日，朱火始改木。", "春草如有情，山中尚含綠。", "折芳愧遙憶，永路當自勗。", "遠見故人心，平生以此足。", "巨海納百川，麟閣多才賢。", "獻書入金闕，酌醴奉瓊筵。", "屢忝白雲唱，恭聞黃竹篇。", "恩光照拙薄，雲漢希騰遷。", "銘鼎倘云逐，扁丹方渺然。", "我留在金門，君去臥丹壑。", "未果三山期，遙欣一丘樂。", "玄珠寄象罔，赤水非寥廓。", "願狎東海鷗，共營西山藥。", "棲巖君寂滅，處世余龍蠖。", "良辰不同賞，永日應閑居。", "鳥吟簷間樹，花落窗下書。", "緣溪見綠篠，隔岫窺紅蕖。", "採薇行笑歌，眷我情何已。", "月出石鏡間，松鳴風琴裏。", "得心自虛妙，外物空頹靡。", "身世如兩忘，從君老煙水。"]'),
('4089b003-8676-43b7-8fba-1850766efd93','詶坊州王司馬與閻正字對雪見贈','李白','唐','唐诗','tang','','[]','遊子東南來，自宛適京國。',120,'全唐诗/poet.tang.8000.json','["遊子東南來，自宛適京國。", "飄然無心雲，倏忽復西北。", "訪戴昔未偶，尋嵇此相得。", "愁顏發新懽，終宴敘前識。", "閻公漢庭舊，沈鬱富才力。", "價重銅龍樓，聲高重門側。", "寧期此相遇，華館陪遊息。", "積雪明遠峰，寒城鎖春色。", "主人蒼生望，假我青雲翼。", "風水如見資，投竿佐皇極。"]'),
('db37c733-57f0-4134-9d05-8bd7aca4789a','詶中都小吏攜斗酒雙魚於逆旅見贈','李白','唐','唐诗','tang','','["\u53cb\u4eba", "\u5199\u4eba", "\u53cb\u8c0a", "\u5199\u4eba\u8bd7"]','魯酒若琥珀，汶魚紫錦鱗。',92,'全唐诗/poet.tang.8000.json','["魯酒若琥珀，汶魚紫錦鱗。", "山東豪吏有俊氣，手攜此物贈遠人。", "意氣相傾兩相顧，斗酒雙魚表情素。", "雙鰓呀呷鰭鬣張，蹳刺銀盤欲飛去。", "呼兒拂几霜刃揮，紅肌花落白雪霏。", "爲君下筯一餐飽，醉著金鞍上馬歸。"]'),
('d6bd5d14-d55c-4148-ae14-f92d8ca5404a','詶張卿夜宿南陵見贈','李白','唐','唐诗','tang','','[]','月出魯城東，明如天上雪。',180,'全唐诗/poet.tang.8000.json','["月出魯城東，明如天上雪。", "魯女驚莎雞，鳴機應秋節。", "當君相思夜，火落金風高。", "河漢挂戶牖，欲濟無輕舠。", "我昔辭林丘，雲龍忽相見。", "客星動太微，朝去洛陽殿。", "爾來得茂彥，七葉仕漢餘。", "身爲下邳客，家有圯橋書。", "傅說未夢時，終當起巖野。", "萬古騎辰星，光輝照天下。", "與君各未遇，長策委蒿萊。", "寶刀隱玉匣，鏽澀空莓苔。", "遂令世上愚，輕我土與灰。", "一朝攀龍去，鼃黽安在哉？", "故山定有酒，與爾傾金罍。"]'),
('be282475-3b26-49f9-9e82-5e8de52f2938','詶岑勳見尋就元丹丘對酒相待以詩見招','李白','唐','唐诗','tang','','[]','黃鶴東南來，寄書寫心曲。',168,'全唐诗/poet.tang.8000.json','["黃鶴東南來，寄書寫心曲。", "倚松開其緘，憶我腸斷續。", "不以千里遙，命駕來相招。", "中逢元丹丘，登嶺宴碧霄。", "對酒忽思我，長嘯臨清飆。", "蹇予未相知，茫茫綠雲垂。", "俄然素書及，解此長渴飢。", "策馬望山月，途窮造階墀。", "喜茲一會面，若覩瓊樹枝。", "憶君我遠來，我懽方速至。", "開顏酌美酒，樂極忽成醉。", "我情既不淺，君意方亦深。", "相知兩相得，一顧輕千金。", "且向山客笑，與君論素心。"]'),
('7b1260d3-387d-4279-8ff0-1f3ca652ab89','荅從弟幼成過西園見贈','李白','唐','唐诗','tang','','[]','一身自瀟灑，萬物何囂諠。',108,'全唐诗/poet.tang.8000.json','["一身自瀟灑，萬物何囂諠。", "拙薄謝明時，棲閑歸故園。", "二季過舊壑，四鄰馳華軒。", "衣劍照松宇，賓徒光石門。", "山童薦珍果，野老開芳樽。", "上陳樵漁事，下敘農圃言。", "昨來荷花滿，今見蘭苕繁。", "一笑復一歌，不知夕景昏。", "醉罷同所樂，此情難具論。"]'),
('063a9180-4dfe-49a1-95ec-ff727e0173b5','詶王補闕惠翼莊廟宋丞泚贈別','李白','唐','唐诗','tang','','[]','學道三千春，自言羲和人。',120,'全唐诗/poet.tang.8000.json','["學道三千春，自言羲和人。", "軒蓋宛若夢，雲松長相親。", "偶將二公合，復與三山鄰。", "喜結海上契，自爲天外賓。", "鸞翮我先鎩，龍性君莫馴。", "朴散不尚古，時訛皆失真。", "勿踏荒溪坡，朅來浩然津。", "薜帶何辭楚，桃源堪避秦。", "世迫且離別，心在期隱淪。", "酬贈非炯誡，永言銘佩紳。"]'),
('dc853655-75b8-468b-b213-75cabf00d1fd','詶裴侍御對雨感時見贈','李白','唐','唐诗','tang','','["\u5199\u96e8", "\u540c\u60c5", "\u5199\u98ce", "\u79cb\u5929", "\u98ce", "\u5199\u4eba"]','雨色秋來寒，風嚴清江爽。',120,'全唐诗/poet.tang.8000.json','["雨色秋來寒，風嚴清江爽。", "孤高繡衣人，瀟灑青霞賞。", "平生多感激，忠義非外獎。", "禍連積怨生，事及徂川往。", "楚邦有壯士，鄢郢翻掃蕩。", "申包哭秦庭，泣血將安仰。", "鞭屍辱已及，堂上羅宿莽。", "頗似今之人，蟊賊陷忠讜。", "渺然一水隔，何由稅歸鞅。", "日夕聽猨怨，懷賢盈夢想。"]'),
('c64927b7-0793-4eeb-8f81-3bc2f5c61ebc','詶崔侍御','李白','唐','唐诗','tang','','[]','嚴陵不從萬乘遊，歸臥空山釣碧流。',32,'全唐诗/poet.tang.8000.json','["嚴陵不從萬乘遊，歸臥空山釣碧流。", "自是客星辭帝座，元非太白醉揚州。"]'),
('dfde445a-0083-451f-af51-822c00e6db7a','翫月金陵城西孫楚酒樓達曙歌吹日晚乘醉著紫綺裘烏紗巾與酒客數人櫂歌秦淮往石頭訪崔四侍御','李白','唐','唐诗','tang','','[]','昨翫西城月，青天垂玉鉤。',180,'全唐诗/poet.tang.8000.json','["昨翫西城月，青天垂玉鉤。", "朝沽金陵酒，歌吹孫楚樓。", "忽憶繡衣人，乘船往石頭。", "草裹烏紗巾，倒被紫綺裘。", "兩岸拍手笑，疑是王子猷。", "酒客十數公，崩騰醉中流。", "謔浪櫂海客，喧呼傲陽侯。", "半道逢吳姬，卷簾出揶揄。", "我憶君到此，不知狂與羞。", "一月一見君，三杯便回橈。", "舍舟共連袂，行上南渡橋。", "興發歌綠水，秦客爲之搖。", "雞鳴復相招，清宴逸雲霄。", "贈我數百字，字字凌風飆。", "繫之衣裘上，相憶每長謠。"]'),
('d6a3b471-ec83-4f0f-9229-a42c7ebff998','江上答崔宣城','李白','唐','唐诗','tang','','["\u534e\u5c71"]','太華三芙蓉，明星玉女峰。',96,'全唐诗/poet.tang.8000.json','["太華三芙蓉，明星玉女峰。", "尋仙下西嶽，陶令忽相逢。", "問我將何事，湍波歷幾重。", "貂裘非季子，鶴氅似王恭。", "謬忝燕臺召，而陪郭隗蹤。", "水流知入海，雲去或從龍。", "樹繞蘆洲月，山鳴鵲鎮鐘。", "還期如可訪，台嶺蔭長松。"]'),
('d389abf1-07e8-42f3-a9dc-6d2b22e13b37','答族姪僧中孚贈玉泉仙人掌茶','李白','唐','唐诗','tang','','[]','常聞玉泉山，山洞多乳窟。',120,'全唐诗/poet.tang.8000.json','["常聞玉泉山，山洞多乳窟。", "仙鼠如白鴉，倒懸清溪月。", "茗生此中石，玉泉流不歇。", "根柯灑芳津，採服潤肌骨。", "叢老卷綠葉，枝枝相接連。", "曝成仙人掌，似拍洪崖肩。", "舉世未見之，其名定誰傳。", "宗英乃禪伯，投贈有佳篇。", "清鏡燭無鹽，顧慚西子妍。", "朝坐有餘興，長吟播諸天。"]'),
('30df8cfb-4e71-49b9-96e3-a8b770d50dd0','詶裴侍御留岫師彈琴見寄','李白','唐','唐诗','tang','','[]','君同鮑明遠，邀彼休上人。',48,'全唐诗/poet.tang.8000.json','["君同鮑明遠，邀彼休上人。", "鼓琴亂白雪，秋變江上春。", "瑤草綠未衰，攀翻寄情親。", "相思兩不見，流淚空盈巾。"]'),
('8338e3db-3f5d-49fa-b1c1-1ebcc9678d27','張相公出鎮荆州尋除太子詹事余時流夜郎行至江夏與張公去千里公因太府丞王昔使車寄羅衣二事及五月五日贈余詩余答以此詩','李白','唐','唐诗','tang','','[]','張衡殊不樂，應有四愁詩。',48,'全唐诗/poet.tang.8000.json','["張衡殊不樂，應有四愁詩。", "慙君錦繡段，贈我慰相思。", "鴻鵠復矯翼，鳳凰憶故池。", "榮樂一如此，商山老紫芝。"]'),
('a1224475-cb04-43fc-8d0c-3e901f65f656','醉後荅丁十八以詩譏余搥碎黃鶴樓','李白','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','黃鶴高樓已槌碎，黃鶴仙人無所依。',112,'全唐诗/poet.tang.8000.json','["黃鶴高樓已槌碎，黃鶴仙人無所依。", "黃鶴上天訴玉帝，卻放黃鶴江南歸。", "神明太守再雕飾，新圖粉壁還芳菲。", "一州笑我爲狂客，少年往往來相譏。", "君平簾下誰家子，云是遼東丁令威。", "作詩調我驚逸興，白雲遶筆窗前飛。", "待取明朝酒醒罷，與君爛漫尋春暉。"]'),
('921a744a-2466-41be-966f-b31ae16c5b01','荅裴侍御先行至石頭驛以書見招期月滿泛洞庭','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u9ec4\u9e64\u697c"]','君至石頭驛，寄書黃鶴樓。',96,'全唐诗/poet.tang.8000.json','["君至石頭驛，寄書黃鶴樓。", "開緘識遠意，速此南行舟。", "風水無定準，湍波或滯留。", "憶昨新月生，西簷若瓊鉤。", "今來何所似，破鏡懸清秋。", "恨不三五明，平湖泛澄流。", "此歡竟莫遂，狂殺王子猷。", "巴陵定遙遠，持贈解人憂。"]'),
('eafb2468-0e6a-4369-9c68-1aa857ed4a9d','荅高山人兼呈權顧二侯','李白','唐','唐诗','tang','','[]','虹霓掩天光，哲后起康濟。',240,'全唐诗/poet.tang.8000.json','["虹霓掩天光，哲后起康濟。", "應運生夔龍，開元掃氛翳。", "太微廓金鏡，端拱清遐裔。", "輕塵集嵩嶽，虛點盛明意。", "謬揮紫泥詔，獻納青雲際。", "讒惑英主心，恩疎佞臣計。", "仿徨庭闕下，歎息光陰逝。", "未作仲宣詩，先流賈生涕。", "挂帆秋江上，不爲雲羅制。", "山海向東傾，百川無盡勢。", "我於鴟夷子，相去千餘歲。", "運闊英達稀，同風遙執袂。", "登艫望遠水，忽見滄浪枻。", "高士何處來，虛舟渺安繫。", "衣貌本淳古，文章多佳麗。", "延引故鄉人，風義未淪替。", "顧侯達語默，權子識通蔽。", "曾是無心雲，俱爲此留滯。", "雙萍易飄轉，獨鶴思凌厲。", "明晨去瀟湘，共謁蒼梧帝。"]'),
('dabdeffb-da9c-4f45-9b12-b421f5f15fd6','荅杜秀才五松見贈','李白','唐','唐诗','tang','','[]','昔獻長楊賦，天開雲雨歡。',324,'全唐诗/poet.tang.8000.json','["昔獻長楊賦，天開雲雨歡。", "當時待詔承明裏，皆道揚雄才可觀。", "勅賜飛龍二天馬，黃金絡頭白玉鞍。", "浮雲蔽日去不返，總爲秋風摧紫蘭。", "角巾東出商山道，採秀行歌詠芝草。", "路逢園綺笑向人，兩君解來一何好。", "聞道金陵龍虎盤，還同謝朓望長安。", "千峰夾水向秋浦，五松名山當夏寒。", "銅井炎爐歊九天，赫如鑄鼎荆山前。", "陶公瞿鑠呵赤電，回祿睢盱揚紫煙。", "此中豈是久留處，便欲燒丹從列仙。", "愛聽松風且高臥，颼颼吹盡炎氛過。", "登崖獨立望九州，陽春欲奏誰相和。", "聞君往年遊錦城，章仇尚書倒屣迎。", "飛箋洛繹奏明主，天書降問迴恩榮。", "骯髒不能就珪組，至今空揚高蹈名。", "夫子工文絕世奇，五松新作天下推。", "吾非謝尚邀彥伯，異代風流各一時。", "一時相逢樂在今，袖拂白雲開素琴，彈爲三峽流泉音。", "從茲一別武陵去，去後桃花春水深。"]'),
('a4650220-b06a-4ab1-809c-974a850d795d','至陵陽山登天柱石詶韓侍御見招隱黃山','李白','唐','唐诗','tang','','["\u9ec4\u5c71", "\u4e5d\u534e\u5c71"]','韓衆騎白鹿，西往華山中。',180,'全唐诗/poet.tang.8000.json','["韓衆騎白鹿，西往華山中。", "玉女千餘人，相隨在雲空。", "見我傳祕訣，精誠與天通。", "何意到陵陽，遊目送飛鴻。", "天子昔避狄，與君亦乘驄。", "擁兵五陵下，長策遏胡戎。", "時泰解繡衣，脫身若飛蓬。", "鸞鳳翻羽翼，啄粟坐樊籠。", "海鶴一笑之，思歸向遼東。", "黃山過石柱，巘崿上攢叢。", "因巢翠玉樹，忽見浮丘公。", "又引王子喬，吹笙舞松風。", "朗詠紫霞篇，請開蘂珠宮。", "步綱繞碧落，倚樹招青童。", "何日可攜手，遺形入無窮。"]'),
('af3c2df6-a096-484b-93de-3ed3d24f8d70','詶崔十五見招','李白','唐','唐诗','tang','','[]','爾有鳥跡書，相招琴溪飲。',48,'全唐诗/poet.tang.8000.json','["爾有鳥跡書，相招琴溪飲。", "手跡尺素中，如天落雲錦。", "讀罷向空笑，疑君在我前。", "長吟字不滅，懷袖且三年。"]'),
('4c4c4c27-28fc-43cf-a53f-9ada39b65d94','荅王十二寒夜獨酌有懷','李白','唐','唐诗','tang','','["\u957f\u8bd7", "\u6292\u60c5", "\u53d9\u4e8b"]','昨夜吳中雪，子猷佳興發。',381,'全唐诗/poet.tang.8000.json','["昨夜吳中雪，子猷佳興發。", "萬里浮雲卷碧山，青天中道流孤月。", "孤月滄浪河漢清，北斗錯落長庚明。", "懷余對酒夜霜白，玉牀金井水崢嶸。", "人生飄忽百年內，且須酣暢萬古情。", "君不能狸膏金距學鬬雞，坐令鼻息吹虹霓。", "君不能學哥舒橫行青海夜帶刀，西屠石堡取紫袍。", "吟詩作賦北牕裏，萬言不直一杯水。", "世人聞此皆掉頭，有如東風射馬耳。", "魚目亦笑我，請與明月同。", "驊騮拳跼不能食，蹇驢得志鳴春風。", "折楊皇華合流俗，晉君聽琴枉清角。", "巴人誰肯和陽春，楚地由來賤奇璞。", "黃金散盡交不成，白首爲儒身被輕。", "一談一笑失顏色，蒼蠅貝錦喧謗聲。", "曾參豈是殺人者，讒言三及慈母驚。", "與君論心握君手，榮辱於余亦何有。", "孔聖猶聞傷鳳麟，董龍更是何雞狗。", "一生傲岸苦不諧，恩疎媒勞志多乖。", "嚴陵高揖漢天子，何必長劍拄頤事玉階。", "達亦不足貴，窮亦不足悲。", "韓信羞將絳灌比，禰衡恥逐屠沽兒。", "君不見李北海，英風豪氣今何在？", "君不見裴尚書，土墳三尺蒿棘居。"]'),
('591b076f-722d-439e-8ce1-d934b5b87e07','遊南陽白水登石激作','李白','唐','唐诗','tang','','[]','朝涉白水源，暫與人俗疎。',48,'全唐诗/poet.tang.8000.json','["朝涉白水源，暫與人俗疎。", "島嶼佳境色，江天涵清虛。", "目送去海雲，心閑遊川魚。", "長歌盡落日，乘月歸田廬。"]'),
('eb92cd5b-f833-4dc6-b0b4-6d7f45cc651b','遊南陽清泠泉','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u601d\u4e61", "\u7eaa\u6e38"]','惜彼落日暮，愛此寒泉清。',36,'全唐诗/poet.tang.8000.json','["惜彼落日暮，愛此寒泉清。", "西輝逐流水，蕩漾遊子情。", "空歌望雲月，曲盡長松聲。"]'),
('dbfe3dd9-ea4a-4130-8e31-b3fc0acd90bf','尋魯城北范居士失道落蒼耳中見范置酒摘蒼耳作','李白','唐','唐诗','tang','','["\u8c6a\u653e", "\u996e\u9152", "\u53cb\u60c5"]','雁度秋色遠，日靜無雲時。',168,'全唐诗/poet.tang.8000.json','["雁度秋色遠，日靜無雲時。", "客心不自得，浩漫將何之。", "忽憶范野人，閑園養幽姿。", "茫然起逸興，但恐行來遲。", "城壕失往路，馬首迷荒陂。", "不惜翠雲裘，遂爲蒼耳欺。", "入門且一笑，把臂君爲誰。", "酒客愛秋蔬，山盤薦霜梨。", "他筵不下筯，此席忘朝飢。", "酸棗垂北郭，寒瓜蔓東籬。", "還傾四五酌，自詠猛虎詞。", "近作十日歡，遠爲千載期。", "風流自簸蕩，謔浪偏相宜。", "酣來上馬去，却笑高陽池。"]'),
('05b0b448-8d15-461e-b806-7d94fcb66f49','東魯門泛舟二首 一','李白','唐','唐诗','tang','','[]','日落沙明天倒開，波搖石動水縈迴。',32,'全唐诗/poet.tang.8000.json','["日落沙明天倒開，波搖石動水縈迴。", "輕舟泛月尋溪轉，疑是山隱雪後來。"]'),
('4cb386a3-6488-46f1-a53d-c5a4a2e0b90d','東魯門泛舟二首 二','李白','唐','唐诗','tang','','[]','水作青龍盤石堤，桃花夾岸魯門西。',32,'全唐诗/poet.tang.8000.json','["水作青龍盤石堤，桃花夾岸魯門西。", "若教月下乘舟去，何啻風流到剡溪。"]'),
('9f8f5fe7-eae7-4e94-acd2-3b712e629ae3','秋獵孟諸夜歸置酒單父東樓觀妓','李白','唐','唐诗','tang','','[]','傾暉速短炬，走海無停川。',120,'全唐诗/poet.tang.8000.json','["傾暉速短炬，走海無停川。", "冀餐圓丘草，欲以還頹年。", "此事不可得，微生若浮煙。", "駿發跨名駒，雕弓控鳴弦。", "鷹豪魯草白，狐兔多肥鮮。", "邀遮相馳逐，遂出城東田。", "一掃四野空，喧呼鞍馬前。", "歸來獻所獲，炮炙宜霜天。", "出舞兩美人，飄颻若雲仙。", "留歡不知疲，清曉方來旋。"]'),
('25b6402c-ca6d-4bcb-8a91-fa17eb8a99a9','遊泰山六首 一','李白','唐','唐诗','tang','','["\u6cf0\u5c71"]','四月上泰山，石屏御道開。',144,'全唐诗/poet.tang.8000.json','["四月上泰山，石屏御道開。", "六龍過萬壑，澗谷隨縈迴。", "馬跡遶碧峯，于今滿青苔。", "飛流灑絕巘，水急松聲哀。", "北眺崿嶂奇，傾崖向東摧。", "洞門閉石扇，地底興雲雷。", "登高望蓬瀛，想象金銀臺。", "天門一長嘯，萬里清風來。", "玉女四五人，飄颻下九垓。", "含笑引素手，遺我流霞杯。", "稽首再拜之，自愧非仙才。", "曠然小宇宙，棄世何悠哉。"]'),
('a2a6fda5-a253-4172-87e8-04f071d1f6f5','遊泰山六首 二','李白','唐','唐诗','tang','','["\u6cf0\u5c71", "\u5929\u95e8\u5c71"]','清曉騎白鹿，直上天門山。',72,'全唐诗/poet.tang.8000.json','["清曉騎白鹿，直上天門山。", "山際逢羽人，方瞳好容顏。", "捫蘿欲就語，却掩青雲關。", "遺我鳥跡書，飄然落巖間。", "其字乃上古，讀之了不閑。", "感此三歎息，從師方未還。"]'),
('211e6b5b-433a-44f4-b205-2f00ae6781c6','遊泰山六首 三','李白','唐','唐诗','tang','','["\u6cf0\u5c71", "\u9ec4\u6cb3"]','平明登日觀，舉手開雲關。',84,'全唐诗/poet.tang.8000.json','["平明登日觀，舉手開雲關。", "精神四飛揚，如出天地間。", "黃河從西來，窈窕入遠山。", "憑崖攬八極，目盡長空閑。", "偶然值青童，綠髮雙雲鬟。", "笑我晚學仙，蹉跎凋朱顏。", "躊躇忽不見，浩蕩難追攀。"]'),
('3bbf0796-7fc7-4cf1-8a9b-bd65a604c6b0','遊泰山六首 四','李白','唐','唐诗','tang','','["\u6cf0\u5c71"]','清齋三千日，裂素寫道經。',84,'全唐诗/poet.tang.8000.json','["清齋三千日，裂素寫道經。", "吟誦有所得，衆神衛我形。", "雲行信長風，颯若羽翼生。", "攀崖上日觀，伏檻窺東溟。", "海色動遠山，天雞已先鳴。", "銀臺出倒景，白浪翻長鯨。", "安得不死藥，高飛向蓬瀛。"]'),
('8a349100-cd71-49b6-858b-fc40576b8711','遊泰山六首 五','李白','唐','唐诗','tang','','["\u6cf0\u5c71"]','日觀東北傾，兩崖夾雙石。',84,'全唐诗/poet.tang.8000.json','["日觀東北傾，兩崖夾雙石。", "海水落眼前，天光遙空碧。", "千峯爭攢聚，萬壑絕凌歷。", "緬彼鶴上仙，去無雲中跡。", "長松入雲漢，遠望不盈尺。", "山花異人間，五月雪中白。", "終當遇安期，於此鍊玉液。"]'),
('5066dabc-0991-4da6-b1b4-ef55b625e769','遊泰山六首 六','李白','唐','唐诗','tang','','["\u6cf0\u5c71"]','朝飲王母池，暝投天門關。',108,'全唐诗/poet.tang.8000.json','["朝飲王母池，暝投天門關。", "獨抱綠綺琴，夜行青山間。", "山明月露白，夜靜松風歇。", "仙人遊碧峯，處處笙歌發。", "寂靜娛清暉，玉真連翠微。", "想象鸞鳳舞，飄颻龍虎衣。", "捫天摘匏瓜，恍惚不憶歸。", "舉手弄清淺，誤攀織女機。", "明晨坐相失，但見五雲飛。"]'),
('37577056-1e0c-458b-80c3-460ff23da105','秋夜與劉碭山泛宴喜亭池','李白','唐','唐诗','tang','','[]','明宰試舟楫，張燈宴華池。',48,'全唐诗/poet.tang.8000.json','["明宰試舟楫，張燈宴華池。", "文招梁苑客，歌動郢中兒。", "月色望不盡，空天交相宜。", "令人欲泛海，只待長風吹。"]'),
('4b77eb28-18f7-442c-974a-286a9c65e796','攜妓登梁王棲霞山孟氏桃園中','李白','唐','唐诗','tang','','[]','碧草已滿地，柳與梅爭春。',101,'全唐诗/poet.tang.8000.json','["碧草已滿地，柳與梅爭春。", "謝公自有東山妓，金屏笑坐如花人。", "今日非昨日，明日還復來。", "白髮對綠酒，強歌心已摧。", "君不見梁王池上月，昔照梁王樽酒中。", "梁王已去明月在，黃鸝愁醉啼春風。", "分明感激眼前事，莫惜醉臥桃園東。"]'),
('1743f743-b5f7-4403-945f-4e10e20da60a','與從姪杭州刺史良遊天竺寺','李白','唐','唐诗','tang','','[]','挂席凌蓬丘，觀濤憩樟樓。',72,'全唐诗/poet.tang.8000.json','["挂席凌蓬丘，觀濤憩樟樓。", "三山動逸興，五馬同遨遊。", "天竺森在眼，松風颯驚秋。", "覽雲測變化，弄水窮清幽。", "疊嶂隔遙海，當軒寫歸流。", "詩成傲雲月，佳趣滿吳洲。"]'),
('0084e4f7-d47a-4a2b-8804-1b7b5c9d9220','同友人舟行遊台越作','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u53cb\u4eba"]','楚臣傷江楓，謝客拾海月。',96,'全唐诗/poet.tang.8000.json','["楚臣傷江楓，謝客拾海月。", "懷沙去瀟湘，挂席泛溟渤。", "蹇予訪前跡，獨往造窮髮。", "古人不可攀，去若浮雲沒。", "願言弄倒景，從此鍊真骨。", "華頂窺絕溟，蓬壺望超忽。", "不知青春度，但怪綠芳歇。", "空持釣鼇心，從此謝魏闕。"]'),
('ca4cc6b3-a324-48c0-89c0-bb36c09c4930','下終南山過斛斯山人宿置酒','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u7ec8\u5357\u5c71", "\u4e94\u8a00\u53e4\u8bd7", "\u7530\u56ed", "\u5199\u666f", "\u996e\u9152"]','暮從碧山下，山月隨人歸。',84,'全唐诗/poet.tang.8000.json','["暮從碧山下，山月隨人歸。", "却顧所來徑，蒼蒼橫翠微。", "相攜及田家，童稚開荆扉。", "綠竹入幽徑，青蘿拂行衣。", "歡言得所憩，美酒聊共揮。", "長歌吟松風，曲盡河星稀。", "我醉君復樂，陶然共忘機。"]'),
('b4fbfaa7-4355-4357-b6aa-292e8b2cb05c','朝下過盧郎中敘舊遊','李白','唐','唐诗','tang','','[]','君登金華省，我入銀臺門。',72,'全唐诗/poet.tang.8000.json','["君登金華省，我入銀臺門。", "幸遇聖明主，俱承雲雨恩。", "復此休浣時，閑爲疇昔言。", "却話山海事，宛然林壑存。", "明湖思曉月，疊嶂憶清猿。", "何由返初服，田野醉芳樽。"]'),
('2310cb5d-4326-4bb8-b1ed-69321e803e0b','侍從遊宿溫泉宮作','李白','唐','唐诗','tang','','[]','羽林十二將，羅列應星文。',48,'全唐诗/poet.tang.8000.json','["羽林十二將，羅列應星文。", "霜仗懸秋月，霓旌卷夜雲。", "嚴更千戶肅，清樂九天聞。", "日出瞻佳氣，蔥蔥繞聖君。"]'),
('3563ce30-ecca-41e1-ba9a-79feea89b8d6','邯鄲南亭觀妓','李白','唐','唐诗','tang','','[]','歌鼓燕趙兒，魏姝弄鳴絲。',84,'全唐诗/poet.tang.8000.json','["歌鼓燕趙兒，魏姝弄鳴絲。", "粉色豔日彩，舞袖拂花枝。", "把酒顧美人，請歌邯鄲詞。", "清箏何繚繞，度曲綠雲垂。", "平原君安在，科斗生古池。", "座客三千人，于今知有誰。", "我輩不作樂，但爲後代悲。"]'),
('aa65e1c8-1b13-47d6-919b-e50f7ae5d10a','春日遊羅敷潭','李白','唐','唐诗','tang','','[]','行歌入谷口，路盡無人躋。',48,'全唐诗/poet.tang.8000.json','["行歌入谷口，路盡無人躋。", "攀崖度絕壑，弄水尋迴溪。", "雲從石上起，客到花間迷。", "淹留未盡興，日落羣峯西。"]'),
('d2846a5c-282d-4d64-95d0-c6e8906ce700','春陪商州裴使君遊石娥溪','李白','唐','唐诗','tang','','[]','裴公有僊標，拔俗數千丈。',168,'全唐诗/poet.tang.8000.json','["裴公有僊標，拔俗數千丈。", "澹蕩滄洲雲，飄颻紫霞想。", "剖竹商洛間，政成心已閑。", "蕭條出世表，冥寂閉玄關。", "我來屬芳節，解榻時相悅。", "褰帷對雲峯，揚袂指松雪。", "蹔出東城邊，遂遊西巖前。", "橫天聳翠壁，噴壑鳴紅泉。", "尋幽殊未歇，愛此春光發。", "溪傍饒名花，石上有好月。", "命駕歸去來，露華生翠苔。", "淹留惜將晚，復聽清猨哀。", "清猨斷人腸，遊子思故鄉。", "明發首東路，此懽焉可忘。"]'),
('fe9217d5-9d09-4921-bf96-6eeeea0763ea','陪從祖濟南太守泛鵲山湖三首 一','李白','唐','唐诗','tang','','[]','初謂鵲山近，寧知湖水遙。',24,'全唐诗/poet.tang.8000.json','["初謂鵲山近，寧知湖水遙。", "此行殊訪戴，自可緩歸橈。"]'),
('af18d853-1ee7-4a38-a824-25c8946dd5b1','陪從祖濟南太守泛鵲山湖三首 二','李白','唐','唐诗','tang','','[]','湖闊數千里，湖光搖碧山。',24,'全唐诗/poet.tang.8000.json','["湖闊數千里，湖光搖碧山。", "湖西正有月，獨送李膺還。"]'),
('db175472-50f3-4755-9825-0713a41bae5c','陪從祖濟南太守泛鵲山湖三首 三','李白','唐','唐诗','tang','','[]','水入北湖去，舟從南浦回。',24,'全唐诗/poet.tang.8000.json','["水入北湖去，舟從南浦回。", "遙看鵲山轉，却似送人來。"]'),
('e60472f1-6945-4a2b-a06f-953ef7fc16ba','春日陪楊江寧及諸官宴北湖感古作','李白','唐','唐诗','tang','','["\u6625\u5929", "\u5bb4\u4f1a", "\u611f\u6168"]','昔聞顏光祿，攀龍宴京湖。',168,'全唐诗/poet.tang.8000.json','["昔聞顏光祿，攀龍宴京湖。", "樓船入天鏡，帳殿開雲衢。", "君王歌大風，如樂豐沛都。", "延年獻佳作，邈與詩人俱。", "我來不及此，獨立鍾山孤。", "楊宰穆清風，芳聲騰海隅。", "英僚滿四座，粲若瓊林敷。", "鷁首弄倒景，蛾眉綴明珠。", "新弦採梨園，古舞嬌吳歈。", "曲度繞雲漢，聽者皆歡娛。", "雞棲何嘈嘈，沿月沸笙竽。", "古之帝宮苑，今乃人樵蘇。", "感此勸一觴，願君覆瓢壺。", "榮盛當作樂，無令後賢吁。"]'),
('c91d56b3-e004-4a4f-83ef-475273a3d91b','宴鄭參卿山池','李白','唐','唐诗','tang','','[]','爾恐碧草晚，我畏朱顏移。',48,'全唐诗/poet.tang.8000.json','["爾恐碧草晚，我畏朱顏移。", "愁看楊花飛，置酒正相宜。", "歌聲送落日，舞影迴清池。", "今夕不盡杯，留歡更邀誰。"]'),
('f71ed838-db42-4a19-b6a2-9ee8b77332aa','遊謝氏山亭','李白','唐','唐诗','tang','','[]','淪老臥江海，再歡天地清。',96,'全唐诗/poet.tang.8000.json','["淪老臥江海，再歡天地清。", "病閑久寂寞，歲物徒芬榮。", "借君西池遊，聊以散我情。", "掃雪松下去，捫蘿石道行。", "謝公池塘上，春草颯已生。", "花枝拂人來，山鳥向我鳴。", "田家有美酒，落日與之傾。", "醉罷弄歸月，遙欣稚子迎。"]'),
('cd0e68fe-0e16-4b10-9345-ac567ce9cb62','把酒問月','李白','唐','唐诗','tang','','["\u548f\u7269", "\u54f2\u7406", "\u6708\u4eae", "\u548f\u7269\u8bd7", "\u6292\u6000"]','青天有月來幾時，我今停杯一問之。',128,'全唐诗/poet.tang.8000.json','["青天有月來幾時，我今停杯一問之。", "人攀明月不可得，月行却與人相隨。", "皎如飛鏡臨丹闕，綠烟滅盡清輝發。", "但見宵從海上來，寧知曉向雲間沒。", "白兔擣藥秋復春，嫦娥孤棲與誰鄰。", "今人不見古時月，今月曾經照古人。", "古人今人若流水，共看明月皆如此。", "唯願當歌對酒時，月光長照金樽裏。"]'),
('9f55f53d-0062-4afa-9dd9-69c4d7985ac8','同族姪評事黯遊昌禪師山池二首 一','李白','唐','唐诗','tang','','[]','遠公愛康樂，爲我開禪關。',48,'全唐诗/poet.tang.8000.json','["遠公愛康樂，爲我開禪關。", "蕭然松石下，何異清涼山。", "花將色不染，水與心俱閑。", "一坐度小劫，觀空天地間。"]'),
('591f1059-8d57-4004-b34a-62b6be925723','同族姪評事黯遊昌禪師山池二首 二','李白','唐','唐诗','tang','','[]','客來花雨際，秋水落金池。',48,'全唐诗/poet.tang.8000.json','["客來花雨際，秋水落金池。", "片石寒青錦，疎楊挂綠絲。", "高僧拂玉柄，童子獻霜梨。", "惜去愛佳景，煙蘿欲暝時。"]'),
('af667e00-f3a4-4a68-8f89-3e69d6eaa7a9','金陵鳳凰臺置酒','李白','唐','唐诗','tang','','[]','置酒延落景，金陵鳳凰臺。',108,'全唐诗/poet.tang.8000.json','["置酒延落景，金陵鳳凰臺。", "長波寫萬古，心與雲俱開。", "借問往昔時，鳳凰爲誰來。", "鳳凰去已久，正當今日迴。", "明君越羲軒，天老坐三台。", "豪士無所用，彈弦醉金罍。", "東風吹山花，安可不盡杯。", "六帝沒幽草，深宮冥綠苔。", "置酒勿復道，歌鐘但相催。"]'),
('d2cde2ee-ef80-4089-b343-a5502ca94020','秋浦清溪雪夜對酒客有唱山鷓鴣者','李白','唐','唐诗','tang','','[]','披君貂襜褕，對君白玉壺。',60,'全唐诗/poet.tang.8000.json','["披君貂襜褕，對君白玉壺。", "雪花酒上滅，頓覺夜寒無。", "客有桂陽至，能吟山鷓鴣。", "清風動窗竹，越鳥起相呼。", "持此足爲樂，何煩笙與竽。"]'),
('d22aad4e-2887-40b0-bdfe-71b2a5add45a','與周剛清溪玉鏡潭宴別','李白','唐','唐诗','tang','','[]','康樂上官去，永嘉遊石門。',132,'全唐诗/poet.tang.8000.json','["康樂上官去，永嘉遊石門。", "江亭有孤嶼，千載跡猶存。", "我來游秋浦，三入桃陂源。", "千峯照積雪，萬壑盡啼猨。", "興與謝公合，文因周子論。", "掃厓去落葉，席月開清樽。", "溪當大樓南，溪水正南奔。", "迴作玉鏡潭，澄明洗心魂。", "此中得佳境，可以絕囂喧。", "清夜方歸來，酣歌出平原。", "別後經此地，爲余謝蘭蓀。"]'),
('e3de2bf2-1566-4332-9115-81fffaaf6a3c','遊秋浦白笴陂二首 一','李白','唐','唐诗','tang','','[]','何處夜行好，月明白笴陂。',48,'全唐诗/poet.tang.8000.json','["何處夜行好，月明白笴陂。", "山光搖積雪，猨影挂寒枝。", "但恐佳景晚，小令歸櫂移。", "人來有清興，及此有相思。"]'),
('d305addc-bb71-4e60-ad20-40c499a4a75a','遊秋浦白笴陂二首 二','李白','唐','唐诗','tang','','[]','白笴夜長嘯，爽然溪谷寒。',48,'全唐诗/poet.tang.8000.json','["白笴夜長嘯，爽然溪谷寒。", "魚龍動陂水，處處生波瀾。", "天借一明月，飛來碧雲端。", "故鄉不可見，腸斷正西看。"]'),
('ace9fe7f-c5cb-4b0a-9eac-90408377e833','宴陶家亭子','李白','唐','唐诗','tang','','[]','曲巷幽人宅，高門大士家。',48,'全唐诗/poet.tang.8000.json','["曲巷幽人宅，高門大士家。", "池開照膽鏡，林吐破顏花。", "綠水藏春日，青軒祕晚霞。", "若聞弦管妙，金谷不能誇。"]'),
('a78ae783-79eb-43ab-b491-fe782bd46525','在水軍宴韋司馬樓船觀妓','李白','唐','唐诗','tang','','[]','搖曳帆在空，清流順歸風。',48,'全唐诗/poet.tang.8000.json','["搖曳帆在空，清流順歸風。", "詩因鼓吹發，酒爲劒歌雄。", "對舞青樓妓，雙鬟白玉童。", "行雲且莫去，留醉楚王宮。"]'),
('a0b411fd-df07-468b-9484-dea696ec7b60','流夜郎至江夏陪長史叔及薛明府宴興德寺南閣','李白','唐','唐诗','tang','','[]','紺殿橫江上，青山落鏡中。',48,'全唐诗/poet.tang.8000.json','["紺殿橫江上，青山落鏡中。", "岸迴沙不盡，日暎水成空。", "天樂流香閣，蓮舟颺晚風。", "恭陪竹林宴，留醉與陶公。"]'),
('89c3dc0c-0894-4131-bbc9-09d2052c8423','泛沔州城南郎官湖','李白','唐','唐诗','tang','','["\u6708\u8272", "\u6292\u60c5", "\u591c\u665a"]','張公多逸興，共泛沔城隅。',60,'全唐诗/poet.tang.8000.json','["張公多逸興，共泛沔城隅。", "當時秋月好，不減武昌都。", "四座醉清光，爲歡古來無。", "郎官愛此水，因號郎官湖。", "風流若未減，名與此山俱。"]'),
('0d481a1a-57ef-4546-b9d9-2e7c3e5b296c','陪侍郎叔遊洞庭醉後三首 一','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','今日竹林宴，我家賢侍郎。',24,'全唐诗/poet.tang.8000.json','["今日竹林宴，我家賢侍郎。", "三杯容小阮，醉後發清狂。"]'),
('8efedf3e-fbae-491b-b123-0a5a39bc37f0','陪侍郎叔遊洞庭醉後三首 二','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','船上齊橈樂，湖心泛月歸。',24,'全唐诗/poet.tang.8000.json','["船上齊橈樂，湖心泛月歸。", "白鷗閑不去，爭拂酒筵飛。"]'),
('ed76d8ed-267a-49c3-82e8-4ee0919bd9f6','陪侍郎叔遊洞庭醉後三首 三','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','剗却君山好，平鋪湘水流。',24,'全唐诗/poet.tang.8000.json','["剗却君山好，平鋪湘水流。", "巴陵無限酒，醉殺洞庭秋。"]'),
('fc361275-25d0-4efc-840f-e3ebf563a6fc','夜泛洞庭尋裴侍御清酌','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','日晚湘水綠，孤舟無端倪。',72,'全唐诗/poet.tang.8000.json','["日晚湘水綠，孤舟無端倪。", "明湖漲秋月，獨泛巴陵西。", "過憩裴逸人，巖居陵丹梯。", "抱琴出深竹，爲我彈鵾雞。", "曲盡酒亦傾，北窗醉如泥。", "人生且行樂，何必組與珪。"]'),
('a759f1f9-138e-40dc-b75c-0e9923ab71fe','陪族叔刑部侍郎曄及中書賈舍人至遊洞庭五首 一','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭西望楚江分，水盡南天不見雲。',32,'全唐诗/poet.tang.8000.json','["洞庭西望楚江分，水盡南天不見雲。", "日落長沙秋色遠，不知何處弔湘君。"]'),
('82f6ab4f-11e2-43c1-8db3-3c7faebc17f8','陪族叔刑部侍郎曄及中書賈舍人至遊洞庭五首 二','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u884c\u821f", "\u6292\u6000", "\u6708\u591c", "\u5199\u666f", "\u6c34"]','南湖秋水夜無烟，耐可乘流直上天。',32,'全唐诗/poet.tang.8000.json','["南湖秋水夜無烟，耐可乘流直上天。", "且就洞庭賒月色，將船買酒白雲邊。"]'),
('53718a9e-e29a-42fb-8edb-630fed52a722','陪族叔刑部侍郎曄及中書賈舍人至遊洞庭五首 三','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洛陽才子謫湘川，元禮同舟月下仙。',32,'全唐诗/poet.tang.8000.json','["洛陽才子謫湘川，元禮同舟月下仙。", "記得長安還欲笑，不知何處是西天。"]'),
('d6fb5943-be0a-4559-853c-222c60be55a6','陪族叔刑部侍郎曄及中書賈舍人至遊洞庭五首 四','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭湖西秋月輝，瀟湘江北早鴻飛。',32,'全唐诗/poet.tang.8000.json','["洞庭湖西秋月輝，瀟湘江北早鴻飛。", "醉客滿船歌白苧，不知霜露入秋衣。"]'),
('abc97ffb-bbe7-47e0-bbf4-47d3479095d1','陪族叔刑部侍郎曄及中書賈舍人至遊洞庭五首 五','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','帝子瀟湘去不還，空餘秋草洞庭間。',32,'全唐诗/poet.tang.8000.json','["帝子瀟湘去不還，空餘秋草洞庭間。", "淡掃明湖開玉鏡，丹青畫出是君山。"]'),
('67a064d5-b601-41d7-af93-1a73497582f5','楚江黃龍磯南宴楊執戟治樓','李白','唐','唐诗','tang','','[]','五月入五洲，碧山對青樓。',48,'全唐诗/poet.tang.8000.json','["五月入五洲，碧山對青樓。", "故人楊執戟，春賞楚江流。", "一見醉漂月，三杯歌櫂謳。", "桂枝攀不盡，他日更相求。"]'),
('b599c3b8-bf4d-4718-b1f7-5b1c4a28d83b','銅官山醉後絕句','李白','唐','唐诗','tang','','["\u5e26\u6709\u5730\u540d", "\u7737\u604b", "\u8d5e\u7f8e", "\u5931\u610f", "\u5730\u540d"]','我愛銅官樂，千年未擬還。',24,'全唐诗/poet.tang.8000.json','["我愛銅官樂，千年未擬還。", "要須迴舞袖，拂盡五松山。"]'),
('a93ec327-32ba-4570-970e-0e754e20a0f7','與南陵常贊府遊五松山','李白','唐','唐诗','tang','','[]','安石泛溟渤，獨嘯長風還。',120,'全唐诗/poet.tang.8000.json','["安石泛溟渤，獨嘯長風還。", "逸韻動海上，高情出人間。", "靈異可並跡，澹然與世閑。", "我來五松下，置酒窮躋攀。", "徵古絕遺老，因名五松山。", "五松何清幽，勝境美沃州。", "蕭颯鳴洞壑，終年風雨秋。", "響入百泉去，聽如三峽流。", "剪竹掃天花，且從傲吏遊。", "龍堂若可憩，吾欲歸精修。"]'),
('26ea17e1-8091-4a1d-90a5-5f73dd80c8bb','宣城青溪','李白','唐','唐诗','tang','','[]','青溪勝桐廬，水木有佳色。',48,'全唐诗/poet.tang.8000.json','["青溪勝桐廬，水木有佳色。", "山貌日高古，石容天傾側。", "綵鳥昔未名，白猨初相識。", "不見同懷人，對之空歎息。"]'),
('3150a4bc-eee3-4d04-b4be-54731acf80f3','與謝良輔遊涇川陵巖寺','李白','唐','唐诗','tang','','[]','乘君素舸泛涇西，宛似雲門對若溪。',32,'全唐诗/poet.tang.8000.json','["乘君素舸泛涇西，宛似雲門對若溪。", "且從康樂尋山水，何必東遊入會稽。"]'),
('a28f30cf-3eba-433f-8e0f-e42e7b05a786','遊水西簡鄭明府','李白','唐','唐诗','tang','','[]','天宮水西寺，雲錦照東郭。',96,'全唐诗/poet.tang.8000.json','["天宮水西寺，雲錦照東郭。", "清湍鳴迴溪，綠水遶飛閣。", "涼風日瀟灑，幽客時憩泊。", "五月思貂裘，謂言秋霜落。", "石蘿引古蔓，岸筍開新籜。", "吟翫空復情，相思爾佳作。", "鄭公詩人秀，逸韻宏寥廓。", "何當一來遊，愜我雪山諾。"]'),
('31d006f5-9145-47ca-bdbd-ab91189d5b64','九日登山','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u996e\u9152"]','淵明歸去來，不與世相逐。',204,'全唐诗/poet.tang.8000.json','["淵明歸去來，不與世相逐。", "爲無杯中物，遂偶本州牧。", "因招白衣人，笑酌黃花菊。", "我來不得意，虛過重陽時。", "題輿何俊發，遂結城南期。", "築土按響山，俯臨宛水湄。", "胡人呌玉笛，越女彈霜絲。", "自作英王胄，斯樂不可窺。", "赤鯉湧琴高，白龜道馮夷。", "靈仙如彷彿，奠酹遙相知。", "古來登高人，今復幾人在。", "滄洲違宿諾，明日猶可待。", "連山似驚波，合沓出溟海。", "揚袂揮四座，酩酊安所知。", "齊歌送清揚，起舞亂參差。", "賓隨落葉散，帽逐秋風吹。", "別後登此臺，願言長相思。"]'),
('40cb9862-a17a-4d2e-a955-6cec79c2f1d1','九日','李白','唐','唐诗','tang','','["\u996e\u9152", "\u767b\u9ad8", "\u91cd\u9633\u8282", "\u5178\u6545"]','今日雲景好，水綠秋山明。',60,'全唐诗/poet.tang.8000.json','["今日雲景好，水綠秋山明。", "攜壺酌流霞，搴菊泛寒榮。", "地遠松石古，風揚弦管清。", "窺觴照歡顏，獨笑還自傾。", "落帽醉山月，空歌懷友生。"]'),
('7b550f8c-c635-4b27-808e-1ee7b14acf07','九日龍山飲','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5178\u6545", "\u91cd\u9633\u8282", "\u996e\u9152"]','九日龍山飲，黃花笑逐臣。',24,'全唐诗/poet.tang.8000.json','["九日龍山飲，黃花笑逐臣。", "醉看風落帽，舞愛月留人。"]'),
('6d49e6f8-1cb3-4c16-bc9f-250edead9286','九月十日即事','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u91cd\u9633", "\u91cd\u9633\u8282", "\u83ca\u82b1"]','昨日登高罷，今朝更舉觴。',24,'全唐诗/poet.tang.8000.json','["昨日登高罷，今朝更舉觴。", "菊花何太苦，遭此兩重陽。"]'),
('9b87e14c-3133-4232-a797-4d916ca5ed8c','陪族叔當塗宰遊化城寺升公清風亭','李白','唐','唐诗','tang','','[]','化城若化出，金牓天宮開。',156,'全唐诗/poet.tang.8000.json','["化城若化出，金牓天宮開。", "疑是海上雲，飛空結樓臺。", "升公湖上秀，粲然有辯才。", "濟人不利己，立俗無嫌猜。", "了見水中月，青蓮出塵埃。", "閑居清風亭，左右清風來。", "當暑陰廣殿，太陽爲裴回。", "茗酌待幽客，珍盤薦彫梅。", "飛文何灑落，萬象爲之摧。", "季父擁鳴琴，德聲布雲雷。", "雖遊道林室，亦舉陶潛杯。", "清樂動諸天，長松自吟哀。", "留歡若可盡，劫石乃成灰。"]'),
('6b53c418-c778-429f-ac6b-556bd2a5e36d','登錦城散花樓','李白','唐','唐诗','tang','','[]','日照錦城頭，朝光散花樓。',60,'全唐诗/poet.tang.8000.json','["日照錦城頭，朝光散花樓。", "金窗夾繡戶，珠箔懸銀鉤。", "飛梯綠雲中，極目散我憂。", "暮雨向三峽，春江繞雙流。", "今來一登望，如上九天遊。"]'),
('baf00a44-ea8c-4f88-918a-3c0ed7f1cd5d','登峨眉山','李白','唐','唐诗','tang','','["\u5199\u5c71", "\u63cf\u5199\u5c71"]','蜀國多仙山，峨眉邈難匹。',96,'全唐诗/poet.tang.8000.json','["蜀國多仙山，峨眉邈難匹。", "周流試登覽，絕怪安可息。", "青冥倚天開，彩錯疑畫出。", "泠然紫霞賞，果得錦囊術。", "雲間吟瓊簫，石上弄寶瑟。", "平生有微尚，歡笑自此畢。", "烟容如在顏，塵累忽相失。", "儻逢騎羊子，攜手凌白日。"]'),
('27560ab0-d135-4dcf-a0a9-52c6f7366ed7','大庭庫','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','朝登大庭庫，雲物何蒼然。',60,'全唐诗/poet.tang.8000.json','["朝登大庭庫，雲物何蒼然。", "莫辨陳鄭火，空霾鄒魯煙。", "我來尋梓慎，觀化入寥天。", "古木朔氣多，松風如五弦。", "帝圖終冥沒，歎息滿山川。"]'),
('7f9f0c8e-d8b1-4b3a-86eb-18679f73b0fe','登單父陶少府半月臺','李白','唐','唐诗','tang','','["\u53cb\u60c5"]','陶公有逸興，不與常人俱。',72,'全唐诗/poet.tang.8000.json','["陶公有逸興，不與常人俱。", "築臺像半月，迴向高城隅。", "置酒望白雲，商飆起寒梧。", "秋山入遠海，桑柘羅平蕪。", "水色淥且明，令人思鏡湖。", "終當過江去，愛此暫踟躕。"]'),
('589ca8b3-49ab-4d01-8749-207e80f425d3','天台曉望','李白','唐','唐诗','tang','','["\u53cb\u60c5", "\u666f\u70b9"]','天台鄰四明，華頂高百越。',96,'全唐诗/poet.tang.8000.json','["天台鄰四明，華頂高百越。", "門標赤城霞，樓棲滄島月。", "憑高登遠覽，直下見溟渤。", "雲垂大鵬翻，波動巨鼇沒。", "風潮爭洶湧，神怪何翕忽。", "觀奇跡無倪，好道心不歇。", "攀條摘朱實，服藥鍊金骨。", "安得生羽毛，千春臥蓬闕。"]'),
('f3f2d630-f325-4caa-b96e-a61731c3412d','早望海霞邊','李白','唐','唐诗','tang','','[]','四明三千里，朝起赤城霞。',48,'全唐诗/poet.tang.8000.json','["四明三千里，朝起赤城霞。", "日出紅光散，分輝照雪厓。", "一餐嚥瓊液，五內發金沙。", "舉手何所待，青龍白虎車。"]'),
('bc819866-1931-4db1-bfed-759913252a04','焦山望寥山','李白','唐','唐诗','tang','','["\u559c\u60a6", "\u5c71", "\u63cf\u5199\u5c71", "\u5199\u5c71"]','石壁望松寥，宛然在碧霄。',36,'全唐诗/poet.tang.8000.json','["石壁望松寥，宛然在碧霄。", "安得五綵虹，駕天作長橋。", "仙人如愛我，舉手來相招。"]'),
('86612734-8646-4fdb-a8e7-cbebc13c0140','杜陵絕句','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5f52\u9690", "\u5c71\u6c34"]','南登杜陵上，北望五陵間。',24,'全唐诗/poet.tang.8000.json','["南登杜陵上，北望五陵間。", "秋水明落日，流光滅遠山。"]'),
('64e804c8-f626-4b82-81bb-6d9ac96b43b7','登太白峰','李白','唐','唐诗','tang','','["\u63cf\u5199\u5c71", "\u6292\u60c5", "\u767b\u9ad8", "\u666f\u70b9", "\u5199\u5c71"]','西上太白峯，夕陽窮登攀。',60,'全唐诗/poet.tang.8000.json','["西上太白峯，夕陽窮登攀。", "太白與我語，爲我開天關。", "願乘泠風去，直出浮雲間。", "舉手可近月，前行若無山。", "一別武功去，何時復見還。"]'),
('f6a8c07e-5fb9-432c-af0b-ae0eebc0bb73','登邯鄲洪波臺置酒觀發兵','李白','唐','唐诗','tang','','["\u519b\u65c5", "\u8fb9\u585e"]','我把兩赤羽，來遊燕趙間。',84,'全唐诗/poet.tang.8000.json','["我把兩赤羽，來遊燕趙間。", "天狼正可射，感激無時閑。", "觀兵洪波臺，倚劒望玉關。", "請纓不繫越，且向燕然山。", "風引龍虎旗，歌鐘昔追攀。", "擊筑落高月，投壺破愁顏。", "遙知百戰勝，定掃鬼方還。"]'),
('432d8f62-b1ed-438e-92bf-91c5af04a6c3','登新平樓','李白','唐','唐诗','tang','','["\u6292\u6000", "\u5fe7\u56fd\u5fe7\u6c11", "\u79cb\u5929", "\u58ee\u5fd7\u672a\u916c", "\u671b\u8fdc"]','去國登茲樓，懷歸傷暮秋。',48,'全唐诗/poet.tang.8000.json','["去國登茲樓，懷歸傷暮秋。", "天長落日遠，水淨寒波流。", "秦雲起嶺樹，胡雁飛沙洲。", "蒼蒼幾萬里，目極令人愁。"]'),
('657e2878-b1a1-4ff9-8084-d2a957ab031b','謁老君廟','李白','唐','唐诗','tang','','[]','先君懷聖德，靈廟肅神心。',48,'全唐诗/poet.tang.8000.json','["先君懷聖德，靈廟肅神心。", "草合人蹤斷，塵濃鳥跡深。", "流沙丹竈滅，關路紫煙沈。", "獨傷千載後，空餘松柏林。"]'),
('ffd1b916-0e65-4d35-a718-53725bc02964','秋日登揚州西靈塔','李白','唐','唐诗','tang','','["\u79cb\u5929", "\u5199\u666f"]','寶塔凌蒼蒼，登攀覽四荒。',96,'全唐诗/poet.tang.8000.json','["寶塔凌蒼蒼，登攀覽四荒。", "頂高元氣合，標出海雲長。", "萬象分空界，三天接畫梁。", "水搖金剎影，日動火珠光。", "鳥拂瓊簾度，霞連繡栱張。", "目隨征路斷，心逐去帆揚。", "露浴梧楸白，霜催橘柚黃。", "玉毫如可見，於此照迷方。"]'),
('4903cf79-3b14-4714-abc7-2b4d54bcb1fb','登金陵冶城西北謝安墩','李白','唐','唐诗','tang','','[]','晉室昔橫潰，永嘉遂南奔。',204,'全唐诗/poet.tang.8000.json','["晉室昔橫潰，永嘉遂南奔。", "沙塵何茫茫，龍虎鬬朝昏。", "胡馬風漢草，天驕蹙中原。", "哲匠感頹運，雲鵬忽飛翻。", "組練照楚國，旌旗連海門。", "西秦百萬衆，戈甲如雲屯。", "投鞭可填江，一埽不足論。", "皇運有返正，醜虜無遺魂。", "談笑遏橫流，蒼生望斯存。", "冶城訪古跡，猶有謝安墩。", "憑覽周地險，高標絕人喧。", "想像東山姿，緬懷右軍言。", "梧桐識嘉樹，蕙草留芳根。", "白鷺暎春洲，青龍見朝暾。", "地古雲物在，臺傾禾黍繁。", "我來酌清波，於此樹名園。", "功成拂衣去，歸入武陵源。"]'),
('3bec12bd-f48b-4c3c-83a6-4443892f69d2','登瓦官閣','李白','唐','唐诗','tang','','[]','晨登瓦官閣，極眺金陵城。',120,'全唐诗/poet.tang.8000.json','["晨登瓦官閣，極眺金陵城。", "鍾山對北戶，淮水入南榮。", "漫漫雨花落，嘈嘈天樂鳴。", "兩廊振法鼓，四角吟風箏。", "杳出霄漢上，仰攀日月行。", "山空霸氣滅，地古寒陰生。", "寥廓雲海晚，蒼茫宮觀平。", "門餘閶闔字，樓識鳳凰名。", "雷作百山動，神扶萬栱傾。", "靈光何足貴，長此鎮吳京。"]'),
('78eb70d1-cf6d-475c-96b6-2c8c4bab4a90','登梅岡望金陵贈族姪高座寺僧中孚','李白','唐','唐诗','tang','','["\u79cb\u5929", "\u767b\u9ad8", "\u6000\u53e4"]','鍾山抱金陵，霸氣昔騰發。',192,'全唐诗/poet.tang.8000.json','["鍾山抱金陵，霸氣昔騰發。", "天開帝王居，海色照宮闕。", "羣峰如逐鹿，奔走相馳突。", "江水九道來，雲端遙明沒。", "時遷大運去，龍虎勢休歇。", "我來屬天清，登覽窮楚越。", "吾宗挺禪伯，特秀鸞鳳骨。", "衆星羅青天，明者獨有月。", "冥居順生理，草木不剪伐。", "烟窗引薔薇，石壁老野蕨。", "吳風謝安屐，白足傲履韈。", "幾宿一下山，蕭然忘干謁。", "談經演金偈，降鶴舞海雪。", "時聞天香來，了與世事絕。", "佳遊不可得，春風惜遠別。", "賦詩留巖屏，千載庶不滅。"]'),
('4af86c76-18b3-4069-be90-6d8cef430bc7','登金陵鳳凰臺','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e03\u8a00\u5f8b\u8bd7", "\u4e00\u5e74\u7ea7\u4e0b\u518c", "\u9ad8\u4e2d\u53e4\u8bd7", "\u548f\u53f2\u6000\u53e4"]','鳳凰臺上鳳凰遊，鳳去臺空江自流。',64,'全唐诗/poet.tang.8000.json','["鳳凰臺上鳳凰遊，鳳去臺空江自流。", "吳宮花草埋幽徑，晉代衣冠成古丘。", "三山半落青天外，二水中分白鷺洲。", "總爲浮雲能蔽日，長安不見使人愁。"]'),
('6d15ef0b-73f9-488a-859c-e5b9fdf0a2ac','望廬山瀑布水二首 一','李白','唐','唐诗','tang','','["\u5e90\u5c71", "\u7ec4\u8bd7", "\u5c0f\u5b66\u53e4\u8bd7", "\u5c71\u6c34"]','西登香爐峰，南見瀑布水。',132,'全唐诗/poet.tang.8000.json','["西登香爐峰，南見瀑布水。", "挂流三百丈，噴壑數十里。", "歘如飛電來，隱若白虹起。", "初驚河漢落，半灑雲天裏。", "仰觀勢轉雄，壯哉造化功。", "海風吹不斷，江月照還空。", "空中亂潨射，左右洗青壁。", "飛珠散輕霞，流沫沸穹石。", "而我樂名山，對之心益閑。", "無論潄瓊液，還得洗塵顏。", "且諧宿所好，永願辭人間。"]'),
('c155ff88-deac-4c17-8648-91f478d77ef9','望廬山瀑布水二首 二','李白','唐','唐诗','tang','','["\u5e90\u5c71", "\u4e8c\u5e74\u7ea7\u4e0b\u518c", "\u5c71\u6c34", "\u5199\u666f", "\u5c71", "\u7011\u5e03"]','日照香爐生紫煙，遙看瀑布挂前川。',32,'全唐诗/poet.tang.8000.json','["日照香爐生紫煙，遙看瀑布挂前川。", "飛流直下三千尺，疑是銀河落九天。"]'),
('bfa3c73e-023d-4295-8ca7-7fef63b29207','登廬山五老峰','李白','唐','唐诗','tang','','["\u5e90\u5c71"]','廬山東南五老峰，青天削出金芙蓉。',32,'全唐诗/poet.tang.8000.json','["廬山東南五老峰，青天削出金芙蓉。", "九江秀色可攬結，吾將此地巢雲松。"]'),
('c172e467-ee99-4896-86b9-f1491d127403','江上望皖公山','李白','唐','唐诗','tang','','[]','奇峰出奇雲，秀木含秀氣。',72,'全唐诗/poet.tang.8000.json','["奇峰出奇雲，秀木含秀氣。", "清宴皖公山，巉絕稱人意。", "獨遊滄江上，終日淡無味。", "但愛茲嶺高，何由討靈異。", "默然遙相許，欲徃心莫遂。", "待吾還丹成，投跡歸此地。"]'),
('a7060e8f-cb6c-43de-bcf8-e6753e3e42f1','望黃鶴樓','李白','唐','唐诗','tang','','["\u9ec4\u9e64\u697c", "\u6292\u60c5", "\u751f\u6d3b", "\u666f\u70b9"]','東望黃鶴山，雄雄半空出。',120,'全唐诗/poet.tang.8000.json','["東望黃鶴山，雄雄半空出。", "四面生白雲，中峰倚紅日。", "巖巒行穹跨，峰嶂亦冥密。", "頗聞列仙人，於此學飛術。", "一朝向蓬海，千載空石室。", "金竈生烟埃，玉潭祕清謐。", "地古遺草木，庭寒老芝朮。", "蹇予羨攀躋，因欲保閑逸。", "觀奇徧諸嶽，茲嶺不可匹。", "結心寄青松，永悟客情畢。"]'),
('3e92b69c-cc6d-44ed-b873-573300ac14ac','鸚鵡洲','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5e26\u6709\u5730\u540d", "\u6d41\u653e", "\u5730\u540d"]','鸚鵡來過吳江水，江上洲傳鸚鵡名。',64,'全唐诗/poet.tang.8000.json','["鸚鵡來過吳江水，江上洲傳鸚鵡名。", "鸚鵡西飛隴山去，芳洲之樹何青青。", "烟開蘭葉香風暖，岸夾桃花錦浪生。", "遷客此時徒極目，長洲孤月向誰明。"]'),
('00ad3a0b-6682-4338-be5b-8825f2b9c54f','九日登巴陵置酒望洞庭水軍','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u91cd\u9633\u8282"]','九日天氣清，登高無秋雲。',120,'全唐诗/poet.tang.8000.json','["九日天氣清，登高無秋雲。", "造化闢川嶽，了然楚漢分。", "長風鼓橫波，合沓蹙龍文。", "憶昔傳遊豫，樓船壯橫汾。", "今茲討鯨鯢，旌斾何繽紛。", "白羽落酒樽，洞庭羅三軍。", "黃花不掇手，戰鼓遙相聞。", "劒舞轉頹陽，當時日停曛。", "酣歌激壯士，可以摧妖氛。", "齷齪東籬下，淵明不足羣。"]'),
('1098b99e-9464-4339-8640-301ac4664e04','秋登巴陵望洞庭','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','清晨登巴陵，周覽無不極。',120,'全唐诗/poet.tang.8000.json','["清晨登巴陵，周覽無不極。", "明湖暎天光，徹底見秋色。", "秋色何蒼然，際海俱澄鮮。", "山青滅遠樹，水綠無寒烟。", "來帆出江中，去鳥向日邊。", "風清長沙浦，山空雲夢田。", "瞻光惜頹髮，閱水悲徂年。", "北渚既蕩漾，東流自潺湲。", "郢人唱白雪，越女歌採蓮。", "聽此更腸斷，憑厓淚如泉。"]'),
('3fdb5cd2-7b86-4c2d-9da0-cac80d36b3bc','與夏十二登岳陽樓','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c", "\u559c\u60a6", "\u5e26\u6709\u5730\u540d", "\u5199\u666f", "\u5730\u540d"]','樓觀岳陽盡，川逈洞庭開。',48,'全唐诗/poet.tang.8000.json','["樓觀岳陽盡，川逈洞庭開。", "雁引愁心去，山銜好月來。", "雲間連下榻，天上接行杯。", "醉後涼風起，吹人舞袖迴。"]'),
('575a389f-2b6c-4946-b711-4f457ce3f6de','登巴陵開元寺西閣贈衡嶽僧方外','李白','唐','唐诗','tang','','[]','衡嶽有闡士，五峯秀真骨。',72,'全唐诗/poet.tang.8000.json','["衡嶽有闡士，五峯秀真骨。", "見君萬里心，海水照秋月。", "大臣南溟去，問道皆請謁。", "灑以甘露言，清涼潤肌髮。", "明湖落天鏡，香閣凌銀闕。", "登眺餐惠風，新花期啓發。"]'),
('193e48e6-35b7-42c7-95e0-f57073c1476d','與賈至舍人於龍興寺剪落梧桐枝望㴩湖','李白','唐','唐诗','tang','','[]','剪落青梧枝，㴩湖坐可窺。',48,'全唐诗/poet.tang.8000.json','["剪落青梧枝，㴩湖坐可窺。", "雨洗秋山淨，林光澹碧滋。", "水閑明鏡轉，雲繞畫屏移。", "千古風流事，名賢共此時。"]'),
('fd1f3ce3-4368-44be-a1b8-42e54ceeb421','挂席江上待月有懷','李白','唐','唐诗','tang','','[]','待月月未出，望江江自流。',48,'全唐诗/poet.tang.8000.json','["待月月未出，望江江自流。", "倏忽城西郭，青天懸玉鉤。", "素華雖可攬，清景不可遊。", "耿耿金波裏，空瞻鳷鵲樓。"]'),
('7cac5b4f-8afd-440d-8346-663eb8d8d3e6','金陵望漢江','李白','唐','唐诗','tang','','["\u957f\u6c5f", "\u5199\u666f", "\u5fe7\u56fd\u5fe7\u6c11", "\u6292\u60c5"]','漢江迴萬里，派作九龍盤。',60,'全唐诗/poet.tang.8000.json','["漢江迴萬里，派作九龍盤。", "橫潰豁中國，崔嵬飛迅湍。", "六帝淪亡後，三吳不足觀。", "我君混區宇，垂拱衆流安。", "今日任公子，滄浪罷釣竿。"]'),
('1eb19484-ee82-4fe0-8412-3b61951ef1e9','秋登宣城謝朓北樓','李白','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u79cb\u5929", "\u666f\u70b9", "\u548f\u53f2\u6000\u53e4"]','江城如畫裏，山曉望晴空。',48,'全唐诗/poet.tang.8000.json','["江城如畫裏，山曉望晴空。", "兩水夾明鏡，雙橋落彩虹。", "人煙寒橘柚，秋色老梧桐。", "誰念北樓上，臨風懷謝公。"]'),
('cc7dff19-adc9-4f03-8862-057d1e7722b3','望天門山','李白','唐','唐诗','tang','','["\u5929\u95e8\u5c71", "\u957f\u6c5f", "\u5c71\u6c34", "\u5199\u666f", "\u5c71", "\u6c34"]','天門中斷楚江開，碧水東流至北迴。',32,'全唐诗/poet.tang.8000.json','["天門中斷楚江開，碧水東流至北迴。", "兩岸青山相對出，孤帆一片日邊來。"]'),
('857b0aba-32b8-4d71-be68-f6b3eac5974a','望木瓜山','李白','唐','唐诗','tang','','["\u5e26\u6709\u5730\u540d", "\u5fe7\u4f24", "\u601d\u4e61", "\u5730\u540d"]','早起見日出，暮見棲鳥還。',24,'全唐诗/poet.tang.8000.json','["早起見日出，暮見棲鳥還。", "客心自酸楚，況對木瓜山。"]'),
('7b0b77ea-48cc-48cf-abf8-ed34e73325d8','登敬亭北二小山余時送客逢崔侍御並登此地','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u4eba"]','送客謝亭北，逢君縱酒還。',48,'全唐诗/poet.tang.8000.json','["送客謝亭北，逢君縱酒還。", "屈盤戲白馬，大笑上青山。", "迴鞭指長安，西日落秦關。", "帝鄉三千里，杳在碧雲間。"]'),
('b29d892d-8d75-4e8c-846c-bd751dcd8b3a','過崔八丈水亭','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u5fc3\u60c5", "\u95f2\u9002"]','高閣橫秀氣，清幽併在君。',48,'全唐诗/poet.tang.8000.json','["高閣橫秀氣，清幽併在君。", "簷飛宛溪水，窗落敬亭雲。", "猨嘯風中斷，漁歌月裏聞。", "閑隨白鷗去，沙上自爲羣。"]'),
('3f1a2777-6bfa-419e-806c-970e60fece30','登廣武古戰場懷古','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u53f2\u6000\u53e4"]','秦鹿奔野草，逐之若飛蓬。',180,'全唐诗/poet.tang.8000.json','["秦鹿奔野草，逐之若飛蓬。", "項王氣蓋世，紫電明雙瞳。", "呼吸八千人，橫行起江東。", "赤精斬白帝，叱咤入關中。", "兩龍不並躍，五緯與天同。", "楚滅無英圖，漢興有成功。", "按劒清八極，歸酣歌大風。", "伊昔臨廣武，連兵決雌雄。", "分我一杯羹，太皇乃汝翁。", "戰爭有古跡，壁壘頹層穹。", "猛虎嘯洞壑，飢鷹鳴秋空。", "翔雲列曉陣，殺氣赫長虹。", "撥亂屬豪聖，俗儒安可通。", "沈湎呼豎子，狂言非至公。", "撫掌黃河曲，嗤嗤阮嗣宗。"]'),
('e914e3a4-36f3-4d04-8c60-036c7b034f1c','安州應城玉女湯作','李白','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u5199\u6c34"]','神女歿幽境，湯池流大川。',132,'全唐诗/poet.tang.8000.json','["神女歿幽境，湯池流大川。", "陰陽結炎炭，造化開靈泉。", "地底爍朱火，沙傍歊素煙。", "沸珠躍明月，皎鏡函空天。", "氣浮蘭芳滿，色漲桃花然。", "精覽萬殊入，潛行七澤連。", "愈疾功莫尚，變盈道乃全。", "濯濯氣清泚，晞髮弄潺湲。", "散下楚王國，分澆宋玉田。", "可以奉巡幸，奈何隔窮偏。", "獨隨朝宗水，赴海輸微涓。"]'),
('1eca97f2-6916-444d-9b67-53ea52355fbf','之廣陵宿常二南郭幽居','李白','唐','唐诗','tang','','["\u79bb\u522b", "\u53cb\u60c5", "\u5199\u666f"]','綠水接柴門，有如桃花源。',74,'全唐诗/poet.tang.8000.json','["綠水接柴門，有如桃花源。", "忘憂或假草，滿院羅叢萱。", "[暝]色湖上來，微雨飛南軒。", "故人宿茅宇，夕鳥棲楊園。", "還惜詩酒別，深爲江海言。", "明朝廣陵道，獨憶此傾樽。"]'),
('7f066769-61bb-469b-8224-e90424e5cddf','夜下征虜亭','李白','唐','唐诗','tang','','[]','船下廣陵去，月明征虜亭。',24,'全唐诗/poet.tang.8000.json','["船下廣陵去，月明征虜亭。", "山花如繡頰，江火似流螢。"]'),
('eb5def7d-2b21-4034-a4f2-f63ce6a1c793','下途歸石門舊居','李白','唐','唐诗','tang','','["\u8d60\u522b", "\u5199\u4eba", "\u53cb\u60c5", "\u5199\u4eba\u8bd7"]','吳山高，越水清，握手無言傷別情。',320,'全唐诗/poet.tang.8000.json','["吳山高，越水清，握手無言傷別情。", "將欲辭君挂帆去，離魂不散煙郊樹。", "此心鬱悵誰能論，有愧叨承國士恩。", "雲物共傾三月酒，歲時同餞五侯門。", "羨君素書嘗滿案，含丹照白霞色爛。", "余嘗學道窮冥筌，夢中往往遊仙山。", "何當脫屣謝時去，壺中別有日月天。", "俛仰人間易凋朽，鍾峰五雲在軒牖。", "惜別愁窺玉女窗，歸來笑把洪厓手。", "隱居寺，隱居山，陶公鍊液棲其間。", "靈神閉氣昔登攀，恬然但覺心緒閑。", "數人不知幾甲子，昨夜猶帶冰霜顏。", "我離雖則歲物改，如今了然失所在。", "別君莫道不盡歡，懸知樂客遙相待。", "石門流水徧桃花，我亦曾到秦人家。", "不知何處得雞豕，就中仍見繁桑麻。", "翛然遠與世事間，裝鸞駕鶴又復遠。", "何必長從七貴遊，勞生徒聚萬金產。", "挹君去，長相思，雲遊雨散從此辭。", "欲知悵別心易苦，向暮春風楊柳絲。"]'),
('edea2ab7-a187-497a-8382-bba6b71ba476','客中行','李白','唐','唐诗','tang','','["\u79bb\u522b", "\u8c6a\u8fc8", "\u8d5e\u7f8e"]','蘭陵美酒鬱金香，玉椀盛來琥珀光。',32,'全唐诗/poet.tang.8000.json','["蘭陵美酒鬱金香，玉椀盛來琥珀光。", "但使主人能醉客，不知何處是他鄉。"]'),
('c2a632c7-6efc-44aa-a963-6c62e90589b6','太原早秋','李白','唐','唐诗','tang','','["\u79cb\u5929", "\u601d\u4e61", "\u5199\u666f"]','歲落衆芳歇，時當大火流。',48,'全唐诗/poet.tang.8000.json','["歲落衆芳歇，時當大火流。", "霜威出塞早，雲色渡河秋。", "夢繞邊城月，心飛故國樓。", "思歸若汾水，無日不悠悠。"]'),
('4d2c478f-18d3-4477-9ae4-209fd7426eab','奔亡道中五首 一','李白','唐','唐诗','tang','','[]','蘇武天山上，田橫海島邊。',24,'全唐诗/poet.tang.8000.json','["蘇武天山上，田橫海島邊。", "萬重關塞斷，何日是歸年。"]'),
('ed7382c4-83f6-494a-8a23-4c1c4380c1c5','奔亡道中五首 二','李白','唐','唐诗','tang','','[]','亭伯去安在，李陵降未歸。',24,'全唐诗/poet.tang.8000.json','["亭伯去安在，李陵降未歸。", "愁容變海色，短服改胡衣。"]'),
('aa166845-fac4-4a9c-8df5-731afd1ca151','奔亡道中五首 三','李白','唐','唐诗','tang','','[]','談笑三軍却，交游七貴疎。',24,'全唐诗/poet.tang.8000.json','["談笑三軍却，交游七貴疎。", "仍留一隻箭，未射魯連書。"]'),
('3d26f178-0226-4bfa-9929-0e47726046e2','奔亡道中五首 四','李白','唐','唐诗','tang','','[]','函谷如玉關，幾時可生還。',48,'全唐诗/poet.tang.8000.json','["函谷如玉關，幾時可生還。", "洛陽爲易水，嵩嶽是燕山。", "俗變羗胡語，人多沙塞顏。", "申包惟慟哭，七日鬢毛斑。"]'),
('daf8d13d-79be-4657-8f96-ae6c7b5c0692','奔亡道中五首 五','李白','唐','唐诗','tang','','[]','淼淼望湖水，青青蘆葉齊。',48,'全唐诗/poet.tang.8000.json','["淼淼望湖水，青青蘆葉齊。", "歸心落何處，日沒大江西。", "歇馬傍春草，欲行遠道迷。", "誰忍子規鳥，連聲向我啼。"]'),
('546a04ac-8e3d-4bb3-b73d-3a5bdaaacc40','郢門秋懷','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u65f6\u5149", "\u79cb\u5929", "\u601d\u4e61"]','郢門一爲客，巴月三成弦。',120,'全唐诗/poet.tang.8000.json','["郢門一爲客，巴月三成弦。", "朔風正搖落，行子愁歸旋。", "杳杳山外日，茫茫江上天。", "人迷洞庭水，雁度瀟湘烟。", "清曠諧宿好，緇磷及此年。", "百齡何蕩漾，萬化相推遷。", "空謁蒼梧帝，徒尋溟海仙。", "已聞蓬海淺，豈見三桃圓。", "倚劒增浩歎，捫襟還自憐。", "終當遊五湖，濯足滄浪泉。"]'),
('3763e6be-0dad-43e7-a277-c4253d87197a','至鴨欄驛上白馬磯贈裴侍御','李白','唐','唐诗','tang','','["\u957f\u6c5f", "\u53cb\u60c5"]','側疊萬古石，橫爲白馬磯。',48,'全唐诗/poet.tang.8000.json','["側疊萬古石，橫爲白馬磯。", "亂流若電轉，舉櫂揚珠輝。", "臨驛卷緹幕，升堂接繡衣。", "情親不避馬，爲我解霜威。"]'),
('4d771394-9918-46f0-a621-abdb5ebc9101','荆門浮舟望蜀江','李白','唐','唐诗','tang','','[]','春水月峽來，浮舟望安極。',96,'全唐诗/poet.tang.8000.json','["春水月峽來，浮舟望安極。", "正是桃花流，依然錦江色。", "江色綠且明，茫茫與天平。", "逶迤巴山盡，搖曳楚雲行。", "雪照聚沙雁，花飛出谷鶯。", "芳洲却已轉，碧樹森森迎。", "流目浦烟夕，揚帆海月生。", "江陵識遙火，應到渚宮城。"]'),
('b04d7649-3406-40a7-a582-1b319540a7f4','上三峽','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u884c\u8def", "\u5c71\u6c34", "\u666f\u70b9"]','巫山夾青天，巴水流若茲。',48,'全唐诗/poet.tang.8000.json','["巫山夾青天，巴水流若茲。", "巴水忽可盡，青天無到時。", "三朝上黃牛，三暮行太遲。", "三朝又三暮，不覺鬢成絲。"]'),
('26391863-c700-46d7-b13d-d941358a4c7b','自巴東舟行經瞿唐峽登巫山最高峰晚還題壁','李白','唐','唐诗','tang','','[]','江行幾千里，海月十五圓。',168,'全唐诗/poet.tang.8000.json','["江行幾千里，海月十五圓。", "始經瞿唐峽，遂步巫山巔。", "巫山高不窮，巴國盡所歷。", "日邊攀垂蘿，霞外倚穹石。", "飛步凌絕頂，極目無纖烟。", "却顧失舟壑，仰觀臨青天。", "青天若可捫，銀漢去安在。", "望雲知蒼梧，記水辨瀛海。", "周遊孤光晚，歷覽幽意多。", "積雪照空谷，悲風鳴森柯。", "歸途行欲曛，佳趣尚未歇。", "江寒早啼猨，松暝已吐月。", "月色何悠悠，清猨響啾啾。", "辭山不忍聽，揮策還孤舟。"]'),
('9525f99d-39cb-4d04-8650-263493d223e0','早發白帝城','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u957f\u6c5f", "\u5c71", "\u559c\u60a6", "\u4e03\u8a00\u7edd\u53e5", "\u63cf\u5199\u5c71"]','朝辭白帝彩雲間，千里江陵一日還。',32,'全唐诗/poet.tang.8000.json','["朝辭白帝彩雲間，千里江陵一日還。", "兩岸猨聲啼不盡，輕舟已過萬重山。"]'),
('7743536b-ca93-405f-80b4-95d156f70219','秋下荆門','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u79cb\u6e38"]','霜落荆門江樹空，布帆無恙挂秋風。',32,'全唐诗/poet.tang.8000.json','["霜落荆門江樹空，布帆無恙挂秋風。", "此行不爲鱸魚鱠，自愛名山入剡中。"]'),
('e22a48b0-781e-4c01-a3fd-7bbed834945b','江行寄遠','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u4eb2\u53cb", "\u6545\u4e61"]','刳木出吳楚，危槎百餘尺。',48,'全唐诗/poet.tang.8000.json','["刳木出吳楚，危槎百餘尺。", "疾風吹片帆，日暮千里隔。", "別時酒猶在，已爲異鄉客。", "思君不可得，愁見江水碧。"]'),
('93f7059e-2f45-4d80-9b86-7fc0d3003163','宿五松山下荀媼家','李白','唐','唐诗','tang','','[]','我宿五松下，寂寥無所歡。',48,'全唐诗/poet.tang.8000.json','["我宿五松下，寂寥無所歡。", "田家秋作苦，鄰女夜舂寒。", "跪進雕胡飯，月光明素盤。", "令人慚漂母，三謝不能餐。"]'),
('a048cbb0-9793-4abd-b1d9-b925c8077a07','下涇縣陵陽溪至澁灘','李白','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u52b3\u52a8", "\u751f\u6d3b", "\u8d5e\u7f8e", "\u7cbe\u795e", "\u4eba\u6c11"]','澁灘鳴嘈嘈，兩山足猨猱。',36,'全唐诗/poet.tang.8000.json','["澁灘鳴嘈嘈，兩山足猨猱。", "白波若卷雪，側足不容舠。", "漁子與舟人，撐折萬張篙。"]'),
('4bc8b9d4-3e07-4233-a574-0689bb95c6b4','下陵陽沿高溪三門六剌灘','李白','唐','唐诗','tang','','[]','三門橫峻灘，六剌走波瀾。',36,'全唐诗/poet.tang.8000.json','["三門橫峻灘，六剌走波瀾。", "石驚虎伏起，水狀龍縈盤。", "何慙七里瀨，使我欲垂竿。"]'),
('dc8cb4d0-bdb1-45ab-84ba-eff238065e00','夜泊黃山聞殷十四吳吟','李白','唐','唐诗','tang','','["\u9ec4\u5c71"]','昨夜誰爲吳會吟，風生萬壑振空林。',80,'全唐诗/poet.tang.8000.json','["昨夜誰爲吳會吟，風生萬壑振空林。", "龍驚不敢水中臥，猨嘯時聞巖下音。", "我宿黃山碧溪月，聽之却罷松間琴。", "朝來果是滄洲逸，酤酒醍盤飯霜栗。", "半酣更發江海聲，客愁頓向杯中失。"]'),
('01a954e3-4ca7-4564-9e7d-8db629560b0b','宿鰕湖','李白','唐','唐诗','tang','','["\u9ec4\u5c71"]','雞鳴發黃山，暝投鰕湖宿。',72,'全唐诗/poet.tang.8000.json','["雞鳴發黃山，暝投鰕湖宿。", "白雨暎寒山，森森似銀竹。", "提攜採鉛客，結荷水邊沐。", "半夜四天開，星河爛人目。", "明晨大樓去，岡隴多屈伏。", "當與持斧翁，前溪伐雲木。"]'),
('7bb86c78-913e-4b2b-a1e3-1bdd6408fdd1','西施','李白','唐','唐诗','tang','','["\u7231\u60c5", "\u548f\u53f2\u6000\u53e4"]','西施越溪女，出自苧蘿山。',84,'全唐诗/poet.tang.8000.json','["西施越溪女，出自苧蘿山。", "秀色掩今古，荷花羞玉顏。", "浣紗弄碧水，自與清波閑。", "皓齒信難開，沈吟碧雲間。", "句踐徵絕豔，揚蛾入吳關。", "提攜館娃宮，杳渺詎可攀。", "一破夫差國，千秋竟不還。"]'),
('89b50a83-3a22-4297-9106-20dcee9c3a37','王右軍','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u5199\u4eba\u8bd7"]','右軍本清真，瀟灑出風塵。',48,'全唐诗/poet.tang.8000.json','["右軍本清真，瀟灑出風塵。", "山陰過羽客，愛此好鵝賓。", "掃素寫道經，筆精妙入神。", "書罷籠鵝去，何曾別主人。"]'),
('f21a8baf-4b8d-4d67-9c06-6122a512d9fc','上元夫人','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u795e\u8bdd", "\u5199\u4eba\u8bd7"]','上元誰夫人，偏得王母嬌。',60,'全唐诗/poet.tang.8000.json','["上元誰夫人，偏得王母嬌。", "嵯峨三角髻，餘髮散垂腰。", "裘披青毛錦，身著赤霜袍。", "手提嬴女兒，閑與鳳吹簫。", "眉語兩自笑，忽然隨風飄。"]'),
('41618979-004e-4d9f-b032-c69316eeb660','蘇臺覽古','李白','唐','唐诗','tang','','["\u6708\u4eae", "\u6000\u53e4"]','舊苑荒臺楊柳新，菱歌清唱不勝春。',32,'全唐诗/poet.tang.8000.json','["舊苑荒臺楊柳新，菱歌清唱不勝春。", "只今惟有西江月，曾照吳王宮裏人。"]'),
('3ce6ab82-5b1a-4117-908a-819af59e47ae','越中覽古','李白','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u53f2\u6000\u53e4"]','越王句踐破吳歸，義士還鄉盡錦衣。',32,'全唐诗/poet.tang.8000.json','["越王句踐破吳歸，義士還鄉盡錦衣。", "宮女如花滿春殿，只今惟有鷓鴣飛。"]'),
('98c2eb6b-d408-4b7e-b9ff-3ad80fde6a25','商山四皓','李白','唐','唐诗','tang','','[]','白髮四老人，昂藏南山側。',120,'全唐诗/poet.tang.8000.json','["白髮四老人，昂藏南山側。", "偃臥松雪間，冥翳不可識。", "雲窗拂青靄，石壁橫翠色。", "龍虎方戰爭，於焉自休息。", "秦人失金鏡，漢祖昇紫極。", "陰虹濁太陽，前星遂淪匿。", "一行佐明聖，倏起生羽翼。", "功成身不居，舒卷在胸臆。", "窅冥合元化，茫昧信難測。", "飛聲塞天衢，萬古仰遺則。"]'),
('c54de925-9760-4d21-bfb1-fcfec238ccad','過四皓墓','李白','唐','唐诗','tang','','[]','我行至商洛，幽獨訪神仙。',96,'全唐诗/poet.tang.8000.json','["我行至商洛，幽獨訪神仙。", "園綺復安在，雲蘿尚宛然。", "荒涼千古跡，蕪沒四墳連。", "伊昔鍊金鼎，何年閉玉泉。", "隴寒惟有月，松古漸無煙。", "木魅風號去，山精雨嘯旋。", "紫芝高詠罷，青史舊名傳。", "今日併如此，哀哉信可憐。"]'),
('53dd2dfa-4479-4932-a262-a80648e55557','峴山懷古','李白','唐','唐诗','tang','','["\u5199\u5c71", "\u6000\u53e4", "\u5199\u666f", "\u63cf\u5199\u5c71"]','訪古登峴首，憑高眺襄中。',48,'全唐诗/poet.tang.8000.json','["訪古登峴首，憑高眺襄中。", "天清遠峰出，水落寒沙空。", "弄珠見遊女，醉酒懷山公。", "感歎發秋興，長松鳴夜風。"]'),
('94388fcc-9175-4551-a4f2-08a20319cd53','蘇武','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u6000\u53e4", "\u5199\u4eba\u8bd7"]','蘇武在匈奴，十年持漢節。',72,'全唐诗/poet.tang.8000.json','["蘇武在匈奴，十年持漢節。", "白雁上林飛，空傳一書札。", "牧羊邊地苦，落日歸心絕。", "渴飲月窟冰，肌餐天上雪。", "東還沙塞遠，北愴河梁別。", "泣把李陵衣，相看淚成血。"]'),
('93d35411-4b3c-4b98-8fc2-a319bf1fa6ef','經下邳圯橋懷張子房','李白','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u5199\u4eba", "\u548f\u53f2\u6000\u53e4"]','子房未虎嘯，破產不爲家。',84,'全唐诗/poet.tang.8000.json','["子房未虎嘯，破產不爲家。", "滄海得壯士，椎秦博浪沙。", "報韓雖不成，天地皆振動。", "潛匿遊下邳，豈曰非智勇。", "我來圯橋上，懷古欽英風。", "惟見碧流水，曾無黃石公。", "歎息此人去，蕭條徐泗空。"]'),
('bf9d1226-344a-4620-81cb-368bc9bf8c50','金陵三首 一','李白','唐','唐诗','tang','','[]','晉家南渡日，此地舊長安。',48,'全唐诗/poet.tang.8000.json','["晉家南渡日，此地舊長安。", "地即帝王宅，山爲龍虎盤。", "金陵空壯觀，天塹淨波瀾。", "醉客回橈去，吳歌且自歡。"]'),
('0493fe73-9709-4bba-9d88-196de5ff1932','金陵三首 二','李白','唐','唐诗','tang','','[]','地擁金陵勢，城迴江水流。',48,'全唐诗/poet.tang.8000.json','["地擁金陵勢，城迴江水流。", "當時百萬戶，夾道起朱樓。", "亡國生春草，離宮沒古丘。", "空餘後湖月，波上對江州。"]'),
('df1e5229-512c-4ebd-9966-f23bd8895e41','金陵三首 三','李白','唐','唐诗','tang','','[]','六代興亡國，三杯爲爾歌。',48,'全唐诗/poet.tang.8000.json','["六代興亡國，三杯爲爾歌。", "苑方秦地少，山似洛陽多。", "古殿吳花草，深宮晉綺羅。", "併隨人事滅，東逝與滄波。"]'),
('dc856594-e3fa-417c-a607-17e891c84cbd','秋夜板橋浦泛月獨酌懷謝朓','李白','唐','唐诗','tang','','[]','天上何所有，迢迢白玉繩。',72,'全唐诗/poet.tang.8000.json','["天上何所有，迢迢白玉繩。", "斜低建章闕，耿耿對金陵。", "漢水舊如練，霜江夜清澄。", "長川瀉落月，洲渚曉寒凝。", "獨酌板橋浦，古人誰可徵。", "玄暉難再得，灑酒氣填膺。"]'),
('d4c800e1-8162-4727-9216-a1044731140d','入彭蠡經松門觀石鏡緬懷謝康樂題詩書遊覽之志','李白','唐','唐诗','tang','','[]','謝公之彭蠡，因此遊松門。',120,'全唐诗/poet.tang.8000.json','["謝公之彭蠡，因此遊松門。", "余方窺石鏡，兼得窮江源。", "將欲繼風雅，豈徒清心魂。", "前賞逾所見，後來道空存。", "況屬臨汎美，而無洲渚喧。", "漾水向東去，漳流直南奔。", "空濛三川夕，回合千里昏。", "青桂隱遙月，綠楓鳴愁猨。", "水碧或可采，金精祕莫論。", "吾將學仙去，冀與琴高言。"]'),
('59700741-34ac-4b86-8e8f-bfa50e21b896','廬江主人婦','李白','唐','唐诗','tang','','["\u5178\u6545", "\u5199\u4eba", "\u5199\u4eba\u8bd7"]','孔雀東飛何處棲，廬江小吏仲卿妻。',32,'全唐诗/poet.tang.8000.json','["孔雀東飛何處棲，廬江小吏仲卿妻。", "爲客裁縫君自見，城烏獨宿夜空啼。"]'),
('cc70bec0-2c97-40e3-a3b8-043b00385568','陪宋中丞武昌夜飲懷古','李白','唐','唐诗','tang','','[]','清景南樓夜，風流在武昌。',48,'全唐诗/poet.tang.8000.json','["清景南樓夜，風流在武昌。", "庾公愛秋月，乘興坐胡牀。", "龍笛吟寒水，天河落曉霜。", "我心還不淺，懷古醉餘觴。"]'),
('75cb17e4-7da4-4eaa-a2f7-456161eb6a0c','望鸚鵡洲懷禰衡','李白','唐','唐诗','tang','','[]','魏帝營八極，蟻觀一禰衡。',96,'全唐诗/poet.tang.8000.json','["魏帝營八極，蟻觀一禰衡。", "黃祖斗筲人，殺之受惡名。", "吳江賦鸚鵡，落筆超羣英。", "鏘鏘振金玉，句句欲飛鳴。", "鷙鶚啄孤鳳，千春傷我情。", "五嶽起方寸，隱然詎可平。", "才高竟何施，寡識冒天刑。", "至今芳洲上，蘭蕙不忍生。"]'),
('a2b4078e-5417-4fee-ae8d-23e35a09c429','宿巫山下','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u501f\u666f\u6292\u60c5", "\u6000\u53e4"]','昨夜巫山下，猨聲夢裏長。',48,'全唐诗/poet.tang.8000.json','["昨夜巫山下，猨聲夢裏長。", "桃花飛綠水，三月下瞿塘。", "雨色風吹去，南行拂楚王。", "高丘懷宋玉，訪古一霑裳。"]'),
('23fcc4ef-2c9a-4659-bee8-2b1af4f4965f','金陵白楊十字巷','李白','唐','唐诗','tang','','[]','白楊十字巷，北夾湖溝道。',48,'全唐诗/poet.tang.8000.json','["白楊十字巷，北夾湖溝道。", "不見吳時人，空生唐年草。", "天地有反覆，宮城盡傾倒。", "六帝餘古丘，樵蘇泣遺老。"]'),
('727eb3e0-7ce3-4886-a25d-1b2238703a74','謝公亭','李白','唐','唐诗','tang','','["\u5b64\u72ec", "\u751f\u6d3b", "\u6000\u53e4", "\u53cb\u60c5"]','謝公離別處，風景每生愁。',48,'全唐诗/poet.tang.8000.json','["謝公離別處，風景每生愁。", "客散青天月，山空碧水流。", "池花春暎日，窗竹夜鳴秋。", "今古一相接，長歌懷舊遊。"]'),
('2e4d7c6d-ffb1-4674-9053-292b475ec9fd','紀南陵題五松山','李白','唐','唐诗','tang','','[]','聖達有去就，潛光愚其德。',144,'全唐诗/poet.tang.8000.json','["聖達有去就，潛光愚其德。", "魚與龍同池，龍去魚不測。", "當時版築輩，豈知傅說情。", "一朝和殷羹，光氣爲列星。", "伊尹生空桑，捐庖佐皇極。", "桐宮放太甲，攝政無愧色。", "三年帝道明，委質終輔翼。", "曠哉至人心，萬古可爲則。", "時命或大繆，仲尼將奈何。", "鸞鳳忽覆巢，麒麟不來過。", "龜山蔽魯國，有斧且無柯。", "歸來歸去來，宵濟越洪波。"]'),
('7e1be9c9-fa2f-44c2-a6bc-3edcece745fe','夜泊牛渚懷古','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6000\u53e4", "\u4e94\u8a00\u5f8b\u8bd7", "\u6708\u4eae"]','牛渚西江夜，青天無片雲。',48,'全唐诗/poet.tang.8000.json','["牛渚西江夜，青天無片雲。", "登舟望秋月，空憶謝將軍。", "余亦能高詠，斯人不可聞。", "明朝挂帆席，楓葉落紛紛。"]'),
('342005b5-87b2-41cb-814d-7010ac43e9db','姑孰十詠 姑孰溪','李白','唐','唐诗','tang','','[]','愛此溪水閑，乘流興無極。',48,'全唐诗/poet.tang.8000.json','["愛此溪水閑，乘流興無極。", "漾楫怕鷗驚，垂竿待魚食。", "波飜曉霞影，岸疊春山色。", "何處浣紗人，紅顏未相識。"]'),
('a7e80219-d018-4966-a7d7-4a324f34c4a2','姑孰十詠 丹陽湖','李白','唐','唐诗','tang','','[]','湖與元氣連，風波浩難止。',48,'全唐诗/poet.tang.8000.json','["湖與元氣連，風波浩難止。", "天外賈客歸，雲間片帆起。", "龜遊蓮葉上，鳥宿蘆花裏。", "少女櫂歸舟，歌聲逐流水。"]'),
('d37e079e-33e7-480a-bd39-7bd72e58420b','姑孰十詠 謝公宅','李白','唐','唐诗','tang','','[]','青山日將暝，寂寞謝公宅。',48,'全唐诗/poet.tang.8000.json','["青山日將暝，寂寞謝公宅。", "竹裏無人聲，池中虛月白。", "荒庭衰草徧，廢井蒼苔積。", "惟有清風閑，時時起泉石。"]'),
('8f637920-0d93-44a1-8b24-596ec27fc951','姑孰十詠 陵歊臺','李白','唐','唐诗','tang','','[]','曠望登古臺，臺高極人目。',48,'全唐诗/poet.tang.8000.json','["曠望登古臺，臺高極人目。", "疊嶂列遠空，雜花間平陸。", "閑雲入窗牖，野翠生松竹。", "欲覽碑上文，苔侵豈堪讀。"]'),
('6769dfab-6139-4b48-bc93-11bf56b21e08','姑孰十詠 桓公井','李白','唐','唐诗','tang','','[]','桓公名已古，廢井曾未竭。',48,'全唐诗/poet.tang.8000.json','["桓公名已古，廢井曾未竭。", "石甃冷蒼苔，寒泉湛孤月。", "秋來桐暫落，春至桃還發。", "路遠人罕窺，誰能見清徹。"]'),
('a2a14ea0-64c6-4493-a8de-5c8fa91adcc0','姑孰十詠 慈姥竹','李白','唐','唐诗','tang','','[]','野竹攢石生，含煙暎江島。',48,'全唐诗/poet.tang.8000.json','["野竹攢石生，含煙暎江島。", "翠色落波深，虛聲帶寒早。", "龍吟曾未聽，鳳曲吹應好。", "不學蒲柳凋，貞心嘗自保。"]'),
('8045fafa-3f64-49dd-a6ed-e27a52d8064e','姑孰十詠 望夫山','李白','唐','唐诗','tang','','[]','顒望臨碧空，怨情感離別。',48,'全唐诗/poet.tang.8000.json','["顒望臨碧空，怨情感離別。", "江草不知愁，巖花但爭發。", "雲山萬重隔，音信千里絕。", "春去秋復來，相思幾時歇。"]'),
('e1ba6051-6dc7-42ba-a6d6-9580a426e2fa','姑孰十詠 牛渚磯','李白','唐','唐诗','tang','','[]','絕壁臨巨川，連峰勢相向。',48,'全唐诗/poet.tang.8000.json','["絕壁臨巨川，連峰勢相向。", "亂石流洑間，迴波自成浪。", "但驚羣木秀，莫測精靈狀。", "更聽猨夜啼，憂心醉江上。"]'),
('18c6d150-033a-4d33-a83f-3513323da7d2','姑孰十詠 靈墟山','李白','唐','唐诗','tang','','[]','丁令辭世人，拂衣向仙路。',48,'全唐诗/poet.tang.8000.json','["丁令辭世人，拂衣向仙路。", "伏鍊九丹成，方隨五雲去。", "松蘿蔽幽洞，桃杏深隱處。", "不知曾化鶴，遼海歸幾度。"]'),
('86e9088a-6186-4466-9416-c6d97bec7077','姑孰十詠 天門山','李白','唐','唐诗','tang','','["\u5929\u95e8\u5c71"]','逈出江山上，雙峰自相對。',48,'全唐诗/poet.tang.8000.json','["逈出江山上，雙峰自相對。", "岸暎松色寒，石分浪花碎。", "參差遠天際，縹緲晴霞外。", "落日舟去遙，迴首沈青靄。"]'),
('feaace98-d325-4210-bb70-62e3502da7d9','與元丹丘方城寺談玄作','李白','唐','唐诗','tang','','[]','茫茫大夢中，惟我獨先覺。',108,'全唐诗/poet.tang.8000.json','["茫茫大夢中，惟我獨先覺。", "騰轉風火來，假合作容貌。", "滅除昏疑盡，領略入精要。", "澄慮觀此身，因得通寂照。", "朗悟前後際，始知金仙妙。", "幸逢禪居人，酌玉坐相召。", "彼我俱若喪，雲山豈殊調。", "清風生虛空，明月見談笑。", "怡然青蓮宮，永願姿遊眺。"]'),
('be4fa628-ef1d-41ca-831a-7594974e9429','尋高鳳石門山中元丹丘','李白','唐','唐诗','tang','','[]','尋幽無前期，乘興不覺遠。',120,'全唐诗/poet.tang.8000.json','["尋幽無前期，乘興不覺遠。", "蒼厓渺難涉，白日忽欲晚。", "未窮三四山，已歷千萬轉。", "寂寂聞猨愁，行行見雲收。", "高松來好月，空谷宜清秋。", "溪深古雪在，石斷寒泉流。", "峰巒秀中天，登眺不可盡。", "丹丘遙相呼，顧我忽而哂。", "遂造窮谷間，始知靜者閑。", "留歡達永夜，清曉方言還。"]'),
('1cf7d263-5546-40da-9695-34721dac1493','安州般若水閣納涼喜遇薛員外乂','李白','唐','唐诗','tang','','[]','翛然金園賞，遠近含晴光。',84,'全唐诗/poet.tang.8000.json','["翛然金園賞，遠近含晴光。", "樓臺成海氣，草木皆天香。", "忽逢青雲士，共解丹霞裳。", "水退池上熱，風生松下涼。", "吞討破萬象，搴窺臨衆芳。", "而我遺有漏，與君用無方。", "心垢都已滅，永言題禪房。"]'),
('3935a437-6df6-4006-a5b1-cf35375d7a8b','魯中都東樓醉起作','李白','唐','唐诗','tang','','[]','昨日東樓醉，還應倒接䍦。',24,'全唐诗/poet.tang.8000.json','["昨日東樓醉，還應倒接䍦。", "阿誰扶上馬，不省下樓時。"]'),
('a0eef61e-6dca-4dbc-beff-3228bce783ce','對酒醉題屈突明府廳','李白','唐','唐诗','tang','','[]','陶令八十日，長歌歸去來。',48,'全唐诗/poet.tang.8000.json','["陶令八十日，長歌歸去來。", "故人建昌宰，借問幾時迴。", "風落吳江雪，紛紛入酒杯。", "山翁今已醉，舞袖爲君開。"]'),
('83e70b6e-ff59-4a3b-8e81-249ab0cda0c3','月下獨酌四首 一','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5b64\u72ec", "\u4e94\u8a00\u53e4\u8bd7", "\u666f\u4e2d\u60c5", "\u6292\u60c5", "\u4e2d\u79cb"]','花間一壺酒，獨酌無相親。',84,'全唐诗/poet.tang.8000.json','["花間一壺酒，獨酌無相親。", "舉杯邀明月，對影成三人。", "月既不解飲，影徒隨我身。", "暫伴月將影，行樂須及春。", "我歌月裴回，我舞影零亂。", "醒時同交歡，醉後各分散。", "永結無情遊，相期邈雲漢。"]'),
('0d835f44-d5ee-4d4a-ad46-26891f2b9e6f','月下獨酌四首 二','李白','唐','唐诗','tang','','[]','天若不愛酒，酒星不在天。',84,'全唐诗/poet.tang.8000.json','["天若不愛酒，酒星不在天。", "地若不愛酒，地應無酒泉。", "天地既愛酒，愛酒不愧天。", "已聞清比聖，復道濁如賢。", "賢聖既已飲，何必求神仙。", "三杯通大道，一斗合自然。", "但得酒中趣，勿爲醒者傳。"]'),
('a643857d-d6fc-4f41-a4a7-febaa209562e','月下獨酌四首 三','李白','唐','唐诗','tang','','[]','三月咸陽城，千花晝如錦。',72,'全唐诗/poet.tang.8000.json','["三月咸陽城，千花晝如錦。", "誰能春獨愁，對此徑須飲。", "窮通與修短，造化夙所稟。", "一樽齊死生，萬事固難審。", "醉後失天地，兀然就孤枕。", "不知有吾身，此樂最爲甚。"]'),
('97dad3b0-37a6-4c79-b59c-4500b97d63eb','月下獨酌四首 四','李白','唐','唐诗','tang','','[]','窮愁千萬端，美酒三百杯。',84,'全唐诗/poet.tang.8000.json','["窮愁千萬端，美酒三百杯。", "愁多酒雖少，酒傾愁不來。", "所以知酒聖，酒酣心自開。", "辭粟臥首陽，屢空飢顏回。", "當代不樂飲，虛名安用哉。", "蟹螯即金液，糟丘是蓬萊。", "且須飲美酒，乘月醉高臺。"]'),
('dc0512e6-2249-45ff-a710-43cacb6673be','春歸終南山松龕舊隱','李白','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','我來南山陽，事事不異昔。',60,'全唐诗/poet.tang.8000.json','["我來南山陽，事事不異昔。", "却尋溪中水，還望巖下石。", "薔薇緣東窗，女蘿遶北壁。", "別來能幾日，草木長數尺。", "且復命酒樽，獨酌陶永夕。"]'),
('dfc1da0a-da1f-44f4-94d9-1ad66bed37c4','冬夜醉宿龍門覺起言志','李白','唐','唐诗','tang','','[]','醉來脫寶劒，旅憩高堂眠。',120,'全唐诗/poet.tang.8000.json','["醉來脫寶劒，旅憩高堂眠。", "中夜忽驚覺，起立明燈前。", "開軒聊直望，曉雪河冰壯。", "哀哀歌苦寒，鬱鬱獨惆悵。", "傅說版築臣，李斯鷹犬人。", "歘起匡社稷，寧復長艱辛。", "而我胡爲者，歎息龍門下。", "富貴未可期，殷憂向誰寫。", "去去淚滿襟，舉聲梁甫吟。", "青雲當自致，何必求知音。"]'),
('6a6f2822-0128-4791-b2f3-9d0d1bc33a60','尋山僧不遇作','李白','唐','唐诗','tang','','[]','石徑入丹壑，松門閉青苔。',84,'全唐诗/poet.tang.8000.json','["石徑入丹壑，松門閉青苔。", "閑階有鳥跡，禪室無人開。", "窺窗見白拂，挂壁生塵埃。", "使我空歎息，欲去仍裴回。", "香雲徧山起，花雨從天來。", "已有空樂好，況聞青猨哀。", "了然絕世事，此地方悠哉。"]'),
('4add7af1-aa2b-44fb-b28c-4680d40e4c07','過汪氏別業二首 一','李白','唐','唐诗','tang','','[]','遊山誰可遊，子明與浮丘。',72,'全唐诗/poet.tang.8000.json','["遊山誰可遊，子明與浮丘。", "疊嶺礙河漢，連峰橫斗牛。", "汪生面北阜，池館清且幽。", "我來感意氣，搥炰列珍羞。", "掃石待歸月，開池漲寒流。", "酒酣益爽氣，爲樂不知秋。"]'),
('044f9513-2781-44e0-a6bc-8a8f89662875','過汪氏別業二首 二','李白','唐','唐诗','tang','','[]','疇昔未識君，知君好賢才。',120,'全唐诗/poet.tang.8000.json','["疇昔未識君，知君好賢才。", "隨山起館宇，鑿石營池臺。", "星火五月中，景風從南來。", "數枝石榴發，一丈荷花開。", "恨不當此時，相過醉金罍。", "我行值木落，月苦清猨哀。", "永夜達五更，吳歈送瓊杯。", "酒酣欲起舞，四座歌相催。", "日出遠海明，軒車且裴回。", "更遊龍潭去，枕石拂莓苔。"]'),
('c5cd198a-3ef2-4de5-919a-092a74d067fd','待酒不至','李白','唐','唐诗','tang','','[]','玉壺繫青絲，沽酒來何遲。',48,'全唐诗/poet.tang.8000.json','["玉壺繫青絲，沽酒來何遲。", "山花向我笑，正好銜杯時。", "晚酌東窗下，流鶯復在茲。", "春風與醉客，今日乃相宜。"]'),
('063c9e1b-9794-46ce-acff-5c1030ab7e77','獨酌','李白','唐','唐诗','tang','','[]','春草如有意，羅生玉堂陰。',72,'全唐诗/poet.tang.8000.json','["春草如有意，羅生玉堂陰。", "東風吹愁來，白髮坐相侵。", "獨酌勸孤影，閑歌面芳林。", "長松爾何知，蕭瑟爲誰吟。", "手舞石上月，膝橫花間琴。", "過此一壺外，悠悠非我心。"]'),
('1c74a0fa-9059-4951-af44-9b8a3369ba53','友人會宿','李白','唐','唐诗','tang','','[]','滌蕩千古愁，留連百壺飲。',36,'全唐诗/poet.tang.8000.json','["滌蕩千古愁，留連百壺飲。", "良宵宜清談，皓月未能寢。", "醉來臥空山，天地即衾枕。"]'),
('849c7103-6c9d-40c6-8210-60e602915209','春日獨酌二首 一','李白','唐','唐诗','tang','','[]','東風扇淑氣，水木榮春暉。',60,'全唐诗/poet.tang.8000.json','["東風扇淑氣，水木榮春暉。", "白日照綠草，落花散且飛。", "孤雲還空山，衆鳥各已歸。", "彼物皆有託，吾生獨無依。", "對此石上月，長醉歌芳菲。"]'),
('7f398c63-d380-43c4-8881-38e0a0e8c760','春日獨酌二首 二','李白','唐','唐诗','tang','','[]','我有紫霞想，緬懷滄洲間。',60,'全唐诗/poet.tang.8000.json','["我有紫霞想，緬懷滄洲間。", "思對一壺酒，澹然萬事閑。", "橫琴倚高松，把酒望遠山。", "長空去鳥沒，落日孤雲還。", "但恐光景晚，宿昔成秋顏。"]'),
('c8590a5b-dffc-499f-b09c-b670c0ddd417','金陵江上遇蓬池隱者','李白','唐','唐诗','tang','','[]','心愛名山遊，身隨名山遠。',132,'全唐诗/poet.tang.8000.json','["心愛名山遊，身隨名山遠。", "羅浮麻姑臺，此去或未返。", "遇君蓬池隱，就我石上飯。", "空言不成歡，強笑惜日晚。", "綠水向雁門，黃雲蔽龍山。", "歎息兩客鳥，裴回吳越間。", "共語一執手，留連夜將久。", "解我紫綺裘，且換金陵酒。", "酒來笑復歌，興酣樂事多。", "水影弄月色，清光奈愁何。", "明晨挂帆席，離恨滿滄波。"]'),
('fe631cf2-b06a-45d1-8386-8cb7d1a45fdd','月夜聽盧子順彈琴','李白','唐','唐诗','tang','','["\u660e\u6708", "\u6292\u60c5", "\u5f39\u7434"]','閑坐夜明月，幽人彈素琴。',48,'全唐诗/poet.tang.8000.json','["閑坐夜明月，幽人彈素琴。", "忽聞悲風調，宛若寒松吟。", "白雪亂纖手，綠水清虛心。", "鍾期久已沒，世上無知音。"]'),
('8c735c91-2bc5-4cfb-a245-f732723ea3cb','清溪半夜聞笛','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5fe7\u56fd", "\u6000\u624d\u4e0d\u9047", "\u58ee\u5fd7\u672a\u916c"]','羗笛梅花引，吳溪隴水情。',24,'全唐诗/poet.tang.8000.json','["羗笛梅花引，吳溪隴水情。", "寒山秋浦月，腸斷玉關聲。"]'),
('f7765f83-8373-46f3-9705-8625158a0219','日夕山中忽然有懷','李白','唐','唐诗','tang','','[]','久臥青山雲，遂爲青山客。',84,'全唐诗/poet.tang.8000.json','["久臥青山雲，遂爲青山客。", "山深雲更好，賞弄終日夕。", "月銜樓間峰，泉潄階下石。", "素心自此得，真趣非外惜。", "鼯啼桂方秋，風滅籟歸寂。", "緬思洪厓術，欲往滄海隔。", "雲車來何遲，撫几空歎息。"]'),
('88e393f3-d0e4-41aa-95e0-2cdb17395c21','夏日山中','李白','唐','唐诗','tang','','["\u5c71", "\u590f\u5929", "\u5199\u5c71", "\u63cf\u5199\u5c71"]','嬾搖白羽扇，躶體青林中。',24,'全唐诗/poet.tang.8000.json','["嬾搖白羽扇，躶體青林中。", "脫巾挂石壁，露頂洒松風。"]'),
('a6a4a34d-2a6a-4b04-948f-bbc835e65771','山中與幽人對酌','李白','唐','唐诗','tang','','[]','兩人對酌山花開，一杯一杯復一杯。',32,'全唐诗/poet.tang.8000.json','["兩人對酌山花開，一杯一杯復一杯。", "我醉欲眠卿且去，明朝有意抱琴來。"]'),
('bf4da2f5-1603-4b17-a022-d088cfb2f8c6','春日醉起言志','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u996e\u9152"]','處世若大夢，胡爲勞其生。',72,'全唐诗/poet.tang.8000.json','["處世若大夢，胡爲勞其生。", "所以終日醉，頹然臥前楹。", "覺來盼庭前，一鳥花間鳴。", "借問此何時，春風語流鶯。", "感之欲歎息，對酒還自傾。", "浩歌待明月，曲盡已忘情。"]'),
('d81ca96f-dd8d-45d2-9807-a4a8866ce8ad','廬山東林寺夜懷','李白','唐','唐诗','tang','','["\u5e90\u5c71"]','我尋青蓮宇，獨往謝城闕。',60,'全唐诗/poet.tang.8000.json','["我尋青蓮宇，獨往謝城闕。", "霜清東林鐘，水白虎溪月。", "天香生虛空，天樂鳴不歇。", "宴坐寂不動，大千入毫髮。", "湛然冥真心，曠劫斷出沒。"]'),
('69261f5d-52cd-4de8-96ee-3b7d8c8dfa48','尋雍尊師隱居','李白','唐','唐诗','tang','','["\u8001\u5e08", "\u8d5e\u9882", "\u5178\u6545"]','羣峭碧摩天，逍遙不記年。',48,'全唐诗/poet.tang.8000.json','["羣峭碧摩天，逍遙不記年。", "撥雲尋古道，倚石聽流泉。", "花暖青牛臥，松高白鶴眠。", "語來江色暮，獨自下寒烟。"]'),
('9d5cf185-31e4-4d49-9504-cbc1e9c12723','與史郎中欽聽黃鶴樓上吹笛','李白','唐','唐诗','tang','','["\u9ec4\u9e64\u697c", "\u5fe7\u56fd\u5fe7\u6c11", "\u6292\u60c5", "\u8d2c\u8c2a", "\u601d\u4e61"]','一爲遷客去長沙，西望長安不見家。',32,'全唐诗/poet.tang.8000.json','["一爲遷客去長沙，西望長安不見家。", "黃鶴樓中吹玉笛，江城五月落梅花。"]'),
('e265f41f-3601-48eb-98a0-f1dddb07b9f9','對酒','李白','唐','唐诗','tang','','[]','勸君莫拒杯，春風笑人來。',72,'全唐诗/poet.tang.8000.json','["勸君莫拒杯，春風笑人來。", "桃李如舊識，傾花向我開。", "流鶯啼碧樹，明月窺金罍。", "昨日朱顏子，今日白髮催。", "棘生石虎殿，鹿走姑蘇臺。", "自古帝王宅，城闕閉黃埃。"]'),
('b463c627-1cfa-478a-a454-a4416ada0591','醉題王漢陽廳','李白','唐','唐诗','tang','','[]','我似鷓鴣鳥，南遷嬾北飛。',24,'全唐诗/poet.tang.8000.json','["我似鷓鴣鳥，南遷嬾北飛。", "時尋漢陽令，取醉月中歸。"]'),
('df40c153-838f-47d8-a895-99c81fe62845','嘲王歷陽不肯飲酒','李白','唐','唐诗','tang','','["\u5199\u96ea", "\u51ac\u5929", "\u6292\u60c5", "\u96ea", "\u996e\u9152"]','地白風色寒，雪花大如手。',48,'全唐诗/poet.tang.8000.json','["地白風色寒，雪花大如手。", "笑殺陶淵明，不飲杯中酒。", "浪撫一張琴，虛栽五株柳。", "空負頭上巾，吾於爾何有。"]'),
('f2005d82-8986-400f-9f8f-650d6f734a61','獨坐敬亭山','李白','唐','唐诗','tang','','["\u5c71", "\u5b64\u72ec", "\u5199\u666f", "\u65e0\u5948", "\u56db\u5e74\u7ea7\u4e0b\u518c", "\u63cf\u5199\u5c71"]','衆鳥高飛盡，孤雲獨去閑。',24,'全唐诗/poet.tang.8000.json','["衆鳥高飛盡，孤雲獨去閑。", "相看兩不厭，只有敬亭山。"]'),
('0216beca-aac2-410f-baa4-1007ed7ebafe','自遣','李白','唐','唐诗','tang','','[]','對酒不覺暝，落花盈我衣。',24,'全唐诗/poet.tang.8000.json','["對酒不覺暝，落花盈我衣。", "醉起步溪月，鳥還人亦稀。"]'),
('3bdf02de-ac34-4528-a267-ab6b0becb32a','訪戴天山道士不遇','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u62dc\u8bbf", "\u5199\u666f"]','犬吠水聲中，桃花帶雨濃。',48,'全唐诗/poet.tang.8000.json','["犬吠水聲中，桃花帶雨濃。", "樹深時見鹿，溪午不聞鐘。", "野竹分青靄，飛泉挂碧峰。", "無人知所去，愁倚兩三松。"]'),
('2a909399-c6d6-4a5b-9d87-dd56052c6d1e','秋日與張少府楚城韋公藏書高齋作','李白','唐','唐诗','tang','','[]','日下空庭暮，城荒古跡餘。',72,'全唐诗/poet.tang.8000.json','["日下空庭暮，城荒古跡餘。", "地形連海盡，天影落江虛。", "舊賞人雖隔，新知樂未疎。", "彩雲思作賦，丹壁間藏書。", "楂擁隨流葉，萍開出水魚。", "夕來秋興滿，回首意何如。"]'),
('30402058-21b4-4dae-be09-03b26433360c','秋夜獨坐懷故山','李白','唐','唐诗','tang','','[]','小隱慕安石，遠遊學屈平。',120,'全唐诗/poet.tang.8000.json','["小隱慕安石，遠遊學屈平。", "天書訪江海，雲臥起咸京。", "入侍瑤池宴，出陪玉輦行。", "誇胡新賦作，諫獵短書成。", "但奉紫霄顧，非邀青史名。", "莊周空說劒，墨翟耻論兵。", "拙薄遂疎絕，歸閑事耦耕。", "顧無蒼生望，空愛紫芝榮。", "寥落暝霞色，微茫舊壑情。", "秋山綠蘿月，今夕爲誰明。"]'),
('87762e0a-6022-4d29-a8f6-f4d1a404a10c','憶崔郎中宗之遊南陽遺吾孔子琴撫之潸然感舊','李白','唐','唐诗','tang','','[]','昔在南陽城，唯餐獨山蕨。',96,'全唐诗/poet.tang.8000.json','["昔在南陽城，唯餐獨山蕨。", "憶與崔宗之，白水弄素月。", "時過菊潭上，縱酒無休歇。", "泛此黃金花，頹然清歌發。", "一朝摧玉樹，生死殊飄忽。", "留我孔子琴，琴存人已歿。", "誰傳廣陵散，但哭邙山骨。", "泉戶何時明，長掃狐兔窟。"]'),
('9b0f4e0d-6ad0-4915-ab11-2a4a5901d1ed','憶東山二首 一','李白','唐','唐诗','tang','','[]','不向東山久，薔薇幾度花。',24,'全唐诗/poet.tang.8000.json','["不向東山久，薔薇幾度花。", "白雲還自散，明月落誰家。"]'),
('81275210-59eb-4102-b949-e9de1de6de97','憶東山二首 二','李白','唐','唐诗','tang','','[]','我今攜謝妓，長嘯絕人羣。',24,'全唐诗/poet.tang.8000.json','["我今攜謝妓，長嘯絕人羣。", "欲報東山客，開關掃白雲。"]'),
('3699d9ca-9851-4a75-9caf-61b28f14f8f6','望月有懷','李白','唐','唐诗','tang','','[]','清泉暎疎松，不知幾千古。',48,'全唐诗/poet.tang.8000.json','["清泉暎疎松，不知幾千古。", "寒月搖清波，流光入窗戶。", "對此空長吟，思君意何深。", "無因見安道，興盡愁人心。"]'),
('8a4fb2d0-a124-43b0-bb86-cf8347143eaa','對酒憶賀監二首 一','李白','唐','唐诗','tang','','[]','四明有狂客，風流賀季真。',48,'全唐诗/poet.tang.8000.json','["四明有狂客，風流賀季真。", "長安一相見，呼我謫仙人。", "昔好杯中物，翻爲松下塵。", "金龜換酒處，却憶淚沾巾。"]'),
('2a2f723d-6216-4c10-b2e0-215598dfdc75','對酒憶賀監二首 二','李白','唐','唐诗','tang','','[]','狂客歸四明，山陰道士迎。',48,'全唐诗/poet.tang.8000.json','["狂客歸四明，山陰道士迎。", "敕賜鏡湖水，爲君臺沼榮。", "人亡餘故宅，空有荷花生。", "念此杳如夢，淒然傷我情。"]'),
('7df4e423-90f2-48b6-b050-5aae6a097a3d','重憶一首','李白','唐','唐诗','tang','','[]','欲向江東去，定將誰舉杯。',24,'全唐诗/poet.tang.8000.json','["欲向江東去，定將誰舉杯。", "稽山無賀老，却櫂酒船回。"]'),
('e7ff52da-f3e6-4b96-9aa2-2f173e2113fd','春滯沅湘有懷山中','李白','唐','唐诗','tang','','[]','沅湘春色還，風暖烟草綠。',48,'全唐诗/poet.tang.8000.json','["沅湘春色還，風暖烟草綠。", "古之傷心人，於此腸斷續。", "予非懷沙客，但美採菱曲。", "所願歸東山，寸心於此足。"]'),
('f7e582e6-4e11-4710-91cf-82e2c6aa5fda','落日憶山中','李白','唐','唐诗','tang','','["\u98ce", "\u6625\u5929", "\u5199\u98ce"]','雨後烟景綠，晴天散餘霞。',48,'全唐诗/poet.tang.8000.json','["雨後烟景綠，晴天散餘霞。", "東風隨春歸，發我枝上花。", "花落時欲暮，見此令人嗟。", "願遊名山去，學道飛丹砂。"]'),
('80498ffd-7631-427a-ba29-b8bbf1d578dd','憶秋浦桃花舊遊時竄夜郎','李白','唐','唐诗','tang','','[]','桃花春水生，白石今出沒。',48,'全唐诗/poet.tang.8000.json','["桃花春水生，白石今出沒。", "搖蕩女蘿枝，半搖青天月。", "不知舊行徑，初拳幾枝蕨。", "三載夜郎還，於茲鍊金骨。"]'),
('5e520730-d319-4bb4-8253-36e8d5fcc6c1','越中秋懷','李白','唐','唐诗','tang','','[]','越水遶碧山，周迴數千里。',96,'全唐诗/poet.tang.8000.json','["越水遶碧山，周迴數千里。", "乃是天鏡中，分明畫相似。", "愛此從冥搜，永懷臨湍遊。", "一爲滄波客，十見紅蕖秋。", "觀濤壯天險，望海令人愁。", "路遐迫西照，歲晚悲東流。", "何必探禹穴，逝將歸蓬丘。", "不然五湖上，亦可乘扁舟。"]'),
('adb782de-e796-4888-9fe2-58b20ba83c4a','效古二首 一','李白','唐','唐诗','tang','','[]','朝入天苑中，謁帝蓬萊宮。',132,'全唐诗/poet.tang.8000.json','["朝入天苑中，謁帝蓬萊宮。", "青山映輦道，碧樹搖蒼空。", "謬題金閨籍，得與銀臺通。", "待詔奉明主，抽毫頌清風。", "歸時落日晚，躞蹀浮雲驄。", "人馬本無意，飛馳自豪雄。", "入門紫鴛鴦，金井雙梧桐。", "清歌弦古曲，美酒沽新豐。", "快意且爲樂，列筵坐羣公。", "光景不可留，生世如轉蓬。", "早達勝晚遇，羞比垂釣翁。"]'),
('543d61de-90af-48e8-9daf-80ee24e7bfa2','效古二首 二','李白','唐','唐诗','tang','','[]','自古有秀色，西施與東鄰。',60,'全唐诗/poet.tang.8000.json','["自古有秀色，西施與東鄰。", "蛾眉不可妬，況乃效其矉。", "所以尹婕妤，羞見邢夫人。", "低頭不出氣，塞默少精神。", "寄語無鹽子，如君何足珍。"]'),
('d6f963af-2b31-4a18-9e01-a7b37e6e6f13','擬古十二首 一','李白','唐','唐诗','tang','','[]','青天何歷歷，明星如白石。',96,'全唐诗/poet.tang.8000.json','["青天何歷歷，明星如白石。", "黃姑與織女，相去不盈尺。", "銀河無鵲橋，非時將安適。", "閨人理紈素，遊子悲行役。", "瓶冰知冬寒，霜露欺遠客。", "客似秋葉飛，飄颻不言歸。", "別後羅帶長，愁寬去時衣。", "乘月託宵夢，因之寄金徽。"]'),
('35bc02da-b239-4e22-8232-12fe88e62375','擬古十二首 二','李白','唐','唐诗','tang','','[]','高樓入青天，下有白玉堂。',96,'全唐诗/poet.tang.8000.json','["高樓入青天，下有白玉堂。", "明月看欲墮，當窗懸清光。", "遙夜一美人，羅衣霑秋霜。", "含情弄柔瑟，彈作陌上桑。", "弦聲何激烈，風捲遶飛梁。", "行人皆躑躅，栖鳥起迴翔。", "但寫妾意苦，莫辭此曲傷。", "願逢同心者，飛作紫鴛鴦。"]'),
('d4f40444-de50-40a2-8786-64cc1949cbe2','擬古十二首 三','李白','唐','唐诗','tang','','[]','長繩難繫日，自古共悲辛。',72,'全唐诗/poet.tang.8000.json','["長繩難繫日，自古共悲辛。", "黃金高北斗，不惜買陽春。", "石火無留光，還如世中人。", "即事已如夢，後來我誰身。", "提壺莫辭貧，取酒會四鄰。", "仙人殊恍惚，未若醉中真。"]'),
('dbc70889-352b-4356-aaec-0873cf945705','擬古十二首 四','李白','唐','唐诗','tang','','[]','清都綠玉樹，灼爍瑤臺春。',60,'全唐诗/poet.tang.8000.json','["清都綠玉樹，灼爍瑤臺春。", "攀花弄秀色，遠贈天仙人。", "香風送紫蘂，直到扶桑津。", "取掇世上豔，所貴心之珍。", "相思傳一笑，聊欲示情親。"]'),
('4e25cdf4-a9de-469b-a196-39cfa9a1719a','擬古十二首 五','李白','唐','唐诗','tang','','[]','今日風日好，明日恐不如。',84,'全唐诗/poet.tang.8000.json','["今日風日好，明日恐不如。", "春風笑於人，何乃愁自居。", "吹簫舞彩鳳，酌醴鱠神魚。", "千金買一醉，取樂不求餘。", "達士遺天地，東門有二疏。", "愚夫同瓦石，有才知卷舒。", "無事作悲苦，塊然涸轍魚。"]'),
('395f8c38-26db-4220-9fb7-33b755faa04e','擬古十二首 六','李白','唐','唐诗','tang','','[]','運速天地閉，胡風結飛霜。',84,'全唐诗/poet.tang.8000.json','["運速天地閉，胡風結飛霜。", "百草死冬月，六龍頹西荒。", "太白出東方，彗星揚精光。", "鴛鴦非越鳥，何爲眷南翔。", "惟昔鷹將犬，今爲侯與王。", "得水成蛟龍，爭池奪鳳凰。", "北斗不酌酒，南箕空簸揚。"]'),
('a74c0025-6e9a-4b31-8606-fee3784e0e34','擬古十二首 七','李白','唐','唐诗','tang','','[]','世路今太行，迴車竟何託。',72,'全唐诗/poet.tang.8000.json','["世路今太行，迴車竟何託。", "萬族皆凋枯，遂無少可樂。", "曠野多白骨，幽魂共銷鑠。", "榮貴當及時，春華宜照灼。", "人非崑山玉，安得長璀錯。", "身沒期不朽，榮名在麟閣。"]'),
('35aedc22-3117-4065-b6da-d988d8e03fa8','擬古十二首 八','李白','唐','唐诗','tang','','[]','月色不可掃，客愁不可道。',84,'全唐诗/poet.tang.8000.json','["月色不可掃，客愁不可道。", "玉露生秋衣，流螢飛百草。", "日月終銷毀，天地同枯槁。", "蟪蛄啼青松，安見此樹老。", "金丹寧誤俗，昧者難精討。", "爾非千歲翁，多恨去世早。", "飲酒入玉壺，藏身以爲寶。"]'),
('c9205b1b-6ac3-4b28-8843-3432bd6c7afe','擬古十二首 九','李白','唐','唐诗','tang','','[]','生者爲過客，死者爲歸人。',60,'全唐诗/poet.tang.8000.json','["生者爲過客，死者爲歸人。", "天地一逆旅，同悲萬古塵。", "月兔空搗藥，扶桑已成薪。", "白骨寂無言，青松豈知春。", "前後更嘆息，浮榮安足珍。"]'),
('527d85ce-3391-4ada-91ca-55578dac99e6','擬古十二首 十','李白','唐','唐诗','tang','','[]','仙人騎彩鳳，昨下閬風岑。',84,'全唐诗/poet.tang.8000.json','["仙人騎彩鳳，昨下閬風岑。", "海水三清淺，桃源一見尋。", "遺我綠玉桮，兼之紫瓊琴。", "杯以傾美酒，琴以閑素心。", "二物非世有，何論珠與金。", "琴彈松裏風，桮勸天上月。", "風月長相知，世人何倏忽。"]'),
('1b8a6d32-ff98-425f-b75f-d8255b3e79ac','擬古十二首 十一','李白','唐','唐诗','tang','','["\u60c6\u6005", "\u8377\u82b1", "\u8a00\u5fd7"]','涉江弄秋水，愛此荷花鮮。',48,'全唐诗/poet.tang.8000.json','["涉江弄秋水，愛此荷花鮮。", "攀荷弄其珠，蕩漾不成圓。", "佳人綵雲裏，欲贈隔遠天。", "相思無由見，悵望涼風前。"]'),
('8db29d61-2168-4b47-9e7e-a9e812d9df1d','擬古十二首 十二','李白','唐','唐诗','tang','','[]','去去復去去，辭君還憶君。',84,'全唐诗/poet.tang.8000.json','["去去復去去，辭君還憶君。", "漢水既殊流，楚山亦此分。", "人生難稱意，豈得長爲羣。", "越燕喜海日，燕鴻思朔雲。", "別久容華晚，琅玕不能飯。", "日落知天昏，夢長覺道遠。", "望夫登高山，化石竟不返。"]'),
('f47b763f-9870-4c3b-8b19-00cee343bf46','感興六首 一','李白','唐','唐诗','tang','','[]','瑤姬天帝女，精彩化朝雲。',48,'全唐诗/poet.tang.8000.json','["瑤姬天帝女，精彩化朝雲。", "宛轉入宵夢，無心向楚君。", "錦衾抱秋月，綺席空蘭芬。", "茫昧竟誰測，虛傳宋玉文。"]'),
('21c858a3-6eba-43a7-b110-47e716220227','感興六首 二','李白','唐','唐诗','tang','','[]','洛浦有宓妃，飄颻雪爭飛。',72,'全唐诗/poet.tang.8000.json','["洛浦有宓妃，飄颻雪爭飛。", "輕雲拂素月，了可見清輝。", "解珮欲西去，含情詎相違。", "香塵動羅襪，綠水不霑衣。", "陳王徒作賦，神女豈同歸。", "好色傷大雅，多爲世所譏。"]'),
('c3131783-37d0-4609-880c-8175f542c02b','感興六首 三','李白','唐','唐诗','tang','','[]','裂素持作書，將寄萬里懷。',72,'全唐诗/poet.tang.8000.json','["裂素持作書，將寄萬里懷。", "眷眷待遠信，竟歲無人來。", "征鴻務隨陽，又不爲我棲。", "委之在深篋，蠹魚壞其題。", "何如投水中，流落他人開。", "不惜他人開，但恐生是非。"]'),
('bd431a0a-64d3-4b2e-85a7-ea8dcddde134','感興六首 四','李白','唐','唐诗','tang','','[]','十五遊神仙，仙遊未曾歇。',48,'全唐诗/poet.tang.8000.json','["十五遊神仙，仙遊未曾歇。", "吹笙坐松風，汎瑟窺海月。", "西山玉童子，使我鍊金骨。", "欲逐黃鶴飛，相呼向蓬闕。"]'),
('2c72e22e-815a-48c8-8cd8-4cf9dc32541b','感興六首 五','李白','唐','唐诗','tang','','[]','西國有美女，結樓青雲端。',60,'全唐诗/poet.tang.8000.json','["西國有美女，結樓青雲端。", "蛾眉豔曉月，一笑傾城歡。", "高節不可奪，炯心如凝丹。", "常恐彩色晚，不爲人所觀。", "安得配君子，共乘雙飛鸞。"]'),
('eaad4233-739e-4f93-9745-479d93307ec1','感興六首 六','李白','唐','唐诗','tang','','[]','嘉穀隱豐草，草深苗且稀。',48,'全唐诗/poet.tang.8000.json','["嘉穀隱豐草，草深苗且稀。", "農夫既不異，孤穗將安歸。", "常恐委疇隴，忽與秋蓬飛。", "烏得薦宗廟，爲君生光輝。"]'),
('45f76a03-469c-4784-a5f4-258204d5004c','寓言三首 一','李白','唐','唐诗','tang','','[]','周公負斧扆，成王何夔夔。',72,'全唐诗/poet.tang.8000.json','["周公負斧扆，成王何夔夔。", "武王昔不豫，剪爪投河湄。", "賢聖遇讒慝，不免人君疑。", "天風拔大木，禾黍咸傷萎。", "管蔡扇蒼蠅，公賦鴟鴞詩。", "金縢若不啓，忠信誰明之。"]'),
('41dcfe15-cf84-449d-93a5-4b676e67e4f2','寓言三首 二','李白','唐','唐诗','tang','','[]','搖裔雙彩鳳，婉孌三青禽。',48,'全唐诗/poet.tang.8000.json','["搖裔雙彩鳳，婉孌三青禽。", "往還瑤臺裏，鳴舞玉山岑。", "以歡秦娥意，復得王母心。", "區區精衛鳥，銜木空哀吟。"]'),
('ed446759-2c64-4669-88a8-6d94032dc517','寓言三首 三','李白','唐','唐诗','tang','','[]','長安春色歸，先入青門道。',48,'全唐诗/poet.tang.8000.json','["長安春色歸，先入青門道。", "綠楊不自持，從風欲傾倒。", "海燕還秦宮，雙飛入簾櫳。", "相思不相見，託夢遼城東。"]'),
('17433d29-99c9-471e-9fca-431ac6eb3a51','秋夕旅懷','李白','唐','唐诗','tang','','["\u7f81\u65c5", "\u79cb\u5929", "\u6292\u6000", "\u5199\u666f"]','涼風度秋海，吹我鄉思飛。',72,'全唐诗/poet.tang.8000.json','["涼風度秋海，吹我鄉思飛。", "連山去無際，流水何時歸。", "目極浮雲色，心斷明月暉。", "芳草歇柔豔，白露催寒衣。", "夢長銀漢落，覺罷天星稀。", "含悲想舊國，泣下誰能揮。"]'),
('79bf081b-3ce2-4d11-af56-82934b5828d7','感遇四首 一','李白','唐','唐诗','tang','','[]','吾愛王子晉，得道伊洛濱。',60,'全唐诗/poet.tang.8000.json','["吾愛王子晉，得道伊洛濱。", "金骨既不毀，玉顏長自春。", "可憐浮丘公，猗靡與情親。", "舉首白日間，分明謝時人。", "二仙去已遠，夢想空殷勤。"]'),
('7aa629fb-81b1-436f-83dd-13e359bb7ba2','感遇四首 二','李白','唐','唐诗','tang','','[]','可歎東籬菊，莖疎葉且微。',48,'全唐诗/poet.tang.8000.json','["可歎東籬菊，莖疎葉且微。", "雖言異蘭蕙，亦自有芳菲。", "未泛盈樽酒，徒霑清露輝。", "當榮君不採，飄落欲何依。"]'),
('2200e99e-cc15-42b2-9161-efcc9950063c','感遇四首 三','李白','唐','唐诗','tang','','[]','昔余聞姮娥，竊藥駐雲髮。',48,'全唐诗/poet.tang.8000.json','["昔余聞姮娥，竊藥駐雲髮。", "不自嬌玉顏，方希鍊金骨。", "飛去身莫返，含笑坐明月。", "紫宮誇蛾眉，隨手會凋歇。"]'),
('6df05d26-7a31-46ac-a746-1610d0eeed41','感遇四首 四','李白','唐','唐诗','tang','','[]','宋玉事楚王，立身本高潔。',48,'全唐诗/poet.tang.8000.json','["宋玉事楚王，立身本高潔。", "巫山賦綵雲，郢路歌白雪。", "舉國莫能和，巴人皆卷舌。", "一感登徒言，恩情遂中絕。"]'),
('638f0fa8-cbb1-4652-9f75-a62cd7d31fd0','翰林讀書言懷呈集賢諸學士','李白','唐','唐诗','tang','','[]','晨趨紫禁中，夕待金門詔。',108,'全唐诗/poet.tang.8000.json','["晨趨紫禁中，夕待金門詔。", "觀書散遺帙，探古窮至妙。", "片言苟會心，掩卷忽而笑。", "青蠅易相點，白雪難同調。", "本是疎散人，屢貽褊促誚。", "雲天屬清朗，林壑憶遊眺。", "或時清風來，閑倚欄下嘯。", "嚴光桐廬溪，謝客臨海嶠。", "功成謝人間，從此一投釣。"]'),
('1d156eb9-550b-4052-8cfd-cdeeb9c44c73','尋陽紫極宮感秋作','李白','唐','唐诗','tang','','[]','何處聞秋聲，翛翛北窗竹。',96,'全唐诗/poet.tang.8000.json','["何處聞秋聲，翛翛北窗竹。", "迴薄萬古心，攬之不盈掬。", "靜坐觀衆妙，浩然媚幽獨。", "白雲南山來，就我檐下宿。", "嬾從唐生決，羞訪季主卜。", "四十九年非，一往不可復。", "野情轉蕭灑，世道有飜覆。", "陶令歸去來，田家酒應熟。"]'),
('3ffee7a6-2071-4926-97a8-f95d59a071ff','江上秋懷','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u79cb\u5929", "\u5199\u666f"]','餐霞臥舊壑，散髮謝遠遊。',84,'全唐诗/poet.tang.8000.json','["餐霞臥舊壑，散髮謝遠遊。", "山蟬號枯桑，始復知天秋。", "朔雁別海裔，越燕辭江樓。", "颯颯風卷沙，茫茫霧縈洲。", "黃雲結暮色，白水揚寒流。", "惻愴心自悲，潺湲淚難收。", "蘅蘭方蕭瑟，長嘆令人愁。"]'),
('4eed4e2b-2f4d-421c-b637-e5589cfcd327','秋夕書懷','李白','唐','唐诗','tang','','[]','北風吹海鴈，南渡落寒聲。',96,'全唐诗/poet.tang.8000.json','["北風吹海鴈，南渡落寒聲。", "感此瀟湘客，淒其流浪情。", "海懷結滄洲，霞想遊赤城。", "始探蓬壺事，旋覺天地輕。", "澹然吟高秋，閑臥瞻太清。", "蘿月掩空幕，松霜結前楹。", "滅見息羣動，獵微窮至精。", "桃花有源水，可以保吾生。"]'),
('5beaf48e-c727-4fba-8a4c-33629beb03e6','避地司空原言懷','李白','唐','唐诗','tang','','[]','南風昔不競，豪聖思經綸。',132,'全唐诗/poet.tang.8000.json','["南風昔不競，豪聖思經綸。", "劉琨與祖逖，起舞雞鳴晨。", "雖有匡濟心，終爲樂禍人。", "我則異於是，潛光皖水濱。", "卜築司空原，北將天柱鄰。", "雪霽萬里月，雲開九江春。", "俟乎泰階平，然後託微身。", "傾家事金鼎，年貌可長新。", "所願得此道，終然保清真。", "弄景奔日馭，攀星戲河津。", "一隨王喬去，長年玉天賓。"]'),
('f73734e0-155a-449c-b02c-aef8d40f548a','上崔相百憂章','李白','唐','唐诗','tang','','["\u6cf0\u5c71", "\u60b2\u6124", "\u6292\u60c5"]','共公赫怒，天維中摧。',220,'全唐诗/poet.tang.8000.json','["共公赫怒，天維中摧。", "鯤鯨噴蕩，揚濤起雷。", "魚龍陷人，成此禍胎。", "火焚崑山，玉石相磓。", "仰希霖雨，灑寶炎煨。", "箭發石開，戈揮日迴。", "鄒衍慟哭，燕霜颯來。", "微誠不感，猶縶夏臺。", "蒼鷹搏攫，丹棘崔嵬。", "豪聖凋枯，王風傷哀。", "斯文未喪，東嶽豈頹。", "穆逃楚難，鄒脫吳災。", "見機苦遲，二公所咍。", "驥不驟進，麟何來哉。", "星離一門，草擲二孩。", "萬憤結習，憂從中催。", "金瑟玉壺，盡爲愁媒。", "舉酒太息，泣血盈桮。", "台星再朗，天綱重恢。", "屈法申恩，棄瑕取材。", "冶長非罪，尼父無猜。", "覆盆儻舉，應照寒灰。"]'),
('8936accd-7c40-42ed-aa10-8eeb2ff76c58','萬憤詞投魏郎中','李白','唐','唐诗','tang','','["\u611f\u6168", "\u6218\u4e89", "\u6124\u61d1"]','海水渤潏，人罹鯨鯢。',231,'全唐诗/poet.tang.8000.json','["海水渤潏，人罹鯨鯢。", "蓊胡沙而四塞，始滔天於燕齊。", "何六龍之浩蕩，遷白日於秦西。", "九土星分，嗷嗷棲棲。", "南冠君子，呼天而啼。", "戀高堂而掩泣，淚血地而成泥。", "獄戶春而不草，獨幽怨而沈迷。", "兄九江兮弟三峽，悲羽化之難齊。", "穆陵關北愁愛子，豫章天南隔老妻。", "一門骨肉散百草，遇難不復相提攜。", "樹榛拔桂，囚鸞寵雞。", "舜昔授禹，伯成耕犂。", "德自此衰，吾將安棲。", "好我者恤我，不好我者何忍臨危而相擠。", "子胥鴟夷，彭越醢醯。", "自古豪烈，胡爲此繄。", "蒼蒼之天，高乎視低。", "如其聽卑，脫我牢狴。", "儻辨美玉，君收白珪。"]'),
('f40d38b4-85f4-42cc-978d-da08bdca85fe','荆州賊平臨洞庭言懷作','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u7231\u56fd", "\u73b0\u5b9e", "\u6218\u4e89", "\u6124\u61d1"]','修蛇橫洞庭，吞象臨江島。',122,'全唐诗/poet.tang.8000.json','["修蛇橫洞庭，吞象臨江島。", "積骨成巴陵，遺言聞楚老。", "水窮三苗國，地窄三湘道。", "歲[晏]天崢嶸，時危人枯槁。", "思歸阻喪亂，去國傷懷抱。", "郢路方丘墟，章華亦傾倒。", "風悲猨嘯苦，木落鴻飛早。", "日隱西赤沙，月明東城草。", "關河望已絕，氛霧行當掃。", "長呌天可聞，吾將問蒼昊。"]'),
('021b5e5d-ccb6-4e86-aff0-a6796bceeca1','覽鏡書懷','李白','唐','唐诗','tang','','[]','得道無古今，失道還衰老。',48,'全唐诗/poet.tang.8000.json','["得道無古今，失道還衰老。", "自笑鏡中人，白髮如霜草。", "捫心空嘆息，問影何枯槁。", "桃李竟何言，終成南山皓。"]'),
('3d75235b-91c9-4e30-9500-df1989c5a0e7','田園言懷','李白','唐','唐诗','tang','','[]','賈誼三年謫，班超萬里侯。',24,'全唐诗/poet.tang.8000.json','["賈誼三年謫，班超萬里侯。", "何如牽白犢，飲水對清流。"]'),
('c6ca7bc9-ed9d-4165-b8fb-e014d55696eb','江南春懷','李白','唐','唐诗','tang','','["\u9752\u6625", "\u6625\u5929", "\u611f\u4f24"]','青春幾何時，黃鳥鳴不歇。',62,'全唐诗/poet.tang.8000.json','["青春幾何時，黃鳥鳴不歇。", "天涯失鄉路，江外老華髮。", "心飛秦塞雲，影滯楚關月。", "身世殊爛漫，田園久蕪沒。", "歲[晏]何所從，長歌謝金闕。"]'),
('71999aa1-55dd-4449-81b0-41f04686bf2e','聽蜀僧濬彈琴','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u97f3\u4e50", "\u4e94\u8a00\u5f8b\u8bd7"]','蜀僧抱綠綺，西下峨眉峰。',48,'全唐诗/poet.tang.8000.json','["蜀僧抱綠綺，西下峨眉峰。", "爲我一揮手，如聽萬壑松。", "客心洗流水，餘響入霜鐘。", "不覺碧山暮，秋雲暗幾重。"]'),
('0fe41dff-920c-48f6-9950-ee6dda12333e','魯東門觀刈蒲','李白','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u519c\u6c11"]','魯國寒事早，初霜刈渚蒲。',60,'全唐诗/poet.tang.8000.json','["魯國寒事早，初霜刈渚蒲。", "揮鐮若轉月，拂水生連珠。", "此草最可珍，何必貴龍鬚。", "織作玉牀席，欣承清夜娛。", "羅衣能再拂，不畏素塵蕪。"]'),
('45c9a460-8040-4c0c-aad2-336533d9de3d','詠鄰女東窗海石榴','李白','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','魯女東窗下，海榴世所稀。',60,'全唐诗/poet.tang.8000.json','["魯女東窗下，海榴世所稀。", "珊瑚映綠水，未足比光輝。", "清香隨風發，落日好鳥歸。", "願爲東南枝，低舉拂羅衣。", "無由共攀折，引領望金扉。"]'),
('583eb6c2-5b43-493c-a49a-ee1d2e3542ac','南軒松','李白','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u7406\u60f3", "\u6292\u6000", "\u548f\u7269"]','南軒有孤松，柯葉自綿冪。',48,'全唐诗/poet.tang.8000.json','["南軒有孤松，柯葉自綿冪。", "清風無閑時，瀟灑終日夕。", "陰生古苔綠，色染秋烟碧。", "何當凌雲霄，直上數千尺。"]'),
('d2f35c9d-a609-430a-ac00-50a1d775c272','詠山樽二首 一','李白','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u7ec4\u8bd7", "\u6292\u6000", "\u548f\u7269"]','蟠木不彫飾，且將斤斧疎。',48,'全唐诗/poet.tang.8000.json','["蟠木不彫飾，且將斤斧疎。", "樽成山岳勢，材是棟梁餘。", "外與金罍並，中涵玉醴虛。", "慙君垂拂拭，遂忝玳筵居。"]'),
('42ae28d7-25cb-46e2-bbfb-c69947664602','詠山樽二首 二','李白','唐','唐诗','tang','','[]','擁腫寒山木，嵌空成酒樽。',24,'全唐诗/poet.tang.8000.json','["擁腫寒山木，嵌空成酒樽。", "愧無江海量，偃蹇在君門。"]'),
('9aab6852-8e9c-489f-879d-23cadee8b26e','初出金門尋王侍御不遇詠壁上鸚鵡','李白','唐','唐诗','tang','','[]','落羽辭金殿，孤鳴咤繡衣。',24,'全唐诗/poet.tang.8000.json','["落羽辭金殿，孤鳴咤繡衣。", "能言終見棄，還向隴西飛。"]'),
('e6bf8732-b70d-4290-892e-2b5e19d1909f','紫藤樹','李白','唐','唐诗','tang','','[]','紫藤挂雲木，花蔓宜陽春。',24,'全唐诗/poet.tang.8000.json','["紫藤挂雲木，花蔓宜陽春。", "密葉隱歌鳥，香風留美人。"]'),
('33782dec-ab43-4b04-a83a-deb1c8eb2c94','觀放白鷹二首 一','李白','唐','唐诗','tang','','[]','八月邊風高，胡鷹白錦毛。',24,'全唐诗/poet.tang.8000.json','["八月邊風高，胡鷹白錦毛。", "孤飛一片雪，百里見秋毫。"]'),
('08cd7925-03d4-4983-8cfc-e3780f20f55f','觀放白鷹二首 二','李白','唐','唐诗','tang','','[]','寒冬十二月，蒼鷹八九毛。',28,'全唐诗/poet.tang.8000.json','["寒冬十二月，蒼鷹八九毛。", "寄言燕雀莫相啅，自有雲霄萬里高。"]'),
('f90a353d-12fb-4949-aa2d-70e5246d132e','觀博平王志安少府山水粉圖','李白','唐','唐诗','tang','','["\u6292\u6000", "\u601d\u4e61", "\u5199\u666f", "\u8c6a\u8fc8"]','粉壁爲空天，丹青狀江海。',56,'全唐诗/poet.tang.8000.json','["粉壁爲空天，丹青狀江海。", "遊雲不知歸，日見白鷗在。", "博平真人王志安，沈吟至此願挂冠。", "松溪石磴帶秋色，愁客思歸坐曉寒。"]'),
('867666e6-4d65-4122-b487-8103ab1e9035','題雍丘崔明府丹竈','李白','唐','唐诗','tang','','[]','美人爲政本忘機，服藥求仙事不違。',64,'全唐诗/poet.tang.8000.json','["美人爲政本忘機，服藥求仙事不違。", "葉縣已泥丹竈畢，瀛洲當伴赤松歸。", "先師有訣神將助，大聖無心火自飛。", "九轉但能生羽翼，雙鳧忽去定何依。"]'),
('ff97e4cd-746e-455f-8419-d57e058c03ad','觀元丹丘坐巫山屏風','李白','唐','唐诗','tang','','[]','昔遊三峽見巫山，見畫巫山宛相似。',144,'全唐诗/poet.tang.8000.json','["昔遊三峽見巫山，見畫巫山宛相似。", "疑是天邊十二峰，飛入君家彩屏裏。", "寒松蕭瑟如有聲，陽臺微茫如有情。", "錦衾瑤席何寂寂，楚王神女徒盈盈。", "高咫尺，如千里，翠屏丹崖燦如綺。", "蒼蒼遠樹圍荆門，歷歷行舟泛巴水。", "水石潺湲萬壑分，烟光草色俱氛氳。", "溪花笑日何年發，江客聽猨幾歲聞。", "使人對此心緬邈，疑入嵩丘夢綵雲。"]'),
('710f07bb-942c-4408-aec1-6927f7b96126','求崔山人百丈崖瀑布圖','李白','唐','唐诗','tang','','[]','百丈素崖裂，四山丹壁開。',72,'全唐诗/poet.tang.8000.json','["百丈素崖裂，四山丹壁開。", "龍潭中噴射，晝夜生風雷。", "但見瀑泉落，如潨雲漢來。", "聞君寫真圖，島嶼備縈迴。", "石黛刷幽草，曾青澤古苔。", "幽緘儻相傳，何必向天台。"]'),
('072f32eb-bb78-4d53-acd9-fcbbccbc62ac','見野草中有曰白頭翁者','李白','唐','唐诗','tang','','[]','醉入田家去，行歌荒野中。',48,'全唐诗/poet.tang.8000.json','["醉入田家去，行歌荒野中。", "如何青草裏，亦有白頭翁。", "折取對明鏡，宛將衰鬢同。", "微芳似相誚，留恨向東風。"]'),
('cf2b6733-cda9-4704-ae90-a012fc05dade','流夜郎題葵葉','李白','唐','唐诗','tang','','["\u6000\u4eba", "\u6292\u60c5", "\u601d\u4e61"]','慙君能衛足，嘆我遠移根。',24,'全唐诗/poet.tang.8000.json','["慙君能衛足，嘆我遠移根。", "白日如分照，還歸守故園。"]'),
('ccc5b149-cdce-4b5f-a4d4-4e0f31f200ea','塋禪師房觀山海圖','李白','唐','唐诗','tang','','[]','真僧閉精宇，滅跡含達觀。',120,'全唐诗/poet.tang.8000.json','["真僧閉精宇，滅跡含達觀。", "列嶂圖雲山，攢峰入霄漢。", "丹崖森在目，清晝疑卷幔。", "蓬壺來軒窗，瀛海入几案。", "煙濤爭噴薄，島嶼相凌亂。", "征帆飄空中，瀑水灑天半。", "崢嶸若可陟，想像徒盈嘆。", "杳與真心冥，遂諧靜者翫。", "如登赤城裏，揭步滄洲畔。", "即事能娛人，從茲得消散。"]'),
('f8055ae5-be41-44f0-9148-fa5f27dd5d1d','白鷺鶿','李白','唐','唐诗','tang','','[]','白鷺下秋水，孤飛如墜霜。',24,'全唐诗/poet.tang.8000.json','["白鷺下秋水，孤飛如墜霜。", "心閑且未去，獨立沙洲傍。"]'),
('3ff70288-0c55-419f-9e44-34fe40cce41e','詠槿','李白','唐','唐诗','tang','','["\u548f\u7269", "\u548f\u7269\u8bd7", "\u82b1", "\u8d5e\u7f8e", "\u5199\u82b1"]','園花笑芳年，池草豔春色。',48,'全唐诗/poet.tang.8000.json','["園花笑芳年，池草豔春色。", "猶不如槿花，嬋娟玉階側。", "芬榮何夭促，零落在瞬息。", "豈若瓊樹枝，終歲長翕赩。"]'),
('963bf805-633e-4fab-9029-1c379c9e71e9','詠桂','李白','唐','唐诗','tang','','["\u5199\u82b1", "\u82b1", "\u8d5e\u7f8e"]','世人種桃李，皆在金張門。',60,'全唐诗/poet.tang.8000.json','["世人種桃李，皆在金張門。", "攀折爭捷徑，及此春風暄。", "一朝天霜下，榮耀難久存。", "安知南山桂，綠葉垂芳根。", "清陰亦可託，何惜樹君園。"]'),
('764f45de-ea78-4680-8930-b8dee0fba520','白胡桃','李白','唐','唐诗','tang','','[]','紅羅袖裏分明見，白玉盤中看却無。',32,'全唐诗/poet.tang.8000.json','["紅羅袖裏分明見，白玉盤中看却無。", "疑是老僧休念誦，腕前推下水晶珠。"]'),
('35af2a9a-f7c6-4372-8403-e7e6952703ed','巫山枕障','李白','唐','唐诗','tang','','[]','巫山枕障畫高丘，白帝城邊樹色秋。',32,'全唐诗/poet.tang.8000.json','["巫山枕障畫高丘，白帝城邊樹色秋。", "朝雲夜入無行處，巴水橫天更不流。"]'),
('d2f5bf4b-22c5-46ec-90ed-93bb8ce8d1cf','南奔書懷','李白','唐','唐诗','tang','','[]','遙夜何漫漫，空歌白石爛。',228,'全唐诗/poet.tang.8000.json','["遙夜何漫漫，空歌白石爛。", "甯戚未匡齊，陳平終佐漢。", "攙搶掃河洛，直割鴻溝半。", "歷數方未遷，雲雷屢多難。", "天人秉旄鉞，虎竹光藩翰。", "侍筆黃金臺，傳觴青玉案。", "不因秋風起，自有思歸歎。", "主將動讒疑，王師忽離叛。", "自來白沙上，鼓譟丹陽岸。", "賓御如浮雲，從風各消散。", "舟中指可掬，城上骸爭爨。", "草草出近關，行行昧前算。", "南奔劇星火，北寇無涯畔。", "顧乏七寶鞭，留連道傍翫。", "太白夜食昴，長虹日中貫。", "秦趙興天兵，茫茫九州亂。", "感遇明主恩，頗高祖逖言。", "過江誓流水，志在清中原。", "拔劍擊前柱，悲歌難重論。"]'),
('1087aac3-dd31-4943-8fd4-d65979838af0','題隨州紫陽先生壁','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','神農好長生，風俗久已成。',96,'全唐诗/poet.tang.8000.json','["神農好長生，風俗久已成。", "復聞紫陽客，早署丹臺名。", "喘息餐妙氣，步虛吟真聲。", "道與古仙合，心將元化幷。", "樓疑出蓬海，鶴似飛玉京。", "松雪窗外曉，池水階下明。", "忽耽笙歌樂，頗失軒冕情。", "終願惠金液，提攜凌太清。"]'),
('038c9285-f36b-41dc-85a6-c82fc531d5af','題元丹丘山居','李白','唐','唐诗','tang','','["\u5411\u5f80", "\u7530\u56ed", "\u751f\u6d3b", "\u9690\u5c45"]','故人棲東山，自愛丘壑美。',48,'全唐诗/poet.tang.8000.json','["故人棲東山，自愛丘壑美。", "青春臥空林，白日猶不起。", "松風清襟袖，石潭洗心耳。", "羨君無紛喧，高枕碧霞裏。"]'),
('74334c08-0ddd-40f0-b34b-1689da32b1cf','題元丹丘潁陽山居','李白','唐','唐诗','tang','','[]','仙遊渡潁水，訪隱同元君。',96,'全唐诗/poet.tang.8000.json','["仙遊渡潁水，訪隱同元君。", "忽遺蒼生望，獨與洪崖羣。", "卜地初晦跡，興言且成文。", "却顧北山斷，前瞻南嶺分。", "遙通汝海月，不隔嵩丘雲。", "之子合逸趣，而我欽清芬。", "舉跡倚松石，談笑迷朝曛。", "益願狎青鳥，拂衣棲江濆。"]'),
('ad860d8f-eff5-4789-8897-879dea7b8d11','題瓜州新河餞族叔舍人賁','李白','唐','唐诗','tang','','[]','齊公鑿新河，萬古流不絕。',120,'全唐诗/poet.tang.8000.json','["齊公鑿新河，萬古流不絕。", "豐功利生人，天地同朽滅。", "兩橋對雙閣，芳樹有行列。", "愛此如甘棠，誰云敢攀折。", "吳關倚此固，天險自茲設。", "海水落斗門，湖平見沙汭。", "我行送季父，弭櫂徒流悅。", "楊花滿江來，疑是龍山雪。", "惜此林下興，愴爲山陽別。", "瞻望清路塵，歸來空寂滅。"]'),
('0aca73ac-71ff-414b-922c-c5d58c4fc17f','洗脚亭','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u9001\u522b"]','白道向姑熟，洪亭臨道傍。',60,'全唐诗/poet.tang.8000.json','["白道向姑熟，洪亭臨道傍。", "前有昔時井，下有五丈牀。", "樵女洗素足，行人歇金裝。", "西望白鷺洲，蘆花似朝霜。", "送君此時去，回首淚成行。"]'),
('8b4ab666-f675-4484-a3de-6f2d6f6d6cff','勞勞亭','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u9001\u522b", "\u501f\u666f\u6292\u60c5", "\u79bb\u522b"]','天下傷心處，勞勞送客亭。',24,'全唐诗/poet.tang.8000.json','["天下傷心處，勞勞送客亭。", "春風知別苦，不遣柳條青。"]'),
('f29fbd12-b739-4b55-8ed3-51f42e2281e7','題金陵王處士水亭','李白','唐','唐诗','tang','','[]','王子耽玄言，賢豪多在門。',84,'全唐诗/poet.tang.8000.json','["王子耽玄言，賢豪多在門。", "好鵝尋道士，愛竹嘯名園。", "樹色老荒苑，池光蕩華軒。", "此堂見明月，更憶陸平原。", "埽拭青玉簟，爲余置金尊。", "醉罷欲歸去，花枝宿鳥喧。", "何時復來此，再得洗囂煩。"]'),
('d25b546c-88d0-4a92-9eb7-42f5f99d6160','題嵩山逸人元丹丘山居','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u9690\u5c45"]','家本紫雲山，道風未淪落。',168,'全唐诗/poet.tang.8000.json','["家本紫雲山，道風未淪落。", "沈懷丹丘志，沖賞歸寂寞。", "朅來遊閩荒，捫涉窮禹鑿。", "夤緣泛潮海，偃蹇陟廬霍。", "憑雷躡天窗，弄影憩霞閣。", "且欣登眺美，頗愜隱淪諾。", "三山曠幽期，四岳聊所託。", "故人契嵩穎，高義炳丹雘。", "滅跡遺紛囂，終言本峰壑。", "自矜林湍好，不羨朝市樂。", "偶與真意幷，頓覺世情薄。", "爾能折芳桂，吾亦採蘭若。", "拙妻好乘鸞，嬌女愛飛鶴。", "提攜訪神仙，從此鍊金藥。"]'),
('9d8603cf-3b29-4816-86c4-00e46a3601c1','題江夏修靜寺','李白','唐','唐诗','tang','','[]','我家北海宅，作寺南江濱。',48,'全唐诗/poet.tang.8000.json','["我家北海宅，作寺南江濱。", "空庭無玉樹，高殿坐幽人。", "書帶留青草，琴堂冪素塵。", "平生種桃李，寂滅不成春。"]'),
('dd948956-3b61-4faf-9a30-70ae35154f8e','題宛溪館','李白','唐','唐诗','tang','','[]','吾憐宛溪好，百尺照心明。',48,'全唐诗/poet.tang.8000.json','["吾憐宛溪好，百尺照心明。", "何謝新安水，千尋見底清。", "白沙留月色，綠竹助秋聲。", "却笑嚴湍上，于今獨擅名。"]'),
('d9aeda4e-b29a-48a7-b9c9-6ed24f940cca','題東谿公幽居','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','杜陵賢人清且廉，東溪卜築歲將淹。',64,'全唐诗/poet.tang.8000.json','["杜陵賢人清且廉，東溪卜築歲將淹。", "宅近青山同謝朓，門垂碧柳似陶潛。", "好鳥迎春歌後院，飛花送酒舞前簷。", "客到但知留一醉，盤中秪有水晶鹽。"]'),
('87cd9170-3349-46b0-925a-86cf2a31ad71','嘲魯儒','李白','唐','唐诗','tang','','[]','魯叟談五經，白髮死章句。',84,'全唐诗/poet.tang.8000.json','["魯叟談五經，白髮死章句。", "問以經濟策，茫如墜煙霧。", "足著遠遊履，首戴方山巾。", "緩步從直道，未行先起塵。", "秦家丞相府，不重褒衣人。", "君非叔孫通，與我本殊倫。", "時事且未達，歸耕汶水濱。"]'),
('bd0ce687-7545-4e77-addc-0badaf6fb9ec','懼讒','李白','唐','唐诗','tang','','[]','二桃殺三士，詎假劒如霜。',60,'全唐诗/poet.tang.8000.json','["二桃殺三士，詎假劒如霜。", "衆女妬蛾眉，雙花競春芳。", "魏姝信鄭褏，掩袂對懷王。", "一惑巧言子，朱顏成死傷。", "行將泣團扇，戚戚愁人腸。"]'),
('a511cd4d-868d-4b5e-b5e5-cd1529235db2','觀獵','李白','唐','唐诗','tang','','[]','太守耀清威，乘閑弄晚暉。',48,'全唐诗/poet.tang.8000.json','["太守耀清威，乘閑弄晚暉。", "江沙橫獵騎，山火遶行圍。", "箭逐雲鴻落，鷹隨月兔飛。", "不知白日暮，歡賞夜方歸。"]'),
('19caae1a-96be-4c91-8374-126bbca1df8d','觀胡人吹笛','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u97f3\u4e50"]','胡人吹玉笛，一半是秦聲。',48,'全唐诗/poet.tang.8000.json','["胡人吹玉笛，一半是秦聲。", "十月吳山曉，梅花落敬亭。", "愁聞出塞曲，淚滿逐臣纓。", "却望長安道，空懷戀主情。"]'),
('0e98fc4a-b0cd-4259-be02-efd617286a5d','軍行','李白','唐','唐诗','tang','','[]','騮馬新跨白玉鞍，戰罷沙場月色寒。',32,'全唐诗/poet.tang.8000.json','["騮馬新跨白玉鞍，戰罷沙場月色寒。", "城頭鐵鼓聲猶震，匣裏金刀血未乾。"]'),
('32fdc25f-0345-4675-a120-5ba61540eae0','從軍行','李白','唐','唐诗','tang','','["\u6218\u4e89", "\u8fb9\u585e", "\u76f8\u548c\u6b4c\u8f9e"]','百戰沙場碎鐵衣，城南已合數重圍。',32,'全唐诗/poet.tang.8000.json','["百戰沙場碎鐵衣，城南已合數重圍。", "突營射殺呼延將，獨領殘兵千騎歸。"]'),
('f9d89382-9b46-4e84-89d2-2b11942f0ed9','平虜將軍妻','李白','唐','唐诗','tang','','[]','平虜將軍婦，入門二十年。',48,'全唐诗/poet.tang.8000.json','["平虜將軍婦，入門二十年。", "君心自有悅，妾寵豈能專。", "出解牀前帳，行吟道上篇。", "古人不唾井，莫忘昔纏綿。"]'),
('4838bc46-446b-44cb-8296-29eed12cf343','春夜洛城聞笛','李白','唐','唐诗','tang','','["\u97f3\u4e50", "\u601d\u4e61", "\u521d\u4e2d\u53e4\u8bd7", "\u4e03\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5916)"]','誰家玉笛暗飛聲，散入春風滿洛城。',32,'全唐诗/poet.tang.8000.json','["誰家玉笛暗飛聲，散入春風滿洛城。", "此夜曲中聞折柳，何人不起故園情。"]'),
('61347ec6-8ecb-4d4f-b4bc-a38bafdd2bb4','嵩山採菖蒲者','李白','唐','唐诗','tang','','[]','神仙多古貌，雙耳下垂肩。',60,'全唐诗/poet.tang.8000.json','["神仙多古貌，雙耳下垂肩。", "嵩嶽逢漢武，疑是九疑仙。", "我來採菖蒲，服食可延年。", "言終忽不見，滅影入雲烟。", "喻帝竟莫悟，終歸茂陵田。"]'),
('96890538-3448-4e3a-8923-333c8198cbdd','金陵聽韓侍御吹笛','李白','唐','唐诗','tang','','[]','韓公吹玉笛，倜儻流英音。',48,'全唐诗/poet.tang.8000.json','["韓公吹玉笛，倜儻流英音。", "風吹繞鍾山，萬壑皆龍吟。", "王子停鳳管，師襄掩瑤琴。", "餘韻度江去，天涯安可尋。"]'),
('8404ac71-5739-4644-b9ff-b5f7ae31806b','流夜郎聞酺不預','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u4f24\u6000"]','北闕聖人歌太康，南冠君子竄遐荒。',32,'全唐诗/poet.tang.8000.json','["北闕聖人歌太康，南冠君子竄遐荒。", "漢酺聞奏鈞天樂，願得風吹到夜郎。"]'),
('deffd343-83b3-4a8f-9c8e-296b88f888d2','放後遇恩不霑','李白','唐','唐诗','tang','','["\u4e50\u89c2", "\u6292\u60c5", "\u8c6a\u8fc8"]','天作雲與雷，霈然德澤開。',48,'全唐诗/poet.tang.8000.json','["天作雲與雷，霈然德澤開。", "東風日本至，白雉越裳來。", "獨棄長沙國，三年未許回。", "何時入宣室，更問洛陽才。"]'),
('df7e8d1d-50ab-40be-8e0c-f2b082fe6e7c','宣城見杜鵑花','李白','唐','唐诗','tang','','["\u601d\u4e61"]','蜀國曾聞子規鳥，宣城還見杜鵑花。',32,'全唐诗/poet.tang.8000.json','["蜀國曾聞子規鳥，宣城還見杜鵑花。", "一呌一迴腸一斷，三春三月憶三巴。"]'),
('a8f4daad-aab2-4c61-ad45-a261e6b0735d','白田馬上聞鶯','李白','唐','唐诗','tang','','["\u6000\u624d\u4e0d\u9047", "\u7f81\u65c5", "\u590f\u5929", "\u5199\u666f"]','黃鸝啄紫椹，五月鳴桑枝。',48,'全唐诗/poet.tang.8000.json','["黃鸝啄紫椹，五月鳴桑枝。", "我行不記日，誤作陽春時。", "蠶老客未歸，白田已繰絲。", "驅馬又前去，捫心空自悲。"]'),
('05ab8907-1e1b-4f9b-932f-5ca1444adc1f','三五七言','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u6292\u60c5", "\u79cb\u5929", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u7231\u60c5", "\u5b8b\u8bcd\u4e09\u767e\u9996"]','秋風清，秋月明。',36,'全唐诗/poet.tang.8000.json','["秋風清，秋月明。", "落葉聚還散，寒鴉棲復驚。", "相思相見知何日，此時此夜難爲情。"]'),
('54435974-70d8-48c1-bbc6-21344c4d6b20','雜詩','李白','唐','唐诗','tang','','[]','白日與明月，晝夜尚不閑。',72,'全唐诗/poet.tang.8000.json','["白日與明月，晝夜尚不閑。", "況爾悠悠人，安得久世間。", "傳聞海水上，乃有蓬萊山。", "玉樹生綠葉，靈仙每登攀。", "一食駐玄髮，再食留紅顏。", "吾欲從此去，去之無時還。"]'),
('3dd9396f-141b-4899-a1f1-1d3bcd890d3c','寄遠十一首 一','李白','唐','唐诗','tang','','[]','三鳥別王母，銜書來見過。',72,'全唐诗/poet.tang.8000.json','["三鳥別王母，銜書來見過。", "腸斷若剪弦，其如愁思何。", "遙知玉窗裏，纖手弄雲和。", "奏曲有深意，青松交女蘿。", "寫水山井中，同泉豈殊波。", "秦心與楚恨，皎皎爲誰多。"]'),
('660a2210-b61c-4742-8bc9-a71fa887b61e','寄遠十一首 二','李白','唐','唐诗','tang','','[]','青樓何所在，乃在碧雲中。',48,'全唐诗/poet.tang.8000.json','["青樓何所在，乃在碧雲中。", "寶鏡挂秋水，羅衣輕春風。", "新妝坐落日，悵望金屏空。", "念此送短書，願因雙飛鴻。"]'),
('fe47df60-2cf0-410a-b638-e976c5c1b368','寄遠十一首 三','李白','唐','唐诗','tang','','[]','本作一行書，殷勤道相憶。',84,'全唐诗/poet.tang.8000.json','["本作一行書，殷勤道相憶。", "一行復一行，滿紙情何極。", "瑤臺有黃鶴，爲報青樓人。", "朱顏凋落盡，白髮一何新。", "自知未應還，離居經三春。", "桃李今若爲，當窗發光彩。", "莫使香風飄，留與紅芳待。"]'),
('20dc3129-f969-4f7a-8eb2-d323ea564470','寄遠十一首 四','李白','唐','唐诗','tang','','[]','玉[筯]落春鏡，坐愁湖陽水。',62,'全唐诗/poet.tang.8000.json','["玉[筯]落春鏡，坐愁湖陽水。", "聞與陰麗華，風煙接鄰里。", "青春已復過，白日忽相催。", "但恐荷花晚，令人意已摧。", "相思不惜夢，日夜向陽臺。"]'),
('da621f92-7f9f-46c5-a83f-6f80153a8fea','寄遠十一首 五','李白','唐','唐诗','tang','','[]','遠憶巫山陽，花明淥江暖。',48,'全唐诗/poet.tang.8000.json','["遠憶巫山陽，花明淥江暖。", "躊躇未得往，淚向南雲滿。", "春風復無情，吹我夢魂斷。", "不見眼中人，天長音信短。"]'),
('d0c3d026-26c4-4597-939a-b3e18d91cc05','寄遠十一首 六','李白','唐','唐诗','tang','','["\u9ec4\u6cb3"]','陽臺隔楚水，春草生黃河。',48,'全唐诗/poet.tang.8000.json','["陽臺隔楚水，春草生黃河。", "相思無日夜，浩蕩若流波。", "流波向海去，欲見終無因。", "遙將一點淚，遠寄如花人。"]'),
('90cfd7af-86b5-4c1d-9aa2-7a1bbed6ade5','寄遠十一首 七','李白','唐','唐诗','tang','','[]','妾在舂陵東，君居漢江島。',60,'全唐诗/poet.tang.8000.json','["妾在舂陵東，君居漢江島。", "一日望花光，往來成白道。", "一爲雲雨別，此地生秋草。", "秋草秋蛾飛，相思愁落暉。", "何由一相見，滅燭解羅衣。"]'),
('d612da26-bd76-45f8-b159-77c1c8d734af','寄遠十一首 八','李白','唐','唐诗','tang','','[]','憶昨東園桃李紅碧枝，與君此時初別離。',90,'全唐诗/poet.tang.8000.json','["憶昨東園桃李紅碧枝，與君此時初別離。", "金瓶落井無消息，令人行歎復坐思。", "坐思行歎成楚越，春風玉顏畏銷歇。", "碧窗紛紛下落花，青樓寂寂空明月。", "兩不見，但相思，空留錦字表心素，至今緘愁不忍窺。"]'),
('0904fc8b-9caa-4976-aa52-40ea67073a4a','寄遠十一首 九','李白','唐','唐诗','tang','','[]','長短春草綠，緣階如有情。',48,'全唐诗/poet.tang.8000.json','["長短春草綠，緣階如有情。", "卷施心獨苦，抽却死還生。", "覩物知妾意，希君種後庭。", "閑時當採掇，念此莫相輕。"]'),
('6ffd46bb-4dcf-451d-9b4d-9a41578572ba','寄遠十一首 十','李白','唐','唐诗','tang','','[]','魯縞如玉霜，筆題月氏書。',72,'全唐诗/poet.tang.8000.json','["魯縞如玉霜，筆題月氏書。", "寄書白鸚鵡，西海慰離居。", "行數雖不多，字字有委曲。", "天末如見之，開緘淚相續。", "淚盡恨轉深，千里同此心。", "相思千萬里，一書值千金。"]'),
('1c2f7e2e-8dde-49a9-ab92-91653000dc37','寄遠十一首 十一','李白','唐','唐诗','tang','','[]','愛君芙蓉嬋娟之豔色，色可餐兮難再得。',128,'全唐诗/poet.tang.8000.json','["愛君芙蓉嬋娟之豔色，色可餐兮難再得。", "憐君冰玉清逈之明心，情不極兮意已深。", "朝共琅玕之綺食，夜同鴛鴦之錦衾。", "恩情婉孌忽爲別，使人莫錯亂愁心。", "亂愁心，涕如雪，寒燈厭夢魂欲絕。", "覺來相思生白髮，盈盈漢水若可越。", "可惜凌波步羅韤，美人美人兮歸去來，莫作朝雲暮雨兮飛陽臺。"]'),
('a5950085-e09e-4d68-b199-e81bb0d25633','長信宮','李白','唐','唐诗','tang','','[]','月皎昭陽殿，霜清長信宮。',48,'全唐诗/poet.tang.8000.json','["月皎昭陽殿，霜清長信宮。", "天行乘玉輦，飛燕與君同。", "別有歡娛處，承恩樂未窮。", "誰憐團扇妾，獨坐怨秋風。"]'),
('f89038d8-0672-4589-8c23-2d75940047cd','長門怨二首 一','李白','唐','唐诗','tang','','[]','天迴北斗挂西樓，金屋無人螢火流。',32,'全唐诗/poet.tang.8000.json','["天迴北斗挂西樓，金屋無人螢火流。", "月光欲到長門殿，別作深宮一段愁。"]'),
('5ad2c3b5-e54b-4e2a-9261-e258ef34a686','長門怨二首 二','李白','唐','唐诗','tang','','[]','桂殿長愁不記春，黃金四屋起秋塵。',32,'全唐诗/poet.tang.8000.json','["桂殿長愁不記春，黃金四屋起秋塵。", "夜懸明鏡青天上，獨照長門宮裏人。"]'),
('c83b82eb-93fa-4a3d-af84-616a6992b0f3','春怨','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u5987\u5973", "\u6625\u5929", "\u95fa\u6028"]','白馬金羈遼海東，羅帷繡被臥春風。',32,'全唐诗/poet.tang.8000.json','["白馬金羈遼海東，羅帷繡被臥春風。", "落月低軒窺燭盡，飛花入戶笑牀空。"]'),
('9840849f-4221-4fd0-8e95-c0bb33d3a956','代贈遠','李白','唐','唐诗','tang','','[]','妾本洛陽人，狂夫幽燕客。',132,'全唐诗/poet.tang.8000.json','["妾本洛陽人，狂夫幽燕客。", "渴飲易水波，由來多感激。", "胡馬西北馳，香騣搖綠絲。", "鳴鞭從此去，逐虜蕩邊陲。", "昔去有好言，不言久離別。", "燕支多美女，走馬輕風雪。", "見此不記人，恩情雲雨絕。", "啼流玉筯盡，坐恨金閨切。", "織錦作短書，腸隨回文結。", "相思欲有寄，恐君不見察。", "焚之揚其灰，手跡自此滅。"]'),
('4753cb69-c4e4-454f-b86d-828d244405c5','陌上贈美人','李白','唐','唐诗','tang','','["\u7231\u60c5", "\u5c11\u5e74", "\u5973\u5b50"]','駿馬驕行踏落花，垂鞭直拂五雲車。',32,'全唐诗/poet.tang.8000.json','["駿馬驕行踏落花，垂鞭直拂五雲車。", "美人一笑褰珠箔，遙指紅樓是妾家。"]'),
('03e17c9d-eaa8-41bd-8532-03b03f509941','閨情','李白','唐','唐诗','tang','','[]','流水去絕國，浮雲辭故關。',84,'全唐诗/poet.tang.8000.json','["流水去絕國，浮雲辭故關。", "水或戀前浦，雲猶歸舊山。", "恨君流沙去，棄妾漁陽間。", "玉筯夜垂流，雙雙落朱顏。", "黃鳥坐相悲，綠楊誰更攀。", "織錦心草草，挑燈淚斑斑。", "窺鏡不自識，況乃狂夫還。"]'),
('cfc78ce7-25e1-4171-91fd-879df8e705bc','代別情人','李白','唐','唐诗','tang','','["\u7231\u60c5", "\u56de\u5fc6"]','清水本不動，桃花發岸傍。',108,'全唐诗/poet.tang.8000.json','["清水本不動，桃花發岸傍。", "桃花弄水色，波蕩搖春光。", "我悅子容豔，子傾我文章。", "風吹綠琴去，曲度紫鴛鴦。", "昔作一水魚，今成兩枝鳥。", "哀哀長雞鳴，夜夜達五曉。", "起折相思樹，歸贈知寸心。", "覆水不可收，行雲難重尋。", "天涯有度鳥，莫絕瑤華音。"]'),
('fcd315fe-e269-45bc-ae28-ed1a7b9ede04','代秋情','李白','唐','唐诗','tang','','["\u5199\u666f", "\u6292\u60c5", "\u79cb\u5929", "\u60b2\u4f24", "\u79bb\u522b"]','幾日相別離，門前生穭葵。',48,'全唐诗/poet.tang.8000.json','["幾日相別離，門前生穭葵。", "寒蟬聒梧桐，日夕長鳴悲。", "白露濕螢火，清霜凌兔絲。", "空掩紫羅袂，長啼無盡時。"]'),
('e564d728-17e6-40e0-8e90-4607f683345f','對酒','李白','唐','唐诗','tang','','[]','蒲萄酒，金叵羅，吳姬十五細馬馱。',48,'全唐诗/poet.tang.8000.json','["蒲萄酒，金叵羅，吳姬十五細馬馱。", "青黛畫眉紅錦靴，道字不正嬌唱歌。", "玳瑁筵中懷裏醉，芙蓉帳底奈君何。"]'),
('0a532137-253d-4ba7-bb5b-4f7b929171ac','怨情','李白','唐','唐诗','tang','','[]','新人如花雖可寵，故人似玉由來重。',64,'全唐诗/poet.tang.8000.json','["新人如花雖可寵，故人似玉由來重。", "花性飄揚不自持，玉心皎潔終不移。", "故人昔新今尚故，還見新人有故時。", "請看陳后黃金屋，寂寂珠簾生網絲。"]'),
('784b5a89-8c57-4d96-91e6-c5adad655e99','湖邊採蓮婦','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u5987\u5973", "\u5199\u4eba\u8bd7"]','小姑織白紵，未解將人語。',48,'全唐诗/poet.tang.8000.json','["小姑織白紵，未解將人語。", "大嫂採芙蓉，溪湖千萬重。", "長兄行不在，莫使外人逢。", "願學秋胡婦，貞心比古松。"]'),
('22e72306-f41c-4621-a925-83bab7f9d76e','怨情','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u7edd\u53e5", "\u5973\u5b50"]','美人捲珠簾，深坐顰蛾眉。',24,'全唐诗/poet.tang.8000.json','["美人捲珠簾，深坐顰蛾眉。", "但見淚痕濕，不知心恨誰。"]'),
('3c5e9539-ad36-48ff-87ac-3b5568434b55','代寄情楚詞體','李白','唐','唐诗','tang','','[]','君不來兮，徒蓄怨積思而孤吟。',151,'全唐诗/poet.tang.8000.json','["君不來兮，徒蓄怨積思而孤吟。", "雲陽一去已遠，隔巫山綠水之沈沈。", "留餘香兮染繡被，夜欲寢兮愁人心。", "朝馳余馬於青樓，怳若空而夷猶。", "浮雲深兮不得語，却惆悵而懷憂。", "使青鳥兮銜書，恨獨宿兮傷離居。", "何無情而雨絕，夢雖往而交疎。", "橫流涕而長嗟，折芳洲之瑤華。", "送飛鳥以極目，怨夕陽之西斜。", "願爲連根同死之秋草，不作飛空之落花。"]'),
('e13e252b-786b-46fd-bf7e-495708f63b57','學古思邊','李白','唐','唐诗','tang','','[]','銜悲上隴首，腸斷不見君。',108,'全唐诗/poet.tang.8000.json','["銜悲上隴首，腸斷不見君。", "流水若有情，幽哀從此分。", "蒼茫愁邊色，惆悵落日曛。", "山外接遠天，天際復有雲。", "白雁從中來，飛鳴苦難聞。", "足繫一書札，寄言難離羣。", "離羣心斷絕，十見花成雪。", "胡地無春暉，征人行不歸。", "相思杳如夢，珠淚濕羅衣。"]'),
('da2cf966-4604-454f-9297-b7acd57a677a','思邊','李白','唐','唐诗','tang','','[]','去年何時君別妾，南園綠草飛蝴蝶。',48,'全唐诗/poet.tang.8000.json','["去年何時君別妾，南園綠草飛蝴蝶。", "今歲何時妾憶君，西山白雪暗晴雲。", "玉關去此三千里，欲寄音書那可聞。"]'),
('6c4e1236-ae4e-40dd-9790-2183767e57ee','口號吳王美人半醉','李白','唐','唐诗','tang','','["\u897f\u65bd", "\u5199\u4eba", "\u5199\u4eba\u8bd7", "\u501f\u53e4\u8bbd\u4eca", "\u793e\u4f1a", "\u8bbd\u523a"]','風動荷花水殿香，姑蘇臺上宴吳王。',32,'全唐诗/poet.tang.8000.json','["風動荷花水殿香，姑蘇臺上宴吳王。", "西施醉舞嬌無力，笑倚東窗白玉牀。"]'),
('88ae4b43-a036-4895-bfd8-7a1f741ced8e','代美人愁鏡二首 一','李白','唐','唐诗','tang','','[]','明明金鵲鏡，了了玉臺前。',48,'全唐诗/poet.tang.8000.json','["明明金鵲鏡，了了玉臺前。", "拂拭交冰月，光輝何清圓。", "紅顏老昨日，白髮多去年。", "鉛粉坐相誤，照來空淒然。"]'),
('441198ac-3221-4f13-b2d2-6c5f5c755333','代美人愁鏡二首 二','李白','唐','唐诗','tang','','[]','美人贈此盤龍之寶鏡，燭我金縷之羅衣。',82,'全唐诗/poet.tang.8000.json','["美人贈此盤龍之寶鏡，燭我金縷之羅衣。", "時將紅袖拂明月，爲惜普照之餘暉。", "影中金鵲飛不滅，臺下青鸞思獨絕。", "藳砧一別若箭弦，去有日，來無年。", "狂風吹却妾心斷，玉筯幷墮菱花前。"]'),
('1f12f256-2436-48a6-bbe2-58e47c9b7cb4','贈段七娘','李白','唐','唐诗','tang','','[]','羅韤凌波生網塵，那能得計訪情親。',32,'全唐诗/poet.tang.8000.json','["羅韤凌波生網塵，那能得計訪情親。", "千杯綠酒何辭醉，一面紅妝惱殺人。"]'),
('7d7454d0-5261-48f8-b97b-b68bdc4b03a1','別內赴徵三首 一','李白','唐','唐诗','tang','','[]','王命三徵去未還，明朝離別出吳關。',32,'全唐诗/poet.tang.8000.json','["王命三徵去未還，明朝離別出吳關。", "白玉高樓看不見，相思須上望夫山。"]'),
('8ca2f34d-ed6a-40ee-8f75-b74e4e5ccf39','別內赴徵三首 二','李白','唐','唐诗','tang','','[]','出門妻子強牽衣，問我西行幾日歸。',32,'全唐诗/poet.tang.8000.json','["出門妻子強牽衣，問我西行幾日歸。", "歸時儻佩黃金印，莫學蘇秦不下機。"]'),
('1c89e422-d326-433c-b9e8-d7d8be805866','別內赴徵三首 三','李白','唐','唐诗','tang','','[]','翡翠爲樓金作梯，誰人獨宿倚門啼。',32,'全唐诗/poet.tang.8000.json','["翡翠爲樓金作梯，誰人獨宿倚門啼。", "夜坐寒燈連曉月，行行淚盡楚關西。"]'),
('e8900ac3-78df-4ace-a19c-4d69aacc74e6','秋浦寄內','李白','唐','唐诗','tang','','["\u6000\u4eba", "\u6292\u60c5", "\u601d\u4e61", "\u6101\u82e6"]','我今尋陽去，辭家千里餘。',96,'全唐诗/poet.tang.8000.json','["我今尋陽去，辭家千里餘。", "結荷倦水宿，却寄大雷書。", "雖不同辛苦，愴離各自居。", "我自入秋浦，三年北信疎。", "紅顏愁落盡，白髮不能除。", "有客自梁苑，手攜五色魚。", "開魚得錦字，歸問我何如。", "江山雖道阻，意合不爲殊。"]'),
('6a78794b-8968-4fd0-9780-d10e7066ff9e','自代內贈','李白','唐','唐诗','tang','','[]','寶刀截流水，無有斷絕時。',180,'全唐诗/poet.tang.8000.json','["寶刀截流水，無有斷絕時。", "妾意逐君行，纏綿亦如之。", "別來門前草，秋巷春轉碧。", "埽盡更還生，萋萋滿行跡。", "鳴鳳始相得，雄驚雌各飛。", "遊雲落何山，一往不見歸。", "估客發大樓，知君在秋浦。", "梁苑空錦衾，陽臺夢行雨。", "妾家三作相，失勢去西秦。", "猶有舊歌管，淒清聞四鄰。", "曲度入紫雲，啼無眼中人。", "妾似井底桃，開花向誰笑。", "君如天上月，不肯一迴照。", "窺鏡不自識，別多憔悴深。", "安得秦吉了，爲人道寸心。"]'),
('2511ca31-bf64-4c30-b4ee-7d4cfa5476d9','秋浦感主人歸燕寄內','李白','唐','唐诗','tang','','["\u7f81\u65c5", "\u6292\u6000", "\u79cb\u5929", "\u601d\u4e61"]','霜凋楚關木，始知殺氣嚴。',84,'全唐诗/poet.tang.8000.json','["霜凋楚關木，始知殺氣嚴。", "寥寥金天廓，婉婉綠紅潛。", "胡燕別主人，雙雙語前簷。", "三飛四迴顧，欲去復相瞻。", "豈不戀華屋，終然謝珠簾。", "我不及此鳥，遠行歲已淹。", "寄書道中歎，淚下不能緘。"]'),
('fb13388b-3d3a-4104-8687-5948a47849a1','送內尋廬山女道士李騰空二首 一','李白','唐','唐诗','tang','','["\u5e90\u5c71"]','君尋騰空子，應到碧山家。',36,'全唐诗/poet.tang.8000.json','["君尋騰空子，應到碧山家。", "水舂雲母確，風埽石楠花。", "若愛幽居好，相邀弄紫霞。"]'),
('e581a851-f222-4cce-8a41-f194e30cf044','送內尋廬山女道士李騰空二首 二','李白','唐','唐诗','tang','','["\u5e90\u5c71"]','多君相門女，學道愛神仙。',36,'全唐诗/poet.tang.8000.json','["多君相門女，學道愛神仙。", "素手掬青靄，羅衣曳紫煙。", "一往屏風疊，乘鸞着玉鞭。"]'),
('60ec5bb3-629e-402c-8481-89828f960481','贈內','李白','唐','唐诗','tang','','[]','三百六十日，日日醉如泥。',24,'全唐诗/poet.tang.8000.json','["三百六十日，日日醉如泥。", "雖爲李白婦，何異太常妻。"]'),
('730675ae-6683-4433-9313-b292eab2ac63','在潯陽非所寄內','李白','唐','唐诗','tang','','[]','聞難知慟哭，行啼入府中。',60,'全唐诗/poet.tang.8000.json','["聞難知慟哭，行啼入府中。", "多君同蔡琰，流淚請曹公。", "知登吳章嶺，昔與死無分。", "崎嶇行石道，外折入青雲。", "相見若悲歌，哀聲那可聞。"]'),
('ac279462-e1b7-426c-85ff-7ef1cb56a2b2','南流夜郎寄內','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u601d\u4e61", "\u6101\u82e6"]','夜郎天外怨離居，明月樓中音信疎。',32,'全唐诗/poet.tang.8000.json','["夜郎天外怨離居，明月樓中音信疎。", "北雁春歸看欲盡，南來不得豫章書。"]'),
('5f84a2b0-3d36-4a6a-8df1-89c5d0936493','越女詞五首 一','李白','唐','唐诗','tang','','[]','長干吳兒女，眉目豔新月。',24,'全唐诗/poet.tang.8000.json','["長干吳兒女，眉目豔新月。", "屐上足如霜，不着鴉頭襪。"]'),
('d1a5002d-2a82-4ed7-961a-45dac460e13c','越女詞五首 二','李白','唐','唐诗','tang','','[]','吳兒多白皙，好爲蕩舟劇。',24,'全唐诗/poet.tang.8000.json','["吳兒多白皙，好爲蕩舟劇。", "賣眼擲春心，折花調行客。"]'),
('f91b5f91-553d-4cff-946c-86a75aa9641a','越女詞五首 三','李白','唐','唐诗','tang','','[]','耶溪採蓮女，見客櫂歌迴。',24,'全唐诗/poet.tang.8000.json','["耶溪採蓮女，見客櫂歌迴。", "笑入荷花去，佯羞不出來。"]'),
('30bbaacd-ff02-4272-9c8e-e6a1637c7cc3','越女詞五首 四','李白','唐','唐诗','tang','','[]','東陽素足女，會稽素舸郎。',24,'全唐诗/poet.tang.8000.json','["東陽素足女，會稽素舸郎。", "相看月未墮，白地斷肝腸。"]'),
('19f6ea6b-fc90-4fe8-a886-d0249f47ca1e','越女詞五首 五','李白','唐','唐诗','tang','','[]','鏡湖水如月，耶溪女似雪。',24,'全唐诗/poet.tang.8000.json','["鏡湖水如月，耶溪女似雪。", "新妝蕩新波，光景兩奇絕。"]'),
('179a1c8b-2f36-4e45-8d8f-10c606e5bd5b','浣紗石上女','李白','唐','唐诗','tang','','[]','玉面耶溪女，青娥紅粉妝。',24,'全唐诗/poet.tang.8000.json','["玉面耶溪女，青娥紅粉妝。", "一雙金齒屐，兩足白如霜。"]'),
('a0a36d01-71af-4596-8eb5-6814ea2a5a01','示金陵子','李白','唐','唐诗','tang','','["\u957f\u6c5f", "\u5199\u4eba", "\u5973\u5b50", "\u5199\u4eba\u8bd7"]','金陵城東誰家子，竊聽琴聲碧窗裏。',64,'全唐诗/poet.tang.8000.json','["金陵城東誰家子，竊聽琴聲碧窗裏。", "落花一片天上來，隨人直渡西江水。", "楚歌吳語嬌不成，似能未能最有情。", "謝公正要東山妓，攜手林泉處處行。"]'),
('8e9ca496-b39f-4656-95fa-d3172f410596','出妓金陵子呈盧六四首 一','李白','唐','唐诗','tang','','[]','安石東山三十春，傲然攜妓出風塵。',32,'全唐诗/poet.tang.8000.json','["安石東山三十春，傲然攜妓出風塵。", "樓中見我金陵子，何似陽臺雲雨人。"]'),
('06f4fd03-e1f2-46b0-aa65-ba633506827a','出妓金陵子呈盧六四首 二','李白','唐','唐诗','tang','','[]','南國新豐酒，東山小妓歌。',24,'全唐诗/poet.tang.8000.json','["南國新豐酒，東山小妓歌。", "對君君不樂，花月奈愁何。"]'),
('8c72a47b-053b-4b11-9f15-5062ab4ae138','出妓金陵子呈盧六四首 三','李白','唐','唐诗','tang','','[]','東道煙霞主，西江詩酒筵。',24,'全唐诗/poet.tang.8000.json','["東道煙霞主，西江詩酒筵。", "相逢不覺醉，日墮歷陽川。"]'),
('4efb1951-8c97-460d-94c3-3228d0e6474f','出妓金陵子呈盧六四首 四','李白','唐','唐诗','tang','','[]','小妓金陵歌楚聲，家僮丹砂學鳳鳴。',32,'全唐诗/poet.tang.8000.json','["小妓金陵歌楚聲，家僮丹砂學鳳鳴。", "我亦爲君飲清酒，君心不肯向人傾。"]'),
('5ec2ee4c-87cb-4015-a26b-be3a6d3854d1','巴女詞','李白','唐','唐诗','tang','','["\u4e0d\u820d", "\u5199\u4eba", "\u5206\u522b", "\u5973\u5b50", "\u5199\u4eba\u8bd7"]','巴水急如箭，巴船去若飛。',24,'全唐诗/poet.tang.8000.json','["巴水急如箭，巴船去若飛。", "十月三千里，郎行幾歲歸。"]'),
('1ff7ee81-66a3-4390-aadb-0e58801625b9','哭晁卿衡','李白','唐','唐诗','tang','','["\u54c0\u60bc", "\u5199\u666f", "\u53cb\u60c5", "\u60dc\u522b"]','日本晁卿辭帝都，征帆一片繞蓬壺。',32,'全唐诗/poet.tang.8000.json','["日本晁卿辭帝都，征帆一片繞蓬壺。", "明月不歸沈碧海，白雲愁色滿蒼梧。"]'),
('7b020b1d-0654-4a76-a4e1-b9dbe3ce0820','自溧水道哭王炎三首 一','李白','唐','唐诗','tang','','[]','白楊雙行行，白馬悲路傍。',108,'全唐诗/poet.tang.8000.json','["白楊雙行行，白馬悲路傍。", "晨興見曉月，更似發雲陽。", "溧水通吳關，逝川去未央。", "故人萬化盡，閉骨茅山岡。", "天上墜玉棺，泉中掩龍章。", "名飛日月上，義與風雲翔。", "逸氣竟莫展，英圖俄夭傷。", "楚國一老人，來嗟龔勝亡。", "有言不可道，雪泣憶蘭芳。"]'),
('1381eb21-aa70-4450-acb8-43cb35e2946e','自溧水道哭王炎三首 二','李白','唐','唐诗','tang','','[]','王公希代寶，棄世一何早。',52,'全唐诗/poet.tang.8000.json','["王公希代寶，棄世一何早。", "弔死不及哀，殯宮已秋草。", "悲來欲脫劒，挂向何枝好。", "哭向茅山雖未摧，一生淚盡丹陽道。"]'),
('b1ada597-12de-452d-9396-720dc2506292','自溧水道哭王炎三首 三','李白','唐','唐诗','tang','','[]','王家碧瑤樹，一樹忽先摧。',48,'全唐诗/poet.tang.8000.json','["王家碧瑤樹，一樹忽先摧。", "海內故人泣，天涯弔鶴來。", "未成霖雨用，先失濟川材。", "一罷廣陵散，鳴琴更不開。"]'),
('2d4fe2e9-a528-4997-8877-0621c3689a78','哭宣城善釀紀叟','李白','唐','唐诗','tang','','[]','紀叟黃泉裏，還應釀老春。',24,'全唐诗/poet.tang.8000.json','["紀叟黃泉裏，還應釀老春。", "夜臺無曉日，沽酒與何人。"]'),
('ccb929e1-428b-4f20-80bc-931a506701c4','宣城哭蔣徵君華','李白','唐','唐诗','tang','','[]','敬亭埋玉樹，知是蔣徵君。',48,'全唐诗/poet.tang.8000.json','["敬亭埋玉樹，知是蔣徵君。", "安得相如草，空餘封禪文。", "池臺空有月，詞賦舊凌雲。", "獨挂延陵劒，千秋在古墳。"]'),
('9da2d0f8-74e1-4d1d-bbff-613b43a4bfd6','鞠歌行','李白','唐','唐诗','tang','','[]','麗莫似漢宮妃，謙莫似黃家女。',119,'全唐诗/poet.tang.8000.json','["麗莫似漢宮妃，謙莫似黃家女。", "黃女持謙齒髮高，漢妃恃麗天庭去。", "人生容德不自保，聖人安用推天道。", "君不見蔡澤嵌枯詭怪之形狀，大言直取秦丞相。", "又不見田千秋才智不出人，一朝富貴如有神。", "二侯行事在方冊，泣麟老人終困厄。", "夜光抱恨良歎悲，日月逝矣吾何之。"]'),
('c630be6b-327d-43c0-9b05-ce3eb2163a14','胡無人','李白','唐','唐诗','tang','','[]','十萬羽林兒，臨洮破郅支。',48,'全唐诗/poet.tang.8000.json','["十萬羽林兒，臨洮破郅支。", "殺添胡地骨，降足漢營旗。", "塞闊牛羊散，兵休帳幕移。", "空餘隴頭水，嗚咽向人悲。"]'),
('324dc103-79a2-41b5-9d25-6f34edf86542','月夜金陵懷古','李白','唐','唐诗','tang','','[]','蒼蒼金陵月，空懸帝王州。',72,'全唐诗/poet.tang.8000.json','["蒼蒼金陵月，空懸帝王州。", "天文列宿在，霸業大江流。", "綠水絕馳道，青松摧古丘。", "臺傾鳷鵲觀，宮沒鳳凰樓。", "別殿悲清暑，芳園罷樂遊。", "一聞歌玉樹，蕭瑟後庭秋。"]'),
('883a745a-9d91-45b6-b9b1-db4b55f61eae','冬日歸舊山','李白','唐','唐诗','tang','','["\u5199\u666f", "\u52b1\u5fd7", "\u51ac\u5929"]','未洗染塵纓，歸來芳草平。',120,'全唐诗/poet.tang.8000.json','["未洗染塵纓，歸來芳草平。", "一條藤徑綠，萬點雪峰晴。", "地冷葉先盡，谷寒雲不行。", "嫩篁侵舍密，古樹倒江橫。", "白犬離村吠，蒼苔壁上生。", "穿廚孤雉過，臨屋舊猨鳴。", "木落禽巢在，籬疎獸路成。", "拂牀蒼鼠走，倒篋素魚驚。", "洗硯修良策，敲松擬素貞。", "此時重一去，去合到三清。"]'),
('0c14fb62-852a-49a1-bfa6-2d3baefd45af','望夫石','李白','唐','唐诗','tang','','[]','髣髴古容儀，含愁帶曙輝。',48,'全唐诗/poet.tang.8000.json','["髣髴古容儀，含愁帶曙輝。", "露如今日淚，苔似昔年衣。", "有恨同湘女，無言類楚妃。", "寂然芳靄內，猶若待夫歸。"]'),
('3f7d06a9-3582-4a7a-b6c1-75688af2150b','對雨','李白','唐','唐诗','tang','','[]','卷簾聊舉目，露濕草綿芊。',48,'全唐诗/poet.tang.8000.json','["卷簾聊舉目，露濕草綿芊。", "古岫藏雲毳，空庭織碎烟。", "水紋愁不起，風線重難牽。", "盡日扶犂叟，往來江樹前。"]'),
('f3967be5-99ef-4c0e-b3e9-0b967443e22d','曉晴','李白','唐','唐诗','tang','','[]','野涼疎雨歇，春色徧萋萋。',48,'全唐诗/poet.tang.8000.json','["野涼疎雨歇，春色徧萋萋。", "魚躍青池滿，鶯吟綠樹低。", "野花妝面濕，山草紐斜齊。", "零落殘雪片，風吹挂竹谿。"]'),
('92f43b04-0c69-4e8c-9726-fc61ba49ee7c','初月','李白','唐','唐诗','tang','','[]','玉蟾離海上，白露濕花時。',48,'全唐诗/poet.tang.8000.json','["玉蟾離海上，白露濕花時。", "雲畔風生爪，沙頭水浸眉。", "樂哉弦管客，愁殺戰征兒。", "因絕西園賞，臨風一詠詩。"]'),
('dfb19e4d-76d0-483e-8a9c-c662467ef043','雨後望月','李白','唐','唐诗','tang','','["\u6708\u4eae"]','四郊陰靄散，開戶半蟾生。',48,'全唐诗/poet.tang.8000.json','["四郊陰靄散，開戶半蟾生。", "萬里舒霜合，一條江練橫。", "出時山眼白，高後海心明。", "爲惜如團扇，長吟到五更。"]'),
('79c25f0c-49a5-49ee-b42f-5ae627a64f63','賦得鶴送史司馬赴崔相公幕','李白','唐','唐诗','tang','','[]','崢嶸丞相府，清切鳳凰池。',72,'全唐诗/poet.tang.8000.json','["崢嶸丞相府，清切鳳凰池。", "羨爾瑤臺鶴，高棲瓊樹枝。", "歸飛晴日好，吟弄惠風吹。", "正有乘軒樂，初當學舞時。", "珍禽在羅網，微命若游絲。", "願托周周羽，相銜漢水湄。"]'),
('1552ccde-4052-4faa-84d2-272223ed5ec5','送客歸吳','李白','唐','唐诗','tang','','[]','江村秋雨歇，酒盡一帆飛。',48,'全唐诗/poet.tang.8000.json','["江村秋雨歇，酒盡一帆飛。", "路歷波濤去，家惟坐臥歸。", "島花開灼灼，汀柳細依依。", "別後無餘事，還應埽釣磯。"]'),
('a4b167df-21c5-4e24-9ac8-443735ce164f','送友生遊峽中','李白','唐','唐诗','tang','','[]','風靜楊柳垂，看花又別離。',48,'全唐诗/poet.tang.8000.json','["風靜楊柳垂，看花又別離。", "幾年同在此，今日各驅馳。", "峽裏聞猨呌，山頭見月時。", "殷勤一杯酒，珍重歲寒姿。"]'),
('b7bacfad-487a-4c51-b382-bb9a4d87332b','送袁明府任長沙','李白','唐','唐诗','tang','','["\u957f\u6c5f"]','別離楊柳青，樽酒表丹誠。',48,'全唐诗/poet.tang.8000.json','["別離楊柳青，樽酒表丹誠。", "古道攜琴去，深山見峽迎。", "暖風花繞樹，秋雨草沿城。", "自此長江內，無因夜犬驚。"]'),
('6cc213f6-5c78-4785-a051-bfd8e7fa63e7','鄒衍谷','李白','唐','唐诗','tang','','[]','燕谷無煖氣，窮巖閉嚴陰。',24,'全唐诗/poet.tang.8000.json','["燕谷無煖氣，窮巖閉嚴陰。", "鄒子一吹律，能迴天地心。"]'),
('db3d51e7-0092-4575-83be-77f207edd9a3','雜言用投丹陽知己兼奉宣慰判官','李白','唐','唐诗','tang','','[]','客從崑崙來，遺我雙玉璞。',136,'全唐诗/poet.tang.8000.json','["客從崑崙來，遺我雙玉璞。", "云是古之得道者西王母食之餘，食之可以凌太虛。", "受之頗謂絕今昔，求識江淮人猶乎比石。", "如今雖在卞和手，□□正憔悴。", "了了知之亦何益，恭聞士有調相如。", "始從鎬京還，復欲鎬京去。", "能上秦王殿，何時迴光一相眄。", "欲投君，保君年，幸君持取無棄捐。", "無棄捐，服之與君俱神仙。"]'),
('938a1650-678a-4b9f-b554-7adba5ad4f21','觀魚潭','李白','唐','唐诗','tang','','[]','觀魚碧潭上，木落潭水清。',48,'全唐诗/poet.tang.8000.json','["觀魚碧潭上，木落潭水清。", "日暮紫鱗躍，圓波處處生。", "涼煙浮竹盡，秋月照沙明。", "何必滄浪去，茲焉可濯纓。"]'),
('3ca361a7-ec8f-4356-8059-0269d49c2157','自廣平乘醉走馬六十里至邯鄲登城樓覽古書懷','李白','唐','唐诗','tang','','[]','醉騎白花馬，西走邯鄲城。',240,'全唐诗/poet.tang.8000.json','["醉騎白花馬，西走邯鄲城。", "揚鞭動柳色，寫鞚春風生。", "入郭登高樓，山川與雲平。", "深宮翳綠草，萬事傷人情。", "相如章華巔，猛氣折秦嬴。", "兩虎不可鬬，廉公終負荆。", "提攜袴中兒，杵臼及程嬰。", "立孤就白刃，必死耀丹誠。", "平原三千客，談笑盡豪英。", "毛君能頴脫，二國且同盟。", "皆爲黃泉土，使我涕縱橫。", "磊磊石子岡，蕭蕭白楊聲。", "諸賢沒此地，碑版有殘銘。", "太古共今時，由來互哀榮。", "傷哉何足道，感激仰空名。", "趙俗愛長劒，文儒少逢迎。", "閑從博陵遊，暢飲雪朝酲。", "歌酣易水動，鼓震叢臺傾。", "日落把燭歸，凌晨向燕京。", "方陳五餌策，一使胡塵清。"]'),
('a309224f-e137-429e-b4ec-5bba8d73f0ad','宣州長史弟昭贈余琴谿中雙舞鶴詩以見志','李白','唐','唐诗','tang','','[]','令弟佐宣城，贈余琴谿鶴。',72,'全唐诗/poet.tang.8000.json','["令弟佐宣城，贈余琴谿鶴。", "謂言天涯雪，忽向窗前落。", "白玉爲毛衣，黃金不肯博。", "背風振六翮，對舞臨山閣。", "顧我如有情，長鳴似相託。", "何當駕此物，與爾騰寥廓。"]'),
('4968d09f-33f5-46e2-981c-6bcb3be2d9d8','題舒州司空山瀑布','李白','唐','唐诗','tang','','[]','斷崖如削瓜，嵐光破崖綠。',48,'全唐诗/poet.tang.8000.json','["斷崖如削瓜，嵐光破崖綠。", "天河從中來，白雲漲川谷。", "玉案赤文字，世眼不可讀。", "攝身凌青霄，松風拂我足。"]'),
('f91af95d-c3ed-4932-b907-1a638e0a8afe','金陵新亭','李白','唐','唐诗','tang','','["\u7231\u56fd", "\u5fd7\u58eb", "\u8d5e\u7f8e", "\u548f\u53f2\u6000\u53e4"]','金陵風景好，豪士集新亭。',48,'全唐诗/poet.tang.8000.json','["金陵風景好，豪士集新亭。", "舉目山河異，偏傷周顗情。", "四坐楚囚悲，不憂社稷傾。", "王公何慷慨，千載仰雄名。"]'),
('22159e97-251c-440a-83b4-b6b6387f56c9','上清寶鼎詩 一','李白','唐','唐诗','tang','','[]','我居清空表，君處紅埃中。',36,'全唐诗/poet.tang.8000.json','["我居清空表，君處紅埃中。", "仙人持玉尺，廢君多少才。", "玉尺不可盡，君才無時休。"]'),
('3bfa34ff-3532-4774-8bda-8f5e88637854','上清寶鼎詩 二','李白','唐','唐诗','tang','','[]','嚥服十二環，奄有仙人房。',36,'全唐诗/poet.tang.8000.json','["嚥服十二環，奄有仙人房。", "暮騎紫麟去，海氣侵肌涼。", "贈我纍纍珠，靡靡明月光。"]'),
('f1aa65f7-c533-48c5-a405-ae46a3a6e137','題許宣平菴壁','李白','唐','唐诗','tang','','[]','我吟傳舍詠，來訪真人居。',48,'全唐诗/poet.tang.8000.json','["我吟傳舍詠，來訪真人居。", "煙嶺迷高跡，雲林隔太虛。", "窺庭但蕭瑟，倚杖空躊躇。", "應化遼天鶴，歸當千歲餘。"]'),
('18d50cb2-d2f6-48bf-b4bf-2226429a2bca','戲贈杜甫','李白','唐','唐诗','tang','','["\u559c\u60a6", "\u53cb\u60c5", "\u91cd\u9022"]','飯顆山頭逢杜甫，頂戴笠子日卓午。',32,'全唐诗/poet.tang.8000.json','["飯顆山頭逢杜甫，頂戴笠子日卓午。", "借問別來太瘦生，總爲從前作詩苦。"]'),
('2a0011ec-102c-4d51-b204-d5909a1f63eb','春感詩','李白','唐','唐诗','tang','','[]','茫茫南與北，道直事難諧。',48,'全唐诗/poet.tang.8000.json','["茫茫南與北，道直事難諧。", "榆莢錢生樹，楊花玉糝街。", "塵縈遊子面，蝶弄美人釵。", "却憶青山上，雲門掩竹齋。"]'),
('8938db72-4784-4d3e-ba8c-f9fe6174dc58','白微時募縣小吏入令臥內嘗驅牛經堂下令妻怒將加詰責白亟以詩謝云','李白','唐','唐诗','tang','','[]','素面倚欄鉤，嬌聲出外頭。',24,'全唐诗/poet.tang.8000.json','["素面倚欄鉤，嬌聲出外頭。", "若非是織女，何得問牽牛。"]'),
('7e2b38c6-e869-4ce3-b8c6-0bbce1d30892','句','李白','唐','唐诗','tang','','[]','焰隨紅日去，煙逐暮雲飛。',48,'全唐诗/poet.tang.8000.json','["焰隨紅日去，煙逐暮雲飛。", "綠鬢隨波散，紅顏逐浪無。", "因何逢伍相，應是想秋胡。", "舉袖露條脫，招我飯胡麻。"]'),
('e81879f9-92ef-4102-85fc-9262132b1bea','擬古詩十二首 一','韋應物','唐','唐诗','tang','','[]','辭君遠行邁，飲此長恨端。',96,'全唐诗/poet.tang.8000.json','["辭君遠行邁，飲此長恨端。", "已謂道里遠，如何中險艱。", "流水赴大壑，孤雲還暮山。", "無情尚有歸，行子何獨難。", "驅車背鄉園，朔風卷行迹。", "嚴冬霜斷肌，日入不遑息。", "憂歡容髮變，寒暑人事易。", "中心君詎知，冰玉徒貞白。"]'),
('c22f5d58-f0de-4f54-872a-3373e0f6bb58','擬古詩十二首 二','韋應物','唐','唐诗','tang','','[]','黃鳥何關關，幽蘭亦靡靡。',60,'全唐诗/poet.tang.8000.json','["黃鳥何關關，幽蘭亦靡靡。", "此時深閨婦，日照紗窗裏。", "娟娟雙青娥，微微啓玉齒。", "自惜桃李年，誤身遊俠子。", "無事久離別，不知今生死。"]'),
('5174ca76-0016-4f4f-ba75-34bc3de872b2','擬古詩十二首 三','韋應物','唐','唐诗','tang','','[]','峨峨高山巔，浼浼青川流。',96,'全唐诗/poet.tang.8000.json','["峨峨高山巔，浼浼青川流。", "世人不自悟，馳謝如驚飍。", "百金非所重，厚意良難得。", "旨酒親與朋，芳年樂京國。", "京城繁華地，軒蓋凌晨出。", "垂楊十二衢，隱暎金張室。", "漢宮南北對，飛觀齊白日。", "游泳屬芳時，平生自云畢。"]'),
('fc0c9861-665b-4e00-9ec5-eb4b017bf664','擬古詩十二首 四','韋應物','唐','唐诗','tang','','[]','綺樓何氛氳，朝日正杲杲。',96,'全唐诗/poet.tang.8000.json','["綺樓何氛氳，朝日正杲杲。", "四壁含清風，丹霞射其牖。", "玉顏上哀囀，絕耳非世有。", "但感離恨情，不知誰家婦。", "孤雲忽無色，邊馬爲回首。", "曲絕碧天高，餘聲散秋草。", "徘徊帷中意，獨夜不堪守。", "思逐朔風翔，一去千里道。"]'),
('f84e421e-25b4-4b12-81d5-2dda8638e7dc','擬古詩十二首 五','韋應物','唐','唐诗','tang','','[]','嘉樹藹初綠，靡蕪吐幽芳。',48,'全唐诗/poet.tang.8000.json','["嘉樹藹初綠，靡蕪吐幽芳。", "君子不在賞，寄之雲路長。", "路長信難越，惜此芳時歇。", "孤鳥去不還，緘情向天末。"]'),
('907d645d-c71a-47d3-9839-d533267777cc','擬古詩十二首 六','韋應物','唐','唐诗','tang','','[]','月滿秋夜長，驚烏號北林。',72,'全唐诗/poet.tang.8000.json','["月滿秋夜長，驚烏號北林。", "天河橫未落，斗柄當西南。", "寒蛩悲洞房，好鳥無遺音。", "商飆一夕至，獨宿懷重衾。", "舊交日千里，隔我浮與沈。", "人生豈草木，寒暑移此心。"]'),
('51190e9d-a05d-40e7-929f-b1f9ae5dacbd','擬古詩十二首 七','韋應物','唐','唐诗','tang','','[]','酒星非所酌，月桂不爲食。',72,'全唐诗/poet.tang.8000.json','["酒星非所酌，月桂不爲食。", "虛薄空有名，爲君長歎息。", "蘭蕙雖可懷，芳香與時息。", "豈如凌霜葉，歲暮藹顏色。", "折柔將有贈，延意千里客。", "草木知賤微，所貴寒不易。"]'),
('fff406b3-57a8-42dc-85cf-65824402eec4','擬古詩十二首 八','韋應物','唐','唐诗','tang','','[]','神州高爽地，遐瞰靡不通。',120,'全唐诗/poet.tang.8000.json','["神州高爽地，遐瞰靡不通。", "寒月野無綠，寥寥天宇空。", "陰陽不停馭，貞脆各有終。", "汾沮何鄙儉，考槃何退窮。", "反志解牽跼，無爲尚勞躬。", "美人奪南國，一笑開芙蓉。", "清鏡理容髮，褰簾出深重。", "豔曲呈皓齒，舞羅不堪風。", "慊慊情有待，贈芳爲我容。", "可嗟青樓月，流影君帷中。"]'),
('580567df-30f6-453f-aa5b-d0a0d274f99b','擬古詩十二首 九','韋應物','唐','唐诗','tang','','[]','春至林木變，洞房夕含清。',96,'全唐诗/poet.tang.8000.json','["春至林木變，洞房夕含清。", "單居誰能裁，好鳥對我鳴。", "良人久燕趙，新愛移平生。", "別時雙鴛綺，留此千恨情。", "碧草生舊迹，綠琴歇芳聲。", "思將魂夢歡，反側寐不成。", "攬衣迷所次，起望空前庭。", "孤影中自惻，不知雙涕零。"]'),
('6a9cf3f6-e425-4854-9623-1815fc769f97','擬古詩十二首 十','韋應物','唐','唐诗','tang','','[]','秋天無留景，萬物藏光輝。',48,'全唐诗/poet.tang.8000.json','["秋天無留景，萬物藏光輝。", "落葉隨風起，愁人獨何依。", "華月屢圓缺，君還浩無期。", "如何雨絕天，一去音問違。"]'),
('cb39fc22-c738-4644-b7d2-068403c6e047','擬古詩十二首 十一','韋應物','唐','唐诗','tang','','[]','有客天一方，寄我孤桐琴。',48,'全唐诗/poet.tang.8000.json','["有客天一方，寄我孤桐琴。", "迢迢萬里隔，託此傳幽音。", "冰霜中自結，龍鳳相與吟。", "絃以明直道，漆以固交深。"]'),
('f05bfa6a-aed8-4bf9-9c53-caa640e22c6b','擬古詩十二首 十二','韋應物','唐','唐诗','tang','','[]','白日淇上沒，空閨生遠愁。',60,'全唐诗/poet.tang.8000.json','["白日淇上沒，空閨生遠愁。", "寸心不可限，淇水長悠悠。", "芳樹自妍芳，春禽自相求。", "徘徊東西廂，孤妾誰與儔。", "年華逐絲淚，一落俱不收。"]'),
('8607ee04-dce7-4d86-8b41-5844798ce148','雜體五首 一','韋應物','唐','唐诗','tang','','[]','沈沈匣中鏡，爲此塵垢蝕。',72,'全唐诗/poet.tang.8000.json','["沈沈匣中鏡，爲此塵垢蝕。", "輝光何所如，月在雲中黑。", "南金既雕錯，鞶帶共輝飾。", "空存鑒物名，坐使妍蚩惑。", "美人竭肝膽，思照冰玉色。", "自非磨瑩工，日日空嘆息。"]'),
('89f63d03-a042-4097-a55c-f7ea652657a2','雜體五首 二','韋應物','唐','唐诗','tang','','[]','古宅集祆鳥，羣號枯樹枝。',72,'全唐诗/poet.tang.8000.json','["古宅集祆鳥，羣號枯樹枝。", "黃昏窺人室，鬼物相與期。", "居人不安寢，搏擊思此時。", "豈無鷹與鸇，飽肉不肯飛。", "既乖逐鳥節，空養凌雲姿。", "孤負肉食恩，何異城上鴟。"]'),
('ffbd3115-d22a-4e51-9fe1-2887fe021bbb','雜體五首 三','韋應物','唐','唐诗','tang','','[]','春羅雙鴛鴦，出自寒夜女。',60,'全唐诗/poet.tang.8000.json','["春羅雙鴛鴦，出自寒夜女。", "心精煙霧色，指歷千萬緒。", "長安貴豪家，妖豔不可數。", "裁此百日功，唯將一朝舞。", "舞罷復裁新，豈思勞者苦。"]'),
('99f718cc-d4e8-4c98-9694-0f0b46ec29cb','雜體五首 四','韋應物','唐','唐诗','tang','','[]','同聲自相應，體質不必齊。',72,'全唐诗/poet.tang.8000.json','["同聲自相應，體質不必齊。", "誰知賈人鐸，能使大樂諧。", "鏗鏘發宮徵，和樂變其哀。", "人神既昭享，鳳鳥亦下來。", "豈非至賤物，一奏升天階。", "物情苟有合，莫問玉與泥。"]'),
('80b0ce27-8e7b-4a57-aa95-948a6f4e7416','雜體五首 五','韋應物','唐','唐诗','tang','','[]','碌碌荆山璞，卞和獻君門。',48,'全唐诗/poet.tang.8000.json','["碌碌荆山璞，卞和獻君門。", "荆璞非有求，和氏非有恩。", "所獻知國寶，至公不待言。", "是非吾欲默，此道今豈存。"]'),
('4474e54f-e79a-4d01-8a8c-2e0ce79fc86b','與友生野飲效陶體','韋應物','唐','唐诗','tang','','[]','攜酒花林下，前有千載墳。',60,'全唐诗/poet.tang.8000.json','["攜酒花林下，前有千載墳。", "於時不共酌，奈此泉下人。", "始自翫芳物，行當念徂春。", "聊舒遠世蹤，坐望還山雲。", "且遂一歡笑，焉知賤與貧。"]'),
('1bec7dde-19d2-4417-853a-cdf536bdb908','效何水部二首 一','韋應物','唐','唐诗','tang','','[]','玉宇含清露，香籠散輕煙。',24,'全唐诗/poet.tang.8000.json','["玉宇含清露，香籠散輕煙。", "應當結沈抱，難從茲夕眠。"]'),
('8d3ed695-4ade-4738-85fd-69d006e8c7e4','效何水部二首 二','韋應物','唐','唐诗','tang','','[]','夕漏起遙恨，蟲響亂秋陰。',24,'全唐诗/poet.tang.8000.json','["夕漏起遙恨，蟲響亂秋陰。", "反覆相思字，中有故人心。"]'),
('dd32e1c1-aef1-45b1-a97d-18b710aa4c21','效陶彭澤','韋應物','唐','唐诗','tang','','[]','霜露悴百草，時菊獨妍華。',48,'全唐诗/poet.tang.8000.json','["霜露悴百草，時菊獨妍華。", "物性有如此，寒暑其奈何。", "掇英泛濁醪，日入會田家。", "盡醉茅簷下，一生豈在多。"]'),
('e08f12ae-400b-4d0c-98fb-382020e3534a','大梁亭會李四栖梧作','韋應物','唐','唐诗','tang','','[]','梁王昔愛才，千古化不泯。',120,'全唐诗/poet.tang.8000.json','["梁王昔愛才，千古化不泯。", "至今蓬池上，遠集八方賓。", "車馬平明合，城郭滿埃塵。", "逢君一相許，豈要平生親。", "入仕三十載，如何獨未伸。", "英聲久籍籍，臺閣多故人。", "置酒發清彈，相與樂佳辰。", "孤亭得長望，白日下廣津。", "富貴良可取，朅來西入秦。", "秋風旦夕起，安得客梁陳。"]'),
('c9c03c2b-a954-4666-b1fa-46f0164a8205','燕李錄事','韋應物','唐','唐诗','tang','','[]','與君十五侍皇闈，曉拂爐煙上赤墀。',64,'全唐诗/poet.tang.8000.json','["與君十五侍皇闈，曉拂爐煙上赤墀。", "花開漢苑經過處，雪下驪山沐浴時。", "近臣零落今猶在，仙駕飄颻不可期。", "此日相逢思舊日，一杯成喜亦成悲。"]'),
('a68013c8-4630-41c6-a5ee-a658b57f58fe','淮上喜會梁川故人','韋應物','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u53cb\u60c5", "\u4e94\u8a00\u5f8b\u8bd7"]','江漢曾爲客，相逢每醉還。',48,'全唐诗/poet.tang.8000.json','["江漢曾爲客，相逢每醉還。", "浮雲一別後，流水十年間。", "歡笑情如舊，蕭疎鬢已斑。", "何因北歸去，淮上對秋山。"]'),
('53682af7-3c97-4fde-8f14-973c6efb436e','揚州偶會前洛陽盧耿主簿','韋應物','唐','唐诗','tang','','[]','楚塞故人稀，相逢本不期。',48,'全唐诗/poet.tang.8000.json','["楚塞故人稀，相逢本不期。", "猶存袖裏字，忽怪鬢中絲。", "客舍盈樽酒，江行滿篋詩。", "更能連騎出，還似洛橋時。"]'),
('041d8e9d-5906-4ee2-ad1b-8b81a8ea8612','賈常侍林亭燕集','韋應物','唐','唐诗','tang','','[]','高賢侍天陛，跡顯心獨幽。',132,'全唐诗/poet.tang.8000.json','["高賢侍天陛，跡顯心獨幽。", "朱軒騖關右，池館在東周。", "繚繞接都城，氤氳望嵩丘。", "羣公盡詞客，方駕永日遊。", "朝旦氣候佳，逍遙寫煩憂。", "綠林藹已布，華沼澹不流。", "沒露摘幽草，涉煙翫輕舟。", "圓荷既出水，廣廈可淹留。", "放神遺所拘，觥罰屢見酬。", "樂燕良未極，安知有沈浮。", "醉罷各云散，何當復相求。"]'),
('02a4f746-8aca-47d8-8284-10d4232c2cf3','月下會徐十一草堂','韋應物','唐','唐诗','tang','','[]','空齋無一事，岸幘故人期。',48,'全唐诗/poet.tang.8000.json','["空齋無一事，岸幘故人期。", "暫輟觀書夜，還題翫月詩。", "遠鐘高枕後，清露捲簾時。", "暗覺新秋近，殘河欲曙遲。"]'),
('75a4757e-314f-46c5-a0ab-62231748b2a2','移疾會詩客元生與釋子法朗因貽諸祠曹','韋應物','唐','唐诗','tang','','[]','對此嘉樹林，獨有戚戚顏。',84,'全唐诗/poet.tang.8000.json','["對此嘉樹林，獨有戚戚顏。", "抱瘵知曠職，淹旬非樂閑。", "釋子來問訊，詩人亦扣關。", "道同意暫遣，客散疾徐還。", "園徑自幽靜，玄蟬噪其間。", "高牕瞰遠郊，暮色起秋山。", "英曹幸休暇，悢悢心所攀。"]'),
('a4ea207f-f164-4ca6-8901-823d810415a4','慈恩伽藍清會','韋應物','唐','唐诗','tang','','[]','素友俱薄世，屢招清景賞。',96,'全唐诗/poet.tang.8000.json','["素友俱薄世，屢招清景賞。", "鳴鐘悟音聞，宿昔心已往。", "重門相洞達，高宇亦遐朗。", "嵐嶺曉城分，清陰夏條長。", "氳氛芳臺馥，蕭散竹池廣。", "平荷隨波泛，廻飆激林響。", "蔬食遵道侶，泊懷遺滯想。", "何彼塵昏人，區區在天壤。"]'),
('6fc18fdb-04fc-482f-b298-835d6f82c2de','夜偶詩客操公作','韋應物','唐','唐诗','tang','','[]','塵襟一瀟灑，清夜得禪公。',48,'全唐诗/poet.tang.8000.json','["塵襟一瀟灑，清夜得禪公。", "遠自鶴林寺，了知人世空。", "驚禽翻暗葉，流水注幽叢。", "多謝非玄度，聊將詩興同。"]'),
('4a3d71d7-b2e1-4dda-803c-42208f327175','與韓庫部會王祠曹宅作','韋應物','唐','唐诗','tang','','[]','閑門蔭堤柳，秋渠含夕清。',48,'全唐诗/poet.tang.8000.json','["閑門蔭堤柳，秋渠含夕清。", "微風送荷氣，坐客散塵纓。", "守默共無恡，抱沖俱寡營。", "良時頗高會，琴酌共開情。"]'),
('54b963cc-4793-49f5-a117-4fb409b1a6bd','晦日處士叔園林燕集','韋應物','唐','唐诗','tang','','[]','遽看蓂葉盡，坐闕芳年賞。',72,'全唐诗/poet.tang.8000.json','["遽看蓂葉盡，坐闕芳年賞。", "賴此林下期，清風滌煩想。", "始萌動新煦，佳禽發幽響。", "嵐嶺對高齋，春流灌蔬壤。", "罇酒遺形迹，道言屢開獎。", "幸蒙終夕懽，聊用稅歸鞅。"]'),
('09302e16-18a6-4af9-9188-4f2932512a02','扈亭西陂燕賞','韋應物','唐','唐诗','tang','','[]','杲杲朝陽時，悠悠清陂望。',72,'全唐诗/poet.tang.8000.json','["杲杲朝陽時，悠悠清陂望。", "嘉樹始氤氳，春遊方浩蕩。", "況逢文翰侶，愛此孤舟漾。", "綠野際遙波，橫雲分疊嶂。", "公堂日爲倦，幽襟自茲曠。", "有酒今滿盈，願君盡弘量。"]'),
('97bf03c6-59e1-4c4e-8662-2a10b6ed9e3a','西郊燕集','韋應物','唐','唐诗','tang','','[]','濟濟衆君子，高宴及時光。',84,'全唐诗/poet.tang.8000.json','["濟濟衆君子，高宴及時光。", "羣山靄遐矚，綠野布熙陽。", "列坐遵曲岸，披襟襲蘭芳。", "野庖薦嘉魚，激澗泛羽觴。", "衆鳥鳴茂林，綠草延高岡。", "盛時易徂謝，浩思坐飄颺。", "眷言同心友，茲遊安可忘。"]'),
('cd2a3be1-a81d-4e0a-84ac-e59153eabd63','春宵燕萬年吉少府中孚南館','韋應物','唐','唐诗','tang','','[]','始見斗柄廻，復茲霜月霽。',60,'全唐诗/poet.tang.8000.json','["始見斗柄廻，復茲霜月霽。", "河漢上縱橫，春城夜迢遞。", "賓筵接時彥，樂燕凌芳歲。", "稍愛清觴滿，仰歎高文麗。", "欲去返郊扉，端爲一歡滯。"]'),
('e981288b-2b04-44af-bd84-6ab0328d5947','滁州園池燕元氏親屬','韋應物','唐','唐诗','tang','','[]','日暮遊清池，疎林羅高天。',72,'全唐诗/poet.tang.8000.json','["日暮遊清池，疎林羅高天。", "餘綠飄霜露，夕氣變風煙。", "水門架危閣，竹亭列廣筵。", "一展私姻禮，屢歎芳樽前。", "感往在茲會，傷離屬頽年。", "明晨復云去，且願此流連。"]'),
('60683818-e720-49ee-9441-c70d097687cd','郡樓春燕','韋應物','唐','唐诗','tang','','[]','衆樂雜軍鞞，高樓邀上客。',48,'全唐诗/poet.tang.8000.json','["衆樂雜軍鞞，高樓邀上客。", "思逐花光亂，賞餘山景夕。", "爲郡訪彫瘵，守程難損益。", "聊假一杯歡，暫忘終日迫。"]'),
('982d08cf-9bb3-46d7-b116-f1db398b1c1f','南塘泛舟會元六昆季','韋應物','唐','唐诗','tang','','[]','端居倦時燠，輕舟泛廻塘。',48,'全唐诗/poet.tang.8000.json','["端居倦時燠，輕舟泛廻塘。", "微風飄襟散，橫吹繞林長。", "雲澹水容夕，雨微荷氣涼。", "一寫悁勤意，寧用訴華觴。"]'),
('9f5ded08-4f6f-4641-878e-897904483479','郡齋雨中與諸文士燕集','韋應物','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u53e4\u8bd7", "\u5bb4\u4f1a"]','兵衛森畫戟，宴寢凝清香。',120,'全唐诗/poet.tang.8000.json','["兵衛森畫戟，宴寢凝清香。", "海上風雨至，逍遙池閣涼。", "煩疴近消散，嘉賓復滿堂。", "自慙居處崇，未覩斯民康。", "理會是非遣，性達形迹忘。", "鮮肥屬時禁，蔬果幸見嘗。", "俯飲一杯酒，仰聆金玉章。", "神歡體自輕，意欲凌風翔。", "吳中盛文史，羣彥今汪洋。", "方知大藩地，豈曰財賦疆。"]'),
('f5bd232b-a644-4320-acc1-8944ef3287c9','軍中冬燕','韋應物','唐','唐诗','tang','','[]','滄海已云晏，皇恩猶念勤。',120,'全唐诗/poet.tang.8000.json','["滄海已云晏，皇恩猶念勤。", "式燕徧恆秩，柔遠及斯人。", "茲邦實大藩，伐鼓軍樂陳。", "是時冬服成，戎士氣益振。", "虎竹謬朝寄，英賢降上賓。", "旋罄周旋禮，媿無海陸珍。", "庭中九劍闌，堂上歌吹新。", "光景不知晚，觥酌豈言頻。", "單醪昔所感，大醵況同忻。", "顧謂軍中士，仰答何由申。"]'),
('81be33a1-4c5c-448d-b228-f9abac3cac39','司空主簿琴席','韋應物','唐','唐诗','tang','','[]','煙華方散薄，蕙氣猶含露。',48,'全唐诗/poet.tang.8000.json','["煙華方散薄，蕙氣猶含露。", "澹景發清琴，幽期默玄悟。", "流連白雪意，斷續廻風度。", "掩抑雖已終，忡忡在幽素。"]'),
('128f48cc-c7a3-41bd-8127-263564a9aa36','與村老對飲','韋應物','唐','唐诗','tang','','[]','鬢眉雪色猶嗜酒，言辭淳朴古人風。',32,'全唐诗/poet.tang.8000.json','["鬢眉雪色猶嗜酒，言辭淳朴古人風。", "鄉村年少生離亂，見話先朝如夢中。"]'),
('84d911a9-697b-4728-b824-fb707428e03a','城中臥疾知閻薛二子屢從邑令飲因以贈之','韋應物','唐','唐诗','tang','','[]','車馬日蕭蕭，胡不枉我廬。',84,'全唐诗/poet.tang.8000.json','["車馬日蕭蕭，胡不枉我廬。", "方來從令飲，臥病獨何如。", "秋風起漢臯，開戶望平蕪。", "即此恡音素，焉知中密疎。", "渴者不思火，寒者不求水。", "人生羈寓時，去就當如此。", "猶希心異跡，眷眷存終始。"]'),
('40a24028-d0b4-4bb6-8822-5cdde7c21452','聽嘉陵江水聲寄深上人','韋應物','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u54f2\u7406", "\u5199\u6c34"]','鑿崖泄奔湍，稱古神禹跡。',60,'全唐诗/poet.tang.8000.json','["鑿崖泄奔湍，稱古神禹跡。", "夜喧山門店，獨宿不安席。", "水性自云靜，石中本無聲。", "如何兩相激，雷轉空山驚。", "貽之道門舊，了此物我情。"]'),
('3469293b-e10f-43e6-b8de-f178267573df','高陵書情寄三原盧少府','韋應物','唐','唐诗','tang','','[]','直方難爲進，守此微賤班。',72,'全唐诗/poet.tang.8000.json','["直方難爲進，守此微賤班。", "開卷不及顧，沈埋案牘間。", "兵凶久相踐，徭賦豈得閑。", "促戚下可哀，寬政身致患。", "日夕思自退，出門望故山。", "君心儻如此，攜手相與還。"]'),
('511e6810-5192-4cae-86a0-ba35f3a08bed','假中對雨呈縣中僚友','韋應物','唐','唐诗','tang','','[]','卻足甘爲笑，閑居夢杜陵。',48,'全唐诗/poet.tang.8000.json','["卻足甘爲笑，閑居夢杜陵。", "殘鶯知夏淺，社雨報年登。", "流麥非關忘，收書獨不能。", "自然憂曠職，緘此謝良朋。"]'),
('acc7d44e-53fe-475f-b9a7-a0925821df1f','贈蕭河南','韋應物','唐','唐诗','tang','','[]','厭劇辭京縣，褒賢待詔書。',48,'全唐诗/poet.tang.8000.json','["厭劇辭京縣，褒賢待詔書。", "酇侯方繼業，潘令且閑居。", "霽後三川冷，秋深萬木疎。", "對琴無一事，新興復何如。"]'),
('51060b19-f87f-4c53-9c6b-6015eb4aae1f','示從子河南尉班','韋應物','唐','唐诗','tang','','[]','拙直余恆守，公方爾所存。',48,'全唐诗/poet.tang.8000.json','["拙直余恆守，公方爾所存。", "同占朱鳥剋，俱起小人言。", "立政思懸棒，謀身類觸藩。", "不能林下去，祗戀府廷恩。"]'),
('14534ea6-ff68-4d27-a2c8-7d19f158ddf3','趨府候曉呈兩縣僚友','韋應物','唐','唐诗','tang','','[]','趨府不遑安，中宵出戶看。',48,'全唐诗/poet.tang.8000.json','["趨府不遑安，中宵出戶看。", "滿天星尚在，近壁燭仍殘。", "立馬頻驚曙，垂簾却避寒。", "可憐同宦者，應悟下流難。"]'),
('acc986d8-cf6d-4a12-8b28-a583a9607144','贈李儋','韋應物','唐','唐诗','tang','','[]','絲桐本異質，音響合自然。',60,'全唐诗/poet.tang.8000.json','["絲桐本異質，音響合自然。", "吾觀造化意，二物相因緣。", "誤觸龍鳳嘯，靜聞寒夜泉。", "心神自安宅，煩慮頓可捐。", "何因知久要，絲白漆亦堅。"]'),
('b26701df-5d43-4394-9402-2ced1822df0c','贈盧嵩','韋應物','唐','唐诗','tang','','[]','百川注東海，東海無虛盈。',84,'全唐诗/poet.tang.8000.json','["百川注東海，東海無虛盈。", "泥滓不能濁，澄波非益清。", "恬然自安流，日照萬里晴。", "雲物不隱象，三山共分明。", "奈何疾風怒，忽若砥柱傾。", "海水雖無心，洪濤亦相驚。", "怒號在倏忽，誰識變化情。"]'),
('38db14c8-8909-4764-b768-37500d13ca6c','寄馮著','韋應物','唐','唐诗','tang','','[]','春雷起萌蟄，土壤日已疎。',96,'全唐诗/poet.tang.8000.json','["春雷起萌蟄，土壤日已疎。", "胡能遭盛明，才俊伏里閭。", "偃仰遂真性，所求惟斗儲。", "披衣出茅屋，盥漱臨清渠。", "吾道亦自適，退身保玄虛。", "幸無職事牽，且覽案上書。", "親友各馳騖，誰當訪敝廬。", "思君在何夕，明月照廣除。"]'),
('c1152d7e-75af-4611-8d90-420ac2c3b01a','早春對雪寄前殿中元侍御','韋應物','唐','唐诗','tang','','[]','掃雪開幽徑，端居望故人。',48,'全唐诗/poet.tang.8000.json','["掃雪開幽徑，端居望故人。", "猶殘臘月酒，更值早梅春。", "幾日東城陌，何時曲水濱。", "聞閑且共賞，莫待繡衣新。"]'),
('ecafcfe1-2f57-4c28-aef2-13e92857a524','贈王侍御','韋應物','唐','唐诗','tang','','[]','心同野鶴與塵遠，詩似冰壺見底清。',64,'全唐诗/poet.tang.8000.json','["心同野鶴與塵遠，詩似冰壺見底清。", "府縣同趨昨日事，升沈不改故人情。", "上陽秋晚蕭蕭雨，洛水寒來夜夜聲。", "自歎猶爲折腰吏，可憐驄馬路傍行。"]'),
('5b08c0f6-ab25-41d6-afa2-e308faa52342','將往江淮寄李十九儋','韋應物','唐','唐诗','tang','','[]','燕燕東向來，文鵷亦西飛。',72,'全唐诗/poet.tang.8000.json','["燕燕東向來，文鵷亦西飛。", "如何不相見，羽翼有高卑。", "徘徊到河洛，華屋未及窺。", "秋風飄我行，遠與淮海期。", "廻首隔煙霧，遙遙兩相思。", "陽春自當返，短翮欲追隨。"]'),
('d9a042d5-c2ef-42b1-8413-b7321440466d','自鞏洛舟行入黃河即事寄府縣僚友','韋應物','唐','唐诗','tang','','["\u9ec4\u6cb3"]','夾水蒼山路向東，東南山豁大河通。',64,'全唐诗/poet.tang.8000.json','["夾水蒼山路向東，東南山豁大河通。", "寒樹依微遠天外，夕陽明滅亂流中。", "孤村幾歲臨伊岸，一鴈初晴下朔風。", "爲報洛橋遊宦侶，扁舟不繫與心同。"]'),
('0746182f-5825-41be-95b8-8e218ca6ae32','寄盧庾','韋應物','唐','唐诗','tang','','[]','悠悠遠離別，分此歡會難。',84,'全唐诗/poet.tang.8000.json','["悠悠遠離別，分此歡會難。", "如何兩相近，反使心不安。", "亂髮思一櫛，垢衣思一浣。", "豈如望友生，對酒起長嘆。", "時節異京洛，孟冬天未寒。", "廣陵多車馬，日夕自遊盤。", "獨我何耿耿，非君誰爲歡。"]'),
('31b2bab2-19eb-46e8-8d1a-fca253be333a','發廣陵留上家兄兼寄上長沙','韋應物','唐','唐诗','tang','','[]','將違安可懷，宿戀復一方。',120,'全唐诗/poet.tang.8000.json','["將違安可懷，宿戀復一方。", "家貧無舊業，薄宦各飄颺。", "執板身有屬，淹時心恐惶。", "拜言不得留，聲結淚滿裳。", "漾漾動行舫，亭亭遠相望。", "離晨苦須臾，獨往道路長。", "蕭條風雨過，得此海氣涼。", "感秋意已違，況自結中腸。", "推道固當遣，及情豈所忘。", "何時共還歸，舉翼鳴春陽。"]'),
('5b3a5651-2a80-4fb1-b1bf-c9fb5ec38905','初發揚子寄元大校書','韋應物','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u79bb\u522b", "\u4e94\u8a00\u53e4\u8bd7", "\u4f9d\u604b"]','悽悽去親愛，泛泛入煙霧。',48,'全唐诗/poet.tang.8000.json','["悽悽去親愛，泛泛入煙霧。", "歸棹洛陽人，殘鐘廣陵樹。", "今朝此爲別，何處還相遇。", "世事波上舟，沿洄安得住。"]'),
('b72e4b62-fc1c-4866-a964-6651f05cca64','淮上即事寄廣陵親故','韋應物','唐','唐诗','tang','','[]','前舟已眇眇，欲渡誰相持。',48,'全唐诗/poet.tang.8000.json','["前舟已眇眇，欲渡誰相持。", "秋山起暮鐘，楚雨連滄海。", "風波離思滿，宿昔容鬢改。", "獨鳥下東南，廣陵何處在。"]'),
('4ff430d2-bacf-41c1-97f0-19fa2f66b620','寄洪州幕府二十一侍御','韋應物','唐','唐诗','tang','','[]','忽報南昌令，乘驄入郡城。',48,'全唐诗/poet.tang.8000.json','["忽報南昌令，乘驄入郡城。", "同時趨府客，此日望塵迎。", "文苑臺中妙，冰壺幕下清。", "洛陽相去遠，猶使故林榮。"]'),
('b1e3be40-892a-4867-bf55-f68fac532fad','經少林精舍寄都邑親友','韋應物','唐','唐诗','tang','','[]','息駕依松嶺，高閣一攀緣。',72,'全唐诗/poet.tang.8000.json','["息駕依松嶺，高閣一攀緣。", "前瞻路已窮，既詣喜更延。", "出巘聽萬籟，入林濯幽泉。", "鳴鐘生道心，暮磬空雲煙。", "獨往雖暫適，多累終見牽。", "方思結茅地，歸息期暮年。"]'),
('9c7b9466-bb57-4aa1-9144-b474fb38ecef','同長源歸南徐寄子西子烈有道','韋應物','唐','唐诗','tang','','[]','東洛何蕭條，相思邈遐路。',84,'全唐诗/poet.tang.8000.json','["東洛何蕭條，相思邈遐路。", "策駕復誰遊，入門無與晤。", "還因送歸客，達此緘中素。", "屢暌心所歡，豈得顏如故。", "所歡不可暌，嚴霜晨淒淒。", "如彼萬里行，孤妾守空閨。", "臨觴一長嘆，素欲何時諧。"]'),
('8df2abdf-1b4f-43d5-9bf4-bab1d9debb04','雪中聞李儋過門不訪聊以寄贈','韋應物','唐','唐诗','tang','','[]','度門能不訪，冒雪屢西東。',48,'全唐诗/poet.tang.9000.json','["度門能不訪，冒雪屢西東。", "已想人如玉，遙憐馬似驄。", "乍迷金谷路，稍變上陽宮。", "還比相思意，紛紛正滿空。"]'),
('3f7ee19b-eada-416a-8932-66779e0a79f2','同德精舍養疾寄河南兵曹東廳掾','韋應物','唐','唐诗','tang','','[]','逍遙東城隅，雙樹寒葱蒨。',84,'全唐诗/poet.tang.9000.json','["逍遙東城隅，雙樹寒葱蒨。", "廣庭流華月，高閣凝餘霰。", "杜門非養素，抱疾阻良讌。", "孰謂無他人，思君歲云變。", "官曹亮先忝，陳躅慙俊彥。", "豈知晨與夜，相代不相見。", "緘書問所如，詶藻當芬絢。"]'),
('f6200028-1512-4eaa-86d6-dcff74906953','同德寺雨後寄元侍御李博士','韋應物','唐','唐诗','tang','','[]','川上風雨來，須臾滿城闕。',72,'全唐诗/poet.tang.9000.json','["川上風雨來，須臾滿城闕。", "岧嶢青蓮界，蕭條孤興發。", "前山遽已淨，陰靄夜來歇。", "喬木生夏涼，流雲吐華月。", "嚴城自有限，一水非難越。", "相望曙河遠，高齋坐超忽。"]'),
('1c80b8f0-8478-4174-a49a-19d975ef7dc0','同德閣期元侍御李博士不至各投贈二首 一','韋應物','唐','唐诗','tang','','[]','庭樹忽已暗，故人那不來。',24,'全唐诗/poet.tang.9000.json','["庭樹忽已暗，故人那不來。", "祗因厭煩暑，永日坐霜臺。"]'),
('d7432ef1-43f0-49b4-b4ef-541c15db749e','同德閣期元侍御李博士不至各投贈二首 二','韋應物','唐','唐诗','tang','','[]','官榮多所繫，閑居亦愆期。',24,'全唐诗/poet.tang.9000.json','["官榮多所繫，閑居亦愆期。", "高閣猶相望，青山欲暮時。"]'),
('f18c3b7c-c1ea-429d-9b11-7071275e9eb9','使雲陽寄府曹','韋應物','唐','唐诗','tang','','[]','夙駕祗府命，冒炎不遑息。',108,'全唐诗/poet.tang.9000.json','["夙駕祗府命，冒炎不遑息。", "百里次雲陽，閭閻問漂溺。", "上天屢愆氣，胡不均寸澤。", "仰瞻喬樹巔，見此洪流跡。", "良苗免湮沒，蔓草生宿昔。", "頹墉滿故墟，喜返將安宅。", "周旋涉塗潦，側峭緣溝脉。", "仁賢憂斯民，賤子甘所役。", "公堂衆君子，言笑思與覿。"]'),
('2c3b2e00-f29e-456d-9de2-34fce2dfc1ba','過扶風精舍舊居簡朝宗巨川兄弟','韋應物','唐','唐诗','tang','','[]','佛剎出高樹，晨光閭井中。',84,'全唐诗/poet.tang.9000.json','["佛剎出高樹，晨光閭井中。", "年深念陳迹，迨此獨忡忡。", "零落逢故老，寂寥悲草蟲。", "舊宇多改構，幽篁延本叢。", "栖止事如昨，芳時去已空。", "佳人亦攜手，再往今不同。", "新文聊感舊，想子意無窮。"]'),
('e7fa583c-e983-4518-9005-bbc2b2fae23a','贈令狐士曹','韋應物','唐','唐诗','tang','','[]','秋簷滴滴對牀寢，山路迢迢聯騎行。',32,'全唐诗/poet.tang.9000.json','["秋簷滴滴對牀寢，山路迢迢聯騎行。", "到家俱及東籬菊，何事先歸半日程。"]'),
('13754f15-8ec6-4d8d-b697-a65309992128','贈馮著','韋應物','唐','唐诗','tang','','[]','契闊仕兩京，念子亦飄蓬。',96,'全唐诗/poet.tang.9000.json','["契闊仕兩京，念子亦飄蓬。", "方來屬追往，十載事不同。", "歲晏乃云至，微褐還未充。", "慘悽遊子情，風雪自關東。", "華觴發懽顏，嘉藻播清風。", "始此盈抱恨，曠然一夕中。", "善蘊豈輕售，懷才希國工。", "誰當念素士，零落歲華空。"]'),
('2e4ba324-7f45-4a75-ac89-d335d8ef0ff9','對雨寄韓庫部協','韋應物','唐','唐诗','tang','','[]','颯至池館涼，靄然和曉霧。',48,'全唐诗/poet.tang.9000.json','["颯至池館涼，靄然和曉霧。", "蕭條集新荷，氤氳散高樹。", "閑居興方澹，默想心已屢。", "暫出仍濕衣，況君東城住。"]'),
('f44eb280-078e-47e6-95b1-91f9b8b4980b','寄子西','韋應物','唐','唐诗','tang','','[]','夏景已難度，懷賢思方續。',72,'全唐诗/poet.tang.9000.json','["夏景已難度，懷賢思方續。", "喬樹落疎陰，微風散煩燠。", "傷離枉芳札，忻遂見心曲。", "藍上舍已成，田家雨新足。", "託鄰素多欲，殘帙猶見束。", "日夕上高齋，但望東原綠。"]'),
('8eb29b0f-72d8-437e-b798-9b2da4411355','縣內閑居贈溫公','韋應物','唐','唐诗','tang','','[]','滿郭春[風]嵐已昏，鴉栖散吏掩重門。',34,'全唐诗/poet.tang.9000.json','["滿郭春[風]嵐已昏，鴉栖散吏掩重門。", "雖居世網常清淨，夜對高僧無一言。"]'),
('cc01356f-bc55-4736-aa6f-cefb16557b61','對雪贈徐秀才','韋應物','唐','唐诗','tang','','[]','靡靡寒欲收，靄靄陰還結。',48,'全唐诗/poet.tang.9000.json','["靡靡寒欲收，靄靄陰還結。", "晨起望南端，千林散春雪。", "妍光屬瑤階，亂緒陵新節。", "無爲掩扉臥，獨守袁生轍。"]'),
('7bf23e05-60e2-4b35-b5a1-b1b78fe8a1ad','西郊遊宴寄贈邑僚李巽','韋應物','唐','唐诗','tang','','[]','升陽曖春物，置酒臨芳席。',84,'全唐诗/poet.tang.9000.json','["升陽曖春物，置酒臨芳席。", "高宴闕英僚，衆賓寡懽懌。", "是時尚多壘，板築興頹壁。", "羇旅念越疆，領徒方祗役。", "如何嘉會日，當子憂勤夕。", "西郊鬱已茂，春嵐重如積。", "何當返徂雨，雜英紛可惜。"]'),
('200d19a9-28c9-42b1-b4b0-f60a5ac9d376','對雨贈李主簿高秀才','韋應物','唐','唐诗','tang','','[]','邐迤曙雲薄，散漫東風來。',48,'全唐诗/poet.tang.9000.json','["邐迤曙雲薄，散漫東風來。", "青山滿春野，微雨灑輕埃。", "吏局勞佳士，賓筵得上才。", "終朝狎文墨，高興共徘徊。"]'),
('4fab1420-150e-4d48-be58-818481e5b345','休沐東還胄貴里示端','韋應物','唐','唐诗','tang','','[]','宦遊三十載，田野久已疎。',120,'全唐诗/poet.tang.9000.json','["宦遊三十載，田野久已疎。", "休沐遂茲日，一來還故墟。", "山明宿雨霽，風煖百卉舒。", "泓泓野泉潔，熠熠林光初。", "竹木稍摧翳，園場亦荒蕪。", "俯驚鬢已衰，周覽昔所娛。", "存沒惻私懷，遷變傷里閭。", "欲言少留心，中復畏簡書。", "世道良自退，榮名亦空虛。", "與子終攜手，歲晏當來居。"]'),
('3b4bf381-68b3-41e8-a79e-07d8b6de6693','朝請後還邑寄諸友生','韋應物','唐','唐诗','tang','','[]','宰邑分甸服，夙駕朝上京。',120,'全唐诗/poet.tang.9000.json','["宰邑分甸服，夙駕朝上京。", "是時當暮春，休沐集友生。", "抗志青雲表，俱踐高世名。", "樽酒且歡樂，文翰亦縱橫。", "良遊昔所希，累讌夜復明。", "晨露含瑤琴，夕風殞素英。", "一旦遵歸路，伏軾出京城。", "誰言再念別，忽若千里行。", "閑閤寡喧訟，端居結幽情。", "況茲晝方永，展轉何由平。"]'),
('6d5d75b0-00ae-4cf7-b363-c93a09094a79','灃上西齋寄諸友','韋應物','唐','唐诗','tang','','[]','絕岸臨西野，曠然塵事遙。',96,'全唐诗/poet.tang.9000.json','["絕岸臨西野，曠然塵事遙。", "清川下邐迤，茅棟上岧嶢。", "翫月愛佳夕，望山屬清朝。", "俯砌視歸翼，開襟納遠飆。", "等陶辭小秩，效朱方負樵。", "閑遊忽無累，心跡隨景超。", "明世重才彥，雨露降丹霄。", "羣公正雲集，獨予忻寂寥。"]'),
('69b265f8-bbee-4c80-9cd3-c98960c9cef4','獨遊西齋寄崔主簿','韋應物','唐','唐诗','tang','','[]','同心忽已別，昨事方成昔。',48,'全唐诗/poet.tang.9000.json','["同心忽已別，昨事方成昔。", "幽徑還獨尋，綠苔見行跡。", "秋齋正蕭散，烟水易昏夕。", "憂來結幾重，非君不可釋。"]'),
('612ef8d1-e061-4e42-99ca-e73986831570','紫閣東林居士叔緘賜松英丸捧對忻喜蓋非塵侶之所當服輙獻詩代啓','韋應物','唐','唐诗','tang','','[]','碧澗蒼松五粒稀，侵雲采去露沾衣。',64,'全唐诗/poet.tang.9000.json','["碧澗蒼松五粒稀，侵雲采去露沾衣。", "夜啓羣僊合靈藥，朝思俗侶寄將歸。", "道場齋戒今初服，人事葷羶已覺非。", "一望嵐峰拜還使，腰間銅印與心違。"]'),
('2e5edb07-51bb-4c8f-8eb8-19f18ab58f84','秋集罷還途中作謹獻壽春公黎公','韋應物','唐','唐诗','tang','','[]','束帶自衡門，奉命宰王畿。',144,'全唐诗/poet.tang.9000.json','["束帶自衡門，奉命宰王畿。", "君侯枉高鑒，舉善掩瑕疵。", "斯民本已安，工拙兩無施。", "何以酬明德，歲晏不磷緇。", "時節乃來集，欣懷方載馳。", "平明大府開，一得拜光輝。", "溫如春風至，肅若嚴霜威。", "羣屬所載瞻，而忘倦與飢。", "公堂燕華筵，禮罷復言辭。", "將從平門道，憩車灃水湄。", "山川降嘉歲，草木蒙潤滋。", "孰云還本邑，懷戀獨遲遲。"]'),
('7f287df2-96b4-4dff-b299-a4518ffc35f3','閑居贈友','韋應物','唐','唐诗','tang','','[]','補吏多下遷，罷歸聊自度。',96,'全唐诗/poet.tang.9000.json','["補吏多下遷，罷歸聊自度。", "園廬既蕪沒，煙景空澹泊。", "閑居養疴瘵，守素甘葵藿。", "顏鬢日衰耗，冠帶亦寥落。", "青苔已生路，綠筠始分籜。", "夕氣下遙陰，微風動疎薄。", "草玄良見誚，杜門無請託。", "非君好事者，誰來顧寂寞。"]'),
('100f4e4a-9884-4c89-8b2d-9e3d3a9a4d42','四禪精舍登覽悲舊寄朝宗巨川兄弟','韋應物','唐','唐诗','tang','','[]','蕭散人事憂，迢遰古原行。',108,'全唐诗/poet.tang.9000.json','["蕭散人事憂，迢遰古原行。", "春風日已暄，百草亦復生。", "躋閣謁金像，攀雲造禪扃。", "新景林際曙，雜花川上明。", "徂歲方緬邈，陳事尚縱橫。", "溫泉有佳氣，馳道指京城。", "攜手思故日，山河留恨情。", "存者邈難見，去者已冥冥。", "臨風一長慟，誰畏行路驚。"]'),
('22513478-2b2a-42d7-8fe8-b183545869c9','善福閣對雨寄李儋幼遐','韋應物','唐','唐诗','tang','','[]','飛閣凌太虛，晨躋鬱崢嶸。',132,'全唐诗/poet.tang.9000.json','["飛閣凌太虛，晨躋鬱崢嶸。", "驚飆觸懸檻，白雲冒層甍。", "太陰布其地，密雨垂八紘。", "仰觀固不測，俯視但冥冥。", "感此窮秋氣，沈鬱命友生。", "及時未高步，羇旅遊帝京。", "聖朝無隱才，品物俱昭形。", "國士秉繩墨，何以表堅貞。", "寸心東北馳，思與一會幷。", "我車夙已駕，將逐晨風征。", "郊塗住成淹，默默阻中情。"]'),
('cab08611-682e-4650-9b8a-365f7e46ee5e','寺居獨夜寄崔主簿','韋應物','唐','唐诗','tang','','[]','幽人寂不寐，木葉紛紛落。',48,'全唐诗/poet.tang.9000.json','["幽人寂不寐，木葉紛紛落。", "寒雨暗深更，流螢度高閣。", "坐使青燈曉，還傷夏衣薄。", "寧知歲方晏，離居更蕭索。"]'),
('829b6820-b69d-4ac5-b31c-434e9daf366b','九日灃上作寄崔主簿倬二李端擊','韋應物','唐','唐诗','tang','','[]','淒淒感時節，望望臨灃涘。',96,'全唐诗/poet.tang.9000.json','["淒淒感時節，望望臨灃涘。", "翠嶺明華秋，高天澄遙滓。", "川寒流愈迅，霜交物初委。", "林葉索已空，晨禽迎飆起。", "時菊乃盈泛，濁醪自爲美。", "良遊雖可娛，殷念在之子。", "人生不自省，營欲無終已。", "孰能同一酌，陶然冥斯理。"]'),
('12ce42f9-c3de-4d4d-b33c-b4e8186dc226','西郊養疾聞暢校書有新什見贈久佇不至先寄此詩','韋應物','唐','唐诗','tang','','[]','養病愜清夏，郊園敷卉木。',72,'全唐诗/poet.tang.9000.json','["養病愜清夏，郊園敷卉木。", "牕夕含澗涼，雨餘愛筠綠。", "披懷始高詠，對琴轉幽獨。", "仰子遊羣英，吐詞如蘭馥。", "還聞枉嘉藻，佇望延昏旭。", "唯見草青青，閉戶灃水曲。"]'),
('623c10f7-3d51-41c4-88fc-2be143ef81a7','灃上寄幼遐','韋應物','唐','唐诗','tang','','[]','寂寞到城闕，惆悵返柴荆。',108,'全唐诗/poet.tang.9000.json','["寂寞到城闕，惆悵返柴荆。", "端居無所爲，念子遠徂征。", "夏晝人已息，我懷獨未寧。", "忽從東齋起，兀兀尋澗行。", "罥罣叢榛密，披玩孤花明。", "曠然西南望，一極山水情。", "周覽同遊處，逾恨阻音形。", "壯圖非旦夕，君子勤令名。", "勿復久留燕，蹉跎在北京。"]'),
('a71b9518-7c15-4726-939d-5a8d5b612911','善福精舍示諸生','韋應物','唐','唐诗','tang','','[]','湛湛嘉樹陰，清露夜景沈。',72,'全唐诗/poet.tang.9000.json','["湛湛嘉樹陰，清露夜景沈。", "悄然羣物寂，高閣似陰岑。", "方以玄默處，豈爲名跡侵。", "法妙不知歸，獨此抱沖襟。", "齋舍無餘物，陶器與單衾。", "諸生時列坐，共愛風滿林。"]'),
('18e1c375-cf0d-45ee-be07-c4e577256eeb','晚出灃上贈崔都水','韋應物','唐','唐诗','tang','','[]','臨流一舒嘯，望山意轉延。',72,'全唐诗/poet.tang.9000.json','["臨流一舒嘯，望山意轉延。", "隔林分落景，餘霞明遠川。", "首起趣東作，已看耘夏田。", "一從民里居，歲月再徂遷。", "昧質得全性，世名良自牽。", "行忻攜手歸，聊復飲酒眠。"]'),
('f44453fa-d035-463a-b0c1-e496f413be10','寓居灃上精舍于張二舍人','韋應物','唐','唐诗','tang','','[]','萬木叢雲出香閣，西連碧澗竹林園。',64,'全唐诗/poet.tang.9000.json','["萬木叢雲出香閣，西連碧澗竹林園。", "高齋猶宿遠山曙，微霰下庭寒雀喧。", "道心淡泊對流水，生事蕭疎空掩門。", "時憶故交那得見，曉排閶闔奉明恩。"]'),
('c662609f-7fb0-459a-8ad2-68c6ae44b63c','開元觀懷舊寄李二韓二裴四兼呈崔郎中嚴家令','韋應物','唐','唐诗','tang','','[]','宿昔清都燕，分散各西東。',48,'全唐诗/poet.tang.9000.json','["宿昔清都燕，分散各西東。", "車馬行跡在，霜雪竹林空。", "方軫故五念，誰復一樽同。", "聊披道書暇，還此聽松風。"]'),
('628f68ba-02c9-4663-9c34-55373fd59f31','春日郊居寄萬年吉少府中孚三原少府偉夏侯校書審','韋應物','唐','唐诗','tang','','[]','谷鳥時一囀，田園春雨餘。',48,'全唐诗/poet.tang.9000.json','["谷鳥時一囀，田園春雨餘。", "光風動林早，高牕照日初。", "獨飲澗中水，吟詠老氏書。", "城闕應多事，誰憶此閑居。"]'),
('09245ef2-abd7-4ca9-81bb-6fe56a6ca3f2','灃上醉題寄滌武','韋應物','唐','唐诗','tang','','[]','芳園知夕燕，西郊已獨還。',24,'全唐诗/poet.tang.9000.json','["芳園知夕燕，西郊已獨還。", "誰言不同賞，俱是醉花間。"]'),
('342047fb-4d9d-4f7f-857e-008fe5ff7c43','西郊期滌武不至書示','韋應物','唐','唐诗','tang','','[]','山高鳴過雨，澗樹落殘花。',24,'全唐诗/poet.tang.9000.json','["山高鳴過雨，澗樹落殘花。", "非關春不待，當由期自賒。"]'),
('6df5b6e1-6755-40bc-a67c-efc1213e5b5b','灃上對月寄孔諫議','韋應物','唐','唐诗','tang','','[]','思懷在雲闕，泊素守中林。',24,'全唐诗/poet.tang.9000.json','["思懷在雲闕，泊素守中林。", "出處雖殊跡，明月兩知心。"]'),
('ad7458ba-a75d-4dfc-89b9-54d9c9613d17','將往滁城戀新竹簡崔都水示端','韋應物','唐','唐诗','tang','','[]','停車欲去繞叢竹，偏愛新筠十數竿。',32,'全唐诗/poet.tang.9000.json','["停車欲去繞叢竹，偏愛新筠十數竿。", "莫遣兒童觸瓊粉，留待幽人廻日看。"]'),
('10fa8c7c-77ca-4602-915a-9e336a6e47b8','還闕首途寄精舍親友','韋應物','唐','唐诗','tang','','[]','休沐日云滿，沖然將罷觀。',60,'全唐诗/poet.tang.9000.json','["休沐日云滿，沖然將罷觀。", "嚴車候門側，晨起正朝冠。", "山澤含餘雨，川澗注驚湍。", "攬轡遵東路，廻首一長嘆。", "居人已不見，高閣在林端。"]'),
('55940ba8-1a3a-4dc6-a56a-e7e24f8eb55d','秋夜南宮寄灃上弟及諸生','韋應物','唐','唐诗','tang','','[]','暝色起煙閣，沈抱積離憂。',48,'全唐诗/poet.tang.9000.json','["暝色起煙閣，沈抱積離憂。", "況茲風雨夜，蕭條梧葉秋。", "空宇感涼至，頹顏驚歲周。", "日夕遊闕下，山水憶同遊。"]'),
('3814497e-2add-45ca-8d72-5c63f5b02e52','途中書情寄灃上兩弟因送二甥却還','韋應物','唐','唐诗','tang','','[]','華簪豈足戀，幽林徒自違。',36,'全唐诗/poet.tang.9000.json','["華簪豈足戀，幽林徒自違。", "遙知別後意，寂寞掩郊扉。", "廻首昆池上，更羨爾同歸。"]'),
('3bb7212c-1a89-4317-a4a2-50e3c769cfb7','雪夜下朝呈省中一絕','韋應物','唐','唐诗','tang','','[]','南望青山滿禁闈，曉陪鴛鷺正差池。',32,'全唐诗/poet.tang.9000.json','["南望青山滿禁闈，曉陪鴛鷺正差池。", "共愛朝來何處雪，蓬萊宮裏拂松枝。"]'),
('3f7fb6e7-251a-4727-af3a-d15ac65bf8b9','寄柳州韓司戶郎中','韋應物','唐','唐诗','tang','','[]','達識與昧機，智殊迹同靜。',108,'全唐诗/poet.tang.9000.json','["達識與昧機，智殊迹同靜。", "於焉得攜手，屢賞清夜景。", "瀟灑陪高詠，從容羨華省。", "一逐風波遷，南登桂陽嶺。", "舊里門空掩，歡遊事皆屏。", "悵望城闕遙，幽居時序永。", "春風吹百卉，和煦變閭井。", "獨悶終日眠，篇書不復省。", "唯當望雨露，霑子荒遐境。"]'),
('42f2e8a2-92a0-4313-affc-0c84adcdc54b','寄令狐侍郎','韋應物','唐','唐诗','tang','','[]','三山有瓊樹，霜雪色逾新。',144,'全唐诗/poet.tang.9000.json','["三山有瓊樹，霜雪色逾新。", "始自風塵交，中結綢繆姻。", "西掖方掌誥，南宮復司春。", "夕燕華池月，朝奉玉階塵。", "衆寶歸和氏，吹噓多俊人。", "羣公共然諾，聲問邁時倫。", "孤鴻既高舉，燕雀在荆榛。", "翔集且不同，豈不欲殷勤。", "一旦遷南郡，江湖渺無垠。", "寵辱良未定，君子豈緇磷。", "寒暑已推斥，別離生苦辛。", "非將會面目，書札何由申。"]'),
('4ba2371d-b993-4f0b-93bb-eb76292f108a','閑居寄端及重陽','韋應物','唐','唐诗','tang','','[]','山明野寺曙鐘微，雪滿幽林人跡稀。',32,'全唐诗/poet.tang.9000.json','["山明野寺曙鐘微，雪滿幽林人跡稀。", "閑居寥落生高興，無事風塵獨不歸。"]'),
('2ab1f275-24c7-4cbc-a8c0-402573836d3c','園林晏起寄昭應韓明府盧主簿','韋應物','唐','唐诗','tang','','[]','田家已耕作，井屋起晨煙。',96,'全唐诗/poet.tang.9000.json','["田家已耕作，井屋起晨煙。", "園林鳴好鳥，閑居猶獨眠。", "不覺朝已晏，起來望青天。", "四體一舒散，情性亦忻然。", "還復茅簷下，對酒思數賢。", "束帶理官府，簡牘盈目前。", "當念中林賞，覽物遍山川。", "上非遇明世，庶以道自全。"]'),
('9e292d6d-b50a-45d7-80e3-b612c2e87992','寄大梁諸友','韋應物','唐','唐诗','tang','','[]','分竹守南譙，弭節過梁池。',84,'全唐诗/poet.tang.9000.json','["分竹守南譙，弭節過梁池。", "雄都衆君子，出餞擁河湄。", "燕謔始云洽，方舟已解維。", "一爲風水便，但見山川馳。", "昨日次睢陽，今夕宿符離。", "雲樹愴重疊，烟波念還期。", "相敦在勤事，海內方勞師。"]'),
('cef91792-2815-4dce-8db8-b86912b9a6b7','新秋夜寄諸弟','韋應物','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u79cb\u5929", "\u76f8\u601d", "\u601d\u5f52"]','兩地俱秋夕，相望共星河。',48,'全唐诗/poet.tang.9000.json','["兩地俱秋夕，相望共星河。", "高梧一葉下，空齋歸思多。", "方用憂人瘼，況自抱微痾。", "無將別來近，顏鬢已蹉跎。"]'),
('7b3d902f-2207-47eb-bca7-c5ba1c9c8fdb','郊園聞蟬寄諸弟','韋應物','唐','唐诗','tang','','[]','去歲郊園別，聞蟬在蘭省。',48,'全唐诗/poet.tang.9000.json','["去歲郊園別，聞蟬在蘭省。", "今歲臥南譙，蟬鳴歸路永。", "夕響依山谷，餘悲散秋景。", "緘書報此時，此心方耿耿。"]'),
('3c6708c6-f6d7-488a-9784-a8f75ea8f5ad','寄中書劉舍人','韋應物','唐','唐诗','tang','','[]','雲霄路竟別，中年跡暫同。',120,'全唐诗/poet.tang.9000.json','["雲霄路竟別，中年跡暫同。", "比翼趨丹陛，連騎下南宮。", "佳詠邀清月，幽賞滯芳藂。", "迨予一出守，與子限西東。", "晨露方愴愴，離抱更忡忡。", "忽睹九天詔，秉綸歸國工。", "玉座浮香氣，秋禁散涼風。", "應向橫門度，環珮杳玲瓏。", "光輝恨未矚，歸思坐難通。", "蒼蒼松桂姿，想在掖垣中。"]'),
('be54a9d9-f2b3-415a-90ec-0ed7708e64f2','郡齋感秋寄諸弟','韋應物','唐','唐诗','tang','','[]','首夏辭舊國，窮秋臥滁城。',120,'全唐诗/poet.tang.9000.json','["首夏辭舊國，窮秋臥滁城。", "方如昨日別，忽覺徂歲驚。", "高閣收煙霧，池水晚澄清。", "戶牖已淒爽，晨夜感深情。", "昔遊郎署間，是月天氣晴。", "授衣還西郊，曉露田中行。", "采菊投酒中，昆弟自同傾。", "簪組聊掛壁，焉知有世榮。", "一旦居遠郡，山川間音形。", "大道庶無累，及茲念已盈。"]'),
('76a434d0-25eb-4103-ae98-299c0cc9beab','郡中對雨贈元錫兼簡楊凌','韋應物','唐','唐诗','tang','','[]','宿雨冒空山，空城響秋葉。',60,'全唐诗/poet.tang.9000.json','["宿雨冒空山，空城響秋葉。", "沈沈暮色至，淒淒涼氣入。", "蕭條林表散，的礫荷上集。", "夜霧著衣重，新苔侵履濕。", "遇茲端憂日，賴與嘉賓接。"]'),
('286f7688-8876-4264-8ce6-ecb451a38223','冬至夜寄京師諸弟兼懷崔都水','韋應物','唐','唐诗','tang','','[]','理郡無異政，所憂在素飡。',96,'全唐诗/poet.tang.9000.json','["理郡無異政，所憂在素飡。", "徒令去京國，羈旅當歲寒。", "子月生一氣，陽景極南端。", "已懷時節感，更抱別離酸。", "私燕席云罷，還齋夜方闌。", "邃幕沈空宇，孤燈照牀單。", "應同茲夕念，寧忘故歲歡。", "川途恍悠邈，涕下一闌干。"]'),
('7babe39c-9fe0-4a82-9b37-c1ab323f3f8b','元日寄諸弟兼呈崔都水','韋應物','唐','唐诗','tang','','[]','一從守茲郡，兩鬢生素髮。',72,'全唐诗/poet.tang.9000.json','["一從守茲郡，兩鬢生素髮。", "新正加我年，故歲去超忽。", "淮濱益時候，了似仲秋月。", "川谷風景溫，城池草木發。", "高齋屬多暇，惆悵臨芳物。", "日月昧還期，念君何時歇。"]'),
('a9f434df-6382-4255-9d63-9f4ca0a77d1c','寄職方劉郎中','韋應物','唐','唐诗','tang','','[]','相聞二十載，不得展平生。',108,'全唐诗/poet.tang.9000.json','["相聞二十載，不得展平生。", "一夕南宮遇，聊用寫中情。", "端服光朝次，羣烈慕英聲。", "歸來坐粉闈，揮筆乃縱橫。", "始陪文翰遊，歡燕難久幷。", "予因謬忝出，君爲沈疾嬰。", "別離寒暑過，荏苒春草生。", "故園茲日隔，新禽池上鳴。", "郡中永無事，歸思徒自盈。"]'),
('5be4cbc5-1ccd-471f-8401-cdc83b732711','社日寄崔都水及諸弟羣屬','韋應物','唐','唐诗','tang','','[]','山郡多暇日，社時放吏歸。',48,'全唐诗/poet.tang.9000.json','["山郡多暇日，社時放吏歸。", "坐閣獨成悶，行塘閱清輝。", "春風動高柳，芳園掩夕扉。", "遙思里中會，心緒悵微微。"]'),
('43410b8c-4207-4410-a9cb-773cede6157f','寒食日寄諸弟','韋應物','唐','唐诗','tang','','[]','禁火曖佳辰，念離獨傷抱。',36,'全唐诗/poet.tang.9000.json','["禁火曖佳辰，念離獨傷抱。", "見此野田花，心思杜陵道。", "聯騎定何時，予今顏已老。"]'),
('a8a6fd0c-1cc3-4521-bde9-ac269438cfb3','三月三日寄諸弟兼懷崔都水','韋應物','唐','唐诗','tang','','[]','暮節看已謝，茲晨愈可惜。',48,'全唐诗/poet.tang.9000.json','["暮節看已謝，茲晨愈可惜。", "風澹意傷春，池寒花斂夕。", "對酒始依依，懷人還的的。", "誰當曲水行，相思尋舊跡。"]'),
('931fb508-1f2d-4295-b58b-953dbe2bd8fd','贈李儋侍御','韋應物','唐','唐诗','tang','','[]','風光山郡少，來看廣陵春。',24,'全唐诗/poet.tang.9000.json','["風光山郡少，來看廣陵春。", "殘花猶待客，莫問意中人。"]'),
('adb0b51a-dcde-45fa-b505-3aea3fbe0076','寄楊協律','韋應物','唐','唐诗','tang','','["\u957f\u6c5f"]','吏散門閣掩，鳥鳴山郡中。',48,'全唐诗/poet.tang.9000.json','["吏散門閣掩，鳥鳴山郡中。", "遠念長江別，俯覺座隅空。", "舟泊南池雨，簟捲北樓風。", "併罷芳樽燕，爲愴昨時同。"]'),
('c1c6c56c-1773-423f-a2e7-26a7bae46cfd','郡齋贈王卿','韋應物','唐','唐诗','tang','','[]','無術謬稱簡，素餐空自嗟。',48,'全唐诗/poet.tang.9000.json','["無術謬稱簡，素餐空自嗟。", "秋齋雨成滯，山藥寒始華。", "濩落人皆笑，幽獨歲逾賒。", "唯君出塵意，賞愛似山家。"]'),
('c222a046-9a8c-4554-81e9-bee95fef8aa1','簡恆璨','韋應物','唐','唐诗','tang','','[]','室虛多涼氣，天高屬秋時。',48,'全唐诗/poet.tang.9000.json','["室虛多涼氣，天高屬秋時。", "空庭夜風雨，草木曉離披。", "簡書日云曠，文墨誰復持。", "聊因遇澄靜，一與道人期。"]'),
('dfa66e60-7ab6-4173-8533-d33ab02ac06d','閑居寄諸弟','韋應物','唐','唐诗','tang','','[]','秋艸生庭白露時，故園諸弟益相思。',32,'全唐诗/poet.tang.9000.json','["秋艸生庭白露時，故園諸弟益相思。", "盡日高齋無一事，芭蕉葉上獨題詩。"]'),
('6669bbb2-5ef2-4c76-a95f-903042c6809b','登樓寄王卿','韋應物','唐','唐诗','tang','','[]','踏閣攀林恨不同，楚雲滄海思無窮。',32,'全唐诗/poet.tang.9000.json','["踏閣攀林恨不同，楚雲滄海思無窮。", "數家砧杵秋山下，一郡荆榛寒雨中。"]'),
('5344df84-20ec-41c5-9df0-939e5ab29644','寄暢當','韋應物','唐','唐诗','tang','','[]','寇賊起東山，英俊方未閑。',96,'全唐诗/poet.tang.9000.json','["寇賊起東山，英俊方未閑。", "聞君新應募，籍籍動京關。", "出身文翰場，高步不可攀。", "青袍未及解，白羽插腰間。", "昔爲瓊樹枝，今有風霜顏。", "秋郊細柳道，走馬一夕還。", "丈夫當爲國，破敵如摧山。", "何必事州府，坐使鬢毛斑。"]'),
('9f0c0d49-b384-4605-9fc2-607ad457e02f','贈崔員外','韋應物','唐','唐诗','tang','','[]','一別十年事，相逢淮海濱。',48,'全唐诗/poet.tang.9000.json','["一別十年事，相逢淮海濱。", "還思洛陽日，更話府中人。", "且對清觴滿，寧知白髮新。", "怱怱何處去，車馬冒風塵。"]'),
('8435b46d-bbf1-49e5-af66-6f2d5681f1bf','寄李儋元錫','韋應物','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u53cb\u4eba", "\u5fe7\u56fd\u5fe7\u6c11", "\u4e03\u8a00\u5f8b\u8bd7"]','去年花裏逢君別，今日花開已一年。',64,'全唐诗/poet.tang.9000.json','["去年花裏逢君別，今日花開已一年。", "世事茫茫難自料，春愁黯黯獨成眠。", "身多疾病思田里，邑有流亡愧俸錢。", "聞道欲來相問訊，西樓望月幾廻圓。"]'),
('ce9efeef-a809-480f-9049-1f886d695963','京師叛亂寄諸弟','韋應物','唐','唐诗','tang','','[]','弱冠遭世難，二紀猶未平。',96,'全唐诗/poet.tang.9000.json','["弱冠遭世難，二紀猶未平。", "羇離官遠郡，虎豹滿西京。", "上懷犬馬戀，下有骨肉情。", "歸去在何時，流淚忽霑纓。", "憂來上北樓，左右但軍營。", "函谷行人絕，淮南春草生。", "鳥鳴野田間，思憶故園行。", "何當四海晏，甘與齊民耕。"]'),
('19b923d1-65b0-4f3f-9d12-16a99b686a83','贈琮公','韋應物','唐','唐诗','tang','','[]','山僧一相訪，吏案正盈前。',48,'全唐诗/poet.tang.9000.json','["山僧一相訪，吏案正盈前。", "出處似殊致，喧靜兩皆禪。", "暮春華池宴，清夜高齋眠。", "此道本無得，寧復有忘筌。"]'),
('4e588a03-7f6b-4c83-bf35-8dcf48d28afd','寄諸弟','韋應物','唐','唐诗','tang','','[]','歲暮兵戈亂京國，帛書間道訪存亡。',32,'全唐诗/poet.tang.9000.json','["歲暮兵戈亂京國，帛書間道訪存亡。", "還信忽從天上落，唯知彼此淚千行。"]'),
('5028501b-3683-4c89-9255-46f10bf27729','寄恆璨','韋應物','唐','唐诗','tang','','[]','心絕去來緣，跡順人間事。',36,'全唐诗/poet.tang.9000.json','["心絕去來緣，跡順人間事。", "獨尋秋草徑，夜宿寒山寺。", "今日郡齋閑，思問楞伽字。"]'),
('3ba9d202-9c99-450b-84c8-23f51130df0e','簡郡中諸生','韋應物','唐','唐诗','tang','','[]','守郡臥秋閣，四面盡荒山。',48,'全唐诗/poet.tang.9000.json','["守郡臥秋閣，四面盡荒山。", "此時聽夜雨，孤燈照窗間。", "藥園日蕪沒，書帷長自閑。", "惟當上客至，論詩一解顏。"]'),
('46503396-3bb3-449c-9c84-f2ff232f7949','寄全椒山中道士','韋應物','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u53e4\u8bd7", "\u6000\u5ff5"]','今朝郡齋冷，忽念山中客。',48,'全唐诗/poet.tang.9000.json','["今朝郡齋冷，忽念山中客。", "澗底束荆薪，歸來煮白石。", "欲持一瓢酒，遠慰風雨夕。", "落葉滿空山，何處尋行跡。"]'),
('c5799af9-92b4-47f5-988d-9fc4edc8dbbd','寄釋子良史酒','韋應物','唐','唐诗','tang','','[]','秋山僧冷病，聊寄三五杯。',24,'全唐诗/poet.tang.9000.json','["秋山僧冷病，聊寄三五杯。", "應瀉山瓢裏，還寄此瓢來。"]'),
('e48d4c21-00ce-4f4f-b08c-9b29ac678af9','重寄','韋應物','唐','唐诗','tang','','[]','復寄滿瓢去，定見空瓢來。',24,'全唐诗/poet.tang.9000.json','["復寄滿瓢去，定見空瓢來。", "若不打瓢破，終當費酒材。"]'),
('36309b08-b592-4143-acf6-a5424993fa1e','答釋子良史送酒瓢','韋應物','唐','唐诗','tang','','[]','此瓢今已到，山瓢知已空。',24,'全唐诗/poet.tang.9000.json','["此瓢今已到，山瓢知已空。", "且飲寒塘水，遙將回也同。"]'),
('f57ecbec-fe77-4a74-889d-1b95dbc8ec07','簡陟巡建三甥','韋應物','唐','唐诗','tang','','[]','忽羨後生連榻話，獨依寒燭一齋空。',32,'全唐诗/poet.tang.9000.json','["忽羨後生連榻話，獨依寒燭一齋空。", "時流歡笑事從別，把酒吟詩待爾同。"]'),
('54eb6543-4506-426c-8761-f5963d8fc9af','覽襃子臥病一絕聊以題示','韋應物','唐','唐诗','tang','','[]','念子抱沈疾，霜露變滁城。',24,'全唐诗/poet.tang.9000.json','["念子抱沈疾，霜露變滁城。", "獨此高窗下，自然無世情。"]'),
('3100f6b2-4f4a-4fdf-bb2c-c53b2528e909','寄璨師','韋應物','唐','唐诗','tang','','[]','林院生夜色，西廊上紗燈。',24,'全唐诗/poet.tang.9000.json','["林院生夜色，西廊上紗燈。", "時憶長松下，獨坐一山僧。"]'),
('6d6e1bcc-8bbc-4ad5-8458-d58a34fca568','寄盧陟','韋應物','唐','唐诗','tang','','[]','柳葉遍寒塘，曉霜凝高閣。',24,'全唐诗/poet.tang.9000.json','["柳葉遍寒塘，曉霜凝高閣。", "累日此流連，別來成寂寞。"]'),
('a32f4101-0ba6-4409-bebe-7a3671d97a38','途中寄楊邈裴緒示襃子','韋應物','唐','唐诗','tang','','[]','上宰領淮右，下國屬星馳。',72,'全唐诗/poet.tang.9000.json','["上宰領淮右，下國屬星馳。", "霧野騰曉騎，霜竿裂凍旗。", "蕭蕭陟連岡，莽莽望空陂。", "風截鴈嘹淚，雲慘樹參差。", "高齋明月夜，中庭松桂姿。", "當暌一酌恨，況此兩旬期。"]'),
('3d885ed0-5113-4495-9c72-5e6e6fa0b0e7','宿永陽寄璨律師','韋應物','唐','唐诗','tang','','[]','遙知郡齋夜，凍雪封松竹。',24,'全唐诗/poet.tang.9000.json','["遙知郡齋夜，凍雪封松竹。", "時有山僧來，懸燈獨自宿。"]'),
('c064e912-16a7-44ee-a19e-7f11cf5c676a','雪行寄襃子','韋應物','唐','唐诗','tang','','[]','淅瀝覆寒騎，飄颻暗川容。',24,'全唐诗/poet.tang.9000.json','["淅瀝覆寒騎，飄颻暗川容。", "行子郡城曉，披雲看杉松。"]'),
('7dc54a18-46f4-4f28-9f95-01c987afc9a0','寄裴處士','韋應物','唐','唐诗','tang','','[]','春風駐遊騎，晚景澹山暉。',48,'全唐诗/poet.tang.9000.json','["春風駐遊騎，晚景澹山暉。", "一問清泠子，獨掩荒園扉。", "草木雨來長，里閭人到稀。", "方從廣陵宴，花落未言歸。"]'),
('652cdae6-ec60-4dc2-9c3c-ed128d0f28ff','偶入西齋院示釋子恆璨','韋應物','唐','唐诗','tang','','[]','僧齋地雖密，忘子跡要賒。',24,'全唐诗/poet.tang.9000.json','["僧齋地雖密，忘子跡要賒。", "一來非問訊，自是看山花。"]'),
('3e105457-08ca-48c7-a77d-c1bc47b7f69d','示全真元常','韋應物','唐','唐诗','tang','','[]','余辭郡符去，爾爲外事牽。',48,'全唐诗/poet.tang.9000.json','["余辭郡符去，爾爲外事牽。", "寧知風雪夜，復此對牀眠。", "始話南池飲，更詠西樓篇。", "無將一會易，歲月坐推遷。"]'),
('0e8da910-15dd-443b-aba8-1b4cb1aecb4d','寄劉尊師','韋應物','唐','唐诗','tang','','[]','世間荏苒縈此身，長望碧山到無因。',32,'全唐诗/poet.tang.9000.json','["世間荏苒縈此身，長望碧山到無因。", "白鶴徘徊看不去，遙知下有清都人。"]'),
('c32284e3-2ad7-46b1-a1d1-b9ea203d4935','寄廬山椶衣居士','韋應物','唐','唐诗','tang','','["\u5e90\u5c71"]','兀兀山行無處歸，山中猛虎識椶衣。',32,'全唐诗/poet.tang.9000.json','["兀兀山行無處歸，山中猛虎識椶衣。", "俗客欲尋應不遇，雲溪道士見猶稀。"]'),
('66b5b451-6b63-4977-b257-e66478fed4ae','因省風俗與從姪成緒遊山水中道先歸寄示','韋應物','唐','唐诗','tang','','[]','累宵同燕酌，十舍攜征騎。',108,'全唐诗/poet.tang.9000.json','["累宵同燕酌，十舍攜征騎。", "始造雙林寂，遐搜洞府祕。", "羣峰繞盤鬱，懸泉仰特異。", "陰壑雲松埋，陽崖煙花媚。", "每慮觀省牽，中乖遊踐志。", "我尚山水行，子歸棲息地。", "一操臨流袂，上聳干雲轡。", "獨往倦危途，懷沖寡幽致。", "賴爾還都期，方將登樓遲。"]'),
('ed7ce24a-197a-42fb-a622-e331144496b4','寒食寄京師諸弟','韋應物','唐','唐诗','tang','','["\u601d\u5ff5", "\u5bd2\u98df\u8282", "\u5b64\u72ec"]','雨中禁火空齋冷，江上流鶯獨坐聽。',32,'全唐诗/poet.tang.9000.json','["雨中禁火空齋冷，江上流鶯獨坐聽。", "把酒看花想諸弟，杜陵寒食草青青。"]'),
('1d0eae94-0bd8-49f6-b87f-a1fab2f196dd','歲日寄京師諸[季]端武等','韋應物','唐','唐诗','tang','','[]','獻歲抱深惻，僑居念歸緣。',120,'全唐诗/poet.tang.9000.json','["獻歲抱深惻，僑居念歸緣。", "常患親愛離，始覺世務牽。", "少事河陽府，晚守淮南壖。", "平生幾會散，已及蹉跎年。", "昨日罷符竹，家貧遂留連。", "部曲多已去，車馬不復全。", "閑將酒爲偶，默以道自詮。", "聽松南巖寺，見月西澗泉。", "爲政無異術，當責豈望遷。", "終理來時裝，歸鑿杜陵田。"]'),
('02c6d320-b3b2-473b-8978-ad9f3a39ee60','簡盧陟','韋應物','唐','唐诗','tang','','[]','可憐白雪曲，未遇知音人。',48,'全唐诗/poet.tang.9000.json','["可憐白雪曲，未遇知音人。", "恓惶戎旅下，蹉跎淮海濱。", "澗樹含朝雨，山鳥哢餘春。", "我有一瓢酒，可以慰風塵。"]'),
('6e99e6a8-2880-4c2c-90f3-fa762dba9724','西澗即事示盧陟','韋應物','唐','唐诗','tang','','[]','寢扉臨碧澗，晨起澹忘情。',48,'全唐诗/poet.tang.9000.json','["寢扉臨碧澗，晨起澹忘情。", "空林細雨至，圓文遍水生。", "永日無餘事，山中伐木聲。", "知子塵喧久，暫可散煩纓。"]'),
('9aef24cb-945d-410b-aff3-a1ce838780a2','登郡寄京師諸季淮南子弟','韋應物','唐','唐诗','tang','','[]','始罷永陽守，復臥潯陽樓。',48,'全唐诗/poet.tang.9000.json','["始罷永陽守，復臥潯陽樓。", "懸檻飄寒雨，危堞侵江流。", "迨茲聞雁夜，重憶別離秋。", "徒有盈樽酒，鎮此百端憂。"]'),
('42b4c71e-e70b-4aa5-af91-0db1b1c9d5ea','寄黃尊師','韋應物','唐','唐诗','tang','','[]','結茅種杏在雲端，掃雪焚香宿石壇。',32,'全唐诗/poet.tang.9000.json','["結茅種杏在雲端，掃雪焚香宿石壇。", "靈祇不許世人到，忽作雷風登嶺難。"]'),
('7913e7de-ef79-4534-8b35-6dfde61fd8e9','寄黃劉二尊師','韋應物','唐','唐诗','tang','','["\u5e90\u5c71"]','廬山兩道士，各在一峰居。',72,'全唐诗/poet.tang.9000.json','["廬山兩道士，各在一峰居。", "矯掌白雲表，晞髮陽和初。", "清夜降真侶，焚香滿空虛。", "中有無爲樂，自然與世疎。", "道尊不可屈，符守豈暇餘。", "高齋遙致敬，願示一編書。"]'),
('96455db1-a0c6-402c-8892-05c6b9a3d029','秋夜寄丘二十二員外','韋應物','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u79cb\u5929", "\u6000\u4eba", "\u4e94\u8a00\u7edd\u53e5"]','懷君屬秋夜，散步詠涼天。',24,'全唐诗/poet.tang.9000.json','["懷君屬秋夜，散步詠涼天。", "山空松子落，幽人應未眠。"]'),
('9deac157-0946-47da-9f9a-9094a2f5bdae','贈丘員外二首 一','韋應物','唐','唐诗','tang','','[]','高詞棄浮靡，貞行表鄉閭。',120,'全唐诗/poet.tang.9000.json','["高詞棄浮靡，貞行表鄉閭。", "未真南宮拜，聊偃東山居。", "大藩本多事，日與文章疎。", "每一覩之子，高詠遂起予。", "宵晝方連燕，煩恡亦頓祛。", "格言雅誨闕，善謔矜數餘。", "久跼思遊曠，窮慘遇陽舒。", "虎丘愜登眺，吳門悵躊躇。", "方此戀攜手，豈云還舊墟。", "告諸吳子弟，文學爲何如。"]'),
('2d01edfd-9e02-4a1c-a4a6-3e0acf11dd62','贈丘員外二首 二','韋應物','唐','唐诗','tang','','[]','跡與孤雲遠，心將野鶴俱。',24,'全唐诗/poet.tang.9000.json','["跡與孤雲遠，心將野鶴俱。", "那同石氏子，每到府門趨。"]'),
('03a9fde8-1a26-41ac-8fc8-0195b16a38d5','贈李判官','韋應物','唐','唐诗','tang','','[]','良玉定爲寶，長材世所稀。',108,'全唐诗/poet.tang.9000.json','["良玉定爲寶，長材世所稀。", "佐幕方巡郡，奏命布恩威。", "食蔬程獨守，飲冰節靡違。", "決獄興邦頌，高文稟天機。", "賓館在林表，望山啓西扉。", "下有千畝田，泱漭吳土肥。", "始耕已見穫，袗絺今授衣。", "政拙勞詳省，淹留未得歸。", "雖慙且忻願，日夕覩光輝。"]'),
('5c3bd4fb-9400-4f20-b667-50141679abbb','寄皎然上人','韋應物','唐','唐诗','tang','','[]','吳興老釋子，野雪蓋精廬。',96,'全唐诗/poet.tang.9000.json','["吳興老釋子，野雪蓋精廬。", "詩名徒自振，道心長晏如。", "想茲棲禪夜，見月東峰初。", "鳴鐘驚巖壑，焚香滿空虛。", "叨慕端成舊，未識豈爲疎。", "願以碧雲思，方君怨別餘。", "茂苑文華地，流水古僧居。", "何當一遊詠，倚閣吟躊躇。"]'),
('34f06116-cbd0-4f5c-9e32-1414b666c561','贈舊識','韋應物','唐','唐诗','tang','','[]','少年遊太學，負氣蔑諸生。',24,'全唐诗/poet.tang.9000.json','["少年遊太學，負氣蔑諸生。", "蹉跎三十載，今日海隅行。"]'),
('78f8ccd5-d32a-41ad-81cf-763be1de2352','復理西齋寄丘員外','韋應物','唐','唐诗','tang','','[]','前歲理西齋，得與君子同。',96,'全唐诗/poet.tang.9000.json','["前歲理西齋，得與君子同。", "迨茲已一周，悵望臨春風。", "始自疎林竹，還復長榛叢。", "端正良難久，蕪穢易爲功。", "援斧開衆鬱，如師啓羣蒙。", "庭宇還清曠，煩抱亦舒通。", "海隅雨雪霽，春序風景融。", "時物方如故，懷賢思無窮。"]'),
('4f9535fc-6a54-4bab-8cf9-d786375155da','和張舍人夜直中書寄吏部劉員外','韋應物','唐','唐诗','tang','','[]','西垣草詔罷，南宮憶上才。',48,'全唐诗/poet.tang.9000.json','["西垣草詔罷，南宮憶上才。", "月臨蘭殿出，涼自鳳池來。", "松桂生丹禁，鴛鷺集雲臺。", "託身各有所，相望徒徘徊。"]'),
('ea87cf5c-f4b1-404d-b2f4-391143b570d0','和李二主簿寄淮上綦毋三','韋應物','唐','唐诗','tang','','[]','滿城憐傲吏，終日賦新詩。',24,'全唐诗/poet.tang.9000.json','["滿城憐傲吏，終日賦新詩。", "請報淮陰客，春帆浪作期。"]'),
('4501fd99-4a46-4994-afc9-056ec629fa6f','寄二嚴','韋應物','唐','唐诗','tang','','[]','絲竹久已懶，今日遇君忺。',28,'全唐诗/poet.tang.9000.json','["絲竹久已懶，今日遇君忺。", "打破蜘蛛千道網，總爲鶺鴒兩箇嚴。"]'),
('9af5671d-7a66-48a3-b22c-8386d3a668f8','李五席送李主簿歸西臺','韋應物','唐','唐诗','tang','','[]','請告嚴程盡，西歸道路寒。',48,'全唐诗/poet.tang.9000.json','["請告嚴程盡，西歸道路寒。", "欲陪鷹隼集，猶戀鶺鴒單。", "洛邑人全少，嵩高雪尚殘。", "滿臺誰不故，報我在微官。"]'),
('593ae5b3-4b44-4478-bf2a-f408a5785659','送崔押衙相州','韋應物','唐','唐诗','tang','','[]','禮樂儒家子，英豪燕趙風。',96,'全唐诗/poet.tang.9000.json','["禮樂儒家子，英豪燕趙風。", "驅雞嘗理邑，走馬却從戎。", "白刃千夫闢，黃金四海同。", "嫖姚恩顧下，諸將指揮中。", "別路憐芳草，歸心伴塞鴻。", "鄴城新騎滿，魏帝舊臺空。", "望闕應懷戀，遭時貴立功。", "萬方如已靜，何處欲輸忠。"]'),
('f3a4d344-efec-4080-863a-82faa46eaa2c','送宣城路錄事','韋應物','唐','唐诗','tang','','[]','江上宣城郡，孤舟遠到時。',48,'全唐诗/poet.tang.9000.json','["江上宣城郡，孤舟遠到時。", "雲林謝家宅，山水敬亭祠。", "綱紀多閑日，觀遊得賦詩。", "都門且盡醉，此別數年期。"]'),
('fab821c1-7d3d-4d65-898f-441e53ff1c6f','送李十四山東遊','韋應物','唐','唐诗','tang','','[]','聖朝有遺逸，披膽謁至尊。',132,'全唐诗/poet.tang.9000.json','["聖朝有遺逸，披膽謁至尊。", "豈是貿榮寵，誓將救元元。", "權豪非所便，書奏寢禁門。", "高歌長安酒，忠憤不可吞。", "欻來客河洛，日與靜者論。", "濟世飜小事，丹砂駐精魂。", "東遊無復繫，梁楚多大蕃。", "高論動侯伯，疎懷脫塵喧。", "送君都門野，飲我林中樽。", "立馬望東道，白雲滿梁園。", "踟躕欲何贈，空是平生言。"]'),
('85e381ff-c51c-4fe2-9326-64d832bc4c4b','送李二歸楚州','韋應物','唐','唐诗','tang','','[]','情人南楚別，復詠在原詩。',48,'全唐诗/poet.tang.9000.json','["情人南楚別，復詠在原詩。", "忽此嗟歧路，還令泣素絲。", "風波朝夕遠，音信往來遲。", "好去扁舟客，青雲何處期。"]'),
('de217f9f-e4f0-45d0-b87f-97a3ae4784aa','送閻寀赴東川辟','韋應物','唐','唐诗','tang','','[]','冰炭俱可懷，孰云熱與寒。',84,'全唐诗/poet.tang.9000.json','["冰炭俱可懷，孰云熱與寒。", "何如結髮友，不得攜手懽。", "晨登嚴霜野，送子天一端。", "祗承簡書命，俯仰豸角冠。", "上陟白雲嶠，下冥玄壑湍。", "離羣自有託，歷險得所安。", "當念反窮巷，登朝成慨嘆。"]'),
('337639a4-b1f1-4e9d-b0a3-5a48dba69d56','送令狐岫宰恩陽','韋應物','唐','唐诗','tang','','[]','大雪天地閉，羣山夜來晴。',108,'全唐诗/poet.tang.9000.json','["大雪天地閉，羣山夜來晴。", "居家猶苦寒，子有千里行。", "行行安得辭，荷此蒲璧榮。", "賢豪爭追攀，飲餞出西京。", "樽酒豈不歡，暮春自有程。", "離人起視日，僕御促前征。", "逶遲歲已窮，當造巴子城。", "和風被草木，江水日夜清。", "從來知善政，離別慰友生。"]'),
('5575cb2e-f83e-46b5-963d-1fad347af280','送馮著受李廣州署爲錄事','韋應物','唐','唐诗','tang','','[]','鬱鬱楊柳枝，蕭蕭征馬悲。',144,'全唐诗/poet.tang.9000.json','["鬱鬱楊柳枝，蕭蕭征馬悲。", "送君灞陵岸，糾郡南海湄。", "名在翰墨場，羣公正追隨。", "如何從此去，千里萬里期。", "大海吞東南，橫嶺隔地維。", "建邦臨日域，溫燠御四時。", "百國共臻奏，珍奇獻京師。", "富豪虞興戎，繩墨不易持。", "州伯荷天寵，還當翊丹墀。", "子爲門下生，終始豈見遺。", "所願酌貪泉，心不爲磷緇。", "上將玩國士，下以報渴飢。"]'),
('55dbaccb-ddf8-467e-94f1-729a96e18e8d','送元倉曹歸廣陵','韋應物','唐','唐诗','tang','','[]','官閑得去住，告別戀音徽。',48,'全唐诗/poet.tang.9000.json','["官閑得去住，告別戀音徽。", "舊國應無業，他鄉到是歸。", "楚山明月滿，淮甸夜鐘微。", "何處孤舟泊，遙遙心曲違。"]'),
('bd789a80-d20a-49da-a1ba-c0b177ab9e9c','送唐明府赴溧水','韋應物','唐','唐诗','tang','','[]','三爲百里宰，已過十餘年。',48,'全唐诗/poet.tang.9000.json','["三爲百里宰，已過十餘年。", "祗嘆官如舊，旋聞邑屢遷。", "魚鹽濱海利，薑蔗傍湖田。", "到此安甿俗，琴堂又晏然。"]'),
('41cd3ab4-9463-43b3-8a5c-87c70ca0b35e','喜於廣陵拜覲家兄奉送發還池州','韋應物','唐','唐诗','tang','','[]','青青連枝樹，苒苒久別離。',96,'全唐诗/poet.tang.9000.json','["青青連枝樹，苒苒久別離。", "客遊廣陵中，俱到若有期。", "俯仰敘存歿，哀腸發酸悲。", "收情且爲歡，累日不知飢。", "夙駕多所迫，復當還歸池。", "長安三千里，歲晏獨何爲。", "南出登閶門，驚飆左右吹。", "所別諒非遠，要令心不怡。"]'),
('1353e07f-fe8e-4780-bd14-374dba6d58b8','送章八元秀才擢第往上都應制','韋應物','唐','唐诗','tang','','[]','決勝文場戰已酣，行應辟命復才堪。',64,'全唐诗/poet.tang.9000.json','["決勝文場戰已酣，行應辟命復才堪。", "旅食不辭遊闕下，春衣未換報江南。", "天邊宿鳥生歸思，關外晴山滿夕嵐。", "立馬欲從何處別，都門楊柳正毿毿。"]'),
('7bec25d3-378b-4098-a26e-5111edc31bbe','送張侍御祕書江左覲省','韋應物','唐','唐诗','tang','','["\u957f\u6c5f"]','莫歎都門路，歸無駟馬車。',48,'全唐诗/poet.tang.9000.json','["莫歎都門路，歸無駟馬車。", "繡衣猶在篋，芸閣已觀書。", "沃野收紅稻，長江釣白魚。", "晨飡亦可薦，名利欲何如。"]'),
('643fa837-422c-458a-9036-81a92d946a55','賦得鼎門送盧耿赴任','韋應物','唐','唐诗','tang','','[]','名因定鼎地，門對鑿龍山。',48,'全唐诗/poet.tang.9000.json','["名因定鼎地，門對鑿龍山。", "水北樓臺近，城南車馬還。", "稍開芳野靜，欲掩暮鐘閑。", "去此無嗟屈，前賢尚抱關。"]'),
('9e22d607-c30a-4ce9-8d29-6728180a3fd3','賦得浮雲起離色送鄭述誠','韋應物','唐','唐诗','tang','','[]','遊子欲言去，浮雲那得知。',48,'全唐诗/poet.tang.9000.json','["遊子欲言去，浮雲那得知。", "偏能見行色，自是獨傷離。", "晚帶城遙暗，秋生峰尚奇。", "還因朔吹斷，匹馬與相隨。"]'),
('f0aafd21-88cf-4849-b4b0-524fbadd2566','餞雍聿之潞州謁李中丞','韋應物','唐','唐诗','tang','','[]','鬱鬱雨相遇，出門草青青。',96,'全唐诗/poet.tang.9000.json','["鬱鬱雨相遇，出門草青青。", "酒酣拔劒舞，慷慨送子行。", "驅馬涉大河，日暮懷洛京。", "前登太行路，志士亦未平。", "薄遊五府都，高步振英聲。", "主人才且賢，重士百金輕。", "絲竹促飛觴，夜醼達晨星。", "娛樂易淹暮，諒在執高情。"]'),
('dcceee3d-2938-487b-af32-0dda3c4d5fce','上東門會送李幼舉南遊徐方','韋應物','唐','唐诗','tang','','[]','離絃既罷彈，罇酒亦已闌。',84,'全唐诗/poet.tang.9000.json','["離絃既罷彈，罇酒亦已闌。", "聽我歌一曲，南徐在雲端。", "雲端雖云邈，行路本非難。", "諸侯皆愛才，公子遠結歡。", "濟濟都門宴，將去復盤桓。", "令姿何昂昂，良馬遠遊冠。", "意氣且爲別，由來非所嘆。"]'),
('ea3f53a5-72a3-4286-b656-04fb4ceb1bf8','送洛陽韓丞東遊','韋應物','唐','唐诗','tang','','[]','仙鳥何飄颻，綠衣翠爲襟。',96,'全唐诗/poet.tang.9000.json','["仙鳥何飄颻，綠衣翠爲襟。", "顧我差池羽，咬咬懷好音。", "徘徊洛陽中，遊戲清川潯。", "神交不在結，歡愛自中心。", "駕言忽徂征，雲路邈且深。", "朝遊尚同啄，夕息當異林。", "出餞宿東郊，列筵屬城陰。", "舉酒欲爲樂，憂懷方沈沈。"]'),
('4269cd3d-9f7e-4c42-8335-ca0088089487','送鄭長源','韋應物','唐','唐诗','tang','','[]','少年一相見，飛轡河洛間。',84,'全唐诗/poet.tang.9000.json','["少年一相見，飛轡河洛間。", "歡遊不知罷，中路忽言還。", "泠泠鵾絃哀，悄悄冬夜閑。", "丈夫雖耿介，遠別多苦顏。", "君行拜高堂，速駕難久攀。", "雞鳴儔侶發，朔雪滿河關。", "須臾在今夕，罇酌且循環。"]'),
('9c30b450-c7f4-43c0-9df1-524d63508a4c','送李儋','韋應物','唐','唐诗','tang','','[]','別離何從生，乃在親愛中。',84,'全唐诗/poet.tang.9000.json','["別離何從生，乃在親愛中。", "反念行路子，拂衣自西東。", "日昃不留宴，嚴車出崇墉。", "行遊非所樂，端憂道未通。", "春野百卉發，清川思無窮。", "芳時坐離散，世事誰可同。", "歸當掩重關，默默想音容。"]'),
('83dcb67c-ccbc-4592-b232-368a6b5275ce','賦得暮雨送李胄','韋應物','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u96e8", "\u53cb\u60c5", "\u9001\u522b", "\u4e94\u8a00\u5f8b\u8bd7", "\u96e8"]','楚江微雨裏，建業暮鐘時。',48,'全唐诗/poet.tang.9000.json','["楚江微雨裏，建業暮鐘時。", "漠漠帆來重，冥冥鳥去遲。", "海門深不見，浦樹遠含滋。", "相送情無限，沾襟比散絲。"]'),
('02c48718-06ba-4b1a-b220-0a1f2d2afe23','留別洛京親友','韋應物','唐','唐诗','tang','','[]','握手出都門，駕言適京師。',84,'全唐诗/poet.tang.9000.json','["握手出都門，駕言適京師。", "豈不懷舊廬，惆悵與子辭。", "麗日坐高閣，清觴醼華池。", "昨遊倏已過，後遇良未知。", "念結路方永，歲陰野無暉。", "單車我當前，暮雪子獨歸。", "臨流一相望，零淚忽沾衣。"]'),
('ad7ba4e5-9d7b-4e0c-acd9-4b55033c5810','賦得沙際路送從叔象','韋應物','唐','唐诗','tang','','["\u79bb\u522b"]','獨樹沙邊人跡稀，欲行愁遠暮鍾時。',32,'全唐诗/poet.tang.9000.json','["獨樹沙邊人跡稀，欲行愁遠暮鍾時。", "野泉幾處侵應盡，不過山僧知問誰。"]'),
('2f2c67e1-55c5-430c-9d04-8d9576dec49e','送榆次林明府','韋應物','唐','唐诗','tang','','[]','無嗟千里遠，亦是宰王畿。',48,'全唐诗/poet.tang.9000.json','["無嗟千里遠，亦是宰王畿。", "策馬雨中去，逢人關外稀。", "邑傳榆石在，路遶晉山微。", "別思方蕭索，新秋一葉飛。"]'),
('f47c3f1e-22d6-4f85-a154-d197ad529d61','雜言送黎六郎','韋應物','唐','唐诗','tang','','[]','冰壺見底未見清，少年如玉有詩名。',120,'全唐诗/poet.tang.9000.json','["冰壺見底未見清，少年如玉有詩名。", "聞話嵩峰多野寺，不嫌黃綬向陽城。", "朱門嚴訓朝辭去，騎出東郊滿飛絮。", "河南庭下拜府君，陽城歸路山氛氳。", "山氛氳，長不見，釣臺水淥荷已生，少姨廟寒花始徧。", "縣閑吏傲與塵隔，移竹疏泉常岸幘。", "莫言去作折腰官，豈似長安折腰客。"]'),
('4f3fcee2-0c1b-4150-8be6-2a6a823f2764','天長寺上方別子西有道','韋應物','唐','唐诗','tang','','[]','假邑非拙素，況乃別伊人。',84,'全唐诗/poet.tang.9000.json','["假邑非拙素，況乃別伊人。", "聊登釋氏居，攜手戀茲晨。", "高曠出塵表，逍遙滌心神。", "青山對芳苑，列樹遶通津。", "車馬無時絕，行子倦風塵。", "今當遵往路，佇立欲何申。", "唯持貞白志，以慰心所親。"]'),
('0937405c-be42-435b-b59e-f26a0950541c','送黎六郎赴陽翟少府','韋應物','唐','唐诗','tang','','[]','試吏向嵩陽，春山躑躅芳。',48,'全唐诗/poet.tang.9000.json','["試吏向嵩陽，春山躑躅芳。", "腰垂新綬色，衣滿舊芸香。", "喬樹別時綠，客程關外長。", "祗應傳善政，日夕慰高堂。"]'),
('008ca8a4-5226-475b-968d-edaa3be21cb8','送別覃孝廉','韋應物','唐','唐诗','tang','','[]','思親自當去，不第未蹉跎。',48,'全唐诗/poet.tang.9000.json','["思親自當去，不第未蹉跎。", "家住青山下，門前芳草多。", "秭歸通遠徼，巫峽注驚波。", "州舉年年事，還期復幾何。"]'),
('6d9c8a1f-5baa-4b18-9d7f-dae56393677e','送開封盧少府','韋應物','唐','唐诗','tang','','[]','雄藩車馬地，作尉有光輝。',48,'全唐诗/poet.tang.9000.json','["雄藩車馬地，作尉有光輝。", "滿席賓常侍，闐街燭夜歸。", "關河征斾遠，煙樹夕陽微。", "到處無留滯，梁園花欲稀。"]'),
('fb36b544-6c83-4b89-81b5-cf7e3839958a','送槐廣落第歸揚州','韋應物','唐','唐诗','tang','','[]','下第常稱屈，少年心獨輕。',48,'全唐诗/poet.tang.9000.json','["下第常稱屈，少年心獨輕。", "拜親歸海畔，似舅得詩名。", "晚對青山別，遙尋芳草行。", "還期應不遠，寒露濕蕪城。"]'),
('94940d3a-7ed5-4809-b80d-b04e650163a9','送汾城王主簿','韋應物','唐','唐诗','tang','','[]','少年初帶印，汾上又經過。',48,'全唐诗/poet.tang.9000.json','["少年初帶印，汾上又經過。", "芳草歸時徧，情人故郡多。", "禁鐘春雨細，宮樹野煙和。", "相望東橋別，微風起夕波。"]'),
('44e316ee-4bad-4598-b7cf-3e07180f239d','送澠池崔主簿','韋應物','唐','唐诗','tang','','[]','邑帶洛陽道，年年應此行。',48,'全唐诗/poet.tang.9000.json','["邑帶洛陽道，年年應此行。", "當時匹馬客，今日縣人迎。", "暮雨投關郡，春風別帝城。", "東西殊不遠，朝夕待佳聲。"]'),
('950ba5ca-ed43-46ba-82ff-aef90c479fdd','送顏司議使蜀訪圖書','韋應物','唐','唐诗','tang','','[]','軺駕一封急，蜀門千嶺曛。',48,'全唐诗/poet.tang.9000.json','["軺駕一封急，蜀門千嶺曛。", "詎分江轉字，但見路緣雲。", "山館夜聽雨，秋猿獨呌羣。", "無爲久留滯，聖主待遺文。"]'),
('8f32b9e7-ab07-4b99-8448-52eba9d2896c','奉送從兄宰晉陵','韋應物','唐','唐诗','tang','','[]','東郊暮草歇，千里夏雲生。',48,'全唐诗/poet.tang.9000.json','["東郊暮草歇，千里夏雲生。", "立馬愁將夕，看山獨送行。", "依微吳苑樹，迢遞晉陵城。", "慰此斷行別，邑人多頌聲。"]'),
('6fb0d0d8-2909-46b1-98db-3153a224e133','贈別河南李功曹','韋應物','唐','唐诗','tang','','[]','耿耿抱私戚，寥寥獨掩扉。',120,'全唐诗/poet.tang.9000.json','["耿耿抱私戚，寥寥獨掩扉。", "臨觴自不飲，況與故人違。", "故人方琢磨，瓌朗代所稀。", "憲禮更右職，文翰灑天機。", "聿來自東山，羣彥仰餘輝。", "談笑取高第，綰綬即言歸。", "洛都遊燕地，千里及芳菲。", "今朝章臺別，楊柳亦依依。", "雲霞未改色，山川猶夕暉。", "忽復不相見，心思亂霏霏。"]'),
('3a7a8a69-b61d-4254-964e-7dd549a6fa25','送五經趙隨登科授廣德尉','韋應物','唐','唐诗','tang','','[]','明經有清秩，當在石渠中。',48,'全唐诗/poet.tang.9000.json','["明經有清秩，當在石渠中。", "獨往宣城郡，高齋謁謝公。", "寒原正蕪漫，夕鳥自西東。", "秋日不堪別，淒淒多朔風。"]'),
('d60e616d-5c6f-4e28-ad5d-fab7c6db851e','宴別幼遐與君貺兄弟','韋應物','唐','唐诗','tang','','[]','乖闕意方弭，安知忽來翔。',108,'全唐诗/poet.tang.9000.json','["乖闕意方弭，安知忽來翔。", "累日重歡宴，一旦復離傷。", "置酒慰茲夕，秉燭坐華堂。", "契闊未及展，晨星出東方。", "征人慘已辭，車馬儼成裝。", "我懷自無歡，原野滿春光。", "羣水含時澤，野雉鳴朝陽。", "平生有壯志，不覺淚霑裳。", "況自守空宇，日夕但徬徨。"]'),
('29cec281-c255-4007-8724-e216e5b078ef','送宣州周錄事','韋應物','唐','唐诗','tang','','[]','清時重儒士，糾郡屬伊人。',96,'全唐诗/poet.tang.9000.json','["清時重儒士，糾郡屬伊人。", "薄遊長安中，始得一交親。", "英豪若雲集，餞別塞城闉。", "高駕臨長路，日夕起風塵。", "方念清宵宴，已度芳林春。", "從茲一分手，緬邈吳與秦。", "但覩年運駛，安知後會因。", "唯當存令德，可以解悁勤。"]'),
('c6d0603f-f8b1-48d8-91e3-6a7787e096a5','謝櫟陽令歸西郊贈別諸友生','韋應物','唐','唐诗','tang','','[]','結髮仕州縣，蹉跎在文墨。',132,'全唐诗/poet.tang.9000.json','["結髮仕州縣，蹉跎在文墨。", "徒有排雲心，何由生羽翼。", "幸遭明盛日，萬物蒙生植。", "獨此抱微痾，頹然謝斯職。", "世道方荏苒，郊園思偃息。", "爲歡日已延，君子情未極。", "馳觴忽云晏，高論良難測。", "遊步清都宮，迎風嘉樹側。", "晨起西郊道，原野分黍稷。", "自樂陶唐人，服勤在微力。", "佇君列丹陛，出處兩爲得。"]'),
('f775ac78-2e99-49cc-9710-f1ac2c2f01e7','送端東行','韋應物','唐','唐诗','tang','','[]','世承清白遺，躬服古人言。',36,'全唐诗/poet.tang.9000.json','["世承清白遺，躬服古人言。", "從官俱守道，歸來共閉門。", "驅車何處去，暮雪滿平原。"]'),
('13e227e0-a8f9-479f-9bbc-68b3b8b7da6f','送姚孫還河中','韋應物','唐','唐诗','tang','','[]','上國旅遊罷，故園生事微。',48,'全唐诗/poet.tang.9000.json','["上國旅遊罷，故園生事微。", "風塵滿路起，行人何處歸。", "留思芳樹飲，惜別暮春暉。", "幾日投關郡，河山對掩扉。"]'),
('9417801f-4ca2-4456-8bbc-85fcc6cade9f','始除尚書郎別善福精舍','韋應物','唐','唐诗','tang','','[]','簡略非世器，委身同草木。',144,'全唐诗/poet.tang.9000.json','["簡略非世器，委身同草木。", "逍遙精舍居，飲酒自爲足。", "累日曾一櫛，對書常懶讀。", "社臘會高年，山川恣遊矚。", "明世方選士，中朝懸美祿。", "除書忽到門，冠帶便拘束。", "愧忝郎署跡，謬蒙君子錄。", "俯仰垂華纓，飄颻翔輕轂。", "行將親愛別，戀此西澗曲。", "遠峰明夕川，夏雨生衆綠。", "迅風飄野路，廻首不遑宿。", "明晨下煙閣，白雲在幽谷。"]'),
('34b13103-af4f-4f03-adb0-ef2c1b785810','送常侍御却使西蕃','韋應物','唐','唐诗','tang','','[]','歸奏聖朝行萬里，却銜天詔報蕃臣。',64,'全唐诗/poet.tang.9000.json','["歸奏聖朝行萬里，却銜天詔報蕃臣。", "本是諸生守文墨，今將匹馬靜煙塵。", "旅宿關河逢暮雨，春耕亭障識遺民。", "此去多應收故地，寧辭沙塞往來頻。"]'),
('66e99c90-2d08-4468-8872-a6cc5dec67dd','送郗詹事','韋應物','唐','唐诗','tang','','[]','聖朝列羣彥，穆穆佐休明。',120,'全唐诗/poet.tang.9000.json','["聖朝列羣彥，穆穆佐休明。", "君子獨知止，懸車守國程。", "忠良信舊德，文學播英聲。", "既獲天爵美，況將齒位幷。", "書奏蒙省察，命駕乃東征。", "皇恩賜印綬，歸爲田里榮。", "朝野同稱歎，園綺鬱齊名。", "長衢軒葢集，飲餞出西京。", "時屬春陽節，草木已含英。", "洛川當盛宴，斯焉爲達生。"]'),
('0dffd275-e938-46a3-a4b9-005623b3fa2a','送蘇評事','韋應物','唐','唐诗','tang','','[]','季弟仕譙都，元兄坐蘭省。',48,'全唐诗/poet.tang.9000.json','["季弟仕譙都，元兄坐蘭省。", "言訪始忻忻，念離當耿耿。", "嵯峨夏雲起，迢遰山川永。", "登高望去塵，紛思終難整。"]'),
('25f71b36-8615-4900-9dc8-051bfdce8d3e','送李侍御益赴幽州幕','韋應物','唐','唐诗','tang','','[]','二十揮篇翰，三十窮典墳。',108,'全唐诗/poet.tang.9000.json','["二十揮篇翰，三十窮典墳。", "辟書五府至，名爲四海聞。", "始從車騎幕，今赴嫖姚軍。", "契闊晚相遇，草慼遽離羣。", "悠悠行子遠，眇眇川途分。", "登高望燕代，日夕生夏雲。", "司徒擁精甲，誓將除國氛。", "儒生幸持斧，可以佐功勳。", "無言羽書急，坐闕相思文。"]'),
('878f36d8-5f49-4a16-8e05-ffd2481f139b','自尚書郎出爲滁州刺史','韋應物','唐','唐诗','tang','','[]','少年不遠仕，秉笏東西京。',132,'全唐诗/poet.tang.9000.json','["少年不遠仕，秉笏東西京。", "中歲守淮郡，奉命乃征行。", "素慙省閣姿，況忝符竹榮。", "効愚方此始，顧私豈獲幷。", "徘徊親交戀，愴悢昆友情。", "日暮風雪起，我去子還城。", "登塗建隼旟，勒駕望承明。", "雲臺煥中天，龍闕鬱上征。", "晨興奉早朝，玉露霑華纓。", "一朝從此去，服膺理庶甿。", "皇恩儻歲月，歸服廁羣英。"]'),
('11071f40-e192-4519-a90d-133bf4cbeabb','送元錫楊凌','韋應物','唐','唐诗','tang','','[]','荒林翳山郭，積水成秋晦。',48,'全唐诗/poet.tang.9000.json','["荒林翳山郭，積水成秋晦。", "端居意自違，況別親與愛。", "歡筵慊未足，離燈悄已對。", "還當掩郡閣，佇君方此會。"]'),
('f800050a-d7a0-4f12-a614-17fe23df8f41','送楊氏女','韋應物','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9001\u522b", "\u611f\u4f24", "\u4e94\u8a00\u53e4\u8bd7"]','永日方慼慼，出門復悠悠。',144,'全唐诗/poet.tang.9000.json','["永日方慼慼，出門復悠悠。", "女子今有行，大江泝輕舟。", "爾輩況無恃，撫念益慈柔。", "幼爲長所育，兩別泣不休。", "對此結中腸，義往難復留。", "自小闕內訓，事姑貽我憂。", "賴茲託令門，仁恤庶無尤。", "貧儉誠所尚，資從豈待周。", "孝恭遵婦道，容止順其猷。", "別離在今晨，見爾當何秋。", "居閑始自遣，臨感忽難收。", "歸來視幼女，零淚緣纓流。"]'),
('527e9413-ac14-409b-a6f6-b2bb7d33a3e1','送中弟','韋應物','唐','唐诗','tang','','[]','秋風入疎戶，離人起晨朝。',48,'全唐诗/poet.tang.9000.json','["秋風入疎戶，離人起晨朝。", "山郡多風雨，西樓更蕭條。", "嗟予淮海老，送子關河遙。", "同來不同去，沈憂寧復消。"]'),
('256dd26f-9223-4e29-84bb-b1253886cb65','寄別李儋','韋應物','唐','唐诗','tang','','[]','首戴惠文冠，心有決勝籌。',96,'全唐诗/poet.tang.9000.json','["首戴惠文冠，心有決勝籌。", "翩翩四五騎，結束向幷州。", "名在相公幕，丘山恩未酬。", "妻子不及顧，親友安得留。", "宿昔同文翰，交分共綢繆。", "忽枉別離札，涕淚一交流。", "遠郡臥殘疾，涼氣滿西樓。", "想子臨長路，時當淮海秋。"]'),
('69758b16-d314-44a0-8c82-85309d6778f7','送倉部蕭員外院長存','韋應物','唐','唐诗','tang','','[]','襆被蹉跎老江國，情人邂逅此相逢。',32,'全唐诗/poet.tang.9000.json','["襆被蹉跎老江國，情人邂逅此相逢。", "不隨鴛鷺朝天去，遙想蓬萊臺閣重。"]'),
('f65d874a-316b-4c34-9fab-cc0eb6265d33','送王校書','韋應物','唐','唐诗','tang','','[]','同宿高齋換時節，共看移石復栽杉。',32,'全唐诗/poet.tang.9000.json','["同宿高齋換時節，共看移石復栽杉。", "送君江浦已惆悵，更上西樓看遠帆。"]'),
('74be64d3-9cc2-4de4-92ce-410e038a044c','送丘員外還山','韋應物','唐','唐诗','tang','','[]','長棲白雲表，蹔訪高齋宿。',72,'全唐诗/poet.tang.9000.json','["長棲白雲表，蹔訪高齋宿。", "還辭郡邑諠，歸泛松江淥。", "結茅隱蒼嶺，伐薪響深谷。", "同是山中人，不知往來躅。", "靈芝非庭草，遼鶴委池鶩。", "終當署里門，一表高陽族。"]'),
('76214013-558f-49ff-ac2a-a988621405ce','重送丘二十二還臨平山居','韋應物','唐','唐诗','tang','','[]','歲中始再覯，方來又解攜。',48,'全唐诗/poet.tang.9000.json','["歲中始再覯，方來又解攜。", "纔留野艇語，已憶故山棲。", "幽澗人夜汲，深林鳥長啼。", "還持郡齋酒，慰子霜露淒。"]'),
('ec82071b-cfe0-4bb2-b814-a98d42c34c32','送鄭端公弟移院常州','韋應物','唐','唐诗','tang','','[]','時瞻憲臣重，禮爲內兄全。',72,'全唐诗/poet.tang.9000.json','["時瞻憲臣重，禮爲內兄全。", "公程儻見責，私愛信不愆。", "況昔陪朝列，今茲俱海壖。", "清觴方對酌，天書忽告遷。", "豈徒咫尺地，使我心思綿。", "應當自此始，歸拜雲臺前。"]'),
('87149227-342f-4959-9dd8-058e590e2169','送房杭州','韋應物','唐','唐诗','tang','','[]','專城未四十，暫謫豈蹉跎。',24,'全唐诗/poet.tang.9000.json','["專城未四十，暫謫豈蹉跎。", "風雨吳門夜，惻愴別情多。"]'),
('fda4b0ab-0aba-4b42-8092-137a2aacf9df','送陸侍御還越','韋應物','唐','唐诗','tang','','[]','居藩久不樂，遇子聊一欣。',96,'全唐诗/poet.tang.9000.json','["居藩久不樂，遇子聊一欣。", "英聲頗籍甚，交辟迺時珍。", "繡衣過舊里，驄馬輝四鄰。", "敬恭尊郡守，牋簡具州民。", "謬忝誠所愧，思懷方見申。", "置榻宿清夜，加籩醼良辰。", "遵塗還盛府，行舫遶長津。", "自有賢方伯，得此文翰賓。"]'),
('f064a8c2-d27b-40d2-a5f9-55ec5afd55a1','聽江笛送陸侍御','韋應物','唐','唐诗','tang','','[]','遠聽江上笛，臨觴一送君。',24,'全唐诗/poet.tang.9000.json','["遠聽江上笛，臨觴一送君。", "還愁獨宿夜，更向郡齋聞。"]'),
('a080dcfa-22cc-41e6-8378-1a1179a853e8','送丘員外歸山居','韋應物','唐','唐诗','tang','','[]','郡閣始嘉宴，青山憶舊居。',24,'全唐诗/poet.tang.9000.json','["郡閣始嘉宴，青山憶舊居。", "爲君量革履，且願住藍轝。"]'),
('ad2f0faa-3a7f-4554-a338-a9addcf65180','送崔叔清遊越','韋應物','唐','唐诗','tang','','[]','忘茲適越意，愛我郡齋幽。',48,'全唐诗/poet.tang.9000.json','["忘茲適越意，愛我郡齋幽。", "野情豈好謁，詩興一相留。", "遠水帶寒樹，閶門望去舟。", "方伯憐文士，無爲成滯遊。"]'),
('c37681ff-4f6d-4098-a1a5-dd7b1808546a','送雲陽鄒儒立少府侍奉還京師','韋應物','唐','唐诗','tang','','[]','建中即藩守，天寶爲侍臣。',144,'全唐诗/poet.tang.9000.json','["建中即藩守，天寶爲侍臣。", "歷觀兩都士，多閱諸侯人。", "鄒生乃後來，英俊亦罕倫。", "爲文頗瓌麗，稟度自貞醇。", "甲科推令名，延閣播芳塵。", "再命趨王畿，請告奉慈親。", "一鍾信榮祿，可以展歡欣。", "昆弟俱時秀，長衢當自伸。", "聊從郡閣暇，美此時景新。", "方將極娛宴，已復及離晨。", "省署慙再入，江海綿十春。", "今日閶門路，握手子歸秦。"]'),
('53977d89-ac24-472a-b263-e05375222bdc','送豆盧策秀才','韋應物','唐','唐诗','tang','','[]','歲交冰未泮，地卑海氣昏。',96,'全唐诗/poet.tang.9000.json','["歲交冰未泮，地卑海氣昏。", "子有京師遊，始發吳閶門。", "新黃含遠林，微綠生陳根。", "詩人感時節，行道當憂煩。", "古來濩落者，俱不事田園。", "文如金石韻，豈乏知音言。", "方辭郡齋榻，爲酌離亭罇。", "無爲倦羈旅，一去高飛翻。"]'),
('d0a29119-bdbe-430c-abbc-bab4893d8f96','送王卿','韋應物','唐','唐诗','tang','','[]','別酌春林啼鳥稀，雙旌背日晚風吹。',32,'全唐诗/poet.tang.9000.json','["別酌春林啼鳥稀，雙旌背日晚風吹。", "却憶回來花已盡，東郊立馬望城池。"]'),
('24288aa4-a7b2-4e88-b4f2-55b59b376dff','送劉評事','韋應物','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','聲華滿京洛，藻翰發陽春。',108,'全唐诗/poet.tang.9000.json','["聲華滿京洛，藻翰發陽春。", "未遂鵷鴻舉，尚爲江海賓。", "吳中高宴罷，西上一遊秦。", "已想函關道，遊子冒風塵。", "籠禽羨歸翼，遠守懷交親。", "況復歲云暮，凜凜冰霜辰。", "旭霽開郡閣，寵餞集文人。", "洞庭摘朱實，松江獻白鱗。", "丈夫豈恨別，一酌且歡忻。"]'),
('341f804d-2536-4b3d-8db6-f9601994b9b1','送雷監赴闕庭','韋應物','唐','唐诗','tang','','[]','才大無不備，出入爲時須。',96,'全唐诗/poet.tang.9000.json','["才大無不備，出入爲時須。", "雄藩精理行，祕府擢文儒。", "詔書忽已至，焉得久踟躅。", "方舟趂朝謁，觀者盈路衢。", "廣筵列衆賓，送爵無停迂。", "攀餞誠愴恨，賀榮且歡娛。", "長陪柏梁宴，日向丹墀趨。", "時方重右職，蹉跎獨海隅。"]'),
('ec552279-91ec-4018-bfbb-d11abd1eaa53','送秦系赴潤州','韋應物','唐','唐诗','tang','','[]','近作新婚鑷白髯，長懷舊卷映藍衫。',32,'全唐诗/poet.tang.9000.json','["近作新婚鑷白髯，長懷舊卷映藍衫。", "更欲攜君虎丘寺，不知方伯望征帆。"]'),
('944a28ec-3ced-4bd1-8145-bc4a526b9b8d','送孫徵赴雲中','韋應物','唐','唐诗','tang','','[]','黃驄少年舞雙戟，目視傍人皆辟易。',96,'全唐诗/poet.tang.9000.json','["黃驄少年舞雙戟，目視傍人皆辟易。", "百戰會誇隴上兒，一身復作雲中客。", "寒風動地氣蒼芒，橫吹先悲出塞長。", "敲石軍中傳夜火，斧冰河畔汲朝漿。", "前鋒直指陰山外，虜騎紛紛翦應碎。", "匈奴破盡看君歸，金印酬功如斗大。"]'),
('e183b980-003b-43fa-8e3e-3443de151dca','期盧嵩枉書稱日暮無馬不赴以詩答','韋應物','唐','唐诗','tang','','[]','佳期不可失，終願枉衡門。',48,'全唐诗/poet.tang.9000.json','["佳期不可失，終願枉衡門。", "南陌人猶度，西林日未昏。", "庭前空倚杖，花裏獨留罇。", "莫道無來駕，知君有短轅。"]'),
('7b4080ad-bdb7-42ed-b2bf-2d1d1dd40b78','任洛陽丞答前長安田少府問','韋應物','唐','唐诗','tang','','[]','相逢且對酒，相問欲何如。',48,'全唐诗/poet.tang.9000.json','["相逢且對酒，相問欲何如。", "數歲猶卑吏，家人笑著書。", "告歸應未得，榮宦又知疎。", "日日生春草，空令憶舊居。"]'),
('a6f667e6-dbf3-4565-9d3c-fe2a2c3857d9','假中枉盧二十二書亦稱臥疾兼訝李二久不訪問以詩答書因亦戲李二','韋應物','唐','唐诗','tang','','[]','微官何事勞趨走，服藥閑眠養不才。',64,'全唐诗/poet.tang.9000.json','["微官何事勞趨走，服藥閑眠養不才。", "花裏棋盤憎鳥汙，枕邊書卷訝風開。", "故人問訊緣同病，芳月相思阻一杯。", "應笑王戎成俗物，遙持麈尾獨徘徊。"]'),
('7903b8d8-92bf-4a77-955f-858859783050','酬盧嵩秋夜見寄五韻','韋應物','唐','唐诗','tang','','[]','喬木生夜涼，月華滿前墀。',60,'全唐诗/poet.tang.9000.json','["喬木生夜涼，月華滿前墀。", "去君咫尺地，勞君千里思。", "素秉棲遁志，況貽招隱詩。", "坐見林木榮，願赴滄洲期。", "何能待歲晏，攜手當此時。"]'),
('9c726c82-b094-4258-bdfc-12b27cf1a3c9','酬鄭戶曹驪山感懷','韋應物','唐','唐诗','tang','','[]','蒼山何鬱盤，飛閣凌上清。',192,'全唐诗/poet.tang.9000.json','["蒼山何鬱盤，飛閣凌上清。", "先帝昔好道，下元朝百靈。", "白雲已蕭條，麋鹿但縱橫。", "泉水今尚煖，舊林亦青青。", "我念綺襦歲，扈從當太平。", "小臣職前驅，馳道出灞亭。", "翻翻日月旗，殷殷鼙鼓聲。", "萬馬自騰驤，八駿按轡行。", "日出煙嶠綠，氛氳麗層甍。", "登臨起遐想，沐浴懽聖情。", "朝燕詠無事，時豐賀國禎。", "日和絃管音，下使萬室聽。", "海內湊朝貢，賢愚共歡榮。", "合沓車馬喧，西聞長安城。", "事往世如寄，感深迹所經。", "申章報蘭藻，一望雙涕零。"]'),
('771bbf2f-d2c9-4f35-ad0c-88316209ff40','答李澣三首 一','韋應物','唐','唐诗','tang','','[]','孤客逢春暮，緘情寄舊遊。',24,'全唐诗/poet.tang.9000.json','["孤客逢春暮，緘情寄舊遊。", "海隅人使遠，書到洛陽秋。"]'),
('4736d323-1659-4795-bed4-39fb2f67c084','答李澣三首 二','韋應物','唐','唐诗','tang','','[]','馬卿猶有壁，漁父自無家。',24,'全唐诗/poet.tang.9000.json','["馬卿猶有壁，漁父自無家。", "想子今何處，扁舟隱荻花。"]'),
('464481b2-d920-4137-80ec-4abcc16d3698','答李澣三首 三','韋應物','唐','唐诗','tang','','[]','林中觀易罷，溪上對鷗閑。',24,'全唐诗/poet.tang.9000.json','["林中觀易罷，溪上對鷗閑。", "楚俗饒辭客，何人最往還。"]'),
('ada2e6e4-3731-4b83-9f0c-3ade61fbad0c','酬柳郎中春日歸揚州南郭見別之作','韋應物','唐','唐诗','tang','','[]','廣陵三月花正開，花裏逢君醉一廻。',32,'全唐诗/poet.tang.9000.json','["廣陵三月花正開，花裏逢君醉一廻。", "南北相過殊不遠，暮潮從去早潮來。"]'),
('27df5f17-664c-4d3a-829d-a90c868d7264','酬豆盧倉曹題庫壁見示','韋應物','唐','唐诗','tang','','[]','掾局勞才子，新詩動洛川。',48,'全唐诗/poet.tang.9000.json','["掾局勞才子，新詩動洛川。", "運籌知決勝，聚米似論邊。", "宴罷常分騎，晨趨又比肩。", "莫嗟年鬢改，郎署定推先。"]'),
('c1ef593a-1a40-4189-9a5a-878b01b33d67','酬李儋','韋應物','唐','唐诗','tang','','[]','開門臨廣陌，旭旦車駕喧。',96,'全唐诗/poet.tang.9000.json','["開門臨廣陌，旭旦車駕喧。", "不見同心友，徘徊憂且煩。", "都城二十里，居在艮與坤。", "人生所各務，乖闊累朝昏。", "湛湛罇中酒，青青芳樹園。", "緘情未及發，先此枉璵璠。", "邁世超高躅，尋流得真源。", "明當策疲馬，與子同笑言。"]'),
('9ef4e505-6345-47ee-92ae-25fff6ea32c1','酬元偉過洛陽夜燕','韋應物','唐','唐诗','tang','','[]','三載寄關東，所懽皆遠違。',96,'全唐诗/poet.tang.9000.json','["三載寄關東，所懽皆遠違。", "思懷方耿耿，忽得觀容輝。", "親燕在良夜，歡攜闢中闈。", "問我猶杜門，不能奮高飛。", "明燈照四隅，炎炭正可依。", "清觴雖云酌，所媿乏珍肥。", "晨裝復當行，寥落星已稀。", "何以慰心曲，佇子西還歸。"]'),
('ac178252-f128-4e72-8401-eb9543f380bd','酬韓質舟行阻凍','韋應物','唐','唐诗','tang','','[]','晨坐枉嘉藻，持此慰寢興。',96,'全唐诗/poet.tang.9000.json','["晨坐枉嘉藻，持此慰寢興。", "中獲辛苦奏，長河結陰冰。", "皓曜羣玉發，淒清孤景凝。", "至柔反成堅，造化安可恆。", "方舟未得行，鑿飲空兢兢。", "寒苦彌時節，待泮豈所能。", "何必涉廣川，荒衢且升騰。", "殷勤宣中意，庶用達吾朋。"]'),
('3821b830-dbd9-489b-8e78-6c6fb0f0ba82','李博士弟以余罷官居同德精舍共有伊陸名山之期久而未去枉詩見問中云宋生昔登覽未云那能顧蓬蓽直寄鄙懷聊以爲答','韋應物','唐','唐诗','tang','','[]','初夏息衆緣，雙林對禪客。',96,'全唐诗/poet.tang.9000.json','["初夏息衆緣，雙林對禪客。", "枉茲芳蘭藻，促我幽人策。", "冥搜企前哲，逸句陳往迹。", "髣髴陸渾南，迢遞千峰碧。", "從來遲高駕，自顧無物役。", "山水心所娛，如何更朝夕。", "晨興涉清洛，訪子高陽宅。", "莫言往來疎，駑馬知阡陌。"]'),
('26488cf1-994f-4a08-bee7-754c45299cf3','寄酬李博士永寧主簿叔廳見待','韋應物','唐','唐诗','tang','','[]','解鞍先幾日，款曲見新詩。',48,'全唐诗/poet.tang.9000.json','["解鞍先幾日，款曲見新詩。", "定向公堂醉，遙憐獨去時。", "葉霑寒雨落，鐘度遠山遲。", "晨策已云整，當同林下期。"]'),
('f3031b70-afde-4fba-bb06-2fd5de9bd9c5','荅令狐士曹獨孤兵曹聯騎暮歸望山見寄','韋應物','唐','唐诗','tang','','[]','共愛青山住近南，行牽吏役背雙驂。',32,'全唐诗/poet.tang.9000.json','["共愛青山住近南，行牽吏役背雙驂。", "枉書獨宿對流水，遙羨歸時滿夕嵐。"]'),
('cbd60de7-b504-4b65-9f43-831766d41c82','荅李博士','韋應物','唐','唐诗','tang','','[]','休沐去人遠，高齋出林杪。',96,'全唐诗/poet.tang.9000.json','["休沐去人遠，高齋出林杪。", "晴山多碧峰，顥氣疑秋曉。", "端居喜良友，枉使千里路。", "緘書當夏時，開緘時已度。", "簷雛已颻颺，荷露方蕭颯。", "夢遠竹窗幽，行稀蘭徑合。", "舊居共南北，往來只如昨。", "問君今爲誰，日夕度清洛。"]'),
('7be33ce3-fafa-44f9-bb62-381a73cf26ba','荅劉西曹','韋應物','唐','唐诗','tang','','[]','公館夜云寂，微涼羣樹秋。',96,'全唐诗/poet.tang.9000.json','["公館夜云寂，微涼羣樹秋。", "西曹得時彥，華月共淹留。", "長嘯舉清觴，志氣誰與儔。", "千齡事雖邈，俯念忽已周。", "篇翰如雲興，京洛頗優游。", "詮文不獨古，理妙即同流。", "淺劣見推許，恐爲識者尤。", "空慙文璧贈，日夕不能酬。"]'),
('61b242d0-ed07-4658-8c21-94a5b9df3c4a','荅貢士黎逢','韋應物','唐','唐诗','tang','','[]','茂等方上達，諸生安可希。',84,'全唐诗/poet.tang.9000.json','["茂等方上達，諸生安可希。", "栖神澹物表，渙汗布令詞。", "如彼崑山玉，本自有光輝。", "鄙人徒區區，稱歎亦何爲。", "彌月曠不接，公門但驅馳。", "蘭章忽有贈，持用慰所思。", "不見心尚密，況當相見時。"]'),
('c3cd2565-025e-43e9-977a-8f3fc1caccf9','答韓庫部','韋應物','唐','唐诗','tang','','[]','良玉表貞度，麗藻頗爲工。',96,'全唐诗/poet.tang.9000.json','["良玉表貞度，麗藻頗爲工。", "名列金閨籍，心與素士同。", "日晏下朝來，車馬自生風。", "清宵有佳興，皓月直南宮。", "矯翮方上征，顧我邈忡忡。", "豈不願攀舉，執事府庭中。", "智乖時亦蹇，才大命有通。", "還當以道推，解組守蒿蓬。"]'),
('be5eb903-96d8-4524-841d-041dc410d301','荅崔主簿倬','韋應物','唐','唐诗','tang','','[]','朗月分林靄，遙管動離聲。',48,'全唐诗/poet.tang.9000.json','["朗月分林靄，遙管動離聲。", "故驩良已阻，空宇澹無情。", "窈窕雲雁沒，蒼茫河漢橫。", "蘭草不可荅，沖襟徒自盈。"]'),
('215db3c1-14c1-4a25-b696-647b3bd114ee','荅徐秀才','韋應物','唐','唐诗','tang','','[]','鉛鈍謝貞器，時秀猥見稱。',48,'全唐诗/poet.tang.9000.json','["鉛鈍謝貞器，時秀猥見稱。", "豈如白玉仙，方與紫霞升。", "清詩舞豔雪，孤抱瑩玄冰。", "一枝非所貴，懷書思武陵。"]'),
('e52142f8-32c3-4844-9586-173428734494','荅東林道士','韋應物','唐','唐诗','tang','','[]','紫閣西邊第幾峰，茅齋夜雪虎行蹤。',32,'全唐诗/poet.tang.9000.json','["紫閣西邊第幾峰，茅齋夜雪虎行蹤。", "遙看黛色知何處，欲出山門尋暮鐘。"]'),
('78b22e6c-43ed-4896-866d-1c09adb76cfb','荅長寧令楊轍','韋應物','唐','唐诗','tang','','[]','皓月升林表，公堂滿清輝。',108,'全唐诗/poet.tang.9000.json','["皓月升林表，公堂滿清輝。", "嘉賓自遠至，觴飲夜何其。", "宰邑視京縣，歸來無寸資。", "瓌文溢衆寶，雅正得吾師。", "廣川含澄瀾，茂樹擢華滋。", "短才何足數，枉贈媿妍詞。", "歡盼良見屬，素懷亦已披。", "何意雲棲翰，不嫌蓬艾卑。", "但恐河漢沒，回車首路岐。"]');
